-- Poems batch 4
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('89150285-38e4-480d-87d6-95db4cb9a4ed','自淇涉黃河途中作十三首 四','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','南登滑臺上，却望河淇間。',48,'全唐诗/poet.tang.10000.json','["南登滑臺上，却望河淇間。", "竹樹夾流水，孤城對遠山。", "念茲川路闊，羨爾沙鷗閑。", "長想別離處，猶無音信還。"]'),
('62492dd9-477c-4ce8-af80-cf9f9f895a3f','自淇涉黃河途中作十三首 五','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','東入黃河水，茫茫汎紆直。',48,'全唐诗/poet.tang.10000.json','["東入黃河水，茫茫汎紆直。", "北望太行山，峨峨半天色。", "山河相暎帶，深淺未可測。", "自昔有賢才，相逢不相識。"]'),
('bbe30e55-8238-495c-bcf9-8144fe363439','自淇涉黃河途中作十三首 六','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','秋日登滑臺，臺高秋已暮。',108,'全唐诗/poet.tang.10000.json','["秋日登滑臺，臺高秋已暮。", "獨行既未愜，懷土悵無趣。", "晉宋何蕭條，羌胡散馳騖。", "當時無戰略，此地即邊戍。", "兵革徒自勤，山河孰云固。", "乘閑喜臨眺，感物傷遊寓。", "惆悵落日前，飄颻遠帆處。", "北風吹萬里，南雁不知數。", "歸意方浩然，雲沙更廻互。"]'),
('b0e51eac-3f11-473d-b3de-f2e9bdc1e74f','自淇涉黃河途中作十三首 七','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','亂流自茲遠，倚檝時一望。',72,'全唐诗/poet.tang.10000.json','["亂流自茲遠，倚檝時一望。", "遙見楚漢城，崔嵬高山上。", "天道昔未測，人心無所向。", "屠釣稱侯王，龍蛇爭霸王。", "緬懷多殺戮，顧此生慘愴。", "聖代休甲兵，吾其得閑放。"]'),
('45e93c66-046f-44aa-9752-7e4246ad6c43','自淇涉黃河途中作十三首 八','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','茲川方悠邈，雲沙無前後。',48,'全唐诗/poet.tang.10000.json','["茲川方悠邈，雲沙無前後。", "古堰對河壖，長林出淇口。", "獨行非吾意，東向日已久。", "憂來誰得知，且酌尊中酒。"]'),
('fb5a52a2-c14b-4302-b5b1-ab18d92348ab','自淇涉黃河途中作十三首 九','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','朝從北岸來，泊船南河滸。',72,'全唐诗/poet.tang.10000.json','["朝從北岸來，泊船南河滸。", "試共野人言，深覺農夫苦。", "去秋雖薄熟，今夏猶未雨。", "耕耘日勤勞，租稅兼舃鹵。", "園蔬空寥落，產業不足數。", "尚有獻芹心，無因見明主。"]'),
('cea51298-9d8e-468f-a075-8e843c97e018','自淇涉黃河途中作十三首 十','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','茫茫濁河注，懷古臨河濱。',84,'全唐诗/poet.tang.10000.json','["茫茫濁河注，懷古臨河濱。", "禹功本豁達，漢跡方因循。", "坎德昔滂沱，馮夷胡不仁。", "激潏陵堤防，東郡多悲辛。", "天子忽驚悼，從官皆負薪。", "畚築豈無謀，祈禱如有神。", "宣房今安在，高岸空嶙峋。"]'),
('c501f17a-230a-49b5-833c-5889a4e9bc85','自淇涉黃河途中作十三首 十一','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','我行倦風湍，輟棹將問津。',72,'全唐诗/poet.tang.10000.json','["我行倦風湍，輟棹將問津。", "空傳歌瓠子，感慨獨愁人。", "孟夏桑葉肥，穠陰夾長津。", "蠶農有時節，田野無閑人。", "臨水狎漁樵，望山懷隱淪。", "誰能去京洛，顦顇對風塵。"]'),
('b9811b91-7522-46d2-ae55-63d63968adca','自淇涉黃河途中作十三首 十二','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','朝景入平川，川長復垂柳。',108,'全唐诗/poet.tang.10000.json','["朝景入平川，川長復垂柳。", "遙看魏公墓，突兀前山後。", "憶昔大業時，羣雄角奔走。", "伊人何電邁，獨立風塵首。", "傳檄舉敖倉，擁兵屯洛口。", "連營一百萬，六合如可有。", "方項終比肩，亂隋將假手。", "力爭固難恃，驕戰曷能久。", "若使學蕭曹，功名當不朽。"]'),
('ef119060-f85f-444a-a103-4a07a56d1202','自淇涉黃河途中作十三首 十三','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','皤皤河濱叟，相遇似有耻。',96,'全唐诗/poet.tang.10000.json','["皤皤河濱叟，相遇似有耻。", "輟榜聊問之，荅言盡終結。", "一生雖貧賤，九十年未死。", "且喜對兒孫，彌慙遠城市。", "結廬黃河曲，垂釣長河裏。", "漫漫望雲沙，蕭條聽風水。", "所思強飯食，永願在鄉里。", "萬事吾不知，其心只如此。"]'),
('efb2f4fe-cbfc-424a-9980-7015cd556941','宋中遇陳二','高適','唐','唐诗','tang','','[]','常忝鮑叔義，所期王佐才。',96,'全唐诗/poet.tang.10000.json','["常忝鮑叔義，所期王佐才。", "如何守苦節，獨此無良媒。", "離別十年外，飄颻千里來。", "安知罷官後，惟見柴門開。", "窮巷隱東郭，高堂詠南陔。", "籬根長花草，井上生莓苔。", "伊昔望霄漢，於今倦蒿萊。", "男兒命未達，且盡手中桮。"]'),
('cd99fae2-e492-43a5-991d-5febb80ba51d','宋中遇劉書記有別','高適','唐','唐诗','tang','','[]','何代無秀士，高門生此才。',96,'全唐诗/poet.tang.10000.json','["何代無秀士，高門生此才。", "森然覩毛髮，若見河山來。", "幾載困常調，一朝時運催。", "白身謁明主，待詔登雲臺。", "相逢梁宋間，與我醉蒿萊。", "寒楚眇千里，雪天晝不開。", "末路終離別，不能強悲哀。", "男兒爭富貴，勸爾莫遲廻。"]'),
('50d96cb2-de4f-4cbe-bf62-3159b077d2f6','魯郡途中遇徐十八錄事','高適','唐','唐诗','tang','','[]','誰謂嵩潁客，遂經鄒魯鄉。',96,'全唐诗/poet.tang.10000.json','["誰謂嵩潁客，遂經鄒魯鄉。", "前臨少昊墟，始覺東蒙長。", "獨行豈吾心，懷古激中腸。", "聖人久已矣，游夏遙相望。", "裴回野澤間，左右多悲傷。", "日出見闕里，川平知汶陽。", "弱冠負高節，十年思自強。", "終然不得意，去去任行藏。"]'),
('1ca1c436-1a66-4274-94b3-12c87aae8f73','遇沖和先生','高適','唐','唐诗','tang','','[]','沖和生何代，或謂遊東溟。',120,'全唐诗/poet.tang.10000.json','["沖和生何代，或謂遊東溟。", "三命謁金殿，一言拜銀青。", "自云多方術，往往通神靈。", "萬乘親問道，六宮無敢聽。", "昔去限霄漢，今來覩儀形。", "頭戴鶡鳥冠，手遙白鶴翎。", "終日飲醇酒，不醉復不醒。", "常憶雞鳴山，每誦西昇經。", "拊背念離別，依然出戶庭。", "莫見今如此，曾爲一客星。"]'),
('d533a0a3-9b2f-4242-be08-532ac4eb526d','魯西至東平','高適','唐','唐诗','tang','','[]','沙岸拍不定，石橋水橫流。',36,'全唐诗/poet.tang.10000.json','["沙岸拍不定，石橋水橫流。", "問津見魯俗，懷古傷家丘。", "寥落千載後，空傳褒聖侯。"]'),
('781223c9-12d7-42f1-8a53-273d4a032a11','東平路作三首 一','高適','唐','唐诗','tang','','[]','南圖適不就，東走豈吾心。',36,'全唐诗/poet.tang.10000.json','["南圖適不就，東走豈吾心。", "索索涼風動，行行秋水深。", "蟬鳴木葉落，茲夕更愁霖。"]'),
('a01fffef-b801-4397-958b-8435953a1802','東平路作三首 二','高適','唐','唐诗','tang','','[]','明時好畫策，動欲干王公。',36,'全唐诗/poet.tang.10000.json','["明時好畫策，動欲干王公。", "今日無成事，依依親老農。", "扁舟向何處？吾愛汶陽中。"]'),
('d5249aa5-2cf7-4e8f-b031-c4796e6b246c','東平路作三首 三','高適','唐','唐诗','tang','','[]','清曠涼夜月，裴回孤客舟。',36,'全唐诗/poet.tang.10000.json','["清曠涼夜月，裴回孤客舟。", "渺然風波上，獨愛前山秋。", "秋至復搖落，空令行者愁。"]'),
('760090ec-525e-4d37-bc53-fd01dd495681','東平路中遇大水','高適','唐','唐诗','tang','','[]','天災自古有，昏墊彌今秋。',168,'全唐诗/poet.tang.10000.json','["天災自古有，昏墊彌今秋。", "霖霪溢川原，澒洞涵田疇。", "指途適汶陽，挂席經蘆洲。", "永望齊魯郊，白雲何悠悠。", "傍沿鉅野澤，大水縱橫流。", "蟲蛇擁獨樹，麋鹿奔行舟。", "稼穡隨波瀾，西成不可求。", "室居相枕藉，蛙黽聲啾啾。", "仍憐穴蟻漂，益羨雲禽游。", "農夫無倚着，野老生殷憂。", "聖主當深仁，廟堂運良籌。", "倉廩終爾給，田租應罷收。", "我心胡鬱陶，征旅亦悲愁。", "縱懷濟時策，誰肯論吾謀。"]'),
('dcccde71-c438-4fa8-ac7a-a9ac53638a7c','登壠','高適','唐','唐诗','tang','','[]','壠頭遠行客，壠上分流水。',48,'全唐诗/poet.tang.10000.json','["壠頭遠行客，壠上分流水。", "流水無盡期，行人未云已。", "淺才登一命，孤劒通萬里。", "豈不思故鄉，從來感知己。"]'),
('3e598395-2064-42df-ae7a-16bf591c0695','苦雪四首 一','高適','唐','唐诗','tang','','[]','二月猶北風，天陰雪冥冥。',36,'全唐诗/poet.tang.10000.json','["二月猶北風，天陰雪冥冥。", "寥落一室中，悵然慙百齡。", "苦愁正如此，門柳復青青。"]'),
('4941ee70-92db-47bc-87d7-ba11b212025f','苦雪四首 二','高適','唐','唐诗','tang','','[]','惠連發清興，袁安念高臥。',36,'全唐诗/poet.tang.10000.json','["惠連發清興，袁安念高臥。", "余故非斯人，爲性兼懶惰。", "賴茲尊中酒，終日聊自過。"]'),
('23aa1422-258b-4783-a800-1f28dc71facd','苦雪四首 三','高適','唐','唐诗','tang','','[]','濛濛灑平陸，淅瀝至幽居。',36,'全唐诗/poet.tang.10000.json','["濛濛灑平陸，淅瀝至幽居。", "且喜潤羣物，焉能悲斗儲。", "故交久不見，鳥雀投吾廬。"]'),
('359bc72a-6f60-4c69-a4cd-9d579e22fc8e','苦雪四首 四','高適','唐','唐诗','tang','','[]','孰云久閑曠，本自保知寡。',48,'全唐诗/poet.tang.10000.json','["孰云久閑曠，本自保知寡。", "窮巷獨無成，春條秪盈把。", "安能羨鵬舉，且欲歌牛下。", "乃知古時人，亦有如我者。"]'),
('e953a74d-4075-48bb-928f-114d0cd1a9eb','哭單父梁九少府','高適','唐','唐诗','tang','','[]','開篋淚沾臆，見君前日書。',144,'全唐诗/poet.tang.10000.json','["開篋淚沾臆，見君前日書。", "夜臺今寂寞，獨是子雲居。", "疇昔探雲奇，登臨賦山水。", "同舟南浦下，望月西江裏。", "契闊多別離，綢繆到生死。", "九原即何處，萬事皆如此。", "晉山徒峨峨，斯人已冥冥。", "常時祿且薄，歿後家復貧。", "妻子在遠道，弟兄無一人。", "十上多苦辛，一官恆自哂。", "青雲將可致，白日忽先盡。", "唯有身後名，空留無遠近。"]'),
('d669feeb-edbb-433a-b46f-9c302e3e7516','哭裴少府','高適','唐','唐诗','tang','','[]','世人誰不死，嗟君非生慮。',48,'全唐诗/poet.tang.10000.json','["世人誰不死，嗟君非生慮。", "扶病適到官，田園在何處？", "公才羣吏感，葬事他人助。", "余亦未識君，深悲哭君去。"]'),
('ed2b4826-b408-4aec-9fbc-1d69b9f58e6d','行路難二首 一','高適','唐','唐诗','tang','','[]','長安少年不少錢，能騎駿馬鳴金鞭。',64,'全唐诗/poet.tang.10000.json','["長安少年不少錢，能騎駿馬鳴金鞭。", "五侯相逢大道邊，美人弦管爭留連。", "黃金如斗不敢惜，片言如山莫棄捐。", "安知顦顇讀書者，暮宿靈臺私自憐。"]'),
('7b8079ae-910c-4680-883a-6f747712ce0d','行路難二首 二','高適','唐','唐诗','tang','','[]','君不見富家翁，舊時貧賤誰比數。',95,'全唐诗/poet.tang.10000.json','["君不見富家翁，舊時貧賤誰比數。", "一朝金多結豪貴，萬事勝人健如虎。", "子孫成行滿眼前，妻能管絃妾能舞。", "自矜一身忽如此，却笑傍人獨愁苦。", "東鄰少年安所如，席門窮巷出無車。", "有才不肯學干謁，何用年年空讀書。"]'),
('9cb15c8b-c714-4e8c-84eb-3658b637d12e','秋胡行','高適','唐','唐诗','tang','','[]','妾本邯鄲未嫁時，容華倚翠人未知。',256,'全唐诗/poet.tang.10000.json','["妾本邯鄲未嫁時，容華倚翠人未知。", "一朝結髮從君子，將妾迢迢東魯陲。", "時逢大道無艱阻，君方遊宦從陳汝。", "蕙樓獨臥頻度春，彩閣辭君幾徂暑。", "三月垂楊蠶未眠，攜籠結侶南陌邊。", "道逢行子不相識，贈妾黃金買少年。", "妾家夫壻經離久，寸心誓與長相守。", "願言行路莫多情，道妾貞心在人口。", "日暮蠶飢相命歸，攜籠端飾來庭闈。", "勞心苦力終無恨，所冀君恩即可依。", "聞說行人已歸止，乃是向來贈金子。", "相看顏色不復言，相顧懷慙有何已。", "從來自隱無疑背，直爲君情也相會。", "如何咫尺仍有情，況復迢迢千里外。", "誓將顧恩不顧身，念君此日赴河津。", "莫道向來不得意，故欲留規誡後人。"]'),
('5e31820a-bcc7-4bb7-b173-ab69e432e45c','古大梁行','高適','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','古城莽蒼饒荆榛，驅馬荒城愁殺人。',160,'全唐诗/poet.tang.10000.json','["古城莽蒼饒荆榛，驅馬荒城愁殺人。", "魏王宮觀盡禾黍，信陵賓客隨灰塵。", "憶昨雄都舊朝市，軒車照耀歌鐘起。", "軍容帶甲三十萬，國步連營一千里。", "全盛須臾那可論，高臺曲池無復存。", "遺墟但見狐狸迹，古地空餘草木根。", "暮天搖落傷懷抱，倚劒悲歌對秋草。", "俠客猶傳朱亥名，行人尚識夷門道。", "白璧黃金萬戶侯，寶刀駿馬填山丘。", "年代淒涼不可問，往來唯有水東流。"]'),
('d0639b4d-1c8e-40a7-a3d8-1275bec19b03','邯鄲少年行','高適','唐','唐诗','tang','','[]','邯鄲城南游俠子，自矜生長邯鄲裏。',113,'全唐诗/poet.tang.10000.json','["邯鄲城南游俠子，自矜生長邯鄲裏。", "千塲縱博家仍富，幾度報讐身不死。", "宅中歌笑日紛紛，門外車馬常如雲。", "未知肝膽向誰是，令人却憶平原君。", "君不見今人交態薄，黃金用盡還疎索。", "以茲感歎辭舊遊，更於時事無所求。", "且與少年飲美酒，往來射獵西山頭。"]'),
('e34f74b5-69ff-4136-927a-80d42eaeef6d','燕歌行','高適','唐','唐诗','tang','','[]','漢家煙塵在東北，漢將辭家破殘賊。',225,'全唐诗/poet.tang.10000.json','["漢家煙塵在東北，漢將辭家破殘賊。", "男兒本自重橫行，天子非常賜顏色。", "摐金伐鼓下榆關，旌斾逶迤碣石間。", "校尉羽書飛瀚海，單于獵火照狼山。", "山川蕭條極邊土，胡騎憑陵雜風雨。", "戰士軍前半死生，美人帳下猶歌舞。", "大漠窮秋塞草腓，孤城落日鬬兵稀。", "身當恩遇恆輕敵，力盡關山未解圍。", "鐵衣遠戍辛勤久，玉筯應啼別離後。", "少婦城南欲斷腸，征人薊北空回首。", "邊庭飄颻那可度，絕域蒼茫更何有。", "殺氣三時作陣雲，寒聲一夜傳刁斗。", "相看白刃血紛紛，死節從來豈顧勳。", "君不見沙場征戰苦，至今猶憶李將軍。"]'),
('32ade105-6639-4a2d-8ba5-afb25200c6b3','古歌行','高適','唐','唐诗','tang','','[]','君不見漢家三葉從代至，高皇舊臣多富貴。',67,'全唐诗/poet.tang.10000.json','["君不見漢家三葉從代至，高皇舊臣多富貴。", "天子垂衣方晏如，廟堂拱手無餘議。", "蒼生偃臥休征戰，露臺百金以爲費。", "田舍老翁不出門，洛陽少年莫論事。"]'),
('a7318ace-183f-44e8-9704-3fceabe908be','人日寄杜二拾遺','高適','唐','唐诗','tang','','["\u601d\u5ff5"]','人日題詩寄草堂，遙憐故人思故鄉。',96,'全唐诗/poet.tang.10000.json','["人日題詩寄草堂，遙憐故人思故鄉。", "柳條弄色不忍見，梅花滿枝空斷腸。", "身在遠藩無所預，心懷百憂復千慮。", "今年人日空相憶，明年人日知何處。", "一臥東山三十春，豈知書劒老風塵。", "龍鐘還忝二千石，愧爾東西南北人。"]'),
('6b65b2f9-0c0d-4b94-92ad-af22334582cf','九日酬顏少府','高適','唐','唐诗','tang','','[]','簷前白日應可惜，籬下黃花爲誰有。',64,'全唐诗/poet.tang.10000.json','["簷前白日應可惜，籬下黃花爲誰有。", "行子迎霜未授衣，主人得錢始沽酒。", "蘇秦顦顇人多厭，蔡澤棲遲世看醜。", "縱使登高只斷腸，不如獨坐空搔首。"]'),
('b541e528-83cc-4c89-9990-94fda479abdb','留別鄭三韋九兼洛下諸公','高適','唐','唐诗','tang','','[]','憶昨相逢論久要，顧君哂我輕常調。',144,'全唐诗/poet.tang.10000.json','["憶昨相逢論久要，顧君哂我輕常調。", "羈旅雖同白社遊，詩書已作青雲料。", "蹇質蹉跎竟不成，年過四十尚躬耕。", "長歌達者桮中物，大笑前人身後名。", "幸逢明盛多招隱，高山大澤徵求盡。", "此時亦得辭漁樵，青袍裹身荷聖朝。", "犂牛釣竿不復見，縣人邑吏來相邀。", "遠路鳴蟬秋興發，華堂美酒離憂銷。", "不知何日更攜手，應念茲晨去折腰。"]'),
('420a25fa-1c7e-4684-9919-838c96d1c61a','送楊山人歸嵩陽','高適','唐','唐诗','tang','','[]','不到嵩陽動十年，舊時心事已徒然。',80,'全唐诗/poet.tang.10000.json','["不到嵩陽動十年，舊時心事已徒然。", "一二故人不復見，三十六峰猶眼前。", "夷門二月柳條色，流鶯數聲淚沾臆。", "鑿井耕田不我招，知君以此忘帝力。", "山人好去嵩陽路，惟余眷眷長相憶。"]'),
('86467334-de4e-4df6-a218-51630701b941','送別','高適','唐','唐诗','tang','','[]','昨夜離心正鬱陶，三更白露西風高。',64,'全唐诗/poet.tang.10000.json','["昨夜離心正鬱陶，三更白露西風高。", "螢飛木落何淅瀝，此時夢見西歸客。", "曙鐘寥亮三四聲，東鄰嘶馬使人驚。", "攬衣出戶一相送，唯見歸雲縱復橫。"]'),
('b5d52c7f-9cd4-4805-8b40-47771a17af7b','贈別晉三處士','高適','唐','唐诗','tang','','[]','有人家住清河源，渡河問我游梁園。',96,'全唐诗/poet.tang.10000.json','["有人家住清河源，渡河問我游梁園。", "手持道經注已畢，心知內篇口不言。", "盧門十年見秋草，此心惆悵誰能道。", "知己從來不易知，慕君爲人與君好。", "別時九月桑葉疎，出門千里無行車。", "愛君且欲君先達，今上求賢早上書。"]'),
('344df1ed-e20f-4fb2-8f39-4f9634effe80','送渾將軍出塞','高適','唐','唐诗','tang','','["\u7231\u56fd", "\u9001\u522b", "\u5c06\u519b", "\u5199\u4eba"]','將軍族貴兵且強，漢家已是渾邪王。',192,'全唐诗/poet.tang.10000.json','["將軍族貴兵且強，漢家已是渾邪王。", "子孫相承在朝野，至今部曲燕支下。", "控弦盡用陰山兒，登陣常騎大宛馬。", "銀鞍玉勒繡蝥弧，每逐嫖姚破骨都。", "李廣從來先將士，衛青未肯學孫吳。", "傳有沙場千萬騎，昨日邊庭羽書至。", "城頭畫角三四聲，匣裏寶刀晝夜鳴。", "意氣能甘萬里去，辛勤判作一年行。", "黃雲白草無前後，朝建旌旄夕刁斗。", "塞下應多俠少年，關西不見春楊柳。", "從軍借問所從誰，擊劒酣歌當此時。", "遠別無輕繞朝策，平戎早寄仲宣詩。"]'),
('9a09444a-363a-4ca9-9537-2c6a91683de4','送蔡山人','高適','唐','唐诗','tang','','[]','東山布衣明古今，自言獨未逢知音。',96,'全唐诗/poet.tang.10000.json','["東山布衣明古今，自言獨未逢知音。", "識者閱見一生事，到處豁然千里心。", "看書學劒長辛苦，近日方思謁明主。", "斗酒相留醉復醒，悲歌數年淚如雨。", "丈夫遭遇不可知，買臣主父皆如斯。", "我今蹭蹬無所似，看爾崩騰何若爲。"]'),
('371ccd3f-c864-4c88-b53e-4feab2f090c0','封丘作','高適','唐','唐诗','tang','','[]','我本漁樵孟諸野，一生自是悠悠者。',128,'全唐诗/poet.tang.10000.json','["我本漁樵孟諸野，一生自是悠悠者。", "乍可狂歌草澤中，寧堪作吏風塵下。", "秪言小邑無所爲，公門百事皆有期。", "拜迎官長心欲碎，鞭撻黎庶令人悲。", "歸來向家問妻子，舉家盡笑今如此。", "生事應須南畝田，世情付與東流水。", "夢想舊山安在哉，爲銜君命且遲廻。", "乃知梅福徒爲爾，轉憶陶潛歸去來。"]'),
('febfce55-5c76-4c97-b44d-e4b97fe13b29','題李別駕壁','高適','唐','唐诗','tang','','[]','去鄉不遠逢知己，握手相歡得如此。',64,'全唐诗/poet.tang.10000.json','["去鄉不遠逢知己，握手相歡得如此。", "禮樂遙傳魯伯禽，賓客爭過魏公子。", "酒筵暮散明月上，櫪馬長鳴春風起。", "一生稱意能幾人，今日從君問終始。"]'),
('784b5bc3-05d5-425d-8935-49c42bf2cccc','寄宿田家','高適','唐','唐诗','tang','','[]','田家老翁住東陂，說道平生隱在茲。',128,'全唐诗/poet.tang.10000.json','["田家老翁住東陂，說道平生隱在茲。", "鬢白未曾記日月，山青每到識春時。", "門前種柳深成巷，野谷流泉添入池。", "牛壯日耕十畝地，人閑常掃一茅茨。", "客來滿酌清尊酒，感興平吟才子詩。", "巖際窟中藏鼴鼠，潭邊竹裏隱鸕鶿。", "村墟日落行人少，醉後無心怯路岐。", "今夜只應還寄宿，明朝拂曙與君辭。"]'),
('a03c0482-ee78-47d7-9762-18a156b751af','別韋參軍','高適','唐','唐诗','tang','','[]','二十解書劒，西遊長安城。',168,'全唐诗/poet.tang.10000.json','["二十解書劒，西遊長安城。", "舉頭望君門，屈指取公卿。", "國風沖融邁三五，朝廷歡樂彌寰宇。", "白璧皆言賜近臣，布衣不得干明主。", "歸來洛陽無負郭，東過梁宋非吾土。", "兔苑爲農歲不登，雁池垂釣心長苦。", "世人遇我同衆人，唯君於我最相親。", "且喜百年有交態，未嘗一日辭家貧。", "彈棊擊筑白日晚，縱酒高歌楊柳春。", "歡娛未盡分散去，使我惆悵驚心神。", "丈夫不作兒女別，臨岐涕淚沾衣巾。"]'),
('1e169041-882d-475c-bb60-8df9ecc9ac19','送田少府貶蒼梧','高適','唐','唐诗','tang','','[]','沈吟對遷客，惆悵西南天。',92,'全唐诗/poet.tang.10000.json','["沈吟對遷客，惆悵西南天。", "昔爲一官未得意，今向萬里令人憐。", "念茲斗酒成暌間，停舟歎君日將晏。", "遠樹應憐北地春，行人却羨南歸雁。", "丈夫窮達未可知，看君不合長數奇。", "江山到處堪乘興，楊柳青青那足悲。"]'),
('203b10c7-2886-4ae6-870f-6eb1ec9ff558','平臺夜遇李景參有別','高適','唐','唐诗','tang','','[]','離心忽悵然，策馬對秋天。',76,'全唐诗/poet.tang.10000.json','["離心忽悵然，策馬對秋天。", "孟諸薄暮涼風起，歸客相逢渡睢水。", "昨時攜手已十年，今日分途各千里。", "歲物蕭條滿路岐，此行浩蕩令人悲。", "家貧羨爾有微祿，欲往從之何所之。"]'),
('fb790ed4-04db-48f5-9b55-6f7d2b0a2042','送郭處士往萊蕪兼寄茍山人','高適','唐','唐诗','tang','','[]','君爲東蒙客，往來東蒙畔。',88,'全唐诗/poet.tang.10000.json','["君爲東蒙客，往來東蒙畔。", "雲臥臨嶧陽，山行窮日觀。", "少年詞賦皆可聽，秀眉白面風清泠。", "身上未曾染名利，口中猶未知膻腥。", "今日還山意無極，豈辭世路多相識。", "歸見萊蕪九十翁，爲論別後長相憶。"]'),
('03ca699d-7447-498d-8251-cf9f85deae11','賦得還山吟送沈四山人','高適','唐','唐诗','tang','','["\u8d60\u522b", "\u5199\u4eba", "\u53cb\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','還山吟，天高日暮寒山深。',108,'全唐诗/poet.tang.10000.json','["還山吟，天高日暮寒山深。", "送君還山識君心，人生老大須恣意。", "看君解作一生事，山間偃仰無不至。", "石泉淙淙若風雨，桂花松子常滿地。", "賣藥囊中應有錢，還山服藥又長年。", "白雲勸盡桮中物，明月相隨何處眠。", "眠時憶問醒時事，夢魂可以相周旋。"]'),
('2656cc2f-8178-477d-88b4-13bb0d73a634','崔司錄宅燕大理李卿','高適','唐','唐诗','tang','','[]','多雨殊未已，秋雲更沈沈。',92,'全唐诗/poet.tang.10000.json','["多雨殊未已，秋雲更沈沈。", "洛陽故人初解印，山東小吏來相尋。", "上卿才大名不朽，早朝至尊暮求友。", "豁達常推海內賢，殷勤但酌尊中酒。", "飲醉欲言歸剡溪，門前駟馬光照衣。", "路傍觀者徒唧唧，我公不以爲是非。"]'),
('4b563103-d593-41f9-96a4-b65155ccbde4','同鮮于洛陽於畢員外宅觀畫馬歌','高適','唐','唐诗','tang','','[]','知君愛鳴琴，仍好千里馬。',124,'全唐诗/poet.tang.10000.json','["知君愛鳴琴，仍好千里馬。", "永日恆思單父中，有時心到宛城下。", "遇客丹青天下才，白生胡雛控龍媒。", "主人娛賓畫障開，只言騏驥西極來。", "半壁䟃𧽼勢不住，滿堂風飄颯然度。", "家僮愕視欲先鞭，櫪馬驚嘶還屢顧。", "始知物妙皆可憐，燕昭市駿豈徒然。", "縱令剪拂無所用，猶勝駑駘在眼前。"]'),
('399d7586-1d9c-491f-b854-2f7b61b27980','同河南李少尹畢員外宅夜飲時洛陽告捷遂作春酒歌','高適','唐','唐诗','tang','','[]','故人美酒勝濁醪，故人清詞合風騷。',154,'全唐诗/poet.tang.10000.json','["故人美酒勝濁醪，故人清詞合風騷。", "長歌滿酌惟吾曹，高談正可揮麈毛。", "半醉忽然持蟹螯，洛陽告捷傾前後。", "武侯腰間印如斗，郎官無事時飲酒。", "桮中綠蟻吹轉來，甕上飛花拂還有。", "前年持節將楚兵，去年留司在東京。", "今年復拜二千石，盛夏五月西南行。", "彭門劒門蜀山裏，昨逢軍人刦奪我。", "到家但見妻與子，賴得飲君春酒數十桮，不然令我愁欲死。"]'),
('101844bd-db52-4b7b-a097-c45162545c77','同李九士曹觀壁畫雲作','高適','唐','唐诗','tang','','[]','始知帝鄉客，能畫蒼梧雲。',28,'全唐诗/poet.tang.10000.json','["始知帝鄉客，能畫蒼梧雲。", "秋天萬里一片色，只疑飛盡猶氛氳。"]'),
('17c901f7-75d0-48ce-ac16-95724c21dad9','見薛大臂鷹作','高適','唐','唐诗','tang','','[]','寒楚十二月，蒼鷹八九毛。',28,'全唐诗/poet.tang.10000.json','["寒楚十二月，蒼鷹八九毛。", "寄言燕雀莫相啅，自有雲霄萬里高。"]'),
('e94f7b4c-7e68-4d8b-81b3-053539a689d8','畫馬篇','高適','唐','唐诗','tang','','[]','君侯櫪上驄，貌在丹青中。',108,'全唐诗/poet.tang.10000.json','["君侯櫪上驄，貌在丹青中。", "馬毛連錢蹄鐵色，圖畫光輝驕玉勒。", "馬行不動勢若來，權奇蹴踏無塵埃。", "感茲絕代稱妙手，遂令談者不容口。", "麒麟獨步自可珍，駑駘萬匹知何有，終未如他櫪上驄。", "載華轂，聘飛鴻，荷君剪拂與君用，一日千里如旋風。"]'),
('b7c8a7fe-7ad4-44fe-9b71-3c085eb5e999','詠馬鞭','高適','唐','唐诗','tang','','[]','龍竹養根凡幾年，工人截之爲長鞭。',64,'全唐诗/poet.tang.10000.json','["龍竹養根凡幾年，工人截之爲長鞭。", "一節一目皆天然，珠重重，星連連。", "繞指柔，純金堅，繩不直，規不圓。", "把向空中捎一聲，良馬有心日馳千。"]'),
('1ba275a5-93d8-4d90-9367-7192e01dae10','塞下曲','高適','唐','唐诗','tang','','[]','君不見芳樹枝，春花落盡蜂不窺。',62,'全唐诗/poet.tang.10000.json','["君不見芳樹枝，春花落盡蜂不窺。", "君不見梁上泥，秋風始高燕不棲。", "蕩子從軍事征戰，蛾眉嬋娟守空閨。", "獨宿自然堪下淚，況復時聞鳥夜啼。"]'),
('0be9008f-d175-47f6-aa53-87fce8d020fa','漁父歌','高適','唐','唐诗','tang','','[]','曲岸深潭一山叟，駐眼看鈎不移手。',64,'全唐诗/poet.tang.10000.json','["曲岸深潭一山叟，駐眼看鈎不移手。", "世人欲得知姓名，良久問他不開口。", "笋皮笠子荷葉衣，心無所營守釣磯。", "料得孤舟無定止，日暮持竿何處歸。"]'),
('e16715ca-dc77-4e04-b442-8e0c41c74ec5','部落曲','高適','唐','唐诗','tang','','[]','蕃軍傍塞遊，代馬噴風秋。',48,'全唐诗/poet.tang.10000.json','["蕃軍傍塞遊，代馬噴風秋。", "老將垂金甲，閼支着錦裘。", "琱戈蒙豹尾，紅斾插狼頭。", "日暮天山下，鳴笳漢使愁。"]'),
('31bcaea7-a3c1-47a0-a1d3-eb91a703d1fb','贈杜二拾遺','高適','唐','唐诗','tang','','[]','傳道招[提]客，詩書自討論。',50,'全唐诗/poet.tang.10000.json','["傳道招[提]客，詩書自討論。", "佛香時入院，僧飯屢過門。", "聽法還應難，尋經剩欲翻。", "草玄今已畢，此外復何言。"]'),
('c8ad2060-b409-46e5-b499-a4cd17a9803b','醉後贈張九旭','高適','唐','唐诗','tang','','["\u53cb\u60c5", "\u559d\u9152"]','世上謾相識，此翁殊不然。',48,'全唐诗/poet.tang.10000.json','["世上謾相識，此翁殊不然。", "興來書自聖，醉後語尤顛。", "白髮老閑事，青雲在目前。", "牀頭一壺酒，能更幾回眠。"]'),
('70c1e034-056a-445d-bff6-9afa97a32ef0','途中寄徐錄事','高適','唐','唐诗','tang','','[]','落日風雨至，秋天鴻雁初。',48,'全唐诗/poet.tang.10000.json','["落日風雨至，秋天鴻雁初。", "離憂不堪比，旅館復何如。", "君又幾時去，我知音信疎。", "空多篋中贈，長見右軍書。"]'),
('c7166837-c70d-4cfd-bf45-baf6930473bf','酬衛八雪中見寄','高適','唐','唐诗','tang','','[]','季冬憶淇上，落日歸山樊。',48,'全唐诗/poet.tang.10000.json','["季冬憶淇上，落日歸山樊。", "舊宅帶流水，平田臨古村。", "雪中望來信，醉裏開衡門。", "果得希代寶，緘之那可論。"]'),
('f1b6a20a-bcbf-4886-bc42-3843d99b2368','送白少府送兵之隴右','高適','唐','唐诗','tang','','["\u6218\u4e89", "\u519b\u961f"]','踐更登隴首，遠別指臨洮。',48,'全唐诗/poet.tang.10000.json','["踐更登隴首，遠別指臨洮。", "爲問關山事，何如州縣勞。", "軍容隨赤羽，樹色引青袍。", "誰斷單于臂，今年太白高。"]'),
('3a0b788a-0d41-477a-8361-29f7c9157c41','河西送李十七','高適','唐','唐诗','tang','','[]','邊城多遠別，此去莫徒然。',48,'全唐诗/poet.tang.10000.json','["邊城多遠別，此去莫徒然。", "問禮知才子，登科及少年。", "出門看落日，驅馬向秋天。", "高價人爭重，行當早着鞭。"]'),
('5627d9fa-e648-4151-9a60-08cff928d305','送張瑤貶五谿尉','高適','唐','唐诗','tang','','[]','他日維楨幹，明時懸鏌鋣。',48,'全唐诗/poet.tang.10000.json','["他日維楨幹，明時懸鏌鋣。", "江山遙去國，妻子獨還家。", "離別無嫌遠，沈浮勿強嗟。", "南登有詞賦，知爾弔長沙。"]'),
('49e8d65c-a254-42eb-9bb6-152ba3d3986e','別韋五','高適','唐','唐诗','tang','','[]','徒然酌桮酒，不覺散人愁。',48,'全唐诗/poet.tang.10000.json','["徒然酌桮酒，不覺散人愁。", "相識仍遠別，欲歸翻旅遊。", "夏雲滿郊甸，明月照河洲。", "莫恨征途遠，東看漳水流。"]'),
('c0547256-859d-4caf-aa4b-41684052f2c6','別劉大校書','高適','唐','唐诗','tang','','[]','昔日京華去，知君才望新。',48,'全唐诗/poet.tang.10000.json','["昔日京華去，知君才望新。", "應猶作賦好，莫歎在官貧。", "且復傷遠別，不然愁此身。", "清風幾萬里，江上一歸人。"]'),
('9e50286c-3f34-407e-95d7-3015902c044f','宋中別司功叔各賦一物得商丘','高適','唐','唐诗','tang','','[]','商丘試一望，隱隱帶秋天。',48,'全唐诗/poet.tang.10000.json','["商丘試一望，隱隱帶秋天。", "地與辰星在，城將大路遷。", "干戈悲昔事，墟落對窮年。", "即此傷離緒，悽悽賦酒筵。"]'),
('a98af493-3392-4ac3-b648-cb48118bff10','送蔡十二之海上','高適','唐','唐诗','tang','','[]','黯然何所爲，相對但悲酸。',48,'全唐诗/poet.tang.10000.json','["黯然何所爲，相對但悲酸。", "季弟念離別，賢兄救急難。", "河流冰處盡，海路雪中寒。", "尚有南飛雁，知君不忍看。"]'),
('b34cd445-5b1c-4877-84bd-a5cab8f1ed64','別韋兵曹','高適','唐','唐诗','tang','','[]','離別長千里，相逢數十年。',48,'全唐诗/poet.tang.10000.json','["離別長千里，相逢數十年。", "此心應不變，他事已徒然。", "惆悵春光裏，蹉跎柳色前。", "逢時當自取，看爾欲先鞭。"]'),
('2c065521-b184-4042-a21f-6d433fa32f36','獨孤判官部送兵','高適','唐','唐诗','tang','','[]','餞君嗟遠別，爲客念周旋。',48,'全唐诗/poet.tang.10000.json','["餞君嗟遠別，爲客念周旋。", "征路今如此，前軍猶眇然。", "出關逢漢壁，登隴望胡天。", "亦是封侯地，期君早着鞭。"]'),
('88fe33c7-2174-4ecd-bfda-c6c637d0182e','別從甥萬盈','高適','唐','唐诗','tang','','[]','諸生曰萬盈，四十乃知名。',48,'全唐诗/poet.tang.10000.json','["諸生曰萬盈，四十乃知名。", "宅相予偏重，家丘人莫輕。", "美才應自料，苦節豈無成。", "莫以山田薄，今春又不耕。"]'),
('c6b86ec1-0218-4426-96a9-ee66e88cd449','別崔少府','高適','唐','唐诗','tang','','[]','知君少得意，汶上掩柴扉。',48,'全唐诗/poet.tang.10000.json','["知君少得意，汶上掩柴扉。", "寒食仍留火，春風未授衣。", "皆言黃綬屈，早向青雲飛。", "借問他鄉事，今年歸不歸。"]'),
('b7ce2e16-a019-4b91-aa72-ed498d1aebe3','別馮判官','高適','唐','唐诗','tang','','[]','碣石遼西地，漁陽薊北天。',48,'全唐诗/poet.tang.10000.json','["碣石遼西地，漁陽薊北天。", "關山唯一道，雨雪盡三邊。", "才子方爲客，將軍正渴賢。", "遙知幕府下，書記日翩翩。"]'),
('ca7c9d91-140d-440e-90c8-67421ab0d987','淇上送韋司倉往滑臺','高適','唐','唐诗','tang','','["\u9001\u522b"]','飲酒莫辭醉，醉多適不愁。',48,'全唐诗/poet.tang.10000.json','["飲酒莫辭醉，醉多適不愁。", "孰知非遠別，終念對窮秋。", "滑臺門外見，淇水眼前流。", "君去應回首，風波滿渡頭。"]'),
('d03fbb08-dc93-465e-bca1-471cef5e55ee','送崔功曹赴越','高適','唐','唐诗','tang','','[]','傳有東南別，題詩報客居。',48,'全唐诗/poet.tang.10000.json','["傳有東南別，題詩報客居。", "江山知不厭，州縣復何如。", "莫恨吳歈曲，嘗看越絕書。", "今朝欲乘興，隨爾食鱸魚。"]'),
('976de84b-f21a-4d7a-8a63-9ee51c307921','送蹇秀才赴臨洮','高適','唐','唐诗','tang','','["\u52c9\u52b1", "\u9001\u522b"]','悵望日千里，如何今二毛。',48,'全唐诗/poet.tang.10000.json','["悵望日千里，如何今二毛。", "猶思陽谷去，莫厭隴山高。", "倚馬見雄筆，隨身唯寶刀。", "料君終自致，勳業在臨洮。"]'),
('517f960a-ac39-402d-982a-118f9d845fbc','廣陵別鄭處士','高適','唐','唐诗','tang','','[]','落日知分手，春風莫斷腸。',48,'全唐诗/poet.tang.10000.json','["落日知分手，春風莫斷腸。", "興來無不愜，才在亦何傷。", "溪水堪垂釣，江田耐插秧。", "人生只爲此，亦足傲羲皇。"]'),
('2e65c105-017c-4b5c-b899-6ace25d18507','別孫訢','高適','唐','唐诗','tang','','[]','離人去復留，白馬黑貂裘。',48,'全唐诗/poet.tang.10000.json','["離人去復留，白馬黑貂裘。", "屈指論前事，停鞭惜舊遊。", "帝鄉那可忘，旅館日堪愁。", "誰念無知己，年年睢水流。"]'),
('b42b8d7b-3d04-46ed-ba87-11478e25d391','送劉評事充朔方判官賦得征馬嘶','高適','唐','唐诗','tang','','[]','征馬向邊州，蕭蕭嘶不休。',48,'全唐诗/poet.tang.10000.json','["征馬向邊州，蕭蕭嘶不休。", "思深應帶別，聲斷爲兼秋。", "岐路風將遠，關山月共愁。", "贈君從此去，何日大刀頭。"]'),
('16b8caaa-e64d-4ad8-839f-8627c0a40f62','送魏八','高適','唐','唐诗','tang','','["\u9001\u522b"]','更沽淇上酒，還泛驛前舟。',48,'全唐诗/poet.tang.10000.json','["更沽淇上酒，還泛驛前舟。", "爲惜故人去，復憐嘶馬愁。", "雲山行處合，風雨興中秋。", "此路無知己，明珠莫暗投。"]'),
('054f613f-675f-4387-aa4d-428b8a6c601e','贈別褚山人','高適','唐','唐诗','tang','','[]','攜手贈將行，山人道姓名。',48,'全唐诗/poet.tang.10000.json','["攜手贈將行，山人道姓名。", "光陰薊子訓，才術褚先生。", "牆上梨花白，尊中桂酒清。", "洛陽無二價，猶是慕風聲。"]'),
('384a5a42-d76b-4e09-92f3-3aaec0e9b838','別王八','高適','唐','唐诗','tang','','[]','征馬嘶長路，離人挹佩刀。',48,'全唐诗/poet.tang.10000.json','["征馬嘶長路，離人挹佩刀。", "客來東道遠，歸去北風高。", "時候何蕭索，鄉心正鬱陶。", "傳君遇知己，行日有綈袍。"]'),
('38eb0617-79f7-467d-bc5f-892f6921dc4b','送董判官','高適','唐','唐诗','tang','','[]','逢君說行邁，倚劒別交親。',48,'全唐诗/poet.tang.10000.json','["逢君說行邁，倚劒別交親。", "幕府爲才子，將軍作主人。", "近關多雨雪，出塞有風塵。", "長策須當用，男兒莫顧身。"]'),
('3898eb6d-95df-4b2e-b6d2-348e3f013d5a','送鄭侍御謫閩中','高適','唐','唐诗','tang','','["\u9001\u522b", "\u529d\u52c9", "\u53cb\u60c5"]','謫去君無恨，閩中我舊過。',48,'全唐诗/poet.tang.10000.json','["謫去君無恨，閩中我舊過。", "大都秋雁少，只是夜猿多。", "東路雲山合，南天瘴癘和。", "自當逢雨露，行矣慎風波。"]'),
('c46a848d-86bf-4e2e-9ffc-442759ddfa7a','送李侍御赴安西','高適','唐','唐诗','tang','','["\u9001\u522b", "\u58ee\u5fd7", "\u60dc\u522b"]','行子對飛蓬，金鞭指鐵驄。',48,'全唐诗/poet.tang.10000.json','["行子對飛蓬，金鞭指鐵驄。", "功名萬里外，心事一桮中。", "虜障燕支北，秦城太白東。", "離魂莫惆悵，看取寶刀雄。"]'),
('57bb1245-317d-4fd3-955f-74370298f685','送裴別將之安西','高適','唐','唐诗','tang','','[]','絕域眇難躋，悠然信馬蹄。',48,'全唐诗/poet.tang.10000.json','["絕域眇難躋，悠然信馬蹄。", "風塵經跋涉，搖落怨暌攜。", "地出流沙外，天長甲子西。", "少年無不可，行矣莫悽悽。"]'),
('d3c44130-3588-40ef-88a7-4e0e504743ca','宴郭校書因之有別','高適','唐','唐诗','tang','','[]','綵服趨庭訓，分交載酒過。',48,'全唐诗/poet.tang.10000.json','["綵服趨庭訓，分交載酒過。", "芸香名早著，蓬轉事仍多。", "苦戰知機息，窮愁奈別何。", "雲霄莫相待，年鬢已蹉跎。"]'),
('67e52566-31d7-40e8-8ee5-8cb5bbb057f3','同李太守北池泛舟宴高平鄭太守','高適','唐','唐诗','tang','','[]','每揖龔黃事，還陪李郭舟。',48,'全唐诗/poet.tang.10000.json','["每揖龔黃事，還陪李郭舟。", "雲從四岳起，水向百城流。", "幽意隨登陟，嘉言即獻酬。", "乃知縫掖貴，今日對諸侯。"]'),
('16115ead-7f11-404c-b6c5-1ea87057291a','同崔員外綦毋拾遺九日宴京兆府李士曹','高適','唐','唐诗','tang','','[]','今日好相見，羣賢仍廢曹。',48,'全唐诗/poet.tang.10000.json','["今日好相見，羣賢仍廢曹。", "晚晴催翰墨，秋興引風騷。", "絳葉擁虛砌，黃花隨濁醪。", "閉門無不可，何事更登高。"]'),
('6c607713-fd86-49a7-9e98-6d5858d24e51','同羣公十月朝宴李太守宅','高適','唐','唐诗','tang','','[]','良牧徵高賞，褰帷問考槃。',48,'全唐诗/poet.tang.10000.json','["良牧徵高賞，褰帷問考槃。", "歲時當正月，甲子入初寒。", "已聽甘棠頌，欣陪旨酒歡。", "仍憐門下客，不作布衣看。"]'),
('655ae29b-c115-4b27-a0b8-caa7e01d1808','武威同諸公過楊七山人得藤字','高適','唐','唐诗','tang','','[]','幕府日多暇，田家歲復登。',48,'全唐诗/poet.tang.10000.json','["幕府日多暇，田家歲復登。", "相知恨不早，乘興乃無恆。", "窮巷在喬木，深齋垂古藤。", "邊城唯有醉，此外更何能。"]'),
('31b9d9c3-3b67-428f-8b53-3019cb4a0b67','同羣公登濮陽聖佛寺閣','高適','唐','唐诗','tang','','[]','落日登臨處，悠然意不窮。',48,'全唐诗/poet.tang.10000.json','["落日登臨處，悠然意不窮。", "佛因初地識，人覺四天空。", "來雁清霜後，孤帆遠樹中。", "裴回傷寓目，蕭索對寒風。"]'),
('c1f1cc1d-4eff-438e-8aea-60cb69174965','同衛八題陸少府書齋','高適','唐','唐诗','tang','','[]','知君薄州縣，好靜無冬春。',48,'全唐诗/poet.tang.10000.json','["知君薄州縣，好靜無冬春。", "散帙至棲鳥，明燈留故人。", "深房臘酒熟，高院梅花新。", "若是周旋地，當令風義親。"]'),
('e82c724f-b32f-4454-9051-0a6b94580869','淇上別業','高適','唐','唐诗','tang','','[]','依依西山下，別業桑林邊。',48,'全唐诗/poet.tang.10000.json','["依依西山下，別業桑林邊。", "庭鴨喜多雨，鄰雞知暮天。", "野人種秋菜，古老開原田。", "且向世情遠，吾今聊自然。"]'),
('248e2198-070c-47f8-96a2-33e8952d1938','入昌松東界山行','高適','唐','唐诗','tang','','[]','鳥道幾登頓，馬蹄無暫閑。',48,'全唐诗/poet.tang.10000.json','["鳥道幾登頓，馬蹄無暫閑。", "崎嶇出長坂，合沓猶前山。", "石激水流處，天寒松色間。", "王程應未盡，且莫顧刀環。"]'),
('7f1a7ed4-5873-4cf1-9b28-3a454c54215a','使青夷軍入居庸三首 一','高適','唐','唐诗','tang','','[]','匹馬行將久，征途去轉難。',48,'全唐诗/poet.tang.10000.json','["匹馬行將久，征途去轉難。", "不知邊地別，秪訝客衣單。", "谿冷泉聲苦，山空木葉乾。", "莫言關塞極，雲雪尚漫漫。"]'),
('80a539fd-75f1-4590-83b2-5c7bf5c0c34c','使青夷軍入居庸三首 二','高適','唐','唐诗','tang','','[]','古鎮青山口，寒風落日時。',48,'全唐诗/poet.tang.10000.json','["古鎮青山口，寒風落日時。", "巖巒鳥不過，冰雪馬堪遲。", "出塞應無策，還家賴有期。", "東山足松桂，歸去結茅茨。"]'),
('a3e12b3f-588f-4a2b-a256-a52942c6ab8f','使青夷軍入居庸三首 三','高適','唐','唐诗','tang','','[]','登頓驅征騎，棲遲愧寶刀。',48,'全唐诗/poet.tang.10000.json','["登頓驅征騎，棲遲愧寶刀。", "遠行今若此，微祿果徒勞。", "絕坂水連下，羣峰雲共高。", "自堪成白首，何事一青袍。"]'),
('3e1b6607-1440-4c27-a25a-233c079b8011','自薊北歸','高適','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u8fb9\u585e", "\u6124\u61d1", "\u58ee\u5fd7\u672a\u916c"]','驅馬薊門北，北風邊馬哀。',48,'全唐诗/poet.tang.10000.json','["驅馬薊門北，北風邊馬哀。", "蒼茫遠山口，豁達胡天開。", "五將已深入，前軍止半廻。", "誰憐不得意，長劒獨歸來。"]'),
('f0c3562c-6d4b-464b-9a0f-e00747aed961','東平別前衛縣李寀少府','高適','唐','唐诗','tang','','["\u9001\u522b", "\u60dc\u522b", "\u53cb\u60c5"]','黃鳥翩翩楊柳垂，春風送客使人悲。',64,'全唐诗/poet.tang.10000.json','["黃鳥翩翩楊柳垂，春風送客使人悲。", "怨別自驚千里外，論交却憶十年時。", "雲開汶水孤帆遠，路繞梁山匹馬遲。", "此地從來可乘興，留君不住益淒其。"]'),
('dddc5861-5ad3-438a-999e-f068b10fc886','夜別韋司士得城字','高適','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u79bb\u522b", "\u996e\u9152", "\u60dc\u522b", "\u53cb\u60c5"]','高館張燈酒復清，夜鐘殘月雁歸聲。',64,'全唐诗/poet.tang.10000.json','["高館張燈酒復清，夜鐘殘月雁歸聲。", "只言啼鳥堪求侶，無那春風欲送行。", "黃河曲裏沙爲岸，白馬津邊柳向城。", "莫怨他鄉暫離別，知君到處有逢迎。"]'),
('2c24cec1-4105-4511-bf8b-bc6d5d8d48c7','送李少府貶峽中王少府貶長沙','高適','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u540c\u60c5", "\u9001\u522b", "\u8d2c\u8c2a", "\u8fb9\u585e", "\u4e03\u8a00\u5f8b\u8bd7"]','嗟君此別意何如，駐馬銜桮問謫居。',64,'全唐诗/poet.tang.10000.json','["嗟君此別意何如，駐馬銜桮問謫居。", "巫峽啼猿數行淚，衡陽歸雁幾封書。", "青楓江上秋天遠，白帝城邊古木疎。", "聖代即今多雨露，暫時分手莫躊躇。"]'),
('616f4ecc-b50f-4045-b99b-82cb54059843','同陳留崔司戶早春宴蓬池','高適','唐','唐诗','tang','','[]','同官載酒出郊圻，晴日東馳雁北飛。',64,'全唐诗/poet.tang.10000.json','["同官載酒出郊圻，晴日東馳雁北飛。", "隔岸春雲邀翰墨，傍簷垂柳報芳菲。", "池邊轉覺虛無盡，臺上偏宜酩酊歸。", "州縣徒勞那可度，後時連騎莫相違。"]'),
('b7cf9dad-6b92-4761-a28c-a170b60bcf84','金城北樓','高適','唐','唐诗','tang','','[]','北樓西望滿晴空，積水連山勝畫中。',64,'全唐诗/poet.tang.10000.json','["北樓西望滿晴空，積水連山勝畫中。", "湍上急流聲若箭，城頭殘月勢如弓。", "垂竿已羨磻谿老，體道猶思塞上翁。", "爲問邊庭更何事，至今羌笛怨無窮。"]'),
('15abc23d-8849-43a1-aeb8-28eebdaac884','同顏六少府旅宦秋中之作','高適','唐','唐诗','tang','','[]','傳君昨夜悵然悲，獨坐新齋木落時。',64,'全唐诗/poet.tang.10000.json','["傳君昨夜悵然悲，獨坐新齋木落時。", "逸氣舊來凌燕雀，高才何得混妍媸。", "跡留黃綬人多歎，心在青雲世莫知。", "不是鬼神無正直，從來州縣有瑕疵。"]'),
('c1fa02b3-3fdd-4de6-86d8-264f36cfee99','重陽','高適','唐','唐诗','tang','','[]','節物驚心兩鬢華，東籬空繞未開花。',64,'全唐诗/poet.tang.10000.json','["節物驚心兩鬢華，東籬空繞未開花。", "百年將半仕三已，五畝就荒天一涯。", "豈有白衣來剝啄，一從烏帽自攲斜。", "真成獨坐空搔首，門柳蕭蕭噪暮鴉。"]'),
('be2bff30-cbdc-4dde-87d4-ea7021125a4b','古樂府飛龍曲留上陳左相','高適','唐','唐诗','tang','','[]','德以精靈降，時膺夢寐求。',192,'全唐诗/poet.tang.10000.json','["德以精靈降，時膺夢寐求。", "蒼生謝安石，天子富平侯。", "尊俎資高論，巖廊挹大猷。", "相門連戶牖，卿族嗣弓裘。", "豁達雲開霽，清明月映秋。", "能爲吉甫頌，善用子房籌。", "階砌思攀陟，門闌尚阻修。", "高山不易仰，大匠本難投。", "跡與松喬合，心緣啓沃留。", "公才山吏部，書癖杜荆州。", "幸沐千年聖，何辭一尉休。", "折腰知寵辱，廻首見沈浮。", "天地莊生馬，江湖范蠡舟。", "逍遙堪自樂，浩蕩信無憂。", "去此從黃綬，歸歟任白頭。", "風塵與霄漢，瞻望日悠悠。"]'),
('d0a388eb-dd3d-4735-aacc-392ff3a2bed1','留上李右相','高適','唐','唐诗','tang','','[]','風俗登淳古，君臣挹大庭。',192,'全唐诗/poet.tang.10000.json','["風俗登淳古，君臣挹大庭。", "深沈謀九德，密勿契千齡。", "獨立調元氣，清心豁窅冥。", "本枝連帝系，長策冠生靈。", "傅說明殷道，蕭何律漢刑。", "鈞衡持國柄，柱石總朝經。", "隱軫江山藻，氛氳鼎鼐銘。", "興中皆白雪，身外即丹青。", "江海呼窮鳥，詩書問聚螢。", "吹噓成羽翼，提握動芳馨。", "倚伏悲還笑，棲遲醉復醒。", "恩榮初就列，含育忝宵形。", "有竊丘山惠，無時枕席寧。", "壯心瞻落景，生事感浮萍。", "莫以才難用，終期善易聽。", "未爲門下客，徒謝少微星。"]'),
('89948763-087c-4404-b98d-eedc526849ec','同李員外賀哥舒大夫破九曲之作','高適','唐','唐诗','tang','','[]','遙傳副丞相，昨日破西蕃。',144,'全唐诗/poet.tang.10000.json','["遙傳副丞相，昨日破西蕃。", "作氣羣山動，揚軍大斾翻。", "奇兵邀轉戰，連孥絕歸奔。", "泉噴諸戎血，風驅死虜魂。", "頭飛攢萬戟，面縛聚轅門。", "鬼哭黃埃暮，天愁白日昏。", "石城與巖險，鐵騎皆雲屯。", "長策一言決，高蹤百代存。", "威稜懾沙漠，忠義感乾坤。", "老將黯無色，儒生安敢論。", "解圍憑廟算，止殺報君恩。", "唯有關河渺，蒼茫空樹墩。"]'),
('9ce3c231-ae05-436d-8939-7c3885b708e1','信安王幕府詩','高適','唐','唐诗','tang','','[]','雲紀軒皇代，星高太白年。',288,'全唐诗/poet.tang.10000.json','["雲紀軒皇代，星高太白年。", "廟堂咨上策，幕府制中權。", "盤石藩維固，昇壇禮樂先。", "國章榮印綬，公服貴貂蟬。", "樂善旌深德，輸忠格上玄。", "剪桐光寵錫，題劒美貞堅。", "聖祚雄圖廣，師貞武德虔。", "雷霆七校發，旌斾五營連。", "華省徵羣乂，霜臺舉二賢。", "豈伊公望遠，曾是茂才遷。", "並秉韜鈐術，兼該翰墨筵。", "帝思麟閣像，臣獻柏梁篇。", "振玉登遼甸，摐金歷薊壖。", "度河飛羽檄，橫海泛樓船。", "北伐聲逾邁，東征務以專。", "講戎喧涿野，料敵靜居延。", "軍勢持三略，兵戎自九天。", "朝瞻授鉞去，時聽偃戈旋。", "大漠風沙裏，長城雨雪邊。", "雲端臨碣石，波際隱朝鮮。", "夜壁沖高斗，寒空駐彩旃。", "倚弓玄兔月，飲馬白狼川。", "庶物隨交泰，蒼生解倒懸。", "四郊增氣象，萬里絕風煙。"]'),
('1176207a-3b89-480b-8032-3def1e6a5d05','東平旅遊奉贈薛太守二十四韻','高適','唐','唐诗','tang','','["\u6cf0\u5c71"]','頌美馳千古，欽賢仰大猷。',288,'全唐诗/poet.tang.10000.json','["頌美馳千古，欽賢仰大猷。", "晉公標逸氣，汾水注長流。", "神與公忠節，天生將相儔。", "青雲本自負，赤縣獨推尤。", "御史風逾勁，郎官草屢修。", "鵷鸞粉署起，鷹隼柏臺秋。", "出入交三事，飛鳴揖五侯。", "軍書陳上策，廷議借前籌。", "肅肅趨朝列，雝雝引帝求。", "一麾俄出守，千里再分憂。", "不改任棠水，仍傳晏子裘。", "歌謠隨舉扇，旌斾逐鳴騶。", "郡國長河繞，川原大野幽。", "地連堯泰嶽，山向禹青州。", "汶上春帆渡，秦亭晚日愁。", "遺墟當少昊，懸象逼奎婁。", "即此逢清鑒，終然喜暗投。", "叨承解榻禮，更得問縑遊。", "高興陪登陟，嘉言忝獻酬。", "觀棊知戰勝，探象會冥搜。", "眺聽情何限，沖融惠勿休。", "祗應齊語默，寧肯問沈浮。", "然諾長懷季，棲遑輙累丘。", "平生感知己，方寸豈悠悠。"]'),
('16668b6e-7a0c-4421-b374-d62a8b9c81eb','真定即事奉贈韋使君二十八韻','高適','唐','唐诗','tang','','[]','飄泊懷書客，遲迴此路隅。',288,'全唐诗/poet.tang.10000.json','["飄泊懷書客，遲迴此路隅。", "問津驚棄置，投刺忽踟躕。", "方伯恩彌重，蒼生詠已蘇。", "郡稱廉叔度，朝議管夷吾。", "乃繼三台側，仍將四岳俱。", "江山澄氣象，崖谷倚冰壺。", "詔寵金門策，官榮葉縣鳧。", "擢才登粉署，飛步躡雲衢。", "起草徵調墨，焚香即宴娛。", "光華揚盛矣，霄漢在茲乎。", "隱軫推公望，逶迤協帝俞。", "軒車辭魏闕，旌節副幽都。", "始佩仙郎印，俄兼太守符。", "尤多蜀郡理，更得潁川謨。", "城邑推雄鎮，山川列簡圖。", "舊燕當絕漠，全趙對平蕪。", "曠野何瀰漫，長亭復鬱紆。", "始泉遺俗近，活水戰場無。", "月換思鄉陌，星廻記斗樞。", "歲容歸萬象，和氣發鴻罏。", "淪落而誰遇，棲遑有是夫。", "不才羞擁腫，干祿謝侏儒。", "契闊慙行邁，羈離憶友于。", "田園同季子，儲蓄異陶朱。"]'),
('1122ecf1-e7da-41c0-a35c-16a9ee1dca5f','和竇侍御登涼州七級浮圖之作','高適','唐','唐诗','tang','','[]','化塔屹中起，孤高宜上躋。',72,'全唐诗/poet.tang.10000.json','["化塔屹中起，孤高宜上躋。", "鐵冠雄賞眺，金界寵招攜。", "空色在軒戶，邊聲連鼓鼙。", "天寒萬里北，地豁九州西。", "清興揖才彥，峻風和端倪。", "始知陽春後，具物皆筌蹄。"]'),
('6ace6ac4-c8c7-4ccd-beee-c6cffc1719b6','酬河南節度使賀蘭大夫見贈之作','高適','唐','唐诗','tang','','[]','高閣憑欄檻，中軍倚斾旌。',144,'全唐诗/poet.tang.10000.json','["高閣憑欄檻，中軍倚斾旌。", "感時常激切，於己即忘情。", "河華屯妖氣，伊瀍有戰聲。", "媿無戡難策，多謝出師名。", "秉鉞知恩重，臨戎覺命輕。", "股肱瞻列岳，脣齒賴長城。", "隱隱摧鋒勢，光光弄印榮。", "魯連真義士，陸遜豈書生。", "直道寧殊智，先鞭忽抗行。", "楚雲隨去馬，淮月尚連營。", "撫劒堪投分，悲歌益不平。", "從來重然諾，況值欲橫行。"]'),
('8687726e-b4b8-48f3-be61-f73ccf881e92','奉酬睢陽路太守見贈之作','高適','唐','唐诗','tang','','[]','盛才膺命代，高價動良時。',168,'全唐诗/poet.tang.10000.json','["盛才膺命代，高價動良時。", "帝簡登藩翰，人和發詠思。", "神仙去華省，鵷鷺憶丹墀。", "清淨能無事，優游即賦詩。", "江山紛想像，雲物共萎蕤。", "逸氣劉公幹，玄言向子期。", "多慙汲引速，翻愧激昂遲。", "相馬知何限，登龍反自疑。", "風塵吏道迫，行邁旅心悲。", "拙疾徒爲爾，窮愁欲問誰。", "秋庭一片葉，朝鏡數莖絲。", "州縣甘無取，丘園悔莫追。", "瓊瑤生篋笥，光景借茅茨。", "他日青霄裏，猶應訪所知。"]'),
('4506e47c-d89b-45ca-a9c5-8f9c457409b6','奉酬睢陽李太守','高適','唐','唐诗','tang','','[]','公族稱王佐，朝經允帝求。',288,'全唐诗/poet.tang.10000.json','["公族稱王佐，朝經允帝求。", "本枝疆我李，盤石冠諸劉。", "禮樂光輝盛，山河氣象幽。", "系高周柱史，名重晉陽秋。", "華省膺推擇，青雲寵宴遊。", "握蘭多具美，前席有嘉謀。", "賦得黃金賜，言皆白璧酬。", "着鞭驅駟馬，操刃解全牛。", "出鎮兼方伯，承家復列侯。", "朝瞻孔北海，時用杜荆州。", "廣固纔登陟，毘陵忽阻修。", "三台冀入夢，四岳尚分憂。", "郡邑連京口，山川望石頭。", "海門當建節，江路引鳴騶。", "俗見中興理，人逢至道休。", "先移白額橫，更息赭衣偷。", "梁國歌來晚，徐方怨不留。", "豈伊齊政術，將以變澆浮。", "訟簡知能吏，刑寬察要囚。", "坐堂風偃草，行縣雨隨輈。", "地是蒙莊宅，城遺閼伯丘。", "孝王餘井徑，微子故田疇。", "冬至招搖轉，天寒螮蝀收。", "猿巖飛雨雪，兔苑落梧楸。"]'),
('d08d54a6-354f-4f0b-8454-a0303339a4cb','送柴司戶充劉卿判官之嶺外','高適','唐','唐诗','tang','','[]','嶺外資雄鎮，朝端寵節旄。',72,'全唐诗/poet.tang.10000.json','["嶺外資雄鎮，朝端寵節旄。", "月卿臨幕府，星使出詞曹。", "海對羊城闊，山連象郡高。", "風霜驅瘴癘，忠信涉波濤。", "別恨隨流水，交情脫寶刀。", "有才無不適，行矣莫徒勞。"]'),
('a57f1fe9-7772-4f2d-bc07-868841e21890','送蔡少府赴登州推事','高適','唐','唐诗','tang','','[]','膠東連即墨，萊水入滄溟。',96,'全唐诗/poet.tang.10000.json','["膠東連即墨，萊水入滄溟。", "國小常多事，人訛屢抵刑。", "公才徵郡邑，詔使出郊坰。", "標格誰當犯，風謠信可聽。", "崢嶸大峴口，邐迤汶陽亭。", "地迥雲偏白，天秋山更青。", "祖筵方卜晝，王事急侵星。", "勸爾將爲德，斯言蓋有聽。"]'),
('b1dacf07-db06-4ed7-bb07-6891a34273c8','秦中送李九赴越','高適','唐','唐诗','tang','','[]','攜手望千里，于今將十年。',96,'全唐诗/poet.tang.10000.json','["攜手望千里，于今將十年。", "如何每離別，心事復迍邅。", "適越雖有以，出關終耿然。", "愁霖不可向，長路或難前。", "吳會獨行客，山陰秋夜船。", "謝家徵故事，禹穴訪遺編。", "鏡水君所憶，蓴羹余舊便。", "歸來莫忘此，兼示濟江篇。"]'),
('e5e41409-32f8-475d-b06c-814e28100c8d','餞宋八充彭中丞判官之嶺南','高適','唐','唐诗','tang','','[]','覩君濟時略，使我氣填膺。',192,'全唐诗/poet.tang.10000.json','["覩君濟時略，使我氣填膺。", "長策竟不用，高才徒見稱。", "一朝知己達，累日詔書徵。", "羽翮忽然就，風飆誰敢凌。", "舉鞭趨嶺嶠，屈指冒炎蒸。", "北雁送馳驛，南人思飲冰。", "彼邦本倔強，習俗多驕矜。", "翠羽干平法，黃金撓直繩。", "若將除害馬，慎勿信蒼蠅。", "魑魅寧無患，忠貞適有憑。", "猿啼山不斷，鳶跕路難登。", "海岸出交趾，江城連始興。", "繡衣當節制，幕府盛威稜。", "勿憚九嶷險，須令百越澄。", "立談多感激，行李即嚴凝。", "離別胡爲者，雲霄遲爾昇。"]'),
('d716d017-0695-4d22-a161-c28b88567b15','陪竇侍御泛靈雲池','高適','唐','唐诗','tang','','[]','白露時先降，清川思不窮。',72,'全唐诗/poet.tang.10000.json','["白露時先降，清川思不窮。", "江湖仍塞上，舟楫在軍中。", "舞換臨津樹，歌饒向迥風。", "夕陽連積水，邊色滿秋空。", "乘興宜投轄，邀歡莫避驄。", "誰憐持弱羽，猶欲伴鵷鴻。"]'),
('829d9dfd-b384-4d00-a13e-dd8bd1beb5e5','陪竇侍御靈雲南亭宴詩得雷字','高適','唐','唐诗','tang','','[]','人幽宜眺聽，目極喜亭臺。',84,'全唐诗/poet.tang.10000.json','["人幽宜眺聽，目極喜亭臺。", "風景知愁在，關山憶夢迴。", "秪言殊語默，何意忝遊陪。", "連唱波瀾動，冥搜物象開。", "新秋歸遠樹，殘雨擁輕雷。", "簷外長天盡，尊前獨鳥來。", "常吟塞下曲，多謝幕中才。"]'),
('f61c206e-7b6f-4c94-ad64-bfb843c5269d','同熊少府題盧主簿茅齋','高適','唐','唐诗','tang','','[]','虛院野情在，茅齋秋興存。',72,'全唐诗/poet.tang.10000.json','["虛院野情在，茅齋秋興存。", "孝廉趨下位，才子出高門。", "乃繼幽人靜，能令學者尊。", "江山歸謝客，神鬼下劉根。", "階樹時攀折，窗書任討論。", "自堪成獨往，何必武陵源。"]'),
('ff727be9-d103-4627-890a-94808ee85a13','同朱五題盧使君義井','高適','唐','唐诗','tang','','[]','高義唯良牧，深仁自下車。',72,'全唐诗/poet.tang.10000.json','["高義唯良牧，深仁自下車。", "寧知鑿井處，還是飲冰餘。", "地即泉源久，人當汲引初。", "體清能鑒物，色洞每含虛。", "上善滋來往，中和浹里閭。", "濟時應未竭，懷惠復何如。"]'),
('820f1c82-3269-433c-967a-fdd643cb3e76','同郭十題楊主簿新廳','高適','唐','唐诗','tang','','[]','華館曙沈沈，惟良正在今。',72,'全唐诗/poet.tang.10000.json','["華館曙沈沈，惟良正在今。", "用材兼柱石，聞物象高深。", "更得芝蘭地，兼營枳棘林。", "向風扃戟戶，當署近棠陰。", "勿改安卑節，聊閑理劇心。", "多君有知己，一和郢中吟。"]'),
('47dbfc92-dd51-458f-859a-1953cde28460','秋日作','高適','唐','唐诗','tang','','[]','端居值秋節，此日更愁辛。',72,'全唐诗/poet.tang.10000.json','["端居值秋節，此日更愁辛。", "寂寞無一事，蒿萊通四鄰。", "閉門生白髮，回首憶青春。", "歲月不相待，交游隨衆人。", "雲霄何處託，愚直有誰親。", "舉酒聊自勸，窮通信爾身。"]'),
('7d8d9dcc-9ef1-4fa9-9138-39a17fce08b4','辟陽城','高適','唐','唐诗','tang','','[]','荒城在高岸，凌眺俯清淇。',72,'全唐诗/poet.tang.10000.json','["荒城在高岸，凌眺俯清淇。", "傳道漢天子，而封審食其。", "奸淫且不戮，茅土孰云宜。", "何得英雄主，返令兒女欺。", "母儀良已失，臣節豈如斯。", "太息一朝事，乃令人所嗤。"]'),
('f62c94f3-c060-4595-86c6-b7d32afb146d','赴彭州山行之作','高適','唐','唐诗','tang','','[]','峭壁連崆峒，攢峰疊翠微。',72,'全唐诗/poet.tang.10000.json','["峭壁連崆峒，攢峰疊翠微。", "鳥聲堪駐馬，林色可忘機。", "怪石時侵徑，輕蘿乍拂衣。", "路長愁作客，年老更思歸。", "且悅巖巒勝，寧嗟意緒違。", "山行應未盡，誰與玩芳菲。"]'),
('8ea06c25-d7c8-48f4-ab3e-133bfbae14f3','詠史','高適','唐','唐诗','tang','','[]','尚有綈袍贈，應憐范叔寒。',24,'全唐诗/poet.tang.10000.json','["尚有綈袍贈，應憐范叔寒。", "不知天下士，猶作布衣看。"]'),
('c48a91ea-6d94-42d1-8466-f5a9f42cc1d6','送兵到薊北','高適','唐','唐诗','tang','','[]','積雪與天迥，屯軍連塞愁。',24,'全唐诗/poet.tang.10000.json','["積雪與天迥，屯軍連塞愁。", "誰知此行邁，不爲覓封侯。"]'),
('7a466652-6517-480e-aad3-2d5e4df247be','同羣公題張處士菜園','高適','唐','唐诗','tang','','[]','耕地桑柘間，地肥菜常熟。',24,'全唐诗/poet.tang.10000.json','["耕地桑柘間，地肥菜常熟。", "爲問葵藿資，何如廟堂肉。"]'),
('d7a14b06-eb3f-4534-9f3b-fc81842cefd9','逢謝偃','高適','唐','唐诗','tang','','[]','紅顏愴爲別，白髮始相逢。',24,'全唐诗/poet.tang.10000.json','["紅顏愴爲別，白髮始相逢。", "唯餘昔時淚，無復舊時容。"]'),
('992319d5-c110-4285-9302-cb6d8144bd85','田家春望','高適','唐','唐诗','tang','','[]','出門何所見，春色滿平蕪。',24,'全唐诗/poet.tang.10000.json','["出門何所見，春色滿平蕪。", "可歎無知己，高陽一酒徒。"]'),
('040e5130-04ad-4f82-9991-05dece70949e','閑居','高適','唐','唐诗','tang','','[]','柳色驚心事，春風厭索居。',24,'全唐诗/poet.tang.10000.json','["柳色驚心事，春風厭索居。", "方知一杯酒，猶勝百家書。"]'),
('e925245d-1bce-4553-b1e1-df64fe87a148','封丘作','高適','唐','唐诗','tang','','[]','州縣才難適，雲山道欲窮。',24,'全唐诗/poet.tang.10000.json','["州縣才難適，雲山道欲窮。", "揣摩慚黠吏，棲隱謝愚公。"]'),
('1d7ec3cb-95db-45a4-9cac-1d00de533802','九曲詞三首 一','高適','唐','唐诗','tang','','[]','許國從來徹廟堂，連年不爲在疆塲。',32,'全唐诗/poet.tang.10000.json','["許國從來徹廟堂，連年不爲在疆塲。", "將軍天上封侯印，御史臺中異姓王。"]'),
('f613e665-0ed5-449e-9f4f-e094a102f993','九曲詞三首 二','高適','唐','唐诗','tang','','[]','萬騎爭歌楊柳春，千塲對舞繡騏驎。',32,'全唐诗/poet.tang.10000.json','["萬騎爭歌楊柳春，千塲對舞繡騏驎。", "到處盡逢歡洽事，相看總是太平人。"]'),
('4b6c721e-3383-47a7-ab92-d04732ab8d61','九曲詞三首 三','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','鐵騎橫行鐵嶺頭，西看邏逤取封侯。',32,'全唐诗/poet.tang.10000.json','["鐵騎橫行鐵嶺頭，西看邏逤取封侯。", "青海只今將飲馬，黃河不用更防秋。"]'),
('d43a140a-9152-4bbf-8d94-7254f913f969','營州歌','高適','唐','唐诗','tang','','["\u751f\u6d3b", "\u8fb9\u585e"]','營州少年厭原野，狐裘蒙茸獵城下。',32,'全唐诗/poet.tang.10000.json','["營州少年厭原野，狐裘蒙茸獵城下。", "虜酒千鍾不醉人，胡兒十歲能騎馬。"]'),
('262c4021-fb39-4065-8308-552aa119d46b','玉真公主歌 一','高適','唐','唐诗','tang','','[]','常言龍德本天仙，誰謂仙人每學仙。',32,'全唐诗/poet.tang.10000.json','["常言龍德本天仙，誰謂仙人每學仙。", "更道玄元指李白，多於王母種桃年。"]'),
('1c3cb481-d0f2-48ec-8c6f-a62288e66416','玉真公主歌 二','高適','唐','唐诗','tang','','[]','仙宮仙府有真仙，天寶天仙秘莫傳。',32,'全唐诗/poet.tang.10000.json','["仙宮仙府有真仙，天寶天仙秘莫傳。", "爲問軒皇三百歲，何如大道一千年。"]'),
('58e934ab-546f-4f26-88a3-fe7e825a613c','和王七玉門關聽吹笛','高適','唐','唐诗','tang','','["\u97f3\u4e50", "\u8fb9\u585e"]','胡人吹笛戍樓間，樓上蕭條海月閑。',32,'全唐诗/poet.tang.10000.json','["胡人吹笛戍樓間，樓上蕭條海月閑。", "借問落梅凡幾曲，從風一夜滿關山。"]'),
('36d65b5a-7b4d-4b3d-a1b7-6fd144360f8f','別董大二首 一','高適','唐','唐诗','tang','','[]','十里黃雲白日曛，北風吹雁雪紛紛。',32,'全唐诗/poet.tang.10000.json','["十里黃雲白日曛，北風吹雁雪紛紛。", "莫愁前路無知己，天下誰人不識君。"]'),
('87bd86ac-59ad-4733-b9cc-8dc465e9f445','別董大二首 二','高適','唐','唐诗','tang','','[]','六翮飄颻私自憐，一離京洛十餘年。',32,'全唐诗/poet.tang.10000.json','["六翮飄颻私自憐，一離京洛十餘年。", "丈夫貧賤應未足，今日相逢無酒錢。"]'),
('54d11196-da71-464b-9058-241799947513','送桂陽孝廉','高適','唐','唐诗','tang','','[]','桂陽年少西入秦，數經甲科猶白身。',32,'全唐诗/poet.tang.10000.json','["桂陽年少西入秦，數經甲科猶白身。", "即今江海一歸客，他日雲霄萬里人。"]'),
('7704e8f6-d94f-441c-88de-f064adf709b3','送李少府時在客舍作','高適','唐','唐诗','tang','','[]','相逢旅館意多違，暮雪初晴候雁飛。',32,'全唐诗/poet.tang.10000.json','["相逢旅館意多違，暮雪初晴候雁飛。", "主人酒盡君未醉，薄暮途遙歸不歸。"]'),
('3ec848e8-02b7-43e4-90f3-d2c09813d6c2','聽張立本女吟','高適','唐','唐诗','tang','','[]','危冠廣袖楚宮妝，獨步閑庭逐夜涼。',32,'全唐诗/poet.tang.10000.json','["危冠廣袖楚宮妝，獨步閑庭逐夜涼。", "自把玉釵敲砌竹，清歌一曲月如霜。"]'),
('ac349977-82f5-485f-80b1-3a827a4ed0cb','初至封丘作','高適','唐','唐诗','tang','','[]','可憐薄暮宦遊子，獨臥虛齋思無已。',32,'全唐诗/poet.tang.10000.json','["可憐薄暮宦遊子，獨臥虛齋思無已。", "去家百里不得歸，到官數日秋風起。"]'),
('26d3dbf4-bc0f-4b19-ab8d-fce4d9e2af10','除夜作','高適','唐','唐诗','tang','','["\u5c81\u6708", "\u5b64\u72ec", "\u601d\u4e61", "\u6625\u8282"]','旅館寒燈獨不眠，客心何事轉悽然。',32,'全唐诗/poet.tang.10000.json','["旅館寒燈獨不眠，客心何事轉悽然。", "故鄉今夜思千里，愁鬢明朝又一年。"]'),
('8b49ae18-32e1-406a-be79-b882da27d61a','劒池','李峴','唐','唐诗','tang','','[]','闔閭葬日勞人力，嬴政穿來役鬼功。',32,'全唐诗/poet.tang.10000.json','["闔閭葬日勞人力，嬴政穿來役鬼功。", "澄碧尚疑神物在，等閑雷雨起潭中。"]'),
('d9f3ca70-4faa-4aff-b2b5-28320a22636d','張公洞','李栖筠','唐','唐诗','tang','','[]','一徑深窈窕，上升翠微中。',132,'全唐诗/poet.tang.10000.json','["一徑深窈窕，上升翠微中。", "忽然靈洞前，日月開仙宮。", "道士十二人，往還馭清風。", "焚香入深洞，巨石如虛空。", "夙夜備蘋藻，詔書祠張公。", "五雲何裴回，玄鶴下蒼穹。", "我本道門子，願言出塵籠。", "掃除方寸間，幾與神靈通。", "宿昔勤夢想，契之在深衷。", "遲迴將不還，章綬擊我躬。", "稽首謝真侶，辭滿歸崆峒。"]'),
('06e4c81e-e4e5-4779-be2b-9dc10d14c83c','投宋大夫','李栖筠','唐','唐诗','tang','','[]','十處投人九處違，家鄉萬里又空歸。',32,'全唐诗/poet.tang.10000.json','["十處投人九處違，家鄉萬里又空歸。", "嚴霜昨夜侵人骨，誰念高堂未授衣。"]'),
('209d2029-4af8-471c-91e1-f67ffc20c5b1','寶林寺作','徐浩','唐','唐诗','tang','','[]','茲山昔飛來，遠自琅琊臺。',156,'全唐诗/poet.tang.10000.json','["茲山昔飛來，遠自琅琊臺。", "孤岫龜形在，深泉鰻井開。", "越王屢登陟，何相傳詞才。", "塔廟宗其巔，規模稱壯哉。", "禪堂清溽潤，高閣無恢炱。", "照耀珠吐月，鏗轟鐘隱雷。", "揆余久纓弁，末路遭邅迴。", "一棄滄海曲，六年稽嶺隈。", "逝川惜東駛，馳景憐西頹。", "腰帶愁疾減，容顏衰悴催。", "賴居茲寺中，法士多瓌能。", "洗心聽經論，禮足蠲凶灾。", "永願依勝侶，清江乘度杯。"]'),
('eb1817f2-140c-47c4-b6f3-0f374d7eaded','謁禹廟','徐浩','唐','唐诗','tang','','[]','畝澮敷四海，川源滌九州。',240,'全唐诗/poet.tang.10000.json','["畝澮敷四海，川源滌九州。", "既膺九命錫，乃建洪範疇。", "鼎革固天啓，運興匪人謀。", "肇開宅土業，永庇昏墊憂。", "山足靈廟在，門前清鏡流。", "象筵陳玉帛，容衛儼戈矛。", "探穴圖書朽，卑宮堂殿修。", "梅梁今不壞，松祏古仍留。", "負責故鄉近，朅來申俎羞。", "爲魚知造化，歎鳳仰徽猷。", "不復聞夏樂，唯餘奏楚幽。", "婆娑非舞羽，鏜鞳異鳴球。", "盛德吾無間，高功誰與儔。", "灾淫破凶慝，祚聖擁神休。", "出谷鶯初語，空山猨獨愁。", "春暉生草樹，柳色暖汀洲。", "恩貸題輿重，榮殊衣錦遊。", "宦情同械擊，生理任桴浮。", "地極臨滄海，天遙過斗牛。", "精誠如可諒，他日寄冥搜。"]'),
('ae31da45-73ca-411d-ada1-d564ed9c765a','自悼','薛令之','唐','唐诗','tang','','[]','朝日上團團，照見先生盤。',48,'全唐诗/poet.tang.10000.json','["朝日上團團，照見先生盤。", "盤中何所有，苜蓿長闌干。", "飯澁匙難綰，羹稀筯易寬。", "只可謀朝夕，何由保歲寒。"]'),
('8c70f0e2-8df5-42da-975b-927f7093a3d0','靈巖寺','薛令之','唐','唐诗','tang','','[]','草堂棲在靈山谷，勤苦詩書向燈燭。',32,'全唐诗/poet.tang.10000.json','["草堂棲在靈山谷，勤苦詩書向燈燭。", "柴門半掩寂無人，惟有白雲相伴宿。"]'),
('29027186-38fc-499d-8208-ba6d79db3518','湘夫人','鄒紹先','唐','唐诗','tang','','[]','楓葉下秋渚，二妃愁渡湘。',36,'全唐诗/poet.tang.10000.json','["楓葉下秋渚，二妃愁渡湘。", "疑山空杳藹，何處望君王。", "日落水雲裏，悠悠心自傷。"]'),
('6ceea366-5fc7-4572-9da3-43f181a8dbbc','寄妻父劉長卿','李穆','唐','唐诗','tang','','[]','處處雲山無盡時，桐廬南望轉參差。',32,'全唐诗/poet.tang.10000.json','["處處雲山無盡時，桐廬南望轉參差。", "舟人莫道新安近，欲上潺湲行自遲。"]'),
('90a5027b-b4c8-4f7b-a79a-0590bbba125d','短歌行','馮著','唐','唐诗','tang','','[]','寂寞草中蘭，亭亭山上松。',60,'全唐诗/poet.tang.10000.json','["寂寞草中蘭，亭亭山上松。", "貞芳日有分，生長耐相容。", "結根各得地，幸沾雨露功。", "參辰無停泊，且顧一西東。", "君但開懷抱，猜恨莫怱怱。"]'),
('db34a982-621d-44d8-81c6-e8675b33253e','洛陽道','馮著','唐','唐诗','tang','','[]','洛陽宮中花柳春，洛陽道上無行人。',112,'全唐诗/poet.tang.10000.json','["洛陽宮中花柳春，洛陽道上無行人。", "皮裘氈帳不相識，萬戶千門閉春色。", "春色深，春色深，君王一去何時尋。", "春雨灑，春雨灑，周南一望堪淚下。", "蓬萊殿中寢胡人，鳷鵲樓前放胡馬。", "聞君欲行西入秦，君行不用過天津。", "天津橋上多胡塵，洛陽道上愁殺人。"]'),
('b3ac6bba-d692-4203-9bef-62c9decf88a4','行路難','馮著','唐','唐诗','tang','','["\u9ec4\u6cb3"]','男兒轗軻徒搔首，入市脫衣且沽酒。',137,'全唐诗/poet.tang.10000.json','["男兒轗軻徒搔首，入市脫衣且沽酒。", "行路難，權門慎勿干，平人爭路相摧殘。", "春秋四氣更迴換，人事何須再三歎。", "君不見雀爲鴿，鷹爲鳩，東海成田谷爲岸。", "負薪客，歸去來，龜反顧，鶴裴回，黃河岸上起塵埃。", "相逢未相識，何用強相猜。", "行路難，故山應不改，茅舍漢中在。", "白酒杯中聊一歌，蒼蠅蒼蠅奈爾何。"]'),
('891b2c80-f3fc-4841-93a9-6d68605e175a','燕銜泥','馮著','唐','唐诗','tang','','[]','雙燕碌碌飛入屋，屋中老人喜燕歸。',108,'全唐诗/poet.tang.10000.json','["雙燕碌碌飛入屋，屋中老人喜燕歸。", "裴回繞我牀頭飛，去年爲爾逐黃雀。", "雨多屋漏泥土落，爾莫厭老翁茅屋低，梁頭作窠梁下栖。", "爾不見東家黃鷇鳴嘖嘖，蛇盤瓦溝鼠穿壁。", "豪家大屋爾莫居，嬌兒少婦採爾雛。", "井旁寫水泥自足，銜泥上屋隨爾欲。"]'),
('149b4657-90d4-4415-8dd4-1ac824e81dc5','同孟浩然宴賦','王迥','唐','唐诗','tang','','[]','屈宋英聲今止已，江山繼嗣多才子。',48,'全唐诗/poet.tang.10000.json','["屈宋英聲今止已，江山繼嗣多才子。", "作者于今盡相似，聚宴王家其樂矣。", "共賦新詩發宮徵，書于屋壁彰厥美。"]'),
('e68b6697-98a2-488a-b620-77a99420cc3b','尚書都堂瓦松','李曄','唐','唐诗','tang','','[]','華省祕僊蹤，高堂露瓦松。',72,'全唐诗/poet.tang.10000.json','["華省祕僊蹤，高堂露瓦松。", "葉因春後長，花爲雨來濃。", "影混鴛鴦色，光含翡翠容。", "天然斯所寄，地勢太無從。", "接棟臨雙闕，連甍近九重。", "寧知深澗底，霜雪歲兼封。"]'),
('f89433c6-deba-4097-b892-bbe2eb27d422','省試七月流火','敬括','唐','唐诗','tang','','[]','前庭一葉下，言念忽悲秋。',72,'全唐诗/poet.tang.10000.json','["前庭一葉下，言念忽悲秋。", "變節金初至，分寒火正流。", "氣含涼夜早，光拂夏雲收。", "助月微明散，沿河麗景浮。", "禮標時令爽，詩興國風幽。", "自此觀邦正，深知王業休。"]'),
('bce77cf0-244d-435a-8a25-8d28a83bc4b9','奉贈韋左丞二十二韻','杜甫','唐','唐诗','tang','','["\u7ec8\u5357\u5c71", "\u793e\u4ea4", "\u8bfb\u4e66", "\u58ee\u5fd7"]','紈袴不餓死，儒冠多誤身。',264,'全唐诗/poet.tang.10000.json','["紈袴不餓死，儒冠多誤身。", "丈人試靜聽，賤子請具陳。", "甫昔少年日，早充觀國賓。", "讀書破萬卷，下筆如有神。", "賦料揚雄敵，詩看子建親。", "李邕求識面，王翰願卜鄰。", "自謂頗挺出，立登要路津。", "致君堯舜上，再使風俗淳。", "此意竟蕭條，行歌非隱淪。", "騎驢三十載，旅食京華春。", "朝扣富兒門，暮隨肥馬塵。", "殘杯與冷炙，到處潛悲辛。", "主上頃見徵，歘然欲求伸。", "青冥却垂翅，蹭蹬無縱鱗。", "甚媿丈人厚，甚知丈人真。", "每於百僚上，猥誦佳句新。", "竊效貢公喜，難甘原憲貧。", "焉能心怏怏，秪是走踆踆。", "今欲東入海，即將西去秦。", "尚憐終南山，回首清渭濱。", "常擬報一飯，況懷辭大臣。", "白鷗沒浩蕩，萬里誰能馴。"]'),
('c9e63635-0caa-43c2-b4b8-b459f9983fbf','送高三十五書記','杜甫','唐','唐诗','tang','','[]','崆峒小麥熟，且願休王師。',192,'全唐诗/poet.tang.10000.json','["崆峒小麥熟，且願休王師。", "請公問主將，焉用窮荒爲。", "飢鷹未飽肉，側翅隨人飛。", "高生跨鞍馬，有似幽幷兒。", "脫身簿尉中，始與捶楚辭。", "借問今何官，觸熱向武威。", "答云一書記，所媿國士知。", "人實不易知，更須慎其儀。", "十年出幕府，自可持旌麾。", "此行既特達，足以慰所思。", "男兒功名遂，亦在老大時。", "常恨結驩淺，各在天一涯。", "又如參與商，慘慘中腸悲。", "驚風吹鴻鵠，不得相追隨。", "黃塵翳沙漠，念子何當歸。", "邊城有餘力，早寄從軍詩。"]'),
('f6ac1ff8-366f-42d0-af96-e5c174b42b92','贈李白','杜甫','唐','唐诗','tang','','[]','二年客東都，所歷厭機巧。',72,'全唐诗/poet.tang.10000.json','["二年客東都，所歷厭機巧。", "野人對羶腥，蔬食常不飽。", "豈無青精飯，使我顏色好。", "苦乏大藥資，山林迹如掃。", "李侯金閨彥，脫身事幽討。", "亦有梁宋遊，方期拾瑤草。"]'),
('176bc0de-6659-46ab-8ab4-fd67e4aa5852','遊龍門奉先寺','杜甫','唐','唐诗','tang','','[]','已從招提遊，更宿招提境。',48,'全唐诗/poet.tang.10000.json','["已從招提遊，更宿招提境。", "陰壑生虛籟，月林散清影。", "天闕象緯逼，雲臥衣裳冷。", "欲覺聞晨鐘，令人發深省。"]'),
('12fdaad8-b197-4526-b56d-c7c713267248','望嶽','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6cf0\u5c71", "\u4e94\u8a00\u53e4\u8bd7", "\u52b1\u5fd7", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7"]','岱宗夫如何，齊魯青未了。',48,'全唐诗/poet.tang.10000.json','["岱宗夫如何，齊魯青未了。", "造化鍾神秀，陰陽割昏曉。", "盪胷生曾雲，決眥入歸鳥。", "會當凌絕頂，一覽衆山小。"]'),
('19360992-900d-448d-abe0-5526fcca731e','陪李北海宴歷下亭','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u8c0a", "\u5730\u65b9", "\u5199\u666f"]','東藩駐皁蓋，北渚凌青荷。',72,'全唐诗/poet.tang.10000.json','["東藩駐皁蓋，北渚凌青荷。", "海內此亭古，濟南名士多。", "雲山已發興，玉佩仍當歌。", "修竹不受暑，交流空湧波。", "蘊真愜所遇，落日將如何。", "貴賤俱物役，從公難重過。"]'),
('9a2c1932-4219-483b-a14b-52dc7265f6fb','同李太守登歷下古城員外新亭亭對鵲湖','杜甫','唐','唐诗','tang','','[]','新亭結搆罷，隱見清湖陰。',72,'全唐诗/poet.tang.10000.json','["新亭結搆罷，隱見清湖陰。", "跡籍臺觀舊，氣溟海嶽深。", "圓荷想自昔，遺堞感至今。", "芳宴此時具，哀絲千古心。", "主稱壽尊客，筵秩宴北林。", "不阻蓬蓽興，得兼梁甫吟。"]'),
('bb6d1c12-1eb1-4ee7-aacd-a3f7f6edec37','玄都壇歌寄元逸人','杜甫','唐','唐诗','tang','','[]','故人昔隱東蒙峰，已佩含景蒼精龍。',96,'全唐诗/poet.tang.10000.json','["故人昔隱東蒙峰，已佩含景蒼精龍。", "故人今居子午谷，獨在陰崖結茅屋。", "屋前太古玄都壇，青石漠漠常風寒。", "子規夜啼山竹裂，王母晝下雲旗翻。", "知君此計成長往，芝草琅玕日應長。", "鐵鏁高垂不可攀，致身福地何蕭爽。"]'),
('092c35a3-eaf8-4078-86e6-fb338c21f085','今夕行','杜甫','唐','唐诗','tang','','[]','今夕何夕歲云徂，更長燭明不可孤。',83,'全唐诗/poet.tang.10000.json','["今夕何夕歲云徂，更長燭明不可孤。", "咸陽客舍一事無，相與博塞爲歡娛。", "馮陵大叫呼五白，袒跣不肯成梟盧。", "英雄有時亦如此，邂逅豈即非良圖。", "君莫笑劉毅從來布衣願，家無儋石輸百萬。"]'),
('7014a7a3-6b60-46bc-9631-63c6a724574d','貧交行','杜甫','唐','唐诗','tang','','["\u53cb\u60c5", "\u6000\u53e4", "\u6124\u61d1"]','飜手作雲覆手雨，紛紛輕薄何須數。',32,'全唐诗/poet.tang.10000.json','["飜手作雲覆手雨，紛紛輕薄何須數。", "不見管鮑貧時交，此道今人棄如土。"]'),
('bd57a0b0-28a1-4d53-bc09-51899d2dac38','兵車行','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53d9\u4e8b", "\u6218\u4e89", "\u5fe7\u56fd\u5fe7\u6c11", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','車轔轔，馬蕭蕭，行人弓箭各在腰。',258,'全唐诗/poet.tang.10000.json','["車轔轔，馬蕭蕭，行人弓箭各在腰。", "耶孃妻子走相送，塵埃不見咸陽橋。", "牽衣頓足闌道哭，哭聲直上干雲霄。", "道傍過者問行人，行人但云點行頻。", "或從十五北防河，便至四十西營田。", "去時里正與裹頭，歸來頭白還戍邊。", "邊亭流血成海水，武皇開邊意未已。", "君不聞漢家山東二百州，千村萬落生荆杞。", "縱有健婦把鋤犂，禾生隴畝無東西。", "況復秦兵耐苦戰，被驅不異犬與雞。", "長者雖有問，役夫敢申恨。", "且如今年冬，未休關西卒。", "縣官急索租，租稅從何出？", "信知生男惡，反是生女好。", "生女猶是嫁比鄰，生男埋沒隨百草。", "君不見青海頭，古來白骨無人收。", "新鬼煩冤舊鬼哭，天陰雨濕聲啾啾。"]'),
('06b100d5-9899-4ae0-9eb8-66983943969f','高都護驄馬行','杜甫','唐','唐诗','tang','','[]','安西都護胡青驄，聲價歘然來向東。',128,'全唐诗/poet.tang.10000.json','["安西都護胡青驄，聲價歘然來向東。", "此馬臨陣久無敵，與人一心成大功。", "功成惠養隨所致，飄飄遠自流沙至。", "雄姿未受伏櫪恩，猛氣猶思戰場利。", "腕促蹄高如踣鐵，交河幾蹴曾冰裂。", "五花散作雲滿身，萬里方看汗流血。", "長安壯兒不敢騎，走過掣電傾城知。", "青絲絡頭爲君老，何由却出橫門道。"]'),
('c28c271b-70b9-422c-8bfd-6a062f40d40c','天育驃騎歌','杜甫','唐','唐诗','tang','','[]','吾聞天子之馬走千里，今之畫圖無乃是。',166,'全唐诗/poet.tang.10000.json','["吾聞天子之馬走千里，今之畫圖無乃是。", "是何意態雄且傑，駿尾蕭梢朔風起。", "毛爲綠縹兩耳黃，眼有紫燄雙瞳方。", "矯矯龍性合變化，卓立天骨森開張。", "伊昔太僕張景順，監牧攻駒閱清峻。", "遂令大奴守天育，別養驥子憐神俊。", "當時四十萬匹馬，張公歎其材盡下。", "故獨寫真傳世人，見之座右久更新。", "年多物化空形影，嗚呼健步無由騁。", "如今豈無騕褭與驊騮，時無王良伯樂死即休。"]'),
('c76b78f3-965d-49fe-8151-44568c0e5c37','白絲行','杜甫','唐','唐诗','tang','','[]','繅絲須長不須白，越羅蜀錦金粟尺。',129,'全唐诗/poet.tang.10000.json','["繅絲須長不須白，越羅蜀錦金粟尺。", "象牀玉手亂殷紅，萬草千花動凝碧。", "已悲素質隨時染，裂下鳴機色相射。", "美人細意熨帖平，裁縫滅盡鍼線迹。", "春天衣著爲君舞，蛺蜨飛來黃鸝語。", "落絮游絲亦有情，隨風照日宜輕舉。", "香汗輕塵污顏色，開新合故置何許。", "君不見才士汲引難，恐懼棄捐忍羈旅。"]'),
('7dccdf60-ec93-4a4d-be1c-4d725b92cb8e','秋雨歎三首 一','杜甫','唐','唐诗','tang','','[]','雨中百草秋爛死，階下決明顏色鮮。',64,'全唐诗/poet.tang.10000.json','["雨中百草秋爛死，階下決明顏色鮮。", "著葉滿枝翠羽蓋，開花無樹黃金錢。", "涼風蕭蕭吹汝急，恐汝後時難獨立。", "堂上書生空白頭，臨風三齅馨香泣。"]'),
('92fa6241-0397-448c-8a97-27f659ef9dd9','秋雨歎三首 二','杜甫','唐','唐诗','tang','','[]','闌風長雨（一作「東風細雨」）秋紛紛，四海（一作「萬里」）八荒同一雲。',103,'全唐诗/poet.tang.10000.json','["闌風長雨（一作「東風細雨」）秋紛紛，四海（一作「萬里」）八荒同一雲。", "去馬來牛不復辨，濁涇清渭何當分。", "禾（一作「木」）頭生耳黍穗黑，農夫田婦（一作「父」）無消息。", "城中斗米換（一作「抱」）衾裯，相許寧論兩相直。"]'),
('9c725632-fe02-4fc7-b443-9410da36c7e5','秋雨歎三首 三','杜甫','唐','唐诗','tang','','[]','長安布衣誰比數，反鏁衡門守環堵。',85,'全唐诗/poet.tang.10000.json','["長安布衣誰比數，反鏁衡門守環堵。", "老夫不出長蓬蒿，穉子無憂走（一作「奏」）風雨。", "雨聲颼颼催早寒，胡雁翅濕高飛難。", "秋來未曾（一作「省」）見白日，埿污后（一作「厚」）土何時乾？"]'),
('a0da6bc2-f1d1-468f-885f-4b515398106b','歎庭前甘菊花','杜甫','唐','唐诗','tang','','["\u540c\u60c5", "\u83ca\u82b1", "\u6292\u6000", "\u82b1", "\u5199\u82b1", "\u6124\u61d1"]','檐前甘菊移時晚，青蘂重陽不堪摘。',64,'全唐诗/poet.tang.10000.json','["檐前甘菊移時晚，青蘂重陽不堪摘。", "明日蕭條醉盡醒，殘花爛熳開何益。", "籬邊野外多衆芳，采擷細瑣升中堂。", "念茲空長大枝葉，結根失所纏風霜。"]'),
('22ec1415-85ee-4aa1-8838-62aa3c9b66dd','醉時歌','杜甫','唐','唐诗','tang','','[]','諸公衮衮登臺省，廣文先生官獨冷。',216,'全唐诗/poet.tang.10000.json','["諸公衮衮登臺省，廣文先生官獨冷。", "甲第紛紛厭粱肉，廣文先生飯不足。", "先生有道出羲皇，先生有才過屈宋。", "德尊一代常轗軻，名垂萬古知何用。", "杜陵野客人更嗤，被褐短窄鬢如絲。", "日糴太倉五升米，時赴鄭老同襟期。", "得錢即相覓，沽酒不復疑。", "忘形到爾汝，痛飲真吾師。", "清夜沈沈動春酌，燈前細雨檐花落。", "但覺高歌有鬼神，焉知餓死填溝壑。", "相如逸才親滌器，子雲識字終投閣。", "先生早賦歸去來，石田茅屋荒蒼苔。", "儒術於我何有哉，孔丘盜跖俱塵埃。", "不須聞此意慘愴，生前相遇且銜杯。"]'),
('78a34aac-4478-4911-bafe-19658d500275','醉歌行','杜甫','唐','唐诗','tang','','[]','陸機二十作文賦，汝更小年能綴文。',192,'全唐诗/poet.tang.10000.json','["陸機二十作文賦，汝更小年能綴文。", "總角草書又神速，世上兒子徒紛紛。", "驊騮作駒已汗血，鷙鳥舉翮連青雲。", "詞源倒流三峽水，筆陣獨埽千人軍。", "只今年纔十六七，射策軍門期第一。", "舊穿楊葉真自知，暫蹶霜蹄未爲失。", "偶然擢秀非難取，會是排風有毛質。", "汝身已見唾成珠，汝伯何由髮如漆。", "春光澹沲秦東亭，渚蒲牙白水荇青。", "風吹客衣日杲杲，樹攪離思花冥冥。", "酒盡沙頭雙玉缾，衆賓皆醉我獨醒。", "乃知貧賤別更苦，吞聲躑躅涕淚零。"]'),
('6c7c45a6-c944-4ff3-aa99-f5cb0440436f','贈衛八處士','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u65f6\u5149", "\u4e94\u8a00\u53e4\u8bd7", "\u4eba\u751f", "\u53cb\u60c5"]','人生不相見，動如參與商。',144,'全唐诗/poet.tang.10000.json','["人生不相見，動如參與商。", "今夕復何夕，共此燈燭光。", "少壯能幾時，鬢髮各已蒼。", "訪舊半爲鬼，驚呼熱中腸。", "焉知二十載，重上君子堂。", "昔別君未婚，兒女忽成行。", "怡然敬父執，問我來何方。", "問荅乃未已，兒女羅酒漿。", "夜雨剪春韭，新炊間黃粱。", "主稱會面難，一舉累十觴。", "十觴亦不醉，感子故意長。", "明日隔山岳，世事兩茫茫。"]'),
('e018d77b-84a8-4e85-b9af-d81845efe2a6','苦雨奉寄隴西公兼呈王徵士','杜甫','唐','唐诗','tang','','[]','今秋乃淫雨，仲月來寒風。',144,'全唐诗/poet.tang.10000.json','["今秋乃淫雨，仲月來寒風。", "羣木水光下，萬象雲氣中。", "所思礙行潦，九里信不通。", "悄悄素滻路，迢迢天漢東。", "願騰六尺馬，背若孤征鴻。", "劃見公子面，超然歡笑同。", "奮飛既胡越，局促傷樊籠。", "一飯四五起，憑軒心力窮。", "嘉蔬沒混濁，時菊碎榛叢。", "鷹隼亦屈猛，烏鳶何所蒙。", "式瞻北鄰居，取適南巷翁。", "挂席釣川漲，焉知清興終。"]'),
('e2595ed8-1345-4194-86f6-ec71bd785110','同諸公登慈恩寺塔','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u767b\u9ad8", "\u5199\u666f"]','高標跨蒼天，烈風無時休。',144,'全唐诗/poet.tang.10000.json','["高標跨蒼天，烈風無時休。", "自非曠士懷，登茲翻百憂。", "方知象教力，足可追冥搜。", "仰穿龍蛇窟，始出枝撐幽。", "七星在北戶，河漢聲西流。", "羲和鞭白日，少昊行清秋。", "秦山忽破碎，涇渭不可求。", "俯視但一氣，焉能辨皇州。", "回首叫虞舜，蒼梧雲正愁。", "惜哉瑤池飲，日宴崑崙丘。", "黃鵠去不息，哀鳴何所投。", "君看隨陽雁，各有稻粱謀。"]'),
('c4746c39-49bc-4a22-a6fb-68d7bf0f3fda','示從孫濟','杜甫','唐','唐诗','tang','','[]','平明跨驢出，未知適誰門。',132,'全唐诗/poet.tang.10000.json','["平明跨驢出，未知適誰門。", "權門多噂𠴲，且復尋諸孫。", "諸孫貧無事，宅舍如荒村。", "堂前自生竹，堂後自生萱。", "萱草秋已死，竹枝霜不蕃。", "淘米少汲水，汲多井水渾。", "刈葵莫放手，放手傷葵根。", "阿翁嬾惰久，覺兒行步奔。", "所來爲宗族，亦不爲盤飧。", "小人利口實，薄俗難可論。", "勿受外嫌猜，同姓古所敦。"]'),
('7c5fb4a5-5b1f-4eff-8e7f-a59f35d9d835','九日寄岑參','杜甫','唐','唐诗','tang','','["\u6000\u4eba", "\u91cd\u9633\u8282"]','出門復入門，兩脚但如舊。',144,'全唐诗/poet.tang.10000.json','["出門復入門，兩脚但如舊。", "所向泥活活，思君令人瘦。", "沈吟坐西軒，飲食錯昏晝。", "寸步曲江頭，難爲一相就。", "吁嗟呼蒼生，稼穡不可救。", "安得誅雲師，疇能補天漏。", "大明韜日月，曠野號禽獸。", "君子強逶迤，小人困馳驟。", "維南有崇山，恐與川浸溜。", "是節東籬菊，紛披爲誰秀。", "岑生多新詩，性亦嗜醇酎。", "采采黃金花，何由滿衣袖。"]'),
('8040db71-8a96-49e2-9f4d-5417af0a0e3e','送孔巢父謝病歸遊江東兼呈李白','杜甫','唐','唐诗','tang','','["\u5bb4\u996e", "\u9001\u522b", "\u795d\u798f"]','巢父掉頭不肯住，東將入海隨煙霧。',144,'全唐诗/poet.tang.10000.json','["巢父掉頭不肯住，東將入海隨煙霧。", "詩卷長流天地間，釣竿欲拂珊瑚樹。", "深山大澤龍蛇遠，春寒野陰風景暮。", "蓬萊織女回雲車，指點虛無是征路。", "自是君身有仙骨，世人那得知其故。", "惜君只欲苦死留，富貴何如草頭露。", "蔡侯靜者意有餘，清夜置酒臨前除。", "罷琴惆悵月照席，幾歲寄我空中書。", "南尋禹穴見李白，道甫問信今何如。"]'),
('7cb1e181-617c-4e12-b818-48666992ebf6','飲中八仙歌','杜甫','唐','唐诗','tang','','["\u5199\u4eba", "\u8096\u50cf", "\u559d\u9152", "\u5199\u4eba\u8bd7"]','知章騎馬似乘船，眼花落井水底眠。',176,'全唐诗/poet.tang.10000.json','["知章騎馬似乘船，眼花落井水底眠。", "汝陽三斗始朝天，道逢麴車口流涎。", "恨不移封向酒泉，左相日興費萬錢。", "飲如長鯨吸百川，銜杯樂聖稱世賢。", "宗之瀟灑美少年，舉觴白眼望青天。", "皎如玉樹臨風前，蘇晉長齋繡佛前。", "醉中往往愛逃禪，李白一斗詩百篇。", "長安市上酒家眠，天子呼來不上船。", "自稱臣是酒中仙，張旭三杯草聖傳。", "脫帽露頂王公前，揮毫落紙如雲煙。", "焦遂五斗方卓然，高談雄辨驚四筵。"]'),
('8483aa2d-27c5-4e40-816a-d0f84a04bddc','曲江三章章五句 一','杜甫','唐','唐诗','tang','','[]','曲江蕭條秋氣高，菱荷枯折隨風濤。',40,'全唐诗/poet.tang.10000.json','["曲江蕭條秋氣高，菱荷枯折隨風濤。", "遊子空嗟垂二毛，白石素沙亦相蕩，哀鴻獨叫求其曹。"]'),
('02e39e3f-8aa2-40cb-bc2d-3cb08d009c95','曲江三章章五句 二','杜甫','唐','唐诗','tang','','[]','即事非今亦非古，長歌激越梢林莽。',40,'全唐诗/poet.tang.10000.json','["即事非今亦非古，長歌激越梢林莽。", "比屋豪華固難數，吾人甘作心似灰，弟姪何傷淚如雨。"]'),
('eba84f73-7c00-4307-ba41-09a68002d058','曲江三章章五句 三','杜甫','唐','唐诗','tang','','[]','自斷此生休問天，杜曲幸有桑麻田。',40,'全唐诗/poet.tang.10000.json','["自斷此生休問天，杜曲幸有桑麻田。", "故將移住南山邊，短衣匹馬隨李廣，看射猛虎終殘年。"]'),
('370b53ae-949e-45cf-92b0-3aca072c1b86','麗人行','杜甫','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8bbd\u523a", "\u548f\u53f9"]','三月三日天氣新，長安水邊多麗人。',204,'全唐诗/poet.tang.10000.json','["三月三日天氣新，長安水邊多麗人。", "態濃意遠淑且真，肌理細膩骨肉勻。", "繡羅衣裳照暮春，蹙金孔雀銀麒麟。", "頭上何所有，翠微㔩葉垂鬢脣。", "背後何所見，珠壓腰衱穩稱身。", "就中雲幕椒房親，賜名大國虢與秦。", "紫駝之峰出翠釜，水精之盤行素鱗。", "犀箸厭飫久未下，鑾刀縷切空紛綸。", "黃門飛鞚不動塵，御廚絡繹送八珍。", "簫鼓哀吟感鬼神，賓從雜遝實要津。", "後來鞍馬何逡巡，當軒下馬入錦茵。", "楊花雪落覆白蘋，青鳥飛去銜紅巾。", "炙手可熱勢絕倫，慎莫近前丞相嗔。"]'),
('785330b1-8050-4b3b-beec-8b50916cdb7a','樂遊園歌','杜甫','唐','唐诗','tang','','[]','樂游古園崒森爽，煙緜碧草萋萋長。',160,'全唐诗/poet.tang.10000.json','["樂游古園崒森爽，煙緜碧草萋萋長。", "公子華筵勢最高，秦川對酒平如掌。", "長生木瓢示真率，更調鞍馬狂歡賞。", "青春波浪芙蓉園，白日雷霆夾城仗。", "閶闔晴開昳蕩蕩，曲江翠幕排銀牓。", "拂水低徊舞袖飜，緣雲清切歌聲上。", "却憶年年人醉時，只今未醉已先悲。", "數莖白髮那拋得，百罰深杯亦不辭。", "聖朝亦知賤士醜，一物自荷皇天慈。", "此身飲罷無歸處，獨立蒼茫自詠詩。"]'),
('efa1a341-99b5-4f81-9c2e-4a1e372e41d1','渼陂行','杜甫','唐','唐诗','tang','','[]','岑參兄弟皆好奇，攜我遠來游渼陂。',224,'全唐诗/poet.tang.10000.json','["岑參兄弟皆好奇，攜我遠來游渼陂。", "天地黤慘忽異色，波濤萬頃堆琉璃。", "琉璃汗漫泛舟入，事殊興極憂思集。", "鼉作鯨吞不復知，惡風白浪何嗟及。", "主人錦帆相爲開，舟子喜甚無氛埃。", "鳧鷖散亂櫂謳發，絲管啁啾空翠來。", "沈竿續蔓深莫測，菱葉荷花靜如拭。", "宛在中流渤澥清，下歸無極終南黑。", "半陂已南純浸山，動影褭窕沖融間。", "船舷暝戛雲際寺，水面月出藍田關。", "此時驪龍亦吐珠，馮夷擊鼓羣龍趨。", "湘妃漢女出歌舞，金支翠旗光有無。", "咫尺但愁雷雨至，蒼茫不曉神靈意。", "少壯幾時奈老何，向來哀樂何其多。"]'),
('3d43a429-0280-47db-a8cd-cbd9e6d3fa8b','渼陂西南臺','杜甫','唐','唐诗','tang','','[]','高臺面蒼陂，六月風日冷。',144,'全唐诗/poet.tang.10000.json','["高臺面蒼陂，六月風日冷。", "蒹葭離披去，天水相與永。", "懷新目似擊，接要心已領。", "仿像識鮫人，空蒙辨魚艇。", "錯磨終南翠，顛倒白閣影。", "崷崒增光輝，乘陵惜俄頃。", "勞生媿嚴鄭，外物慕張邴。", "世復輕驊騮，吾甘雜鼃黽。", "知歸俗可忽，取適事莫竝。", "身退豈待官，老來苦便靜。", "況資菱芡足，庶結茅茨迥。", "從此具扁舟，彌年逐清景。"]'),
('6ecd1880-117b-4442-86e0-b79993ea4ca6','戲簡鄭廣文虔兼呈蘇司業源明','杜甫','唐','唐诗','tang','','[]','廣文到官舍，繫馬堂階下。',48,'全唐诗/poet.tang.10000.json','["廣文到官舍，繫馬堂階下。", "醉則騎馬歸，頗遭官長駡。", "才名四十年，坐客寒無氊。", "賴有蘇司業，時時與酒錢。"]'),
('d27f63af-0f0a-4408-8c43-877b18d98620','夏日李公見訪','杜甫','唐','唐诗','tang','','["\u751f\u6d3b", "\u7530\u56ed"]','遠林暑氣薄，公子過我遊。',120,'全唐诗/poet.tang.10000.json','["遠林暑氣薄，公子過我遊。", "貧居類村塢，僻近城南樓。", "旁舍頗淳樸，所願亦易求。", "隔屋喚西家，借問有酒不。", "牆頭過濁醪，展席俯長流。", "清風左右至，客意已驚秋。", "巢多衆鳥鬬，葉密鳴蟬稠。", "苦道此物聒，孰謂吾廬幽。", "水花晚色靜，庶足充淹留。", "預恐尊中盡，更起爲君謀。"]'),
('0f980b6f-473d-4f04-8090-0e04da5e2655','奉同郭給事湯東靈湫作','杜甫','唐','唐诗','tang','','[]','東山氣鴻濛，宮殿居上頭。',240,'全唐诗/poet.tang.10000.json','["東山氣鴻濛，宮殿居上頭。", "君來必十月，樹羽臨九州。", "陰火煮玉泉，噴薄漲巖幽。", "有時浴赤日，光抱空中摟。", "閬風入轍跡，曠原延冥搜。", "沸天萬乘動，觀水百丈湫。", "幽靈斯可佳，王命宮屬休。", "初聞龍用壯，擘石摧林丘。", "中夜窟宅改，移因風雨秋。", "倒懸瑤池影，屈注蒼江流。", "味如甘露漿，揮弄滑且柔。", "翠旗澹偃蹇，雲車紛少留。", "簫鼓蕩四溟，異香泱漭浮。", "鮫人獻微綃，曾祝沈豪牛。", "百祥奔盛明，古先莫能儔。", "坡陀金蝦蟆，出見蓋有由。", "至尊顧之笑，王母不肯收。", "復歸虛無底，化作長黃虯。", "飄飄青瑣郎，文采珊瑚鉤。", "浩歌淥水曲，清絕聽者愁。"]'),
('b45024f9-099b-4057-897c-f5a2e3016dd3','夜聽許十損誦詩愛而有作','杜甫','唐','唐诗','tang','','[]','許生五臺賓，業白出石壁。',120,'全唐诗/poet.tang.10000.json','["許生五臺賓，業白出石壁。", "余亦師粲可，身猶縛禪寂。", "何階子方便，謬引爲匹敵。", "離索晚相逢，包蒙欣有擊。", "誦詩渾遊衍，四座皆辟易。", "應手看捶鉤，清心聽鳴鏑。", "精微穿溟涬，飛動摧霹靂。", "陶謝不枝梧，風騷共推激。", "紫燕自超詣，翠駮誰翦剔。", "君意人莫知，人間夜寥闃。"]'),
('1e319756-6b63-4706-b074-b79db30a8f1b','橋陵詩三十韻因呈縣內諸官','杜甫','唐','唐诗','tang','','[]','先帝昔晏駕，茲山朝百靈。',288,'全唐诗/poet.tang.10000.json','["先帝昔晏駕，茲山朝百靈。", "崇岡擁象設，沃野開天庭。", "即事壯重險，論功超五丁。", "坡陀因厚地，却略羅峻屏。", "雲闕虛冉冉，風松肅泠泠。", "石門霜露白，玉殿莓苔青。", "宮女晚知曙，祠官朝見星。", "空梁簇畫戟，陰井敲銅缾。", "中使日夜繼，惟王心不寧。", "豈徒卹備享，尚謂求無形。", "孝理敦國政，神凝推道經。", "瑞芝產廟柱，好鳥鳴巖扃。", "高岳前嵂崒，洪河左瀅濙。", "金城蓄峻址，沙苑交回汀。", "永與奧區固，川原紛眇冥。", "居然赤縣立，臺榭爭岧亭。", "官屬果稱是，聲華真可聽。", "王劉美竹潤，裴李春蘭馨。", "鄭氏才振古，啖侯筆不停。", "遣辭必中律，利物常發硎。", "綺繡相展轉，琳瑯愈青熒。", "側聞魯恭化，秉德崔瑗銘。", "太史侯鳧影，王喬隨鶴翎。", "朝儀限霄漢，客思回林坰。"]'),
('b0d5efe6-5b52-414f-90d1-0071a61f9be0','沙苑行','杜甫','唐','唐诗','tang','','[]','君不見左輔白沙如白水，繚以周牆百餘里。',195,'全唐诗/poet.tang.10000.json','["君不見左輔白沙如白水，繚以周牆百餘里。", "龍媒昔是渥洼生，汗血今稱獻於此。", "苑中騋牝三千匹，豐草青青寒不死。", "食之豪健西域無，每歲攻駒冠邊鄙。", "王有虎臣司苑門，入門天廄皆雲屯。", "驌骦一骨獨當御，春秋二時歸至尊。", "至尊內外馬盈億，伏櫪在坰空大存。", "逸羣絕足信殊傑，倜儻權奇難具論。", "纍纍塠阜藏奔突，往往坡陀縱超越。", "角壯飜同糜鹿遊，浮身簸蕩黿鼉窟。", "泉出巨魚長比人，丹砂作尾黃金鱗。", "豈知異物同精氣，雖未成龍亦有神。"]'),
('4b0047aa-a695-43a5-a4a7-b1f2529ba792','聰馬行','杜甫','唐','唐诗','tang','','[]','鄧公馬癖人共知，初得花驄大宛種。',192,'全唐诗/poet.tang.10000.json','["鄧公馬癖人共知，初得花驄大宛種。", "夙昔傳聞思一見，牽來左右神皆竦。", "雄姿逸態何崷崪，顧影驕嘶自矜寵。", "隅目青熒夾鏡懸，肉駿碨礌連錢動。", "朝來久試華軒下，未覺千金滿高價。", "赤汗微生白雪毛，銀鞍却覆香羅帕。", "卿家舊賜公取之，天廄真龍此其亞。", "晝洗須騰涇渭深，朝趨可刷幽幷夜。", "吾聞良驥老始成，此馬數年人更驚。", "豈有四蹄疾於鳥，不與八駿俱先鳴。", "時俗造次那得致，雲霧晦冥方降精。", "近聞下詔喧都邑，肯使騏驎地上行。"]'),
('ba4bd65a-2c56-4f81-b0bf-dacc0068c271','去矣行','杜甫','唐','唐诗','tang','','[]','君不見韝上鷹，一飽則飛掣。',58,'全唐诗/poet.tang.10000.json','["君不見韝上鷹，一飽則飛掣。", "焉能作堂上燕，銜泥附炎熱。", "野人曠蕩無靦顏，豈可久在王侯間。", "未試囊中餐玉法，明朝且入藍田山。"]'),
('53ffa213-5085-4349-9866-ea0735ff7b11','自京赴奉先縣詠懷五百字','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u548f\u6000"]','杜陵有布衣，老大意轉拙。',288,'全唐诗/poet.tang.10000.json','["杜陵有布衣，老大意轉拙。", "許身一何愚，竊比稷與契。", "居然成濩落，白手甘契闊。", "蓋棺事則已，此志常覬豁。", "窮年憂黎元，歎息腸內熱。", "取笑同學翁，浩歌彌激烈。", "非無江海志，蕭灑送日月。", "生逢堯舜君，不忍便永訣。", "當今廊廟具，構廈豈云缺。", "葵藿傾太陽，物性固莫奪。", "顧惟螻蟻輩，但自求其穴。", "胡爲慕大鯨，輒擬偃溟渤。", "以茲悟生理，獨恥事干謁。", "兀兀遂至今，忍爲塵埃沒。", "終媿巢與由，未能易其節。", "沈飲聊自適，放歌頗愁絕。", "歲暮百草零，疾風高岡裂。", "天衢陰崢嶸，客子中夜發。", "霜嚴衣帶斷，指直不得結。", "凌晨過驪山，御榻在嵽嵲。", "蚩尤塞寒空，蹴蹋崖谷滑。", "瑤池氣鬱律，羽林相摩戛。", "君臣留歡娛，樂動殷樛嶱。", "賜浴皆長纓，與宴非短褐。"]'),
('ca8dc6f9-911f-4ae1-8f6a-0e6b374a5ede','奉先劉少府新畫山水障歌','杜甫','唐','唐诗','tang','','[]','堂上不合生楓樹，怪底江山起煙霧。',256,'全唐诗/poet.tang.10000.json','["堂上不合生楓樹，怪底江山起煙霧。", "聞君埽却赤縣圖，乘興譴畫滄洲趣。", "畫師亦無數，好手不可遇。", "對此融心神，知君重毫素。", "豈但祁岳與鄭虔，筆迹遠過楊契丹。", "得非懸圃裂，無乃瀟湘飜。", "悄然坐我天姥下，耳邊已似聞清猨。", "反思前夜風雨急，乃是蒲城鬼神人。", "元氣淋漓障猶濕，真宰上訴天應泣。", "野亭春還雜花遠，漁翁暝蹋孤舟立。", "滄浪水深青溟闊，攲岸側島秋毫末。", "不見湘妃鼓瑟時，至今斑竹臨江活。", "劉侯天機精，愛畫入骨髓。", "自有兩兒郎，揮灑亦莫比。", "大兒聰明到，能添老樹巔崖裏。", "小兒心孔開，貌得山僧及童子。", "若耶溪，雲門寺。", "吾獨胡爲在泥滓，青鞵布韤從此始。"]'),
('40806e64-bb99-458f-a2a0-046eed040b76','白水縣崔少府十九翁高齋三十韻','杜甫','唐','唐诗','tang','','[]','客從南縣來，浩蕩無與適。',288,'全唐诗/poet.tang.10000.json','["客從南縣來，浩蕩無與適。", "旅食白日長，況當朱炎赫。", "高齋坐林杪，信宿游衍闃。", "清晨陪躋攀，傲睨俯峭壁。", "崇岡相枕帶，曠野懷咫尺。", "始知賢主人，贈此遣愁寂。", "危階根青冥，曾冰生淅瀝。", "上有無心雲，下有欲落石。", "泉聲聞復急，動靜隨所擊。", "鳥呼藏其身，有似懼彈射。", "吏隱道性情，茲焉其窟宅。", "白水見舅氏，諸翁乃仙伯。", "杖藜長松陰，作尉窮谷僻。", "爲我炊雕胡，逍遙展良覿。", "坐久風頗愁，晚來山更碧。", "相對十丈蛟，歘翻盤渦坼。", "何得空裏雷，殷殷尋地脈。", "煙氛藹崷崪，魍魎森慘戚。", "崑崙崆峒顛，回首如不隔。", "前軒頹反照，巉絕華岳赤。", "兵氣漲林巒，川光雜鋒鏑。", "知是相公軍，鐵馬雲霧積。", "玉觴淡無味，胡羯豈強敵。", "長歌激屋梁，淚下流衽席。"]'),
('212bf433-f47a-4f05-84d1-172804896869','三川觀水漲二十韻','杜甫','唐','唐诗','tang','','[]','我經華原來，不復見平陸。',276,'全唐诗/poet.tang.10000.json','["我經華原來，不復見平陸。", "北上唯土山，連山走窮谷。", "火雲無時出，飛電常在目。", "自多窮岫雨，行潦相豗蹙。", "蓊匌川氣黃，羣流會空曲。", "清晨望高浪，忽謂陰崖踣。", "恐泥竄蛟龍，登危聚麋鹿。", "枯查卷拔樹，礧磈共充塞。", "聲吹鬼神下，勢閱人代速。", "不有萬穴歸，何以尊四瀆。", "及觀泉源漲，反懼江海覆。", "漂沙坼岸去，漱壑松柏禿。", "乘陵破山門，回斡裂地軸。", "交洛赴洪河，及關豈信宿。", "應沈數州沒，如聽萬室哭。", "穢濁殊未清，風濤怒猶蓄。", "何時通舟車，陰氣不黲黷。", "浮生有蕩汨，吾道正羈束。", "人寰難容身，石壁滑側足。", "雲雷此不已，艱險路更跼。", "普天無川梁，欲濟願水縮。", "因悲中林士，未脫衆魚腹。", "舉頭向蒼天，安得騎鴻鵠。"]'),
('f3c09e9e-e471-4489-9d3f-a598832ac638','悲陳陶','杜甫','唐','唐诗','tang','','["\u6218\u4e89", "\u611f\u4f24", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','孟冬十郡良家子，血作陳陶澤中水。',64,'全唐诗/poet.tang.10000.json','["孟冬十郡良家子，血作陳陶澤中水。", "野曠天清無戰聲，四萬義軍同日死。", "羣胡歸來血洗箭，仍唱胡歌飲都市。", "都人回面北向啼，日夜更望官軍至。"]'),
('ee982ff4-8ff7-4f1c-b955-a6f395fb5854','悲青坂','杜甫','唐','唐诗','tang','','["\u6218\u4e89", "\u51ac\u5929", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','我軍青坂在東門，天寒飲馬太白窟。',48,'全唐诗/poet.tang.10000.json','["我軍青坂在東門，天寒飲馬太白窟。", "黃頭奚兒日向西，數騎彎弓敢馳突。", "山雪河冰野蕭飋，青是烽煙白人骨。"]'),
('8474f5c4-d18e-4b42-9702-19ad909b9ea2','哀江頭','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u63cf\u5199\u6c34", "\u7231\u56fd", "\u4f24\u6000", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','少陵野老吞聲哭，春日潛行曲江曲。',160,'全唐诗/poet.tang.10000.json','["少陵野老吞聲哭，春日潛行曲江曲。", "江頭宮殿鎖千門，細柳新蒲爲誰綠。", "憶昔霓旌下南苑，苑中萬物生顏色。", "昭陽殿裏第一人，同輦隨君侍君側。", "輦前才人帶弓箭，白馬嚼齧黃金勒。", "翻身向天仰射雲，一箭正墜雙飛翼。", "明眸皓齒今何在，血污遊魂歸不得。", "清渭東流劒閣深，去住彼此無消息。", "人生有情淚霑臆，江水江花豈終極。", "黃昏胡騎塵滿城，欲往城南忘南北。"]'),
('bd7949f8-c961-4bfd-a307-1fe9e621028c','哀王孫','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53d9\u4e8b", "\u6292\u60c5", "\u65b0\u4e50\u5e9c\u8f9e", "\u4e50\u5e9c", "\u5199\u9e1f"]','長安城頭頭白烏，夜飛延秋門上呼。',224,'全唐诗/poet.tang.10000.json','["長安城頭頭白烏，夜飛延秋門上呼。", "又向人家啄大屋，屋底達官走避胡。", "金鞭斷折九馬死，骨肉不待同馳驅。", "腰下實玦青珊瑚，可憐王孫泣路隅。", "問之不肯道姓名，但道困苦乞爲奴。", "已經百日竄荆棘，身上無有完肌膚。", "高帝子孫盡隆準，龍種自與常人殊。", "豺狼在邑龍在野，王孫善保千金軀。", "不敢長語臨交衢，且爲王孫立斯須。", "昨夜東風吹血腥，東來橐駝滿舊都。", "朔方健兒好身手，昔何勇銳今何愚。", "竊聞天子已傳位，賢德北服南單于。", "花門剺面請雪恥，慎勿出口他人狙。", "哀哉王孫慎勿疎，五陵佳氣無時無。"]'),
('627b0d8c-9d75-414e-9513-4122bc2c350f','大雲寺贊公房四首 一','杜甫','唐','唐诗','tang','','[]','心在水精域，衣霑春雨時。',96,'全唐诗/poet.tang.10000.json','["心在水精域，衣霑春雨時。", "洞門盡徐步，深院果幽期。", "到扉開復閉，撞鐘齋及茲。", "醍醐長發性，飲食過扶衰。", "把臂有多日，開懷無媿辭。", "黃鸝度結構，紫鴿下罘罳。", "愚意會所適，花邊行自遲。", "湯休起我病，微笑索題詩。"]'),
('14c0b327-e1a0-497a-aadb-56cf74d410bc','大雲寺贊公房四首 二','杜甫','唐','唐诗','tang','','[]','細軟青絲履，光明白氎巾。',72,'全唐诗/poet.tang.10000.json','["細軟青絲履，光明白氎巾。", "深藏供老宿，取用及吾身。", "自顧轉無趣，交情何尚新。", "道林才不世，惠遠德過人。", "雨瀉暮檐竹，風吹青井芹。", "天陰對圖畫，最覺潤龍鱗。"]'),
('b81ee4a9-5872-46f9-ab34-9de22f3046be','大雲寺贊公房四首 三','杜甫','唐','唐诗','tang','','[]','燈影照無睡，心清聞妙香。',72,'全唐诗/poet.tang.10000.json','["燈影照無睡，心清聞妙香。", "夜深殿突兀，風動金鋃鐺。", "天黑閉春院，地清棲暗芳。", "玉繩回斷絕，鐵鳳森翱翔。", "梵放時出寺，鐘殘仍殷牀。", "明朝在沃野，苦見塵沙黃。"]'),
('2148248a-2145-43aa-86a4-dc76fd1618eb','大雲寺贊公房四首 四','杜甫','唐','唐诗','tang','','[]','童兒汲井華，慣捷缾上手。',120,'全唐诗/poet.tang.10000.json','["童兒汲井華，慣捷缾上手。", "沾灑不濡地，埽除似無帚。", "明霞爛複閣，霽霧搴高牖。", "側塞被徑花，飄颻委墀柳。", "艱難世事迫，隱遯佳期後。", "晤語契深心，那能總箝口。", "奉辭還杖策，暫別終回首。", "泱泱泥污人，听听國多狗。", "既未免羈絆，時來憩奔走。", "近公如白雪，執熱煩何有。"]'),
('e848498b-1ab8-48c7-8b3e-e98b5550b855','蘇端薛復筵簡薛華醉歌','杜甫','唐','唐诗','tang','','[]','文章有神交有道，端復得之名譽早。',176,'全唐诗/poet.tang.10000.json','["文章有神交有道，端復得之名譽早。", "愛客滿堂盡豪翰，開筵上日思芳草。", "安得健步移遠梅，亂插繁花向晴昊。", "千里猶殘舊冰雪，百壺且試開懷抱。", "垂老惡聞戰鼓悲，急觴爲緩憂心擣。", "少年努力縱談笑，看我形容已枯槁。", "坐中薛華善醉歌，歌辭自作風格老。", "近來海內爲長句，汝與山東李白好。", "何劉沈謝力未工，才兼鮑昭愁絕倒。", "諸生頗盡新知樂，萬事終傷不自保。", "氣酣日落西風來，願吹野水添金杯。"]'),
('6876a62d-3e30-49cf-9e87-a55e75779844','晦日尋崔戢李封','杜甫','唐','唐诗','tang','','[]','朝光入甕牖，尸寢驚敝裘。',240,'全唐诗/poet.tang.10000.json','["朝光入甕牖，尸寢驚敝裘。", "起行視天宇，春氣漸和柔。", "興來不暇嬾，今晨梳我頭。", "出門無所待，徒步覺自由。", "杖藜復恣意，免值公與侯。", "晚定崔李交，會心真罕儔。", "每過得酒傾，二宅可淹留。", "喜結仁里歡，況因令節求。", "李生園欲荒，舊竹頗修修。", "引客看埽除，隨時成獻酬。", "崔侯初筵色，已畏空尊愁。", "未知天下士，至性有此不。", "草牙既青出，蜂聲亦暖遊。", "思見農器陳，何當甲兵休。", "上古葛天民，不貽黃屋憂。", "至今阮籍等，熟醉爲身謀。", "威鳳高其翔，長鯨吞九洲。", "地軸爲之翻，百川昔亂流。", "當歌欲一放，淚下恐莫收。", "濁醪有妙理，庶用慰沈浮。"]'),
('24f063d6-b3bb-4368-ae89-1e2af8fb3a0f','雨過蘇端','杜甫','唐','唐诗','tang','','[]','雞鳴風雨交，久旱雲亦好。',120,'全唐诗/poet.tang.10000.json','["雞鳴風雨交，久旱雲亦好。", "杖藜入春泥，無食起我早。", "諸家憶所歷，一飯跡便埽。", "蘇侯得數過，歡喜每傾倒。", "也復可憐人，呼兒具梨棗。", "濁醪必在眼，盡醉攄懷抱。", "紅稠屋角花，碧委牆隅草。", "親賓縱談謔，喧鬧畏衰老。", "況蒙霈澤垂，糧粒或自保。", "妻孥隔軍壘，撥棄不擬道。"]'),
('10283f19-0d0b-41d7-99b8-8cd117878d2c','喜晴','杜甫','唐','唐诗','tang','','[]','皇天久不雨，既雨晴亦佳。',168,'全唐诗/poet.tang.10000.json','["皇天久不雨，既雨晴亦佳。", "出郭眺西郊，肅肅春增華。", "青熒陵陂麥，窈窕桃李花。", "春夏各有實，我飢豈無涯。", "干戈雖橫放，慘澹鬬龍蛇。", "甘澤不猶愈，且耕今未賒。", "丈夫則帶甲，婦女終在家。", "力難及黍稷，得種菜與麻。", "千載商山芝，往者東門瓜。", "其人骨已朽，此道誰疵瑕。", "英賢遇轗軻，遠引蟠泥沙。", "顧慙昧所適，回首白日斜。", "漢陰有鹿門，滄海有靈查。", "焉能學衆口，咄咄空咨嗟。"]'),
('ebfe208d-e421-470b-805d-b2d7262176ad','送率府程錄事還鄉','杜甫','唐','唐诗','tang','','["\u79bb\u522b"]','鄙夫行衰謝，抱病昏妄集。',168,'全唐诗/poet.tang.10000.json','["鄙夫行衰謝，抱病昏妄集。", "當時往還人，記一不識十。", "程侯晚相遇，與語才傑立。", "熏然耳目開，頗覺聰明人。", "千載得鮑叔，末契有所及。", "意鍾老柏青，義動修蛇蟄。", "若人可數見，慰我垂白泣。", "告別無淹晷，百憂復相襲。", "內媿突不黔，庶羞以賙給。", "素絲挈長魚，碧酒隨玉粒。", "途窮見交態，世梗悲路澀。", "東風吹春冰，泱莽后土濕。", "念君惜羽翮，既飽更思戢。", "莫作翻雲鶻，聞呼向禽急。"]'),
('e0ec8fe8-3c0a-4b2e-85b7-30fe8f267fe4','述懷一首','杜甫','唐','唐诗','tang','','[]','去年潼關破，妻子隔絕久。',192,'全唐诗/poet.tang.10000.json','["去年潼關破，妻子隔絕久。", "今夏草木長，脫身得西走。", "麻鞋見天子，衣袖露兩肘。", "朝廷慜生還，親故傷老醜。", "涕淚授拾遺，流離主恩厚。", "柴門雖得去，未忍即開口。", "寄書問三川，不知家在否。", "比聞同罹禍，殺戮到雞狗。", "山中漏茅屋，誰復依戶牖。", "摧頹蒼松根，地冷骨未朽。", "幾人全性命，盡室豈相偶。", "嶔岑猛虎場，鬱結回我首。", "自寄一封書，今已十月後。", "反畏消息來，寸心亦何有。", "漢運初中興，生平老耽酒。", "沈思歡會處，恐作窮獨叟。"]'),
('26be693a-2f82-4e8b-be8f-4e14129f185d','送長孫九侍御赴武威判官','杜甫','唐','唐诗','tang','','[]','驄馬新鑿蹄，銀鞍被來好。',168,'全唐诗/poet.tang.10000.json','["驄馬新鑿蹄，銀鞍被來好。", "繡衣黃白郎，騎向交河道。", "問君適萬里，取別何草草。", "天子憂涼州，嚴程到須早。", "去秋羣胡反，不得無電埽。", "此行收遺甿，風俗方再造。", "族父領元戎，名聲國中老。", "奪我同官良，飄颻按城堡。", "使我不能餐，令我惡懷抱。", "若人才思闊，溟漲浸絕島。", "尊前失詩流，塞上得國寶。", "皇天悲送遠，雲雨白浩浩。", "東郊尚烽火，朝野色枯槁。", "西極柱亦傾，如何正穹昊。"]'),
('2e1e7ba7-1beb-4430-a7f2-3e5d7241beec','送樊二十三侍御赴漢中判官','杜甫','唐','唐诗','tang','','[]','威弧不能弦，自爾無寧歲。',240,'全唐诗/poet.tang.10000.json','["威弧不能弦，自爾無寧歲。", "川谷血橫流，豺狼沸相噬。", "天子從北來，長驅振凋敝。", "頓兵岐梁下，却跨沙漠裔。", "二京陷未收，四極我得制。", "蕭索漢水清，緬通淮湖稅。", "使者紛星散，王綱尚旒綴。", "南伯從事賢，君行立談際。", "生知七曜曆，手畫三軍勢。", "冰雪淨聰明，雷霆走精銳。", "幕府輟諫官，朝廷無此例。", "至尊方旰食，仗爾布嘉惠。", "補闕暮徵入，柱史晨征憩。", "正當艱難時，實藉長久計。", "回風吹獨樹，白日照執袂。", "慟哭蒼煙根，山門萬重閉。", "居人莽牢落，遊子方迢遞。", "裴回悲生離，局促老一世。", "陶唐歌遺民，後漢更列帝。", "恨無匡復姿，聊欲從此逝。"]'),
('f5ae9776-2997-4e21-9318-b0e2075c7692','送從弟亞赴安西判官','杜甫','唐','唐诗','tang','','[]','南風作秋聲，殺氣薄炎熾。',240,'全唐诗/poet.tang.10000.json','["南風作秋聲，殺氣薄炎熾。", "盛夏鷹隼擊，時危異人至。", "令弟草中來，蒼然請論事。", "詔書引上殿，奮舌動天意。", "兵法五十家，爾腹爲篋笥。", "應對如轉丸，疏通略文字。", "經綸皆新語，足以正神器。", "宗廟尚爲灰，君臣俱下淚。", "崆峒地無軸，青海天軒輊。", "西極最瘡痍，連山暗烽燧。", "帝曰大布衣，藉卿佐元帥。", "坐看清流沙，所以子奉使。", "歸當再前席，適遠非歷試。", "須存武威郡，爲畫長久利。", "孤峰石戴驛，快馬金纏轡。", "黃羊飫不羶，蘆酒多還醉。", "踴躍常人情，慘澹苦士志。", "安邊敵何有，反正計始遂。", "吾聞駕鼓車，不合用騏驥。", "龍吟回其頭，夾輔待所致。"]'),
('76fbf9e9-5941-4a96-a62f-fd66183dfe38','送韋十六評事充同谷郡防禦判官','杜甫','唐','唐诗','tang','','[]','昔沒賊中時，潛與子同遊。',288,'全唐诗/poet.tang.10000.json','["昔沒賊中時，潛與子同遊。", "今歸行在所，王事有去留。", "偪側兵馬間，主憂急良籌。", "子雖軀幹小，老氣橫九州。", "挺身艱難際，張目視寇讎。", "朝廷壯其節，奉詔令參謀。", "鑾輿駐鳳翔，同谷爲咽喉。", "西扼弱水道，南鎮枹罕陬。", "此邦承平日，剽劫吏所羞。", "況乃胡未滅，控帶莽悠悠。", "府中韋使君，道足示懷柔。", "令姪才俊茂，二美又何求。", "受詞太白脚，走馬仇池頭。", "古色沙土裂，積陰雪雲稠。", "羌父豪豬靴，羌兒青兕裘。", "吹角向月窟，蒼山旌旆愁。", "鳥驚出死樹，龍怒拔老湫。", "古來無人境，今代橫戈矛。", "傷哉文儒士，憤激馳林丘。", "中原正格鬬，後會何緣由。", "百年賦命定，豈料沈與浮。", "且復戀良友，握手步道周。", "論兵遠壑淨，亦可縱冥搜。", "題詩得秀句，札翰時相投。"]'),
('cbebf2b4-fabb-4c07-b8bc-f2efcfe377ad','塞蘆子','杜甫','唐','唐诗','tang','','[]','五城何迢迢，迢迢隔河水。',120,'全唐诗/poet.tang.10000.json','["五城何迢迢，迢迢隔河水。", "邊兵盡東征，城內空荆杞。", "思明割懷衛，秀巖西未已。", "迴略大荒來，崤函蓋虛爾。", "延州秦北戶，關防猶可倚。", "焉得一萬人，疾驅塞蘆子。", "岐有薛大夫，旁制山賊起。", "近聞昆戎徒，爲退三百里。", "蘆關扼兩寇，深意實在此。", "誰能叫帝閽，胡行速如鬼。"]'),
('b59e2948-4c90-4b33-8af6-d02b79efd5fd','彭衙行','杜甫','唐','唐诗','tang','','[]','憶昔避賊初，北走經險艱。',276,'全唐诗/poet.tang.10000.json','["憶昔避賊初，北走經險艱。", "夜深彭衙道，月照白水山。", "盡室久徒步，逢人多厚顏。", "參差谷鳥吟，不見遊子還。", "癡女飢齩我，啼畏虎狼聞。", "懷中掩其口，反側聲愈嗔。", "小兒強解事，故索苦李餐。", "一旬半雷雨，泥濘相牽攀。", "既無禦雨備，徑滑衣又寒。", "有時經契闊，竟日數里間。", "野果充餱糧，卑枝成屋椽。", "早行石上水，暮宿天邊煙。", "少留周家窪，欲出蘆子關。", "故人有孫宰，高義薄曾雲。", "延客已曛黑，張燈啓重門。", "煖湯濯我足，剪紙招我魂。", "從此出妻孥，相視涕闌干。", "衆雛爛熳睡，喚起霑盤餐。", "誓將與夫子，永結爲弟昆。", "遂空所坐堂，安居奉我歡。", "誰肯艱難際，豁達露心肝。", "別來歲月周，胡羯仍搆患。", "何當有翅翎，飛去墮爾前。"]'),
('a335f6c4-e9df-47d5-879d-9ebd3c1baf5c','北征','杜甫','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u957f\u8bd7", "\u7231\u56fd", "\u5fe7\u56fd\u5fe7\u6c11"]','皇帝二載秋，閏八月初吉。',288,'全唐诗/poet.tang.10000.json','["皇帝二載秋，閏八月初吉。", "杜子將北征，蒼茫問家室。", "維時遭艱虞，朝野少暇日。", "顧慙恩私被，詔許歸蓬蓽。", "拜辭詣闕下，怵惕久未出。", "雖乏諫諍姿，恐君有遺失。", "君誠中興主，經緯固密勿。", "東胡反未已，臣甫憤所切。", "揮涕戀行在，道途猶恍惚。", "乾坤含瘡痍，憂虞何時畢。", "靡靡踰阡陌，人煙眇蕭瑟。", "所遇多被傷，呻吟更流血。", "回首鳳翔縣，旌旗晚明滅。", "前登寒山重，屢得飲馬窟。", "邠郊入地底，涇水中蕩潏。", "猛虎立我前，蒼崖吼時裂。", "菊垂今秋花，石戴古車轍。", "青雲動高興，幽事亦可悅。", "山果多瑣細，羅生雜橡栗。", "或紅如丹砂，或黑如點漆。", "雨露之所濡，甘苦齊結實。", "緬思桃源內，益歎身世拙。", "坡陀望鄜畤，巖谷互出沒。", "我行已水濱，我僕猶木末。"]'),
('3c6b6ef6-add3-4c51-9886-358b6795fdb7','得舍弟消息','杜甫','唐','唐诗','tang','','[]','風吹紫荆樹，色與春庭暮。',48,'全唐诗/poet.tang.10000.json','["風吹紫荆樹，色與春庭暮。", "花落辭故枝，風回返無處。", "骨肉恩書重，漂泊難相遇。", "猶有淚成河，經天復東注。"]'),
('800f5d12-980c-463a-acbd-4b6d675ac93d','徒步歸行','杜甫','唐','唐诗','tang','','[]','明公壯年值時危，經濟實藉英雄姿。',96,'全唐诗/poet.tang.10000.json','["明公壯年值時危，經濟實藉英雄姿。", "國之社稷今若是，武定禍亂非公誰。", "鳳翔千官且飽飯，衣馬不復能輕肥。", "青袍朝士最困者，白頭拾遺徒步歸。", "人生交契無老少，論交何必先同調。", "妻子山中哭向天，須公櫪上追風驃。"]'),
('cb457f4a-a49c-46cc-becf-d4419d617b79','玉華宮','杜甫','唐','唐诗','tang','','[]','溪回松風長，蒼鼠竄古瓦。',96,'全唐诗/poet.tang.10000.json','["溪回松風長，蒼鼠竄古瓦。", "不知何王殿，遺構絕壁下。", "陰房鬼火青，壞道哀湍瀉。", "萬籟真笙竽，秋色正蕭灑。", "美人爲黃土，況乃粉黛假。", "當時侍金輿，故物獨石馬。", "憂來藉草坐，浩歌淚盈把。", "冉冉征途間，誰是長年者。"]'),
('e35de5fa-807c-4891-8749-b2c83757c89a','九成宮','杜甫','唐','唐诗','tang','','[]','蒼山入百里，崖斷如杵臼。',144,'全唐诗/poet.tang.10000.json','["蒼山入百里，崖斷如杵臼。", "曾宮憑風回，岌嶪土囊口。", "立神扶棟梁，鑿翠開戶牖。", "其陽產靈芝，其陰宿牛斗。", "紛披長松倒，揭𡿗怪石走。", "哀猨啼一聲，客淚迸林藪。", "荒哉隋家帝，製此今頹朽。", "向使國不亡，焉爲巨唐有。", "雖無新增修，尚置官居守。", "巡非瑤水遠，迹是雕牆後。", "我行屬時危，仰望嗟歎久。", "天王守太白，駐馬更搔首。"]'),
('872fd5bd-c6d8-4aef-bc03-85ac1550b561','羌村 一','杜甫','唐','唐诗','tang','','[]','崢嶸赤雲西，日脚下平地。',72,'全唐诗/poet.tang.10000.json','["崢嶸赤雲西，日脚下平地。", "柴門鳥雀噪，歸客千里至。", "妻孥怪我在，驚定還拭淚。", "世亂遭飄蕩，生還偶然遂。", "鄰人滿牆頭，感歎亦歔欷。", "夜闌更秉燭，相對如夢寐。"]'),
('0f5d3f4a-dbf2-4831-b658-e75bd4a0ca38','羌村 二','杜甫','唐','唐诗','tang','','[]','晚歲迫偷生，還家少歡趣。',72,'全唐诗/poet.tang.10000.json','["晚歲迫偷生，還家少歡趣。", "嬌兒不離膝，畏我復却去。", "憶昔好追涼，故繞池邊樹。", "蕭蕭北風勁，撫事煎百慮。", "賴知禾黍收，已覺糟牀注。", "如今足斟酌，且用慰遲暮。"]'),
('26cbab92-a321-44e6-842b-13acc9749fc0','羌村 三','杜甫','唐','唐诗','tang','','["\u611f\u6fc0", "\u751f\u6d3b", "\u521d\u4e2d\u53e4\u8bd7", "\u4e5d\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)"]','羣雞正亂叫，客至雞鬬爭。',96,'全唐诗/poet.tang.10000.json','["羣雞正亂叫，客至雞鬬爭。", "驅雞上樹木，始聞叩柴荆。", "父老四五人，問我久遠行。", "手中各有攜，傾榼濁復清。", "苦辭酒味薄，黍地無人耕。", "兵革既未息，兒童盡東征。", "請爲父老歌，艱難塊深情。", "歌罷仰天歎，四座淚縱橫。"]'),
('e71fc0b1-e5d2-42c3-b084-8076185988fc','偪仄行贈畢曜','杜甫','唐','唐诗','tang','','[]','偪仄何偪仄，我居巷南子巷北。',202,'全唐诗/poet.tang.10000.json','["偪仄何偪仄，我居巷南子巷北。", "可恨鄰里間，十日不一見顏色。", "自從官馬送還宮，行路難行澀如棘。", "我貧無乘非無足，昔者相過今不得。", "實不是愛微軀，又非關足無力。", "徒步翻愁官長怒，此心炯炯君應識。", "曉來急雨春風顛，睡美不聞鐘鼓傳。", "東家蹇驢許借我，泥滑不敢騎朝天。", "已令請急會通籍，男兒信命絕可憐。", "焉能終日心拳拳，憶君誦詩神凜然。", "辛夷始花亦已落，況我與子非壯年。", "街頭酒價常苦貴，方外酒徒稀醉眠。", "速宜相就飲一斗，恰有三百青銅錢。"]'),
('6b6f3cdc-531b-4a51-a6fa-fd047e45da28','送李校書二十六韻','杜甫','唐','唐诗','tang','','[]','代北有豪鷹，生子毛盡赤。',288,'全唐诗/poet.tang.10000.json','["代北有豪鷹，生子毛盡赤。", "渥洼騏驥兒，尤異是龍脊。", "李舟名父子，清峻流輩伯。", "人間好少年，不必須白皙。", "十五富文史，十八足賓客。", "十九授校書，二十聲輝赫。", "衆中每一見，使我潛動魄。", "自恐二男兒，辛勤養無益。", "乾元元年春，萬姓始安宅。", "舟也衣綵衣，告我欲遠適。", "倚門固有望，斂衽就行役。", "南登吟白華，已見楚山碧。", "藹藹咸陽都，冠蓋日雲積。", "何時太夫人，堂上會親戚。", "汝翁草明光，天子正前席。", "歸期豈爛漫，別意終感激。", "顧我蓬屋姿，謬通金閨籍。", "小來習性嬾，晚節慵轉劇。", "每愁悔吝作，如覺天地窄。", "羨君齒髮新，行己能夕惕。", "臨岐意頗切，對酒不能喫。", "回身視綠野，慘澹如荒澤。", "老雁春忍飢，哀號待枯麥。", "時哉高飛燕，絢練新羽翮。"]'),
('26a0266d-313c-4911-b629-2418556d1b03','洗兵馬','杜甫','唐','唐诗','tang','','["\u559c\u60a6", "\u6292\u60c5", "\u6218\u4e89"]','中興諸將收山東，捷書日報清晝同。',384,'全唐诗/poet.tang.10000.json','["中興諸將收山東，捷書日報清晝同。", "河廣傳聞一葦過，胡危命在破竹中。", "祗殘鄴城不日得，獨任朔方無限功。", "京師皆騎汗血馬，回紇餵肉葡萄宮。", "已喜皇威清海岱，常思仙仗過崆峒。", "三年笛裏關山月，萬國兵前草木風。", "成王功大心轉小，郭相謀深古來少。", "司徒清鑒懸明鏡，尚書氣與秋天杳。", "二三豪俊爲時出，整頓乾坤濟時了。", "東走無復憶鱸魚，南飛覺有安巢鳥。", "青春復隨冠冕入，紫禁正耐煙花繞。", "鶴禁通霄鳳輦備，雞鳴問寢龍樓曉。", "攀龍附鳳勢莫當，天下盡化爲侯王。", "汝等豈知蒙帝力，時來不得誇身強。", "關中既留蕭丞相，幕下復用張子房。", "張公一生江海客，身長九尺鬚眉蒼。", "徵起適遇風雲會，扶顛始知籌策良。", "青袍白馬更何有，後漢今周喜再昌。", "寸地尺天皆入貢，奇祥異瑞爭來送。", "不知何國致白環，復道諸山得銀甕。", "隱士休歌紫芝曲，詞人解撰河清頌。", "田家望望惜雨乾，布穀處處催春種。", "淇上健兒歸莫嬾，城南思婦愁多夢。", "安得壯士挽天河，淨洗甲兵長不用。"]'),
('1877173b-b4bb-467b-93da-a390559efe41','留花門','杜甫','唐','唐诗','tang','','[]','北門天驕子，飽肉氣勇決。',168,'全唐诗/poet.tang.10000.json','["北門天驕子，飽肉氣勇決。", "高秋馬肥健，挾矢射漢月。", "自古以爲患，詩人厭薄伐。", "修德使其來，羈縻固不絕。", "胡爲傾國至，出入暗金闕。", "中原有驅除，隱忍用此物。", "公主歌黃鵠，君王指白日。", "連雲屯左輔，百里見積雪。", "長戟鳥休飛，哀笳曙幽咽。", "田家最恐懼，麥倒桑枝折。", "沙苑臨清渭，泉香草豐潔。", "渡河不用船，千騎常撇烈。", "胡塵踰太行，雜種抵京室。", "花門既須留，原野轉蕭瑟。"]'),
('a2d1860f-cd55-488c-9c4b-3d19d5b8d3ef','病後遇王倚飲贈歌','杜甫','唐','唐诗','tang','','[]','麟角鳳觜世莫識，煎膠續弦奇自見。',224,'全唐诗/poet.tang.10000.json','["麟角鳳觜世莫識，煎膠續弦奇自見。", "尚看王生抱此懷，在于甫也何由羨。", "且遇王生慰疇昔，素知賤子甘貧賤。", "酷見凍餒不足恥，多病沈年苦無健。", "王生怪我顏色惡，荅云伏枕艱難徧。", "瘧癘三秋孰可忍，寒熱百日相交戰。", "頭白眼暗坐有胝，肉黃皮皺命如綫。", "惟生哀我未平復，爲我力致美殽膳。", "遣人向市賒香稉，喚婦出房親自饌。", "長安冬葅酸且綠，金城土酥靜如練。", "兼求富豪且割鮮，密沽斗酒諧終宴。", "故人情義晚誰似，令我手腳輕欲漩。", "老馬爲駒信不虛，當時得意況深眷。", "但使殘年飽喫飯，只願無事常相見。"]'),
('88abad3a-4ba9-461a-a592-34eb50aa80ef','湖城東遇孟雲卿復歸劉顥宅宿宴飲散因爲醉歌','杜甫','唐','唐诗','tang','','[]','疾風吹塵暗河縣，行子隔手不相見。',144,'全唐诗/poet.tang.10000.json','["疾風吹塵暗河縣，行子隔手不相見。", "湖城城南一開眼，駐馬偶識雲卿面。", "向非劉顥爲地主，嬾回鞭轡成高宴。", "劉侯歎我攜客來，置酒張燈促華饌。", "且將款曲終今夕，休語艱難尚酣戰。", "照室紅爐促曙光，縈窗素月垂文練。", "天開地裂長安陌，寒盡春生洛陽殿。", "豈知驅車復同軌，可惜刻漏隨更箭。", "人生會合不可常，庭樹雞鳴淚如綫。"]'),
('c166938b-f267-49e1-8a9b-a76852e97540','閿鄉姜七少府設膾戲贈長歌','杜甫','唐','唐诗','tang','','[]','姜侯設膾當嚴冬，昨日今日皆天風。',160,'全唐诗/poet.tang.10000.json','["姜侯設膾當嚴冬，昨日今日皆天風。", "河凍未漁不易得，鑿冰恐侵河伯宮。", "饔人受魚鮫人手，洗魚磨刀魚眼紅。", "無聲細下飛碎雪，有骨已剁觜春蔥。", "偏勸腹腴媿年少，軟炊香飯緣老翁。", "落碪何曾白紙濕，放箸未覺金盤空。", "新歡便飽姜侯德，清觴異味情屢極。", "東歸貪路自覺難，欲別上馬身無力。", "可憐爲人好心事，於我見子真顏色。", "不恨我衰子貴時，悵望且爲今相憶。"]'),
('0f6b5485-6ead-48e3-b211-46aaa1be1238','戲贈閿鄉秦少公短歌','杜甫','唐','唐诗','tang','','[]','去年行宮當太白，朝回君是同舍客。',64,'全唐诗/poet.tang.10000.json','["去年行宮當太白，朝回君是同舍客。", "同心不減骨肉親，每語見許文章伯。", "今日時清兩京道，相逢苦覺人情好。", "昨夜邀歡樂更無，多才依舊能潦倒。"]'),
('48568d08-d789-4eca-b9a8-5dcf09d6a516','李鄠縣丈人胡馬行','杜甫','唐','唐诗','tang','','[]','丈人駿馬名胡騮，前年避胡過金牛。',128,'全唐诗/poet.tang.10000.json','["丈人駿馬名胡騮，前年避胡過金牛。", "回鞭却走見天子，朝飲漢水暮靈州。", "自矜胡騮奇絕代，乘出千人萬人愛。", "一聞說盡急難材，轉益愁向駑駘輩。", "頭上銳耳批秋竹，脚下高蹄削寒玉。", "始知神龍別有種，不比俗馬空多肉。", "洛陽大道時再清，累日喜得俱東行。", "鳳臆龍鬐未易識，側身注目長風生。"]'),
('812e7edc-f0c2-4da9-be16-a14042619ce7','義鶻','杜甫','唐','唐诗','tang','','[]','陰崖有蒼鷹，養子黑柏顛。',216,'全唐诗/poet.tang.10000.json','["陰崖有蒼鷹，養子黑柏顛。", "白蛇登其巢，吞噬恣朝餐。", "雄飛遠求食，雌者鳴辛酸。", "力強不可制，黃口無半存。", "其父從西歸，飜身入長煙。", "斯須領健鶻，痛憤寄所宣。", "斗上捩孤影，噭哮來九天。", "修鱗脫遠枝，巨顙坼老拳。", "高空得蹭蹬，短草辭蜿蜒。", "折尾能一掉，飽腸皆已穿。", "生雖滅衆雛，死亦垂千年。", "物情有報復，快意貴目前。", "茲實鷙鳥最，急難心炯然。", "功成失所往，用舍何其賢。", "近經潏水湄，此事樵夫傳。", "飄蕭覺素髮，凜欲衝儒冠。", "人生許與分，只在顧盼間。", "聊爲義鶻行，用激壯士肝。"]'),
('bf2fb502-1e53-4ff9-a1b8-d9f1273148a7','畫鶻行','杜甫','唐','唐诗','tang','','[]','高堂見生鶻，颯爽動秋骨。',120,'全唐诗/poet.tang.10000.json','["高堂見生鶻，颯爽動秋骨。", "初驚無拘攣，何得立突兀。", "乃知畫師妙，功刮造化窟。", "寫作神駿姿，充君眼中物。", "鳥鵲滿樛枝，軒然恐其出。", "側腦看青霄，寧爲衆禽沒。", "長翮如刀劒，人寰可超越。", "乾坤空崢嶸，粉墨且蕭瑟。", "緬思雲沙際，自有煙霧質。", "吾今意何傷，顧步獨紆鬱。"]'),
('ccbadda6-7e25-4df6-bde4-cff74e45d080','瘦馬行','杜甫','唐','唐诗','tang','','[]','東郊瘦馬使我傷，骨骼硉兀如堵牆。',160,'全唐诗/poet.tang.10000.json','["東郊瘦馬使我傷，骨骼硉兀如堵牆。", "絆之欲動轉敧側，此豈有意仍騰驤。", "細看六印帶官字，衆道三軍遺路旁。", "皮乾剝落雜泥滓，毛暗蕭條連雪霜。", "去歲奔波逐餘寇，驊騮不慣不得將。", "士卒多騎內厩馬，惆悵恐是病乘黃。", "當時歷塊誤一蹶，委棄非汝能周防。", "見人慘澹若哀訴，失主錯莫無晶光。", "天寒遠放雁爲伴，日暮不收烏啄瘡。", "誰家且養願終惠，更試明年春草長。"]'),
('01751db4-8ba6-43f9-a89f-4d96826f5ee1','新安吏','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6218\u4e89"]','客行新安道，喧呼聞點兵。',168,'全唐诗/poet.tang.10000.json','["客行新安道，喧呼聞點兵。", "借問新安吏，縣小更無丁。", "府帖昨夜下，次選中男行。", "中男絕短小，何以守王城。", "肥男有母送，瘦男獨伶俜。", "白水暮東流，青山猶哭聲。", "莫自使眼枯，收汝淚縱橫。", "眼枯即見骨，天地終無情。", "我軍取相州，日夕望其平。", "豈意賊難料，歸軍星散營。", "就糧近故壘，練卒依舊京。", "掘壕不到水，牧馬役亦輕。", "況乃王師順，撫養甚分明。", "送行勿泣血，僕射如父兄。"]'),
('19c2a99b-507a-415a-8e66-1477861f5d71','潼關吏','杜甫','唐','唐诗','tang','','["\u58eb\u5352", "\u6218\u4e89", "\u8d5e\u7f8e", "\u8fb9\u7586"]','士卒何草草，築城潼關道。',120,'全唐诗/poet.tang.10000.json','["士卒何草草，築城潼關道。", "大城鐵不如，小城萬丈餘。", "借問潼關吏，修關還備胡。", "要我下馬行，爲我指山隅。", "連雲列戰格，飛鳥不能踰。", "胡來但自守，豈復憂西都。", "丈人視要處，窄狹容單車。", "艱難奮長戟，萬古用一夫。", "哀哉桃林戰，百萬化爲魚。", "請囑防關將，慎勿學哥舒。"]'),
('ef36b613-c482-4e50-81fa-68436392346e','石壕吏','杜甫','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u4eba\u6c11", "\u521d\u4e2d\u53e4\u8bd7", "\u540c\u60c5"]','暮投石壕邨，有吏夜捉人。',144,'全唐诗/poet.tang.10000.json','["暮投石壕邨，有吏夜捉人。", "老翁踰牆走，老婦出門看。", "吏呼一何怒，婦啼一何苦。", "聽婦前致詞，三男鄴城戍。", "一男附書致，二男新戰死。", "存者且偷生，死者長已矣。", "室中更無人，惟有乳下孫。", "有孫母未去，出入無完帬。", "老嫗力雖衰，請從吏夜歸。", "急應河陽役，猶得備晨炊。", "夜久語聲絕，如聞泣幽咽。", "天明登前途，獨與老翁別。"]'),
('895139ab-9cc7-4fb5-b43a-89416b18a4dc','新婚別','杜甫','唐','唐诗','tang','','["\u79bb\u522b", "\u53d9\u4e8b", "\u5987\u5973", "\u6218\u4e89"]','兔絲附蓬麻，引蔓故不長。',192,'全唐诗/poet.tang.10000.json','["兔絲附蓬麻，引蔓故不長。", "嫁女與征夫，不如棄路旁。", "結髮爲妻子，席不煖君牀。", "暮婚晨告別，無乃太怱忙。", "君行雖不遠，守邊赴河陽。", "妾身未分明，何以拜姑嫜。", "父母養我時，日夜令我藏。", "生女有所歸，雞狗亦得將。", "君今往死地，沈痛迫中腸。", "誓欲隨君去，形勢反蒼黃。", "勿爲新婚念，努力事戎行。", "婦人在軍中，兵氣恐不揚。", "自嗟貧家女，久致羅襦裳。", "羅襦不復施，對君洗紅妝。", "仰視百鳥飛，大小必雙翔。", "人事多錯迕，與君永相望。"]'),
('b0435860-95e5-44e7-bf6c-9eeee324ce96','垂老別','杜甫','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u60dc\u522b"]','四郊未寧靜，垂老不得安。',192,'全唐诗/poet.tang.10000.json','["四郊未寧靜，垂老不得安。", "子孫陣亡盡，焉用身獨完。", "投杖出門去，同行爲辛酸。", "幸有牙齒存，所悲骨髓乾。", "男兒既介胄，長揖別上官。", "老妻臥路啼，歲暮衣裳單。", "孰知是死別，且復傷其寒。", "此去必不歸，還聞勸加餐。", "土門壁甚堅，杏園度亦難。", "勢異鄴城下，縱死時猶寬。", "人生有離合，豈擇衰老端。", "憶昔少壯日，遲回竟長歎。", "萬國盡征戍，烽火被岡巒。", "積屍草木腥，流血川原丹。", "何鄉爲樂土，安敢尚盤桓。", "棄絕蓬室居，塌然摧肺肝。"]'),
('45f29798-b17d-44ed-b4c2-01620eae4868','無家別','杜甫','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u6292\u6000", "\u5199\u666f"]','寂寞天寶後，園廬但蒿藜。',192,'全唐诗/poet.tang.10000.json','["寂寞天寶後，園廬但蒿藜。", "我里百餘家，世亂各東西。", "存者無消息，死者爲塵泥。", "賤子因陣敗，歸來尋舊蹊。", "人行見空巷，日瘦氣慘悽。", "但對狐與貍，豎毛怒我啼。", "四鄰何所有，一二老寡妻。", "宿鳥戀本枝，安辭且窮棲。", "方春獨荷鋤，日暮還灌畦。", "縣吏知我至，召令習鼓鞞。", "雖從本州役，內顧無所攜。", "近行止一身，遠去終轉迷。", "家鄉既盪盡，遠近理亦齊。", "永痛長病母，五年委溝谿。", "生我不得力，終身兩酸嘶。", "人生無家別，何以爲烝黎。"]'),
('fb087f9d-b19c-4c65-a310-c605f73a1fde','夏日歎','杜甫','唐','唐诗','tang','','[]','夏日出東北，陵天經中街。',120,'全唐诗/poet.tang.10000.json','["夏日出東北，陵天經中街。", "朱光徹厚地，鬱蒸何由開。", "上蒼久無雷，無乃號令乖。", "雨降不濡物，良田起黃埃。", "飛鳥苦熱死，池魚涸其泥。", "萬人尚流冗，舉目唯蒿萊。", "至今大河北，化作虎與豺。", "浩蕩想幽薊，王師安在哉？", "對食不能餐，我心殊未諧。", "眇然貞觀初，難與數子偕。"]'),
('c63d308b-f3a7-4520-b041-f7f4e27a5c9d','夏夜歎','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u590f\u5929"]','永日不可暮，炎蒸毒我腸。',144,'全唐诗/poet.tang.10000.json','["永日不可暮，炎蒸毒我腸。", "安得萬里風，飄颻吹我裳。", "昊天出華月，茂林延疎光。", "仲夏苦夜短，開軒納微涼。", "虛明見纖毫，羽蟲亦飛揚。", "物情無巨細，自適固其常。", "念彼荷戈士，窮年守邊疆。", "何由一洗濯，執熱互相望。", "竟夕擊刁斗，喧聲連萬方。", "青紫雖被體，不如早還鄉。", "北城悲笳發，鸛鶴號且翔。", "況復煩促倦，激烈思時康。"]'),
('e8e50fc9-2d2d-4f48-9fe4-2be2d4afad73','立秋後題','杜甫','唐','唐诗','tang','','[]','日月不相饒，節序昨夜隔。',48,'全唐诗/poet.tang.10000.json','["日月不相饒，節序昨夜隔。", "玄蟬無停號，秋燕已如客。", "平生獨往願，惆悵年半百。", "罷官亦由人，何事拘形役。"]'),
('767aa860-e910-4294-9c3e-172277296c37','貽阮隱居','杜甫','唐','唐诗','tang','','[]','陳留風俗衰，人物世不數。',96,'全唐诗/poet.tang.10000.json','["陳留風俗衰，人物世不數。", "塞上得阮生，迥繼先父祖。", "貧知靜者性，自益毛髮古。", "車馬入鄰家，蓬蒿翳環堵。", "清詩近道要，識子用心苦。", "尋我草徑微，褰裳蹋寒雨。", "更議居遠邨，避喧甘猛虎。", "足明箕潁客，榮貴如糞土。"]'),
('e23e9d80-b995-43a0-9321-66d14b9f3bcf','遣興三首 一','杜甫','唐','唐诗','tang','','[]','下馬古戰場，四顧但茫然。',72,'全唐诗/poet.tang.10000.json','["下馬古戰場，四顧但茫然。", "風悲浮雲去，黃葉墜我前。", "朽骨穴螻蟻，又爲蔓草纏。", "故老行歎息，今人尚開邊。", "漢虜互勝負，封疆不常全。", "安得廉恥將，三軍同晏眠。"]'),
('140c81ac-b857-408f-bf47-8938c1b2e048','遣興三首 二','杜甫','唐','唐诗','tang','','[]','高秋登塞山，南望馬邑州。',72,'全唐诗/poet.tang.10000.json','["高秋登塞山，南望馬邑州。", "降虜東擊胡，壯健盡不留。", "穹廬莽牢落，上有行雲愁。", "老弱哭道路，願聞甲兵休。", "鄴中事反覆，死人積如丘。", "諸將已茅土，載驅誰與謀。"]'),
('fb0cdaa5-706e-4765-95a3-95cc78fd27b9','遣興三首 三','杜甫','唐','唐诗','tang','','[]','豐年孰云遲，甘澤不在早。',72,'全唐诗/poet.tang.10000.json','["豐年孰云遲，甘澤不在早。", "耕田秋雨足，禾黍已映道。", "春苗九月交，顏色同日老。", "勸汝衡門士，忽悲尚枯槁。", "時來展材力，先後無醜好。", "但訝鹿皮翁，忘機對芳草。"]'),
('1569e1de-29bd-4e84-a55a-7d300a92e6a7','昔遊','杜甫','唐','唐诗','tang','','[]','昔謁華蓋君，深求洞宮脚。',192,'全唐诗/poet.tang.10000.json','["昔謁華蓋君，深求洞宮脚。", "玉棺已上天，白日亦寂莫。", "暮升艮岑頂，巾几猶未却。", "弟子四五人，入來淚俱落。", "余時遊名山，發軔在遠壑。", "良覿違夙願，含淒向寥廓。", "林昏罷幽磬，竟夜伏石閣。", "王喬下天壇，微月映皓鶴。", "晨溪嚮虛駃，歸徑行已昨。", "豈辭青鞋胝，悵望金匕藥。", "東蒙赴舊隱，尚憶同志樂。", "休事董先生，于今獨蕭索。", "胡爲客關塞，道意久衰薄。", "妻子亦何人，丹砂負前諾。", "雖悲鬒髮變，未憂筋力弱。", "扶藜望清秋，有興入廬霍。"]'),
('f23f7f4c-80d5-4f3d-9328-6f0032eaf2d0','幽人','杜甫','唐','唐诗','tang','','[]','孤雲亦羣遊，神物有所歸。',132,'全唐诗/poet.tang.10000.json','["孤雲亦羣遊，神物有所歸。", "麟鳳在赤霄，何當一來儀。", "往與惠荀輩，中年滄洲期。", "天高無消息，棄我忽若遺。", "內懼非道流，幽人見瑕疵。", "洪濤隱語笑，鼓枻蓬萊池。", "崔嵬扶桑日，照耀珊瑚枝。", "風帆倚翠蓋，暮把東皇衣。", "咽漱元和津，所思煙霞微。", "知名未足稱，局促商山芝。", "五湖復浩蕩，歲暮有餘悲。"]'),
('f2db30a1-f125-44b9-a8d8-287ccb69238a','佳人','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8d5e\u7f8e", "\u4e94\u8a00\u53e4\u8bd7", "\u95fa\u6028", "\u5973\u5b50"]','絕代有佳人，幽居在空谷。',144,'全唐诗/poet.tang.10000.json','["絕代有佳人，幽居在空谷。", "自云良家子，零落依草木。", "關中昔喪敗，兄弟遭殺戮。", "官高何足論，不得收骨肉。", "世情惡衰歇，萬事隨轉燭。", "夫壻輕薄兒，新人已如玉。", "合昏尚知時，鴛鴦不獨宿。", "但見新人笑，那聞舊人哭。", "在山泉水清，出山泉水濁。", "侍婢賣珠回，牽蘿補茅屋。", "摘花不插髮，采柏動盈匊。", "天寒翠袖薄，日暮倚修竹。"]'),
('2b104baa-0304-4ae1-944c-c766ace60ec1','赤谷西崦人家','杜甫','唐','唐诗','tang','','[]','躋險不自喧，出郊已清目。',48,'全唐诗/poet.tang.10000.json','["躋險不自喧，出郊已清目。", "溪回日氣暖，徑轉山田熟。", "鳥雀依茅茨，藩籬帶松菊。", "如行武陵暮，欲問桃花宿。"]'),
('46878bae-9fd8-4808-bb50-ea9bca3cb2bf','西枝邨尋置草堂地夜宿贊公土室二首 一','杜甫','唐','唐诗','tang','','[]','出郭眄細岑，披榛得微路。',120,'全唐诗/poet.tang.10000.json','["出郭眄細岑，披榛得微路。", "溪行一流水，曲折方屢渡。", "贊公湯休徒，好靜心迹素。", "昨枉霞上作，盛論巖中趣。", "怡然共攜手，恣意同遠步。", "捫蘿澀先登，陟巘眩反顧。", "要求陽岡暖，苦陟陰嶺沍。", "惆悵老大藤，沈吟屈蟠樹。", "卜居意未展，杖策回且暮。", "層巔餘落日，早蔓已多露。"]'),
('842a2bf0-573b-4ad7-b8ed-f1f8844408de','西枝邨尋置草堂地夜宿贊公土室二首 二','杜甫','唐','唐诗','tang','','[]','天寒鳥已歸，月出人更靜。',120,'全唐诗/poet.tang.10000.json','["天寒鳥已歸，月出人更靜。", "土室延白光，松門耿疎影。", "躋攀倦日短，語樂寄夜永。", "明燃林中薪，暗汲石底井。", "大師京國舊，德業天機秉。", "從來支許遊，興趣江湖迥。", "數奇謫關塞，道廣存箕潁。", "何知戎馬間，復接塵事屏。", "幽尋豈一路，遠色有諸嶺。", "晨光稍曚曨，更越西南頂。"]'),
('221f5b2d-4997-4a97-bc31-87f0305d7570','寄贊上人','杜甫','唐','唐诗','tang','','[]','一昨陪錫杖，卜鄰南山幽。',120,'全唐诗/poet.tang.10000.json','["一昨陪錫杖，卜鄰南山幽。", "年侵腰脚衰，未便陰崖秋。", "重岡北面起，竟日陽光留。", "茅屋買兼土，斯焉心所求。", "近聞西枝西，有谷杉黍稠。", "亭午頗和暖，石田又足收。", "當期塞雨乾，宿昔齒疾瘳。", "裴回虎穴上，面勢龍泓頭。", "柴荆具茶茗，逕路通林丘。", "與子成二老，來往亦風流。"]'),
('664bcedd-5b20-4884-a2c0-c92b127d4504','太平寺泉眼','杜甫','唐','唐诗','tang','','[]','招提憑高岡，疎散連草莽。',144,'全唐诗/poet.tang.10000.json','["招提憑高岡，疎散連草莽。", "出泉枯柳根，汲引歲月古。", "石間見海眼，天畔縈水府。", "廣深丈尺間，宴息敢輕侮。", "青白二小蛇，幽姿可時覩。", "如絲氣或上，爛熳爲雲雨。", "山頭到山下，鑿井不盡土。", "取供十方僧，香美勝牛乳。", "北風起寒文，弱藻舒翠縷。", "明涵客衣淨，細蕩林影趣。", "何當宅下流，餘潤通藥圃。", "三春濕黃精，一食生毛羽。"]'),
('c9362aba-fb50-481b-a4cd-08ddd65cdd2a','夢李白二首 一','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','死別已吞聲，生別常惻惻。',96,'全唐诗/poet.tang.10000.json','["死別已吞聲，生別常惻惻。", "江南瘴癘地，逐客無消息。", "故人入我夢，明我長相憶。", "恐非平生魂，路遠不可測。", "魂來楓葉青，魂返關塞黑。", "君今在羅網，何以有羽翼。", "落月滿屋梁，猶疑照顏色。", "水深波浪闊，無使蛟龍得。"]'),
('0710a746-8660-4bc1-b073-8ce51ac9f4d9','夢李白二首 二','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u4eba", "\u540c\u60c5", "\u8bb0\u68a6", "\u4e94\u8a00\u53e4\u8bd7"]','浮雲終日行，遊子久不至。',96,'全唐诗/poet.tang.10000.json','["浮雲終日行，遊子久不至。", "三夜頻夢君，情親見君意。", "告歸常局促，苦道來不易。", "江湖多風波，舟楫恐失墜。", "出門搔白首，若負平生志。", "冠蓋滿京華，斯人獨顦顇。", "孰云網恢恢，將老身反累。", "千秋萬歲名，寂莫身後事。"]'),
('058cb6ad-31e4-4d05-a2d7-c1f08ae860f1','有懷台州鄭十八司戶','杜甫','唐','唐诗','tang','','[]','天台隔三江，風浪無晨暮。',144,'全唐诗/poet.tang.10000.json','["天台隔三江，風浪無晨暮。", "鄭公縱得歸，老病不識路。", "昔如水上鷗，今如罝中兔。", "性命由他人，悲辛但狂顧。", "山鬼獨一脚，蝮蛇長如樹。", "呼號傍孤城，歲月誰與度。", "從來禦魑魅，多爲才名誤。", "夫子嵇阮流，更被時俗惡。", "海隅微小吏，眼暗髮垂素。", "黃帽映青袍，非供折腰具。", "平生一杯酒，見我故人遇。", "相望無所成，乾坤莽回互。"]'),
('4b3cec93-fc44-44d2-91fa-a4feed67aaf9','遣興五首 一','杜甫','唐','唐诗','tang','','[]','蟄龍三冬臥，老鶴萬里心。',60,'全唐诗/poet.tang.10000.json','["蟄龍三冬臥，老鶴萬里心。", "昔時賢俊人，未遇猶視今。", "嵇康不得死，孔明有知音。", "又如壠底松，用舍在所尋。", "大哉霜雪榦，歲久爲枯林。"]'),
('914f158e-3c55-4db4-84bb-0f8a4b620f1d','遣興五首 二','杜甫','唐','唐诗','tang','','[]','昔者龐德公，未曾入州府。',60,'全唐诗/poet.tang.10000.json','["昔者龐德公，未曾入州府。", "襄陽耆舊間，處士節獨苦。", "豈無濟時策，終竟畏羅罟。", "林茂鳥有歸，水深魚知聚。", "舉家依鹿門，劉表焉得取。"]'),
('945f8864-ae77-43fb-a9f8-c2c9f34fe39e','遣興五首 三','杜甫','唐','唐诗','tang','','[]','我今日夜憂，諸弟各異方。',60,'全唐诗/poet.tang.10000.json','["我今日夜憂，諸弟各異方。", "不知死與生，何況道路長。", "避寇一分散，飢寒永相望。", "豈無柴門歸，欲出畏虎狼。", "仰看雲中雁，禽鳥亦有行。"]'),
('cf5404fd-70f0-47b7-a4a8-8a2a7fb671c4','遣興五首 四','杜甫','唐','唐诗','tang','','[]','蓬生非無根，漂蕩隨高風。',60,'全唐诗/poet.tang.10000.json','["蓬生非無根，漂蕩隨高風。", "天寒落萬里，不復歸本叢。", "客子念故宅，三年門巷空。", "悵望但烽火，戎車滿關東。", "生涯能幾何，常在羈旅中。"]'),
('13f2246e-b05e-44aa-b907-b642cc77defc','遣興五首 五','杜甫','唐','唐诗','tang','','[]','昔在洛陽時，親友相追攀。',60,'全唐诗/poet.tang.10000.json','["昔在洛陽時，親友相追攀。", "送客東郊道，遨遊宿南山。", "煙塵阻長河，樹羽成臯間。", "回首載酒地，豈無一日還。", "丈夫貴壯健，慘戚非朱顏。"]'),
('1bcd81fb-6fb5-4994-b9ec-6baf5bbd4142','遣興五首 一','杜甫','唐','唐诗','tang','','[]','朔風飄胡雁，慘澹帶砂礫。',48,'全唐诗/poet.tang.10000.json','["朔風飄胡雁，慘澹帶砂礫。", "長林何蕭蕭，秋草萋更碧。", "北里富熏天，高樓夜吹笛。", "焉知南鄰客，九月猶絺綌。"]'),
('5c063d6a-0bc3-49b6-805e-e192478c1bca','遣興五首 二','杜甫','唐','唐诗','tang','','[]','長陵銳頭兒，出獵待明發。',48,'全唐诗/poet.tang.10000.json','["長陵銳頭兒，出獵待明發。", "騂弓金爪鏑，白馬蹴微雪。", "未知所馳逐，但見暮光滅。", "歸來懸兩狼，門戶有旌節。"]'),
('4cc0678f-1272-47ec-89ed-233fee07d436','遣興五首 三','杜甫','唐','唐诗','tang','','[]','漆有用而割，膏以明自煎。',48,'全唐诗/poet.tang.10000.json','["漆有用而割，膏以明自煎。", "蘭摧白露下，桂折秋風前。", "府中羅舊尹，沙道尚依然。", "赫赫蕭京兆，今爲時所憐。"]'),
('9f89a106-6ff8-4deb-a2e5-30d5fe0da0f1','遣興五首 四','杜甫','唐','唐诗','tang','','[]','猛虎憑其威，往往遭急縛。',48,'全唐诗/poet.tang.10000.json','["猛虎憑其威，往往遭急縛。", "雷吼徒咆哮，枝撐已在脚。", "忽看皮寢處，無復睛閃爍。", "人有甚於斯，足以勸元惡。"]'),
('5376f2f6-9068-40c0-947b-f752a7d79892','遣興五首 五','杜甫','唐','唐诗','tang','','[]','朝逢富家葬，前後皆輝光。',48,'全唐诗/poet.tang.10000.json','["朝逢富家葬，前後皆輝光。", "共指親戚大，緦麻百夫行。", "送者各有死，不須羨其強。", "君看束練去，亦得歸山岡。"]'),
('7beb1d4a-e1c9-4fc5-9ba1-82f46a724480','遣興五首 一','杜甫','唐','唐诗','tang','','[]','天用莫如龍，有時繫扶桑。',48,'全唐诗/poet.tang.10000.json','["天用莫如龍，有時繫扶桑。", "頓轡海徒涌，神人身更長。", "性命苟不存，英雄徒自強。", "吞聲勿復道，真宰意茫茫。"]'),
('5768d12d-f4b9-4cbe-b7ae-051ed33d6331','遣興五首 二','杜甫','唐','唐诗','tang','','[]','地用莫如馬，無良復誰記。',48,'全唐诗/poet.tang.10000.json','["地用莫如馬，無良復誰記。", "此日千里鳴，追風可君意。", "君看渥洼種，態與駑駘異。", "不雜蹄齧間，逍遙有能事。"]'),
('fd956840-16b9-4268-9e98-dabb2fc592f0','遣興五首 三','杜甫','唐','唐诗','tang','','[]','陶潛避俗翁，未必能達道。',48,'全唐诗/poet.tang.10000.json','["陶潛避俗翁，未必能達道。", "觀其著詩集，頗亦恨枯槁。", "達生豈是足，默識蓋不早。", "有子賢與愚，何其挂懷抱。"]'),
('bcda5041-e6dc-402d-bf55-66ece895c572','遣興五首 四','杜甫','唐','唐诗','tang','','[]','賀公雅吳語，在位常清狂。',48,'全唐诗/poet.tang.10000.json','["賀公雅吳語，在位常清狂。", "上疏乞骸骨，黃冠歸故鄉。", "爽氣不可致，斯人今則亡。", "山陰一茅宇，江海日淒涼。"]'),
('5f010162-7a84-4c3c-935e-30fbe6f02b9f','遣興五首 五','杜甫','唐','唐诗','tang','','[]','吾憐孟浩然，裋褐即長夜。',48,'全唐诗/poet.tang.10000.json','["吾憐孟浩然，裋褐即長夜。", "賦詩何必多，往往凌鮑謝。", "清江空舊魚，春雨餘甘蔗。", "每望東南雲，令人幾悲吒。"]'),
('b7464f5a-53ed-4e78-92b9-331f0c5a39e9','前出塞九首 一','杜甫','唐','唐诗','tang','','[]','戚戚去故里，悠悠赴交河。',48,'全唐诗/poet.tang.10000.json','["戚戚去故里，悠悠赴交河。", "公家有程期，亡命嬰禍羅。", "君已富士境，開邊一何多。", "棄絕父母恩，吞聲行負戈。"]'),
('c95e1e06-9ca3-46b0-9a8b-f5673b9c7e7d','前出塞九首 二','杜甫','唐','唐诗','tang','','[]','出門日已遠，不受徒旅欺。',48,'全唐诗/poet.tang.10000.json','["出門日已遠，不受徒旅欺。", "骨肉恩豈斷，男兒死無時。", "走馬脫轡頭，手中挑青絲。", "捷下萬仞岡，俯身試搴旗。"]'),
('db93335b-fb58-4e18-b7dc-a0f59a083af3','前出塞九首 三','杜甫','唐','唐诗','tang','','[]','磨刀嗚咽水，水赤刃傷手。',48,'全唐诗/poet.tang.10000.json','["磨刀嗚咽水，水赤刃傷手。", "欲輕腸斷聲，心緒亂已久。", "丈夫誓許國，憤惋復何有。", "功名圖騏驎，戰骨當速朽。"]'),
('253b667d-e9bb-44ec-8ea9-03e1d552d9a7','前出塞九首 四','杜甫','唐','唐诗','tang','','[]','送徒既有長，遠戍亦有身。',48,'全唐诗/poet.tang.10000.json','["送徒既有長，遠戍亦有身。", "生死向前去，不勞吏怒嗔。", "路逢相識人，附書與六親。", "哀哉兩決絕，不復同苦辛。"]'),
('9434b028-3ff5-4d33-866b-e0e2b2d6dc70','前出塞九首 五','杜甫','唐','唐诗','tang','','[]','迢迢萬餘里，領我赴三軍。',48,'全唐诗/poet.tang.10000.json','["迢迢萬餘里，領我赴三軍。", "軍中異苦樂，主將寧盡聞。", "隔河見胡騎，倏忽數百羣。", "我始爲奴僕，幾時樹功勳。"]'),
('77c675b1-10eb-4a59-af03-13eb43a2f9a0','前出塞九首 六','杜甫','唐','唐诗','tang','','["\u54f2\u7406", "\u8bae\u8bba", "\u6218\u4e89"]','挽弓當挽強，用箭當用長。',48,'全唐诗/poet.tang.10000.json','["挽弓當挽強，用箭當用長。", "射人先射馬，擒賊先擒王。", "殺人亦有限，列國自有疆。", "苟能制侵陵，豈在多殺傷。"]'),
('f3f3eb2b-20da-4636-b1cc-a0e09a0620c4','前出塞九首 七','杜甫','唐','唐诗','tang','','[]','驅馬天雨雪，軍行入高山。',48,'全唐诗/poet.tang.10000.json','["驅馬天雨雪，軍行入高山。", "逕危抱寒石，指落曾冰間。", "已去漢月遠，何時築城還。", "浮雲暮南征，可望不可攀。"]'),
('a4b24339-00c0-4745-b66f-11216db55ef6','前出塞九首 八','杜甫','唐','唐诗','tang','','[]','單于寇我壘，百里風塵昏。',48,'全唐诗/poet.tang.10000.json','["單于寇我壘，百里風塵昏。", "雄劒四五動，彼軍爲我奔。", "虜其名王歸，繫頸授轅門。", "潛身備行列，一勝何足論。"]'),
('39f9beec-1292-4208-a8b5-ec971ac6d965','前出塞九首 九','杜甫','唐','唐诗','tang','','[]','從軍十年餘，能無分寸功。',48,'全唐诗/poet.tang.10000.json','["從軍十年餘，能無分寸功。", "衆人貴苟得，欲語羞雷同。", "中原有鬬爭，況在狄與戎。", "丈夫四方志，安可辭固窮。"]'),
('39687061-12a7-4ac3-b911-eb7419d4ac3e','後出塞五首 一','杜甫','唐','唐诗','tang','','[]','男兒生世間，及壯當封侯。',84,'全唐诗/poet.tang.10000.json','["男兒生世間，及壯當封侯。", "戰伐有功業，焉能守舊丘。", "召募赴薊門，軍動不可留。", "千金買馬鞭，百金裝刀頭。", "閭里送我行，親戚擁道周。", "斑白居上列，酒酣進庶羞。", "少年別有贈，含笑看吳鉤。"]'),
('0e981612-b3bb-4124-93a1-06e4abd82099','後出塞五首 二','杜甫','唐','唐诗','tang','','[]','朝進東門營，暮上河陽橋。',72,'全唐诗/poet.tang.10000.json','["朝進東門營，暮上河陽橋。", "落日照大旗，馬鳴風蕭蕭。", "平沙列萬幕，部伍各見招。", "中天懸明月，令嚴夜寂寥。", "悲笳數聲動，壯士慘不驕。", "借問大將誰，恐是霍嫖姚。"]'),
('dc65d380-14d7-4ed4-b225-a6a976172050','後出塞五首 三','杜甫','唐','唐诗','tang','','[]','古人重守邊，今人重高勳。',72,'全唐诗/poet.tang.10000.json','["古人重守邊，今人重高勳。", "豈知英雄主，出師亙長雲。", "六合已一家，四夷且孤軍。", "遂使貔虎士，奮身勇所聞。", "拔劒擊大荒，日收胡馬羣。", "誓開玄冥北，持以奉吾君。"]'),
('74e31da9-682f-45e2-8c18-c5a5689c3ba9','後出塞五首 四','杜甫','唐','唐诗','tang','','[]','獻凱日繼踵，兩蕃靜無虞。',72,'全唐诗/poet.tang.10000.json','["獻凱日繼踵，兩蕃靜無虞。", "漁陽豪俠地，擊鼓吹笙竽。", "雲帆轉遼海，稉稻來東吳。", "越羅與楚練，照耀輿臺軀。", "主將位益崇，氣驕凌上都。", "邊人不敢議，議者死路衢。"]'),
('0fa40901-8543-407c-97dc-95d9e3201b85','後出塞五首 五','杜甫','唐','唐诗','tang','','[]','我本良家子，出師亦多門。',72,'全唐诗/poet.tang.10000.json','["我本良家子，出師亦多門。", "將驕益愁思，身貴不足論。", "躍馬二十年，恐辜明主恩。", "坐見幽州騎，長驅河洛昏。", "中夜間道歸，故里但空邨。", "惡名幸脫免，窮老無兒孫。"]'),
('40de2a56-327b-49db-894d-dbf8735ad3a8','別贊上人','杜甫','唐','唐诗','tang','','[]','百川日東流，客去亦不息。',144,'全唐诗/poet.tang.10000.json','["百川日東流，客去亦不息。", "我生苦漂蕩，何時有終極。", "贊公釋門老，放逐來上國。", "還爲世塵嬰，頗帶顦顇色。", "楊枝晨在手，豆子雨已熟。", "是身如浮雲，安可限南北。", "異縣逢舊友，初忻寫胸臆。", "天長關塞寒，歲暮飢凍逼。", "野風吹征衣，欲別向曛黑。", "馬嘶思故櫪，歸鳥盡斂翼。", "古來聚散地，宿昔長荆棘。", "相看俱衰年，出處各努力。"]'),
('b1b841ee-a837-427e-aecc-1da457c3b102','萬丈潭','杜甫','唐','唐诗','tang','','[]','青溪合冥莫，神物有顯晦。',168,'全唐诗/poet.tang.10000.json','["青溪合冥莫，神物有顯晦。", "龍依積水蟠，窟壓萬丈內。", "跼步凌垠堮，側身下煙靄。", "前臨洪濤寬，却立蒼石大。", "山色一徑盡，崖絕兩壁對。", "削成根虛無，倒影垂澹瀩。", "黑如灣澴底，清見光炯碎。", "孤雲倒來深，飛鳥不在外。", "高蘿成帷幄，寒木累旌旆。", "遠川曲通流，嵌竇潛洩瀨。", "造幽無人境，發興自我輩。", "告歸遺恨多，將老斯遊最。", "閉藏修鱗蟄，出入巨石礙。", "何事暑天過，快意風雨㑹。"]'),
('da6f5381-433a-41d3-afea-2598d19fe9c1','兩當縣吳十侍御江上宅','杜甫','唐','唐诗','tang','','[]','寒城朝煙澹，山谷落葉赤。',216,'全唐诗/poet.tang.10000.json','["寒城朝煙澹，山谷落葉赤。", "陰風千里來，吹汝江上宅。", "鵾雞號枉渚，日色傍阡陌。", "借問持斧翁，幾年長沙客。", "哀哀失木狖，矯矯避弓翮。", "亦知故鄉樂，未敢思夙昔。", "昔在鳳翔都，共通金閨籍。", "天子猶蒙塵，東郊暗長戟。", "兵家忌間諜，此輩常接跡。", "臺中領舉劾，君必慎剖析。", "不忍殺無辜，所以分白黑。", "上官權許與，失意見遷斥。", "仲尼甘旅人，向子識損益。", "朝廷非不知，閉口休歎息。", "余時忝諍臣，丹陛實咫尺。", "相看受狼狽，至死難塞責。", "行邁心多違，出門無與適。", "於公負明義，惆悵頭更白。"]'),
('5aee80a3-db54-4787-9e2a-491e108b8f1d','發秦州','杜甫','唐','唐诗','tang','','[]','我衰更嬾拙，生事不自謀。',192,'全唐诗/poet.tang.10000.json','["我衰更嬾拙，生事不自謀。", "無食問樂土，無衣思南州。", "漢源十月交，天氣涼如秋。", "草木未黃落，況聞山水幽。", "栗亭名更佳，下有良田疇。", "充腸多薯蕷，崖蜜亦易求。", "密竹復冬筍，清池可方舟。", "雖傷旅寓遠，庶遂平生遊。", "此邦俯要衝，實恐人事稠。", "應接非本性，登臨未銷憂。", "谿谷無異石，塞田始微收。", "豈復慰老夫，惘然難久留。", "日色隱孤戍，烏啼滿城頭。", "中宵驅車去，飲馬寒塘流。", "磊落星月高，蒼茫雲霧浮。", "大哉乾坤內，吾道長悠悠。"]'),
('b2f88f34-dc04-4366-8ca7-466e5e6e241c','赤谷','杜甫','唐','唐诗','tang','','[]','天寒霜雪繁，遊子有所之。',96,'全唐诗/poet.tang.10000.json','["天寒霜雪繁，遊子有所之。", "豈但歲月暮，重來未有期。", "晨發赤谷亭，險艱方自茲。", "亂石無改轍，我車已載脂。", "山深苦多風，落日童穉飢。", "悄然邨墟迥，煙火何由追。", "貧病轉零落，故鄉不可思。", "常恐死道路，永爲高人嗤。"]'),
('1b4ed54b-6c20-4817-a102-e0ce802ba019','鐵堂峽','杜甫','唐','唐诗','tang','','[]','山風吹遊子，縹緲乘險絕。',96,'全唐诗/poet.tang.10000.json','["山風吹遊子，縹緲乘險絕。", "峽形藏堂隍，壁色立積鐵。", "徑摩穹蒼蟠，石與厚地裂。", "修纖無垠竹，嵌空太始雪。", "威遲哀壑底，徒旅慘不悅。", "水寒長冰橫，我馬骨正折。", "生涯抵弧矢，盜賊殊未滅。", "飄蓬踰三年，回首肝肺熱。"]'),
('e19f6e14-e964-4d21-a5c7-e9e1a607ed16','鹽井','杜甫','唐','唐诗','tang','','[]','鹵中草木白，青者官鹽煙。',72,'全唐诗/poet.tang.10000.json','["鹵中草木白，青者官鹽煙。", "官作既有程，煮鹽煙在川。", "汲井歲榾榾，出車日連連。", "自公斗三百，轉致斛六千。", "君子慎止足，小人苦喧闐。", "我何良歎嗟，物理固自然。"]'),
('a31bfdee-c214-4ace-af0e-caeead25ec0c','寒硤','杜甫','唐','唐诗','tang','','[]','行邁日悄悄，山谷勢多端。',72,'全唐诗/poet.tang.10000.json','["行邁日悄悄，山谷勢多端。", "雲門轉絕岸，積阻霾天寒。", "寒硤不可度，我實衣裳單。", "況當仲冬交，泝沿增波瀾。", "野人尋煙語，行子傍水餐。", "此生免荷殳，未敢辭路難。"]'),
('ecd3d20d-3811-4313-9588-dfedb060eef4','法鏡寺','杜甫','唐','唐诗','tang','','[]','身危適他州，勉強終勞苦。',96,'全唐诗/poet.tang.10000.json','["身危適他州，勉強終勞苦。", "神傷山行深，愁破崖寺古。", "嬋娟碧鮮淨，蕭摵寒籜聚。", "回回山根水，冉冉松上雨。", "洩雲蒙清晨，初日翳復吐。", "朱甍半光炯，戶牖粲可數。", "拄策忘前期，出蘿已亭午。", "冥冥子規叫，微徑不復取。"]'),
('f220be96-faf6-4538-b69b-12a25f93a1c9','青陽峽','杜甫','唐','唐诗','tang','','[]','塞外苦厭山，南行道彌惡。',120,'全唐诗/poet.tang.10000.json','["塞外苦厭山，南行道彌惡。", "岡巒相經亙，雲水氣參錯。", "林迥硤角來，天窄壁面削。", "磎西五里石，奮怒向我落。", "仰看日車側，俯恐坤軸弱。", "魑魅嘯有風，霜霰浩漠漠。", "昨憶踰隴坂，高秋視吳岳。", "東笑蓮華卑，北知崆峒薄。", "超然侔壯觀，已謂殷寥廓。", "突兀猶趁人，及茲歎冥莫。"]'),
('5ea3afcb-dbb6-4641-abfa-cb4025f43d0a','龍門鎮','杜甫','唐','唐诗','tang','','[]','細泉兼輕冰，沮洳棧道濕。',72,'全唐诗/poet.tang.10000.json','["細泉兼輕冰，沮洳棧道濕。", "不辭辛苦行，迫此短景急。", "石門雪雲隘，古鎮峰巒集。", "旌竿暮慘澹，風水白刃澀。", "胡馬屯成臯，防虞此何及。", "嗟爾遠戍人，山寒夜中泣。"]'),
('db149aaa-c52b-4893-8b6b-7047bd84b92f','石龕','杜甫','唐','唐诗','tang','','[]','熊羆哮我東，虎豹號我西。',96,'全唐诗/poet.tang.10000.json','["熊羆哮我東，虎豹號我西。", "我後鬼長嘯，我前狨又啼。", "天寒昏無日，山遠道路迷。", "驅車石龕下，仲冬見虹蜺。", "伐竹者誰子，悲歌上雲梯。", "爲官采美箭，五歲供梁齊。", "苦云直簳盡，無以充提攜。", "奈何漁陽騎，颯颯驚烝黎。"]'),
('26377acb-f4ce-440c-967e-e4c5eb9ebe48','積草嶺','杜甫','唐','唐诗','tang','','[]','連峰積長陰，白日遞隱見。',96,'全唐诗/poet.tang.10000.json','["連峰積長陰，白日遞隱見。", "颼颼林響交，慘慘石壯變。", "山分積草嶺，路異明水縣。", "旅泊吾道窮，衰年歲時倦。", "卜居尚百里，休駕投諸彥。", "邑有佳主人，情如已會面。", "來書語絕妙，遠客驚深眷。", "食蕨不願餘，茅茨眼中見。"]'),
('46c91e4d-996f-4f29-824a-a2422b6c7971','泥功山','杜甫','唐','唐诗','tang','','[]','朝行青泥上，暮在青泥中。',72,'全唐诗/poet.tang.10000.json','["朝行青泥上，暮在青泥中。", "泥濘非一時，版築勞人功。", "不畏道途永，乃將汩沒同。", "白馬爲鐵驪，小兒成老翁。", "哀猿透却墜，死鹿力所窮。", "寄語北來人，後來莫悤悤。"]'),
('3cf03c99-a183-42d3-b280-0f955523ad22','鳳凰臺','杜甫','唐','唐诗','tang','','[]','亭亭鳳凰臺，北對西康州。',168,'全唐诗/poet.tang.10000.json','["亭亭鳳凰臺，北對西康州。", "西伯今寂寞，凰聲亦悠悠。", "山峻路絕蹤，石林氣高浮。", "安得萬丈梯，爲君上上頭。", "恐有無母雛，飢寒日啾啾。", "我能剖心出，飲啄慰孤愁。", "心以當竹實，炯然無外求。", "血以當醴泉，豈徒比清流。", "所貴王者瑞，敢辭微命休。", "坐看綵翮長，舉意八極周。", "自天銜瑞圖，飛下十二樓。", "圖以奉至尊，鳳以垂鴻猷。", "再光中興業，一洗蒼生憂。", "深衷正爲此，羣盜何淹留。"]'),
('ae8396b9-da62-4b1b-9c75-580ff9bfdda3','乾元中寓居同谷縣作歌七首 一','杜甫','唐','唐诗','tang','','[]','有客有客字子美，白頭亂髮垂過耳。',65,'全唐诗/poet.tang.10000.json','["有客有客字子美，白頭亂髮垂過耳。", "歲拾橡栗隨狙公，天寒日暮山谷裏。", "中原無書歸不得，手脚凍皴皮肉死。", "鳴呼一歌兮歌已哀，悲風爲我從天來。"]'),
('c4b14b05-2686-43b7-9006-ceda18052b2a','乾元中寓居同谷縣作歌七首 二','杜甫','唐','唐诗','tang','','[]','長鑱長鑱白木柄，我生托子以爲命。',65,'全唐诗/poet.tang.10000.json','["長鑱長鑱白木柄，我生托子以爲命。", "黃精無苗山雪盛，短衣數挽不掩脛。", "此時與子空歸來，男呻女吟四壁靜。", "鳴呼二歌兮歌始放，鄰里爲我色惆悵。"]'),
('64e97927-ce01-4928-a011-37716827baeb','乾元中寓居同谷縣作歌七首 三','杜甫','唐','唐诗','tang','','[]','有弟有弟在遠方，三人各瘦何人強。',65,'全唐诗/poet.tang.10000.json','["有弟有弟在遠方，三人各瘦何人強。", "生別展轉不相見，胡塵暗天道路長。", "東飛駕鵝後鶖鶬，安得送我置汝旁。", "鳴呼三歌兮歌三發，汝歸何處收兄骨。"]'),
('d9068fa3-4453-4d44-845f-1a4ab4186a1a','乾元中寓居同谷縣作歌七首 四','杜甫','唐','唐诗','tang','','[]','有妹有妹在鍾離，良人早歿諸孤癡。',65,'全唐诗/poet.tang.10000.json','["有妹有妹在鍾離，良人早歿諸孤癡。", "長淮浪高蛟龍怒，十年不見來何時。", "扁舟欲往箭滿眼，杳杳南國多旌旗。", "鳴呼四歌兮歌四奏，林猨爲我啼清晝。"]'),
('e93a77e9-6f3f-4f80-ac47-02924d3acfd1','乾元中寓居同谷縣作歌七首 五','杜甫','唐','唐诗','tang','','[]','四山多風溪水急，寒雨颯颯枯樹濕。',65,'全唐诗/poet.tang.10000.json','["四山多風溪水急，寒雨颯颯枯樹濕。", "黃蒿古城雲不開，白狐跳梁黃狐立。", "我生何爲在窮谷，中夜起坐萬感集。", "鳴呼五歌兮歌正長，魂招不來歸故鄉。"]'),
('143fe577-0829-4ce8-b075-0ac12d8f64fe','乾元中寓居同谷縣作歌七首 六','杜甫','唐','唐诗','tang','','[]','南有龍兮在山湫，古木巃嵷枝相樛。',65,'全唐诗/poet.tang.10000.json','["南有龍兮在山湫，古木巃嵷枝相樛。", "木葉黃落龍正蟄，蝮蛇東來水上遊。", "我行怪此安敢出，拔劒欲斬且復休。", "鳴呼六歌兮歌思遲，溪壑爲我回春姿。"]'),
('1c556427-1203-45cd-b593-eab55e582569','乾元中寓居同谷縣作歌七首 七','杜甫','唐','唐诗','tang','','[]','男兒生不成名身已老，三年飢走荒山道。',67,'全唐诗/poet.tang.10000.json','["男兒生不成名身已老，三年飢走荒山道。", "長安卿相多少年，富貴應須致身早。", "山中儒生舊相識，但話宿昔傷懷抱。", "鳴呼七歌兮悄終曲，仰視皇天白日速。"]'),
('b178756b-34ab-4c15-a0d3-42af871a6c55','發同谷縣','杜甫','唐','唐诗','tang','','[]','賢有不黔突，聖有不煖席。',120,'全唐诗/poet.tang.10000.json','["賢有不黔突，聖有不煖席。", "況我飢愚人，焉能尚安宅。", "始來茲山中，休駕喜地僻。", "奈何迫物累，一歲四行役。", "忡忡去絕境，杳杳更遠適。", "停驂龍潭雲，回首白崖石。", "臨岐別數子，握手淚再滴。", "交情無舊深，窮老多慘慼。", "平生嬾拙意，偶值棲遁跡。", "去住與願違，仰慙林間翮。"]'),
('63c36b31-8f4d-4e1c-a9dd-c10f3e6a0da5','木皮嶺','杜甫','唐','唐诗','tang','','[]','首路栗亭西，尚想鳳皇邨。',168,'全唐诗/poet.tang.10000.json','["首路栗亭西，尚想鳳皇邨。", "季冬攜童穉，辛苦赴蜀門。", "南登木皮嶺，艱險不易論。", "汗流被我體，祁寒爲之暄。", "遠岫爭輔佐，千巖自崩奔。", "始知五岳外，別有他山尊。", "仰干塞大明，俯入裂厚坤。", "再聞虎豹鬬，屢跼風水昏。", "高有廢閣道，摧折如短轅。", "下有冬青林，石上走長根。", "西崖特秀發，煥若靈芝繁。", "潤聚金碧氣，清無沙土痕。", "憶觀崑崙圖，目擊懸圃存。", "對此欲何適，默傷垂老魂。"]'),
('f4a9f923-e4e3-4a02-856b-892800774ad4','白沙渡','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','畏途隨長江，渡口下絕岸。',96,'全唐诗/poet.tang.10000.json','["畏途隨長江，渡口下絕岸。", "差池上舟楫，杳窕入雲漢。", "天寒荒野外，日暮中流半。", "我馬向北嘶，山猨飲相喚。", "水清石礧礧，沙白灘漫漫。", "迥然洗愁辛，多病一疎散。", "高壁抵嶔崟，洪濤越凌亂。", "臨風獨回首，攬轡復三歎。"]'),
('164c262f-0c01-4baa-b366-adeb077fa1ea','水會渡','杜甫','唐','唐诗','tang','','[]','山行有常程，中夜尚未安。',96,'全唐诗/poet.tang.10000.json','["山行有常程，中夜尚未安。", "微月沒已久，崖傾路何難。", "大江動我前，洶若溟渤寬。", "篙師暗理楫，歌笑輕波瀾。", "霜濃木石滑，風急手足寒。", "入舟已千憂，陟巘仍萬盤。", "迥眺積水外，始知衆星乾。", "遠遊令人瘦，衰疾慙加餐。"]'),
('660a6778-c6b8-40ef-908f-c2d563d1fe0b','飛仙閣','杜甫','唐','唐诗','tang','','[]','土門山行窄，微徑緣秋毫。',96,'全唐诗/poet.tang.10000.json','["土門山行窄，微徑緣秋毫。", "棧雲蘭干峻，梯石結搆牢。", "萬壑攲疎林，積陰帶奔濤。", "寒日外澹泊，長風中怒號。", "歇鞍在地底，始覺所歷高。", "往來雜坐臥，人馬同疲勞。", "浮生有定分，飢飽豈可逃。", "歎息謂妻子，我何隨汝曹。"]'),
('1dbc706e-cef1-4d8b-921e-81ca48757a0e','五盤','杜甫','唐','唐诗','tang','','[]','五盤雖云險，山色佳有餘。',96,'全唐诗/poet.tang.10000.json','["五盤雖云險，山色佳有餘。", "仰凌棧道細，俯映江木疎。", "地僻無網罟，水清反多魚。", "好鳥不妄飛，野人半巢居。", "喜見淳樸俗，坦然心神舒。", "東郊尚格鬬，巨猾何時除。", "故鄉有弟妹，流落隨丘墟。", "成都萬事好，豈若歸吾廬。"]'),
('a7526293-9b93-4acd-afb5-8a75a32e7c27','龍門閣','杜甫','唐','唐诗','tang','','[]','清江下龍門，絕壁無尺土。',96,'全唐诗/poet.tang.10000.json','["清江下龍門，絕壁無尺土。", "長風駕高浪，浩浩自太古。", "危途中縈盤，仰望垂綫縷。", "滑石攲誰鑿，浮梁裊相拄。", "目眩隕雜花，頭風吹過雨。", "百年不敢料，一墜那得取。", "飽聞經瞿塘，足見度大庾。", "終身歷艱險，恐懼從此數。"]'),
('41d7e65e-5a99-4597-a1cc-d716c5380584','石櫃閣','杜甫','唐','唐诗','tang','','[]','季冬日已長，山晚半天赤。',96,'全唐诗/poet.tang.10000.json','["季冬日已長，山晚半天赤。", "蜀道多早花，江間饒奇石。", "石櫃曾波上，臨虛蕩高壁。", "清暉回羣鷗，暝色帶遠客。", "羈棲負幽意，感歎向絕跡。", "信甘孱懦嬰，不獨凍餒迫。", "優游謝康樂，放浪陶彭澤。", "吾衰未自安，謝爾性所適。"]'),
('a5eac1bc-e28b-46ee-b970-69da0951eba1','桔柏渡','杜甫','唐','唐诗','tang','','[]','青冥寒江渡，駕竹爲長橋。',96,'全唐诗/poet.tang.10000.json','["青冥寒江渡，駕竹爲長橋。", "竿濕煙漠漠，江永風蕭蕭。", "連笮動嫋娜，征衣颯飄颻。", "急流鴇鷁散，絕岸黿鼉驕。", "西轅自茲異，東逝不可要。", "高通荆門路，闊會滄海潮。", "孤光隱顧眄，遊子悵寂寥。", "無以洗心胸，前登但山椒。"]'),
('ac2d1332-4163-4dfa-ba76-34563c44f1a6','劒門','杜甫','唐','唐诗','tang','','[]','惟天有設險，劒門天下壯。',132,'全唐诗/poet.tang.10000.json','["惟天有設險，劒門天下壯。", "連山抱西南，石角皆北向。", "兩崖崇墉倚，刻畫城郭狀。", "一夫怒臨關，百萬未可傍。", "珠玉走中原，岷峨氣悽愴。", "三皇五帝前，雞犬各相放。", "後王尚柔遠，職貢道已喪。", "至今英雄人，高視見霸王。", "幷吞與割據，極力不相讓。", "吾將罪真宰，意欲鏟疊嶂。", "恐此復偶然，臨風默惆悵。"]'),
('f19a0f62-4ea4-4ed7-a8e6-7b0057c2dece','鹿頭山','杜甫','唐','唐诗','tang','','[]','鹿頭何亭亭，是日慰飢渴。',144,'全唐诗/poet.tang.10000.json','["鹿頭何亭亭，是日慰飢渴。", "連山西南斷，俯見千里豁。", "遊子出京華，劒門不可越。", "及茲險阻盡，始喜原野闊。", "殊方昔三分，霸氣曾間發。", "天下今一家，雲端失雙闕。", "悠然想揚馬，繼起名硉兀。", "有文令人傷，何處埋爾骨。", "紆餘脂膏地，慘澹豪俠窟。", "仗鉞非老臣，宣風豈專達。", "冀公柱石姿，論道邦國活。", "斯人亦何幸，公鎮逾歲月。"]'),
('e4b624d5-60a5-42e4-8417-298431fb7625','成都府','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5730\u65b9"]','翳翳桑榆日，照我征衣裳。',122,'全唐诗/poet.tang.10000.json','["翳翳桑榆日，照我征衣裳。", "我行山川異，忽在天一方。", "但逢新人民，未卜見故鄉。", "大江東流去，游子去日長。", "曾城填華屋，季冬樹木蒼。", "喧然名都會，吹簫間笙簧。", "信美無與適，側身望川梁。", "鳥[雀]夜各歸，中原杳茫茫。", "初月出不高，衆星尚爭光。", "自古有羈旅，我何苦哀傷。"]'),
('7821c3f6-933b-486e-a712-48aac9999a7e','石筍行','杜甫','唐','唐诗','tang','','[]','君不見益州城西門，陌上石筍雙高蹲。',128,'全唐诗/poet.tang.10000.json','["君不見益州城西門，陌上石筍雙高蹲。", "古來相傳是海眼，苔蘚蝕盡波濤痕。", "雨多往往得瑟瑟此事恍惚難明論。", "恐是昔時卿相墓，立石爲表今仍存。", "惜哉俗態好蒙蔽，亦如小臣媚至尊。", "政化錯迕失大體，坐看傾危受厚恩。", "嗟爾石筍擅虛名，後來未識猶駿奔。", "安得壯士擲天外，使人不疑見本根。"]'),
('9c1286ea-af42-4c24-8aa6-ebe54624d63e','石犀行','杜甫','唐','唐诗','tang','','[]','君不見秦時蜀太守，刻石立作三犀牛。',145,'全唐诗/poet.tang.10000.json','["君不見秦時蜀太守，刻石立作三犀牛。", "自古雖有厭勝法，天生江水向東流。", "蜀人矜誇一千載，汎溢不近張儀樓。", "今年灌口損戶口，此事或恐爲神羞。", "終藉隄防出衆力，高擁木石當清秋。", "先王作法皆正道，鬼怪何得參人謀。", "嗟爾三犀不經濟，缺訛只與長川逝。", "但見元氣常調和，自免洪濤恣凋瘵。", "安得壯士提天綱，再平水土犀奔茫。"]'),
('91233d92-0156-4ead-9981-a5b834f9a3d2','杜鵑行','杜甫','唐','唐诗','tang','','["\u611f\u6168", "\u60b2\u75db", "\u5199\u9e1f", "\u60cb\u60dc", "\u9e1f"]','君不見昔日蜀天子，化作杜鵑似老烏。',129,'全唐诗/poet.tang.10000.json','["君不見昔日蜀天子，化作杜鵑似老烏。", "寄巢生子不自啄，羣鳥至今與哺雛。", "雖同君臣有舊禮，骨肉滿眼身羈孤。", "業工竄伏深樹裏，四月五月偏號呼。", "其聲哀痛口流血，所訴何事常區區。", "爾豈摧殘始發憤，羞帶羽翮傷形愚。", "蒼天變化誰料得，萬事反覆何所無。", "萬事反覆何所無，豈憶當殿羣臣趨。"]'),
('a83272b8-1f96-4b0a-a211-f3f7870d4f9f','贈蜀僧閭丘師兄','杜甫','唐','唐诗','tang','','[]','大師銅梁秀，籍籍名家孫。',263,'全唐诗/poet.tang.10000.json','["大師銅梁秀，籍籍名家孫。", "嗚呼先博士，炳靈精氣奔。", "惟昔武皇后，臨軒御乾坤。", "多士盡儒冠，墨客藹雲屯。", "當時上紫殿，不獨卿相尊。", "世傳閭丘筆峻極逾崑崙。", "鳳藏丹宵暮，龍去白水渾。", "青熒雪嶺東，碑碣舊製存。", "斯文散都邑，高價越璵璠。", "晚看作者意，妙絕與誰論。", "吾祖詩冠古，同年蒙主恩。", "豫章夾日月，歲久空深根。", "小子思疎闊，豈能達詞門。", "窮愁一揮淚，相遇即諸昆。", "我住錦官城，兄居祇樹圖。", "地近慰旅愁，往來當丘樊。", "天涯歇滯雨，稉稻臥不翻。", "漂然薄遊倦，始與道侶敦。", "景晏步修廊，而無車馬喧。", "夜闌接軟語，落月如金盆。", "漠漠世界黑，驅車爭奪繁。", "惟有摩尼珠，可照濁水源。"]'),
('1e1b60ee-3d4e-4551-b39e-44195638c9bb','泛溪','杜甫','唐','唐诗','tang','','[]','落景下高堂，進州泛回溪。',144,'全唐诗/poet.tang.10000.json','["落景下高堂，進州泛回溪。", "誰謂築居小，未盡喬木西。", "遠郊信荒僻，秋色有餘淒。", "練練峰上雪，纖纖雲表霓。", "童戲左右岸，罟弋畢提攜。", "翻倒荷芰亂，指揮徑路迷。", "得魚已割鱗，采藕不洗泥。", "人情逐鮮美，物賤事已睽。", "吾邨藹暝姿，異舍雞亦棲。", "蕭條欲何適，出處無可齊。", "衣上見新月，霜中登故畦。", "濁醪自初熟，東城多鼓鼙。"]'),
('2cb04222-21b9-4866-91a1-7426027b5fa6','題壁畫馬歌','杜甫','唐','唐诗','tang','','[]','韋侯別我有所適，知我憐君畫無敵。',64,'全唐诗/poet.tang.10000.json','["韋侯別我有所適，知我憐君畫無敵。", "戲拈禿筆埽驊騮，歘見騏驎出東壁。", "一匹齕草一匹嘶，坐看千里當霜蹄。", "時危安得真致此，與人同生亦同死。"]'),
('ae1c6979-d71b-48ab-b50d-9a9a210ec4c9','戲題畫山水圖歌','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','十日畫一水，五日畫一石。',116,'全唐诗/poet.tang.10000.json','["十日畫一水，五日畫一石。", "能事不受相促迫，王宰始肯留真跡。", "壯哉崑崙方壺圖，挂君高堂之素壁。", "巴陵洞庭日本東，赤岸水與銀河通，中有雲氣隨飛龍。", "舟人漁子入浦溆，山木盡亞洪濤風。", "尤工遠勢古莫比，咫尺應須論萬里。", "焉得幷州快剪刀，剪取吳松半江水。"]'),
('8488fbf4-2bde-444f-b639-a3324e23b23c','題李尊師松樹障子歌','杜甫','唐','唐诗','tang','','[]','老夫清晨梳白頭，玄都道士來相訪。',128,'全唐诗/poet.tang.10000.json','["老夫清晨梳白頭，玄都道士來相訪。", "握髮呼兒延入戶，手提新畫青松障。", "障子松林靜杳冥，憑軒忽若無丹青。", "陰崖却承霜雪幹，偃蓋反走虯龍形。", "老夫平生好奇古，對此興與精靈聚。", "已知仙客意相親，更覺良工心獨苦。", "松下丈人巾屨同，偶坐似是商山翁。", "悵望聊歌紫芝曲，時危慘澹來悲風。"]'),
('7de7b248-dde5-44c1-a68d-b46cf13c62a5','戲爲雙松圖歌','杜甫','唐','唐诗','tang','','[]','天下幾人畫古松，畢宏已老韋偃少。',136,'全唐诗/poet.tang.10000.json','["天下幾人畫古松，畢宏已老韋偃少。", "絕筆長風起纖末，滿堂動色嗟神妙。", "兩株慘裂苔蘚皮，屈鐵交錯回高枝，白摧朽骨龍虎死。", "黑入太陰雷雨垂，松根胡僧憩寂寞。", "龐眉皓首無住著，偏袒右肩露雙脚。", "葉裏松子僧前落，韋侯韋侯數相見。", "我有一匹好東絹，重之不減錦繡段。", "已命拂拭光凌亂，請公放筆爲直幹。"]'),
('09366fe4-04f9-4665-abc0-810b9a9c6720','投簡成華兩縣諸子','杜甫','唐','唐诗','tang','','[]','赤縣官曹擁材傑，軟裘快馬當冰雪。',113,'全唐诗/poet.tang.10000.json','["赤縣官曹擁材傑，軟裘快馬當冰雪。", "長安苦寒誰獨悲，杜陵野老骨欲折。", "南山豆苗早荒穢，青門瓜地新凍裂。", "鄉里兒童項領成，朝廷故舊禮數絕。", "自然棄擲與時異，況乃疎頑臨事拙。", "飢臥動即向一旬，敝裘何啻聯百結。", "君不見空牆日色晚，此老無聲淚垂血。"]'),
('b0a1ab7c-8206-4c5c-b333-d5410c429a19','徐卿二子歌','杜甫','唐','唐诗','tang','','[]','君不見徐卿二子生絕奇，感應吉夢相追隨。',102,'全唐诗/poet.tang.10000.json','["君不見徐卿二子生絕奇，感應吉夢相追隨。", "孔子釋氏親抱送，竝是天上麒麟兒。", "大兒九齡色清澈，秋水爲神玉爲骨。", "小兒五歲氣食牛，滿堂賓客皆回頭。", "吾知徐公百不憂，積善衮衮生公侯。", "丈夫生兒有如此二雛者，名位豈肯悲微休。"]'),
('7b60930e-556e-433e-a978-8a175c33ee87','病柏','杜甫','唐','唐诗','tang','','[]','有柏生崇岡，童童狀車蓋。',120,'全唐诗/poet.tang.10000.json','["有柏生崇岡，童童狀車蓋。", "偃蹙龍虎姿，主當風雲會。", "神明依正直，故老多再拜。", "豈知千年根，中路顏色壞。", "出非不得地，蟠據亦高大。", "歲寒忽無憑，日夜柯葉改。", "丹鳳領九雛，哀鳴翔其外。", "鴟鴞志意滿，養子穿穴內。", "客從何鄉來，佇立久吁怪。", "靜求元精理，浩蕩難倚賴。"]'),
('cd7b79ad-21b9-4628-ab5f-ddc8ba1343b6','病橘','杜甫','唐','唐诗','tang','','[]','羣橘少生意，雖多亦奚爲。',144,'全唐诗/poet.tang.10000.json','["羣橘少生意，雖多亦奚爲。", "惜哉結實小，酸澀如棠棃。", "剖之盡蠹蟲，采掇爽其宜。", "紛然不適口，豈只存其皮。", "蕭蕭半死葉，未忍別故枝。", "玄冬霜雪積，況乃回風吹。", "嘗聞蓬萊殿，羅列瀟湘姿。", "此物歲不稔，玉食失光輝。", "寇盜尚憑陵，當君減膳時。", "汝病是天意，吾諗罪有司。", "憶昔南海使，奔騰獻荔支。", "百馬死山谷，到今耆舊悲。"]'),
('92c10ce9-23b4-4e64-9b20-fc62a84e288c','枯椶','杜甫','唐','唐诗','tang','','[]','蜀門多椶櫚，高者十八九。',120,'全唐诗/poet.tang.10000.json','["蜀門多椶櫚，高者十八九。", "其皮割剝甚，雖衆亦易朽。", "徒布如雲葉，青黃歲寒後。", "交橫集斧斤，凋喪先蒲柳。", "傷時苦軍乏，一物官盡取。", "嗟爾江漢人，生成復何有。", "有同枯椶木，使我沈歎久。", "死者即已休，生者何自守。", "啾啾黃雀啅，側見寒蓬走。", "念爾形影乾，摧殘沒藜莠。"]'),
('b0c1e693-521d-40f1-9384-a5ecdc3a3f8e','枯柟','杜甫','唐','唐诗','tang','','[]','楩柟枯崢嶸，鄉黨皆莫記。',120,'全唐诗/poet.tang.10000.json','["楩柟枯崢嶸，鄉黨皆莫記。", "不知幾百歲，慘慘無生意。", "上枝摩皇天，下根蟠厚地。", "巨圍雷霆坼，萬孔蟲蟻萃。", "凍雨落流膠，衝風奪佳氣。", "白鵠遂不來，天雞爲愁思。", "猶含棟梁具，無復霄漢志。", "良工古昔少，識者出涕淚。", "種榆水中央，成長何容易。", "截承金露盤，褭褭不自畏。"]'),
('ccea1790-b4a4-422a-b1f0-2cd37caad120','麗春','杜甫','唐','唐诗','tang','','["\u82b1\u8349", "\u6625\u5929"]','百草競春華，麗春應最勝。',48,'全唐诗/poet.tang.10000.json','["百草競春華，麗春應最勝。", "少須好顏色，多漫枝條賸。", "紛紛桃李枝，處處總能移。", "如何貴此重，却怕有人知。"]'),
('e0cbff86-2ace-41db-b528-c33689a3afe8','丈人山','杜甫','唐','唐诗','tang','','[]','自爲青城客，不唾青城地。',56,'全唐诗/poet.tang.10000.json','["自爲青城客，不唾青城地。", "爲愛丈人山，丹梯近幽意。", "丈人祠西佳氣濃，緣雲擬住最高峰。", "埽除白髮黃精在，君看他時冰雪容。"]'),
('d76f179f-60ec-45ef-82b8-8d0e7c121bb5','百憂集行','杜甫','唐','唐诗','tang','','[]','憶年十五心尚孩，健如黃犢走復來。',96,'全唐诗/poet.tang.10000.json','["憶年十五心尚孩，健如黃犢走復來。", "庭前八月棃棗熟，一日上樹能千回。", "即今倏忽已五十，坐臥只多少行立。", "強將笑語供主人，悲見生涯百憂集。", "入門依舊四壁空，老妻覩我顏色同。", "癡兒未知父子禮，叫怒索飯啼門東。"]'),
('554a25ee-27ba-40ed-a77c-0edde1d4fea2','戲作花卿歌','杜甫','唐','唐诗','tang','','[]','成都猛將有花卿，學語小兒知姓名。',80,'全唐诗/poet.tang.10000.json','["成都猛將有花卿，學語小兒知姓名。", "用如快鶻風火生，見賊唯多身始輕。", "緜州副使著柘黃，我卿埽除即日平。", "子章髑髏血糢糊，手提擲還崔大夫。", "李侯重有此節度，人道我卿絕世無。"]'),
('968777d5-0571-4d7b-a00d-8549f311ac3a','入奏行贈西山檢察使竇侍御','杜甫','唐','唐诗','tang','','[]','竇侍御，驥之子，鳳之雛。',224,'全唐诗/poet.tang.10000.json','["竇侍御，驥之子，鳳之雛。", "年未三十忠義俱，骨鯁絕代無。", "炯如一段清冰出萬壑，置在迎風寒露之玉壺。", "蔗漿歸廚金盌凍，洗滌煩熱足以寧君軀。", "政用疎通合典則，戚聯豪貴耽文儒。", "兵革未息人未蘇，天子亦念西南隅。", "吐蕃憑陵氣頗麤，竇氏檢察應時須。", "運糧繩橋壯士喜，斬木火井窮猿呼。", "八州刺史思一戰，三城守邊却可圖。", "此行入奏計未小，密奉賢旨恩宜殊。", "繡衣春當霄漢立，綵服日向庭闈趨。", "省郎京尹必俯拾，江花未落還成都。", "江花未落還成都，肯訪浣花老翁無。", "爲君酤酒滿眼酤，與奴白飯馬青芻。"]'),
('bdeeaa87-d383-44e2-8245-d18fcffb107f','柟樹爲風雨所拔歎','杜甫','唐','唐诗','tang','','[]','倚江柟樹草堂前，故老相傳二百年。',128,'全唐诗/poet.tang.10000.json','["倚江柟樹草堂前，故老相傳二百年。", "誅茅卜居總爲此，五月髣髴聞寒蟬。", "東南飄風動地至，江翻石走流雲氣。", "幹排雷雨猶力爭，根斷泉源豈天意。", "滄波老樹性所愛，浦上童童一青蓋。", "野客頻留懼雪霜，行人不過聽竽籟。", "虎倒龍顛委榛棘，淚痕血點垂胷臆。", "我有新詩何處吟，草堂自此無顏色。"]'),
('9ea879f4-9781-469a-8b52-fc5777e633c2','茅屋爲秋風所破歌','杜甫','唐','唐诗','tang','','["\u52b1\u5fd7", "\u5199\u98ce", "\u5fe7\u56fd\u5fe7\u6c11", "\u79cb\u5929", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7"]','八月秋高風怒號，卷我屋上三重茅。',195,'全唐诗/poet.tang.10000.json','["八月秋高風怒號，卷我屋上三重茅。", "茅飛度江灑江郊，高者挂罥長林梢。", "下者飄轉沈塘坳，南邨羣童欺我老無力。", "忍能對面爲盜賊，公然抱茅入竹去。", "脣焦口燥呼不得，歸來倚仗自歎息。", "俄頃風定雲墨色，秋天漠漠向昏黑。", "布衾多年冷似鐵，驕兒惡臥踏裏裂。", "牀牀屋漏無乾處，雨脚如麻未斷絕。", "自經喪亂少睡眠，長夜霑濕何由徹。", "安得廣廈千萬間，大庇天下寒士俱歡顏。", "風雨不動安如山，嗚呼！何時眼前突兀見此屋？", "吾廬獨破受凍死亦足。"]'),
('3dc49c20-317b-4ef3-9b79-8229b5925fd9','大雨','杜甫','唐','唐诗','tang','','[]','西蜀冬不雪，春農尚嗷嗷。',144,'全唐诗/poet.tang.10000.json','["西蜀冬不雪，春農尚嗷嗷。", "上天回哀眷，朱夏雲鬱陶。", "執熱乃沸鼎，纖絺成緼袍。", "風雷颯萬里，霈澤施蓬蒿。", "敢辭茅葦漏，已喜黍豆高。", "三日無行人，二江聲怒號。", "流惡邑里清，矧茲遠江臯。", "荒庭步鸛鶴，隱几望波濤。", "沈疴聚藥餌，頓忘所進勞。", "則知潤物功，可以貸不毛。", "陰色靜隴畝，勸耕自官曹。", "四鄰耒耜出，何必吾家操。"]'),
('2284b2b3-acf3-4bb9-b736-de901b0967f9','溪漲','杜甫','唐','唐诗','tang','','[]','當時浣花橋，溪水纔尺餘。',120,'全唐诗/poet.tang.10000.json','["當時浣花橋，溪水纔尺餘。", "白石明可把，水中有行車。", "秋夏忽泛溢，豈惟入吾廬。", "蛟龍亦狼狽，況是鼈與魚。", "茲晨已半落，歸路跬步疎。", "馬嘶未敢動，前有深填淤。", "青青屋東麻，散亂牀上書。", "不意遠山雨，夜來復何如。", "我遊都市間，晚憩必邨墟。", "乃知久行客，終日思其居。"]'),
('fd7d2d75-2f42-495c-adef-f37738b0f8d1','戲贈友二首 一','杜甫','唐','唐诗','tang','','[]','元年建巳月，郎有焦校書。',48,'全唐诗/poet.tang.10000.json','["元年建巳月，郎有焦校書。", "自誇足膂力，能騎生馬駒。", "一朝被馬踏，脣裂版齒無。", "壯心不肯已，欲得東擒胡。"]'),
('31c6007d-579e-4a76-9e11-e0fbd8d54d0a','戲贈友二首 二','杜甫','唐','唐诗','tang','','[]','元年建巳月，官有王司直。',48,'全唐诗/poet.tang.10000.json','["元年建巳月，官有王司直。", "馬驚折左臂，骨折面如墨。", "駑駘漫深泥，何不避雨色。", "勸君休歎恨，未必不爲福。"]'),
('6c49fcc2-e014-4a5f-8b7b-bc592de83062','遭田父泥飲美嚴中丞','杜甫','唐','唐诗','tang','','["\u53d9\u8ff0", "\u5199\u4eba", "\u653f\u6cbb", "\u519c\u6c11", "\u5199\u4eba\u8bd7"]','步屧隨春風，邨邨自花柳。',192,'全唐诗/poet.tang.10000.json','["步屧隨春風，邨邨自花柳。", "田翁逼社日，邀我嘗春酒。", "酒酣誇新尹，畜眼未見有。", "回頭指大男，渠是弓弩手。", "名在飛騎籍，長番歲時久。", "前日放營農，辛苦救衰朽。", "差料死則已，誓不舉家走。", "今年大作社，拾遺能住否。", "叫婦開大缾，盆中爲吾取。", "感此氣揚揚，須知風化首。", "語多雖雜亂，說尹終在口。", "朝來偶然出，自卯將及酉。", "久客惜人情，如何拒鄰叟。", "高聲索果栗，欲起時被肘。", "指揮過無禮，未覺邨野醜。", "月出遮我留，仍嗔問升斗。"]'),
('04c4e10d-6c09-4fc2-a702-b55dbba16ee4','喜雨','杜甫','唐','唐诗','tang','','[]','春旱天地昏，日色赤如血。',96,'全唐诗/poet.tang.10000.json','["春旱天地昏，日色赤如血。", "農事都已休，兵戈況騷屑。", "巴人困軍須，慟哭厚土熱。", "滄江夜來雨，真宰罪一雪。", "穀根小蘇息，沴氣終不滅。", "何由見寧歲，解我憂思結。", "崢嶸羣山雲，交會未斷絕。", "安得鞭雷公，滂沱洗吳越。"]'),
('d00e139f-4480-4c4a-afbf-5cdc94ad8714','漁陽','杜甫','唐','唐诗','tang','','[]','漁陽突騎猶精銳，赫赫雍王都節制。',64,'全唐诗/poet.tang.10000.json','["漁陽突騎猶精銳，赫赫雍王都節制。", "猛將飄然恐後時，本朝不入非高計。", "祿山北築雄武城，舊防敗走歸其營。", "繫書請問燕耆舊，今日何須十萬兵。"]'),
('4b0bc117-6db3-4fe7-a7ac-6df03c52a62a','天邊行','杜甫','唐','唐诗','tang','','["\u601d\u4e61", "\u6f02\u6cca"]','天邊老人歸未得，日暮東臨大江哭。',64,'全唐诗/poet.tang.10000.json','["天邊老人歸未得，日暮東臨大江哭。", "隴右河源不種田，胡騎羌兵入巴蜀。", "洪濤滔天風拔木，前飛禿鶖後鴻鵠。", "九度附書向洛陽，十年骨肉無消息。"]'),
('744dfdaa-67fa-4f01-9649-8e94cb50e16e','大麥行','杜甫','唐','唐诗','tang','','[]','大麥乾枯小麥黃，婦女行泣夫走藏。',64,'全唐诗/poet.tang.10000.json','["大麥乾枯小麥黃，婦女行泣夫走藏。", "東至集壁西梁洋，問誰腰鐮胡與羌。", "豈無蜀兵三千人，部領辛苦江山長。", "安得如鳥有羽翅，托身白雲還故鄉。"]'),
('30658953-4fd6-4433-9d53-632ddbdd6113','苦戰行','杜甫','唐','唐诗','tang','','[]','苦戰身死馬將軍，自云伏波之子孫。',64,'全唐诗/poet.tang.10000.json','["苦戰身死馬將軍，自云伏波之子孫。", "干戈未定失壯士，使我歎恨傷精魂。", "去年江南討狂賊，臨江把臂再難得。", "別時孤雲今不飛，時獨看雲淚橫臆。"]'),
('21f7f097-466f-4f6a-b76f-96d443de7109','去秋行','杜甫','唐','唐诗','tang','','[]','去秋涪江木落時，臂槍走馬誰家兒。',64,'全唐诗/poet.tang.10000.json','["去秋涪江木落時，臂槍走馬誰家兒。", "到今不知白骨處，部曲有去皆無歸。", "遂州城中漢節在，遂州城外巴人稀。", "戰場冤魂每夜哭，空令野營猛士悲。"]'),
('3cdab883-fb3c-408e-b908-c96abc8ddcd1','述古三首 一','杜甫','唐','唐诗','tang','','[]','赤驥頓長纓，非無萬里姿。',72,'全唐诗/poet.tang.10000.json','["赤驥頓長纓，非無萬里姿。", "悲鳴淚至地，爲問馭者誰。", "鳳凰從東來，何意復高飛。", "竹花不結實，念子忍朝飢。", "古時君臣合，可以物理推。", "賢人識定分，進退固其宜。"]'),
('751c9ca7-3522-455f-9af1-42be0901e4a9','述古三首 二','杜甫','唐','唐诗','tang','','[]','市人日中集，於利競錐刀。',72,'全唐诗/poet.tang.10000.json','["市人日中集，於利競錐刀。", "置膏烈火上，哀哀自煎熬。", "農人望歲稔，相率除蓬蒿。", "所務穀爲本，邪贏無乃勞。", "舜舉十六相，身尊道何高。", "秦時任商鞅，法令如牛毛。"]'),
('dd0c9db7-7bbe-4d64-9fa6-e70fc28690d4','述古三首 三','杜甫','唐','唐诗','tang','','[]','漢光得天下，祚永固有開。',72,'全唐诗/poet.tang.10000.json','["漢光得天下，祚永固有開。", "豈惟高祖聖，功自蕭曹來。", "經綸中興業，何代無長才。", "吾慕寇鄧勳，濟時信良哉。", "耿賈亦宗臣，羽翼共裴回。", "休運終四百，圖畫在雲臺。"]'),
('0ddd5e1f-b4a4-4973-a9ac-d379dd22ff8e','觀打魚歌','杜甫','唐','唐诗','tang','','[]','緜州江水之東津，魴魚鱍鱍色勝銀。',128,'全唐诗/poet.tang.10000.json','["緜州江水之東津，魴魚鱍鱍色勝銀。", "漁人漾舟沈大網，截江一擁數百鱗。", "衆魚常才盡却棄，赤鯉騰出如有神。", "潛龍無聲老蛟怒，回風颯颯吹沙塵。", "饔子左右揮雙刀，膾飛金盤白雪高。", "徐州禿尾不足憶，漢陰槎頭遠遁逃。", "魴魚肥美知第一，既飽歡娛亦蕭瑟。", "君不朝來割素鬐，咫尺波濤永相失。"]'),
('c132205d-193f-4bf9-be2f-6c58f53a9853','又觀打魚','杜甫','唐','唐诗','tang','','[]','蒼江魚子清晨集，設網提綱萬魚急。',128,'全唐诗/poet.tang.10000.json','["蒼江魚子清晨集，設網提綱萬魚急。", "能者操舟疾若風，撐突波濤挺叉入。", "小魚脫漏不可記，半死半生猶戢戢。", "大魚傷損皆垂頭，屈強泥沙有時立。", "東津觀魚已再來，主人罷鱠還傾杯。", "日暮蛟龍改窟穴，山根鱣鮪隨雲雷。", "干戈兵革鬬未止，鳳凰麒麟安在哉？", "吾徒胡爲縱此樂，暴殄天物聖所哀。"]'),
('a2c48eae-6285-411b-af3d-bb24b2520d4e','越王樓歌','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','緜州州府何磊落，顯慶年中越王作。',64,'全唐诗/poet.tang.10000.json','["緜州州府何磊落，顯慶年中越王作。", "孤城西北起高樓，碧瓦朱甍照城郭。", "樓下長江百丈清，山頭落日半輪明。", "君王舊跡今人賞，轉見千秋萬古情。"]'),
('8ca529f2-4ffa-4317-8f3e-21ed7b78a990','海棕行','杜甫','唐','唐诗','tang','','[]','左緜公館清江濆，海棕一株高入雲。',64,'全唐诗/poet.tang.10000.json','["左緜公館清江濆，海棕一株高入雲。", "龍鱗犀甲相錯落，蒼稜白皮十抱文。", "自是衆木亂紛紛，海棕焉知身出羣。", "移栽北辰不可得，時有西域胡僧識。"]'),
('db1915e5-10c1-40bd-89b7-ea85299fd569','姜楚公畫角鷹歌','杜甫','唐','唐诗','tang','','[]','楚公畫鷹鷹戴角，殺氣森森到幽朔。',64,'全唐诗/poet.tang.10000.json','["楚公畫鷹鷹戴角，殺氣森森到幽朔。", "觀者貪愁掣臂飛，畫師不是無心學。", "此鷹寫真在左緜，却嗟真骨遂虛傳。", "梁間燕雀休驚怕，亦未摶空上九天。"]'),
('97c77587-617f-4389-b566-98d7279a8669','相逢歌贈嚴二別駕','杜甫','唐','唐诗','tang','','[]','我行入東川，十步一回首。',172,'全唐诗/poet.tang.10000.json','["我行入東川，十步一回首。", "城都亂罷氣蕭颯，浣花草堂亦何有。", "梓中豪俊大者誰，本州從事知名久。", "把臂開尊飲我酒，酒酣擊劒蛟龍吼。", "烏帽拂塵青螺粟，紫衣將炙緋衣走。", "銅盤燒蠟光吐日，夜如何其初促膝。", "黃昏始扣主人門，誰謂俄頃膠在漆。", "萬事盡付形骸外，百年未見歡娛畢。", "神傾意豁真佳士，久客多憂今愈疾。", "高視乾坤又可愁，一軀交態同悠悠。", "垂老遇君未恨晚，似君須向古人求。"]'),
('ac4ee7e4-1e08-456e-a693-c04a4254c5c9','光祿坂行','杜甫','唐','唐诗','tang','','[]','山行落日下絕壁，西望千山萬山赤。',64,'全唐诗/poet.tang.10000.json','["山行落日下絕壁，西望千山萬山赤。", "樹枝有鳥亂鳴時，暝色無人獨歸客。", "馬驚不憂深谷墜，草動只怕長弓射。", "安得更似開元中，道路即今多擁隔。"]'),
('8073152d-7f39-430b-93d2-24a9f7fc5323','冬到金華山觀因得故拾遺陳公學堂遺跡','杜甫','唐','唐诗','tang','','[]','涪右衆山內，金華紫崔嵬。',96,'全唐诗/poet.tang.10000.json','["涪右衆山內，金華紫崔嵬。", "上有蔚藍天，垂光抱瓊臺。", "繫舟接絕壁，杖策窮縈回。", "四顧俯層巔，澹然川谷開。", "雪嶺日色死，霜鴻有餘哀。", "焚香玉女跪，霧裏仙人來。", "陳公讀書堂，石柱仄青苔。", "悲風爲我起，激烈傷雄才。"]'),
('96b6faa1-eb87-421e-95e5-8733a10bd9e4','陳拾遺故宅','杜甫','唐','唐诗','tang','','[]','拾遺平昔居，大屋尚修椽。',120,'全唐诗/poet.tang.10000.json','["拾遺平昔居，大屋尚修椽。", "悠揚荒山日，慘澹故園煙。", "位下曷足傷，所貴者聖賢。", "有才繼騷雅，哲匠不比肩。", "公生揚馬後，名與日月懸。", "同遊英俊人，多秉輔佐權。", "彥昭超玉價，郭振起通泉。", "到今素壁滑，灑翰銀鉤連。", "盛事會一時，此堂豈千年。", "終古立忠義，感遇有遺編。"]'),
('bda39e90-fcb0-4a37-8565-a8b31a46681f','謁文公上方','杜甫','唐','唐诗','tang','','[]','野寺隱喬木，山僧高下居。',168,'全唐诗/poet.tang.10000.json','["野寺隱喬木，山僧高下居。", "石門日色異，絳氣橫扶疎。", "窈窕入風磴，長蘆紛卷舒。", "庭前猛虎臥，遂得文公廬。", "俯視萬家邑，煙塵對階除。", "吾師雨花外，不下十年餘。", "長者自布金，禪龕只晏如。", "大珠脫玷翳，白月當空虛。", "甫也南北人，蕪蔓少耘鋤。", "久遭詩酒污，何事忝簪裾。", "王侯與螻蟻，同盡隨丘墟。", "願聞第一義，回向心地初。", "金篦刮眼膜，價重百車渠。", "無生有汲引，茲理儻吹噓。"]'),
('f0f91037-5eae-4988-a135-88b6607ddac5','奉贈射洪李四丈','杜甫','唐','唐诗','tang','','[]','丈人屋上烏，人好烏亦好。',96,'全唐诗/poet.tang.10000.json','["丈人屋上烏，人好烏亦好。", "人生意氣豁，不在相逢早。", "南京亂初定，所向邑枯槁。", "遊子無根株，茅齋付秋草。", "東征下月峽，挂席窮海島。", "萬里須十金，妻孥未相保。", "蒼茫風塵際，蹭蹬騏驎老。", "志士懷感傷，心胸已傾倒。"]'),
('c7f12206-3250-4fe8-be2a-7d2b64b5e9b9','早發射洪縣南途中作','杜甫','唐','唐诗','tang','','[]','將老憂貧窶，筋力豈能及。',120,'全唐诗/poet.tang.10000.json','["將老憂貧窶，筋力豈能及。", "征途乃侵星，得使諸病入。", "鄙人寡道氣，在困無獨立。", "俶裝逐徒旅，達曙凌險澀。", "寒日出霧遲，清江轉山急。", "僕夫行不進，駑馬若維縶。", "汀洲稍疏散，風景開怏悒。", "空慰所尚懷，終非曩遊集。", "衰顏偶一破，勝事難屢挹。", "茫然阮籍途，更灑楊朱泣。"]'),
('7650f439-72a5-4680-901f-72e235c36aab','通泉驛南去通泉縣十五里山水作','杜甫','唐','唐诗','tang','','[]','溪行衣自濕，亭午氣始散。',96,'全唐诗/poet.tang.10000.json','["溪行衣自濕，亭午氣始散。", "冬溫蚊蚋在，人遠鳧鴨亂。", "登頓生曾陰，攲傾出高岸。", "驛樓衰柳側，縣郭輕煙畔。", "一川何綺麗，盡目窮壯觀。", "山色遠寂寞，江光夕滋漫。", "傷時媿孔父，去國同王粲。", "我生苦飄零，所歷有嗟歎。"]'),
('9eed81ff-a045-4b87-b6c1-d1701c0361cc','過郭代公故宅','杜甫','唐','唐诗','tang','','[]','豪俊初未遇，其跡或脫略。',132,'全唐诗/poet.tang.10000.json','["豪俊初未遇，其跡或脫略。", "代公尉通泉，放意何自若。", "及夫登衮冕，直氣森噴薄。", "磊落見異人，豈伊常情度。", "定策神龍後，宮中翕清廓。", "俄頃辨尊親，指揮存顧託。", "羣公有慙色，王室無削弱。", "迥出名臣上，丹青照臺閣。", "我行得遺跡，池館皆疏鑿。", "壯公臨事斷，顧步涕橫落。", "高詠寶劒篇，神交付冥漠。"]'),
('ba0975c2-29c3-47d1-a8d4-5653488ca009','觀薛稷少保書畫壁','杜甫','唐','唐诗','tang','','[]','少保有古風，得之陝郊篇。',120,'全唐诗/poet.tang.10000.json','["少保有古風，得之陝郊篇。", "惜哉功名忤，但見書畫傳。", "我游梓州東，遺跡涪江邊。", "畫藏青蓮界，書入金牓懸。", "仰看垂露姿，不崩亦不騫。", "鬱鬱三大字，蛟龍岌相纏。", "又揮西方變，發地扶屋椽。", "慘澹壁飛動，到今色未填。", "此行疊壯觀，郭薛俱才賢。", "不知百載後，誰復來通泉。"]'),
('d8fe6c90-8cf4-4aa7-ba1d-6b4c2a1f481c','通泉縣署屋壁後薛少保畫鶴','杜甫','唐','唐诗','tang','','[]','薛公十一鶴，皆寫青田真。',120,'全唐诗/poet.tang.10000.json','["薛公十一鶴，皆寫青田真。", "畫色久欲盡，蒼然猶出塵。", "低昂各有意，磊落如長人。", "佳此志氣遠，豈惟粉墨新。", "萬里不以力，羣遊森會神。", "威遲白鳳態，非是倉庚鄰。", "高堂未傾覆，常得慰嘉賓。", "曝露牆壁外，終嗟風雨頻。", "赤霄有真骨，恥飲洿池津。", "冥冥任所往，脫略誰能馴。"]'),
('80e19627-4051-46fc-806c-da3defb76cd1','陪王侍御同登東山最高頂宴姚通泉晚攜酒泛江','杜甫','唐','唐诗','tang','','[]','姚公美政誰與儔，不減昔時陳太丘。',160,'全唐诗/poet.tang.10000.json','["姚公美政誰與儔，不減昔時陳太丘。", "邑中上客有柱史，多暇日陪驄馬遊。", "東山高頂羅珍羞，下顧城郭銷我憂。", "清江白日落欲盡，復攜美人登綵舟。", "笛聲憤怨哀中流，妙舞逶迤夜未休。", "燈前往往大魚出，聽曲低昂如有求。", "三更風起寒浪湧，取樂喧呼覺船重。", "滿空星河光破碎，四座賓客色不動。", "請公臨深莫相違，回船罷酒上馬歸。", "人生歡會豈有極，無使霜過霑人衣。"]'),
('9ac1658d-0e0a-4a87-b599-6dffb7abcfbe','春日戲題惱郝使君兄','杜甫','唐','唐诗','tang','','[]','使君意氣凌青霄，憶昨歡娛常見招。',96,'全唐诗/poet.tang.10000.json','["使君意氣凌青霄，憶昨歡娛常見招。", "細馬時鳴金騕褭，佳人屢出董驕饒。", "東流江水西飛燕，可惜春光不相見。", "願攜王趙兩紅顏，再騁肌膚如素練。", "通泉百里近梓州，請公一來開我愁。", "舞處重看花滿面，尊前還有錦纏頭。"]'),
('7d187686-9944-4690-bc0c-5716539e1a1d','短歌行贈王郎司直','杜甫','唐','唐诗','tang','','["\u60b2\u4f24", "\u6292\u60c5", "\u9001\u522b", "\u6000\u624d\u4e0d\u9047"]','王郎酒酣拔劒斫地歌莫哀，我能拔爾抑塞磊落之奇才。',88,'全唐诗/poet.tang.10000.json','["王郎酒酣拔劒斫地歌莫哀，我能拔爾抑塞磊落之奇才。", "豫章翻風白日動，鯨魚跋浪滄溟開。", "且脫佩劒休裴回，西得諸侯櫂錦水。", "欲向何門趿珠履，仲宣樓頭春色深。", "青眼高歌望吾子，眼中之人吾老矣。"]'),
('f1ada7f0-b14f-4660-8811-aaf1b4a6b67b','短歌行送祁錄事歸合州因寄蘇使君','杜甫','唐','唐诗','tang','','[]','前者途中一相見，人事經年記君面。',64,'全唐诗/poet.tang.10000.json','["前者途中一相見，人事經年記君面。", "後生相動何寂寥，君有長才不貧賤。", "君今起柁春江流，余亦沙邊具小舟。", "幸爲達書賢府主，江花未盡會江樓。"]'),
('5b62d8e7-b536-450c-978d-edbe5e7a4db3','陪章留後惠義寺餞嘉州崔都督赴州','杜甫','唐','唐诗','tang','','[]','中軍待上客，令肅事有恒。',120,'全唐诗/poet.tang.10000.json','["中軍待上客，令肅事有恒。", "前驅入寶地，祖帳飄金繩。", "南陌既留歡，茲山亦深登。", "清聞樹杪磬，遠謁雲端僧。", "回策匪新岸，所攀仍舊藤。", "耳激洞門飆，目存寒谷冰。", "出塵閟軌躅，畢景遺炎蒸。", "永願坐長夏，將衰棲大乘。", "羈旅惜宴會，艱難懷友朋。", "勞生共幾何，離恨兼相仍。"]'),
('ea100f9a-3504-4a7d-844c-c23ba23f364b','將適吳楚留別章使君留後兼幕府諸公得柳字','杜甫','唐','唐诗','tang','','[]','我來入蜀門，歲月亦已久。',216,'全唐诗/poet.tang.10000.json','["我來入蜀門，歲月亦已久。", "豈惟長兒童，自覺成老醜。", "常恐性坦率，失身爲杯酒。", "近辭痛飲徒，折節萬夫後。", "昔如縱壑魚，今如喪家狗。", "既無遊方戀，行止復何有。", "相逢半新故，取別隨薄厚。", "不意青草湖，扁舟落吾手。", "眷眷章梓州，開筵俯高柳。", "樓前出騎馬，帳下羅賓友。", "健兒簸紅旗，此樂或難朽。", "日車隱崑崙，鳥雀噪戶牖。", "波濤未足畏，三峽徒雷吼。", "所憂盜賊多，重見衣冠走。", "中原消息斷，黃屋今安否。", "終作適荆蠻，安排用莊叟。", "隨雲拜東皇，挂席上南斗。", "有使即寄書，無使長回首。"]'),
('8f7c1809-1a9e-4192-a02f-34ae18101cc4','山寺','杜甫','唐','唐诗','tang','','[]','野寺根石壁，諸龕徧崔嵬。',168,'全唐诗/poet.tang.10000.json','["野寺根石壁，諸龕徧崔嵬。", "前佛不復辨，百身一莓苔。", "雖有古殿存，世尊亦塵埃。", "如聞龍象泣，足令信者哀。", "使君騎紫馬，捧擁從西來。", "樹羽靜千里，臨江久裴回。", "山僧衣藍縷，告訴棟梁摧。", "公爲顧賓徒，咄嗟檀施開。", "吾知多羅樹，却倚蓮華臺。", "諸天必歡喜，鬼物無嫌猜。", "以茲撫士卒，孰曰非周才。", "窮子失淨處，高人憂禍胎。", "歲晏風破肉，荒林寒可迴。", "思量入道苦，自哂同嬰孩。"]'),
('704494b5-291d-4f04-a07c-ac2a0c754edc','椶拂子','杜甫','唐','唐诗','tang','','[]','椶拂且薄陋，豈知身效能。',96,'全唐诗/poet.tang.10000.json','["椶拂且薄陋，豈知身效能。", "不堪代白羽，有足除蒼蠅。", "熒熒金錯刀，擢擢朱絲蠅。", "非獨顏色好，亦用顧盼稱。", "吾老抱疾病，家貧臥炎蒸。", "咂膚倦撲滅，賴爾甘服膺。", "物微世競棄，義在誰肯徵。", "三歲清秋至，未敢闕緘藤。"]'),
('87600c40-eb40-430b-ac24-351551bbff5b','桃竹杖引贈章留後','杜甫','唐','唐诗','tang','','[]','江心蟠石生桃竹，蒼波噴浸尺度足。',169,'全唐诗/poet.tang.10000.json','["江心蟠石生桃竹，蒼波噴浸尺度足。", "斬根削皮如紫玉，江妃水仙惜不得。", "梓潼使君開一束，滿堂賓客皆歎息。", "憐我老病贈兩莖，出入爪甲鏗有聲。", "老夫復欲東南征，乘濤鼓枻白帝城。", "路幽必爲鬼神奪，拔劒或與蛟龍爭。", "重爲告曰，杖兮！杖兮！爾之生也甚正直，慎勿見水踴躍學變化爲龍。", "使我不得爾之扶持，滅跡於君山湖上之青峰。", "噫！風塵澒洞兮豺虎齩人，忽失雙杖兮吾將曷從。"]'),
('0003f6ab-a650-4728-acf0-7d248dd3ca3c','寄題江外草堂','杜甫','唐','唐诗','tang','','[]','我生性放誕，雅欲逃自然。',192,'全唐诗/poet.tang.10000.json','["我生性放誕，雅欲逃自然。", "嗜酒愛風竹，卜居必林泉。", "遭亂到蜀江，臥疴遣所便。", "誅茅初一畝，廣地方連延。", "經營上元始，斷手寶應年。", "敢謀土木麗，自覺面勢堅。", "臺亭隨高下，敞豁當清川。", "雖有會心侶，數能同釣船。", "干戈未偃息，安得酣歌眠。", "蛟龍無定窟，黃鵠摩蒼天。", "古來達士志，寧受外物牽。", "顧惟魯鈍姿，豈識悔吝先。", "偶攜老妻去，慘澹凌風煙。", "事跡無固必，幽貞媿雙全。", "尚念四小松，蔓草易拘纏。", "霜骨不甚長，永爲鄰里憐。"]'),
('827e44b1-7064-4ff7-9a9c-192eece94e2d','韋諷錄事宅觀曹將軍畫馬圖','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u9a6c", "\u4e03\u8a00\u53e4\u8bd7", "\u9898\u753b", "\u9a6c"]','國初已來畫鞍馬，神妙獨數江都王。',275,'全唐诗/poet.tang.10000.json','["國初已來畫鞍馬，神妙獨數江都王。", "將軍得名三十載，人間又見真乘黃。", "曾貌先帝照夜白，龍池十日飛霹靂。", "內府殷紅馬腦盌，倢伃傳詔才人索。", "盌賜將軍拜舞歸，輕紈細綺相追飛。", "貴戚權門得筆跡，始覺屏障生光輝。", "昔日太宗拳毛騧，近時郭家師子花。", "今之新圖有二馬，復令識者久歎嗟。", "此皆騎戰一敵萬，縞素漠漠開風沙。", "其餘七匹亦殊絕，迥若寒空動煙雪。", "霜蹄蹴踏長楸間，馬官廝養森成列。", "可憐九馬爭神駿，顧視清高氣深穩。", "借問苦心愛者誰，後有韋諷前支遁。", "憶昔巡幸新豐宮，翠華拂天來向東。", "騰驤磊落三萬匹，皆與此圖筋骨同。", "自從獻寶朝河宗，無復射蛟江水中。", "君不見金粟堆前松柏裏，龍媒去盡鳥呼風。"]'),
('7109feaf-91db-4b77-a50e-3e71c6a4c66c','送韋諷上閬州錄事參軍','杜甫','唐','唐诗','tang','','[]','國步猶艱難，兵革未衰息。',120,'全唐诗/poet.tang.10000.json','["國步猶艱難，兵革未衰息。", "萬方哀嗷嗷，十載供軍食。", "庶官務割剝，不暇憂反側。", "誅求何多門，賢者貴爲德。", "韋生富春秋，洞徹有清識。", "操持紀綱地，喜見朱絲直。", "當令豪奪吏，自此無顏色。", "必若救瘡痍，先應去蟊賊。", "揮淚臨大江，高天意悽惻。", "行行樹佳政，慰我深相憶。"]'),
('13b12259-3750-4c6d-87ee-35283ad63dab','丹青引贈曹將軍霸','杜甫','唐','唐诗','tang','','["\u5199\u4eba", "\u540c\u60c5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u53e4\u8bd7", "\u6005\u60d8"]','將軍魏武之子孫，於今爲庶爲清門。',319,'全唐诗/poet.tang.10000.json','["將軍魏武之子孫，於今爲庶爲清門。", "英雄割據雖已矣，文彩風流猶尚存。", "學書初學衛夫人，但恨無過王右軍。", "丹青不知老將至，富貴於我如浮雲。", "開元之中常引見，承恩數上南熏殿。", "凌煙功臣少顏色，將軍下筆開生面。", "良相頭上進賢冠，猛將腰間大羽箭。", "褒公鄂公毛髮動英姿颯爽來酣戰。", "先帝天馬玉花驄，畫工如山貌不同。", "是日牽來赤墀下，迥立閶闔生長風。", "詔謂將軍拂絹素，意匠慘澹經營中。", "斯須九重真龍出，一洗萬古凡馬空。", "玉花却在御榻上，榻上庭前屹相向。", "至尊含笑催賜金，圉人太僕皆惆悵。", "弟子韓幹早入室，亦能畫馬窮殊相。", "幹惟畫肉不畫骨，忍使驊騮氣凋喪。", "將軍畫善蓋有神，必逢佳士亦寫真。", "即今飄泊干戈際，屢貌尋常行路人。", "途窮反遭俗眼白，世上未有如公貧。", "但看古來盛名下，終日坎壈纏其身。"]'),
('e3553a22-2323-4926-a694-752c3481e2a5','閬州東樓筵奉送十一舅往青城縣得昏字','杜甫','唐','唐诗','tang','','[]','曾城有高樓，制古丹雘存。',120,'全唐诗/poet.tang.10000.json','["曾城有高樓，制古丹雘存。", "迢迢百餘尺，豁達開四門。", "雖有車馬客，而無人世喧。", "遊目俯大江，列筵慰別魂。", "是時秋冬交，節往顏色昏。", "天寒鳥獸休，霜露在草根。", "今我送舅氏，萬感集清尊。", "豈伊山川間，回首盜賊繁。", "高賢意不暇，王命久崩奔。", "臨風欲慟哭，聲出已復吞。"]'),
('bcf6124b-d0ca-48b1-9b9a-c62824a7d759','嚴氏溪放歌行','杜甫','唐','唐诗','tang','','[]','天下甲馬未盡銷，豈免溝壑常漂漂。',129,'全唐诗/poet.tang.10000.json','["天下甲馬未盡銷，豈免溝壑常漂漂。", "劒南歲月不可度，邊頭公卿仍獨驕。", "費心姑息是一役，肥肉大酒徒相要。", "嗚呼古人已糞土，獨覺志士甘漁樵。", "況我飄轉無定所，終日慽慽忍羈旅。", "秋宿霜溪素月高，喜得與子長夜語。", "東遊西還力實倦，從此將身更何許。", "知子松根長茯苓，遲暮有有意來同煮。"]'),
('c3b2e460-ab50-438c-b53e-57ef2aae3d8d','南池','杜甫','唐','唐诗','tang','','[]','崢嶸巴閬間，所向盡山谷。',192,'全唐诗/poet.tang.10000.json','["崢嶸巴閬間，所向盡山谷。", "安知有蒼池，萬頃浸坤軸。", "呀然閬城南，枕帶巴江腹。", "芰荷入異縣，稉稻共比屋。", "皇天不無意，美利戒止足。", "高田失西成，此物頗豐熟。", "清源多衆魚，遠岸富喬木。", "獨歎楓香林，春時好顏色。", "南有漢王祠，終朝走巫祝。", "歌舞散靈衣，荒哉舊風俗。", "高堂亦明王，魂魄猶正直。", "不應空陂上，縹緲親酒食。", "淫祀自古昔，非唯一川瀆。", "干戈浩茫茫，地僻傷極目。", "平生江海興，遭亂身局促。", "駐馬問漁舟，躊躇慰羈束。"]'),
('0932954f-3895-490b-864a-1469ef8e16df','發閬中','杜甫','唐','唐诗','tang','','[]','前有毒蛇後猛虎，溪行盡日無邨塢。',64,'全唐诗/poet.tang.10000.json','["前有毒蛇後猛虎，溪行盡日無邨塢。", "江風蕭蕭雲拂地，山木慘慘天欲雨。", "女病妻憂歸意速，秋花錦石誰復數。", "別家三月一得書，避地何時免愁苦。"]'),
('6d303931-f900-4f29-a8b9-caea611a521f','寄韓諫議','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u6e38\u4ed9", "\u4e03\u8a00\u53e4\u8bd7"]','今我不樂思岳陽，身欲奮飛病在牀。',176,'全唐诗/poet.tang.10000.json','["今我不樂思岳陽，身欲奮飛病在牀。", "美人娟娟隔秋水，濯足洞庭望八荒。", "鴻飛冥冥日月白，青楓葉赤天雨霜。", "玉京羣帝集北斗，或騎騏驎翳鳳皇。", "芙蓉旌旗煙霧樂，影動倒景搖瀟湘。", "星宮之君醉瓊漿，羽人稀少不在旁。", "似聞昨者赤松子，恐是漢代韓張良。", "昔隨劉氏定長安，帷幄未改神慘傷。", "國家成敗吾豈敢，色難腥腐餐風香。", "周南留滯古所惜，南極老人應壽昌。", "美人胡爲隔秋水，焉得置之貢玉堂。"]'),
('5cee205e-5c59-46e5-b060-9b0916c64a3f','憶昔二首 一','杜甫','唐','唐诗','tang','','[]','憶昔先皇巡朔方，千乘萬騎入咸陽。',135,'全唐诗/poet.tang.10000.json','["憶昔先皇巡朔方，千乘萬騎入咸陽。", "陰山驕子汗血馬，長驅東胡胡走藏。", "鄴城反覆不足怪，關中小兒壞紀綱，張后不樂上爲忙。", "至今今上猶撥亂，勞身焦思補四方。", "我昔近侍叨奉引，出兵整肅不可當。", "爲留猛士守未央，致使岐雍防西羌。", "犬戎直來坐御牀，百官跣足隨天王願見北地傅介子，老儒不用尚書郎。"]'),
('80d0b9f1-7ae5-4b37-a34b-9e0d0e62e3fe','憶昔二首 二','杜甫','唐','唐诗','tang','','[]','憶昔開元全盛日，小邑猶藏萬家室。',176,'全唐诗/poet.tang.10000.json','["憶昔開元全盛日，小邑猶藏萬家室。", "稻米流脂粟米白，公私蒼廩俱豐實。", "九州道路無豺虎，遠行不勞吉日出。", "齊紈魯縞車班班，男耕女桑不相失。", "宮中聖人奏雲門，天下朋友皆膠漆。", "百餘年間未災變，叔孫禮樂蕭何律。", "豈聞一絹直萬錢，有田種穀今流血。", "洛陽宮殿燒焚盡，宗廟新除狐兔穴。", "傷心不忍問耆舊，復恐初從亂離說。", "小臣魯鈍無所能，朝廷記識蒙祿秩。", "周宣中興望我皇，灑血江漢身衰疾。"]'),
('6e95c3fb-b575-4343-a576-39168cb01163','冬狩行','杜甫','唐','唐诗','tang','','[]','君不見東川節度兵馬雄，校獵亦似觀成功。',221,'全唐诗/poet.tang.10000.json','["君不見東川節度兵馬雄，校獵亦似觀成功。", "夜發猛士三千人，清晨合圍步驟同。", "禽獸已斃十七八，殺聲落日回蒼穹。", "幕前生致九青兕，駱駝𡾋峞垂玄熊。", "東西南北百里間，髣髴蹴踏寒山空。", "有鳥名鸜鵒，力不能高飛逐走蓬。", "肉味不足登鼎俎，何爲見羈虞羅中。", "春蒐冬狩侯得同，使君五馬一馬驄。", "況今攝行大將權，號令頗有前賢風。", "飄然時危一老翁，十年厭見旌旗紅。", "喜君士卒甚整肅，爲我回轡擒西戎。", "草中狐兔盡何益，天子不在咸陽宮。", "朝廷雖無幽王禍，得不哀痛塵再蒙。", "嗚呼，得不哀痛塵再蒙。"]'),
('b207dcff-1823-4283-88d7-57d8c780c8ab','自平','杜甫','唐','唐诗','tang','','[]','自平宮中呂太一，收珠南海千餘日。',64,'全唐诗/poet.tang.10000.json','["自平宮中呂太一，收珠南海千餘日。", "近供生犀翡翠稀，復恐征戎干戈密。", "蠻溪豪族小動搖，世封刺史非時朝。", "蓬萊殿前諸主將，才如伏波不得驕。"]'),
('0da4b0f7-bb52-4477-a9ef-88d6922198c7','釋悶','杜甫','唐','唐诗','tang','','[]','四海十年不解兵，犬戎也復臨咸京。',96,'全唐诗/poet.tang.10000.json','["四海十年不解兵，犬戎也復臨咸京。", "失道非關出襄野，揚鞭忽是過胡城。", "豺狼塞路人斷絕，烽火照夜屍縱橫。", "天子亦應厭奔走，羣公固合思升平。", "但恐誅求不改轍，聞道嬖孽能全生。", "江邊老翁錯料事，眼暗不見風塵清。"]'),
('28d70a6c-0d49-4e83-99d7-4bd2ece32100','贈別賀蘭銛','杜甫','唐','唐诗','tang','','[]','黃雀飽野粟，羣飛動荆榛。',96,'全唐诗/poet.tang.10000.json','["黃雀飽野粟，羣飛動荆榛。", "今君抱何恨，寂寞向時人。", "老驥倦驤首，蒼鷹愁易馴。", "高賢世未識，固合嬰飢貧。", "國步初返正，乾坤尚風塵。", "悲歌鬢髮白，遠赴湘吳春。", "我戀岷下芋，君思千里蓴。", "生離與死別，自古鼻酸辛。"]'),
('b0dd9a8d-397b-44c3-878d-de914dc5b68c','別唐十五誡因寄禮部賈侍郎','杜甫','唐','唐诗','tang','','[]','九載一相逢，百年能幾何。',192,'全唐诗/poet.tang.10000.json','["九載一相逢，百年能幾何。", "復爲萬里別，送子山之阿。", "白鶴久同林，潛魚本同河。", "未知棲集期，衰老強高歌。", "歌罷兩悽惻，六龍忽蹉跎。", "相視髮皓白，況難駐羲和。", "胡星墜燕地，漢將仍橫戈。", "蕭條四海內，人少豺虎多。", "少人慎莫投，多虎信所過。", "飢有易子食，獸猶畏虞羅。", "子負經濟才，天門鬱嵯峨。", "飄颻適東周，來往若崩波。", "南宮吾故人，白馬金盤陀。", "雄筆映千古，見賢心靡他。", "念子善師事，歲寒守舊柯。", "爲吾謝賈公，病肺臥江沱。"]'),
('14504b92-0aab-4daf-8a8d-623c5a59b487','閬山歌','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u60c5", "\u5199\u666f"]','閬州城中靈山白，閬州城北玉臺碧。',64,'全唐诗/poet.tang.10000.json','["閬州城中靈山白，閬州城北玉臺碧。", "松浮欲盡不盡雲，江動將崩未崩石。", "那知根無鬼神會，已覺氣與嵩華敵。", "中原格鬬且未歸，應結茅齋看青壁。"]'),
('b0d04448-935e-4e7a-ad7e-9a69c31b0ad7','閬水歌','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5730\u65b9", "\u5199\u666f", "\u8d5e\u7f8e"]','嘉陵江色何所似，石黛碧玉相因依。',64,'全唐诗/poet.tang.10000.json','["嘉陵江色何所似，石黛碧玉相因依。", "正憐日破浪花出，更復春從沙際歸。", "巴童蕩槳攲側過，水雞銜魚來去飛。", "閬中勝事可腸斷，閬州城南天下稀。"]'),
('32bfdf4c-b903-4517-8f91-d25331134e12','草堂','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u56fd\u5bb6", "\u611f\u6168"]','昔我去草堂，蠻夷塞成都。',288,'全唐诗/poet.tang.10000.json','["昔我去草堂，蠻夷塞成都。", "今我歸草堂，成都適無虞。", "請陳初亂時，反復乃須臾。", "大將赴朝廷，羣小起異圖。", "中宵斬白馬，盟歃氣已麤。", "西取邛南兵，北斷劒閣隅。", "布衣數十人，亦擁專城居。", "其勢不兩大，始聞蕃漢殊。", "西卒却倒戈，賊臣互相誅。", "焉知肘腋禍，自及梟獍徒。", "義士皆痛憤，紀綱亂相踰。", "一國實三公，萬人欲爲魚。", "唱和作威福，孰肯辨無辜。", "眼前列杻械，背後吹笙竽。", "談笑行殺戮，濺血滿長衢。", "到今用鉞地，風雨聞號呼。", "鬼妾與鬼馬，色悲充爾娛。", "國家法令在，此又足驚吁。", "賤子且奔走，三年望東吳。", "弧矢暗江海，難爲遊五湖。", "不忍竟舍此，復來薙榛蕪。", "入門四松在，步屧萬竹疎。", "舊犬喜我歸，低徊入衣裾。", "鄰舍喜我歸，酤酒攜胡蘆。"]'),
('1762014e-d551-478c-8547-d0e2ac0caa6e','四松','杜甫','唐','唐诗','tang','','[]','四松初移時，大抵三尺強。',168,'全唐诗/poet.tang.10000.json','["四松初移時，大抵三尺強。", "別來忽三載，離立如人長。", "會看根不拔，莫計枝凋傷。", "幽色幸秀發，疎柯亦昂藏。", "所插小藩籬，本亦有隄防。", "終然掁撥損，得恡千葉黃。", "敢爲故林主，黎庶猶未康。", "避賊今始歸，春草滿空堂。", "覽物歎衰謝，及茲慰淒涼。", "清風爲我起，灑面若微霜。", "足以送老姿，聊侍偃蓋張。", "我生無根帶，配爾亦茫茫。", "有情且賦詩，事迹可兩望。", "勿矜千載後，慘澹蟠穹蒼。"]'),
('be10e787-c739-44b9-a572-397e10138d0c','水檻','杜甫','唐','唐诗','tang','','[]','蒼江多風飆，雲雨晝夜飛。',96,'全唐诗/poet.tang.10000.json','["蒼江多風飆，雲雨晝夜飛。", "茅軒駕巨浪，焉得不低垂。", "遊子久在外，門戶無人持。", "高岸尚如谷，何傷浮柱攲。", "扶顛有勸誡，恐貽識者嗤。", "既殊大廈傾，可以一木支。", "臨川視萬里，何必闌檻爲。", "人生感故物，慷慨有餘悲。"]'),
('fbecdcf9-c56b-42c0-bac4-7b05f9864f2a','破船','杜甫','唐','唐诗','tang','','[]','平生江海心，宿昔具扁舟。',96,'全唐诗/poet.tang.10000.json','["平生江海心，宿昔具扁舟。", "豈惟青溪上，日傍柴門遊。", "蒼皇避亂兵，緬邈懷舊丘。", "鄰人亦已非，野竹獨修修。", "船舷不重扣，埋沒已經秋。", "仰看西飛翼，下媿東逝流。", "故者或可掘，新者亦易求。", "所悲數奔竄，白屋難久留。"]'),
('7bb069d9-b053-49cc-8007-8e5bb98c2573','營屋','杜甫','唐','唐诗','tang','','[]','我有陰江竹，能令朱夏寒。',120,'全唐诗/poet.tang.10000.json','["我有陰江竹，能令朱夏寒。", "陰通積水內，高入浮雲端。", "甚疑鬼物憑，不顧翦伐殘。", "東偏若面勢，戶牖永可安。", "愛惜已六載，茲晨去千竿。", "蕭蕭見白日，洶洶開奔湍。", "度堂匪華麗，養拙異考槃。", "草茅雖薙葺，衰疾方少寬。", "洗然順所適，此足代加餐。", "寂無斤斧響，庶遂憩息歡。"]'),
('f69bfe05-49ed-4c28-9f39-6aaae0e2aa74','除草','杜甫','唐','唐诗','tang','','[]','草有害於人，曾何生阻修。',120,'全唐诗/poet.tang.10000.json','["草有害於人，曾何生阻修。", "其毒甚蜂蠆，其多彌道周。", "清晨步前林，江色未散憂。", "芒刺在我眼，焉能待高秋。", "霜露一霑凝，蕙葉亦難留。", "荷鋤先童穉，日入仍討求。", "轉致水中央，豈無雙釣舟。", "頑根易滋蔓，敢使依舊丘。", "自茲藩籬曠，更覺松竹幽。", "芟夷不可闕，疾惡信如讎。"]'),
('d06f921a-9125-4a21-aad1-f98a429e4727','揚旗','杜甫','唐','唐诗','tang','','[]','江雨颯長夏，府中有餘清。',144,'全唐诗/poet.tang.10000.json','["江雨颯長夏，府中有餘清。", "我公會賓客，肅肅有異聲。", "初筵閱軍裝，羅列照廣庭。", "庭空六馬入，駊騀揚旗旌。", "回回偃飛蓋，熠熠迸流星。", "來纏風飆急，去擘山岳傾。", "材歸俯身盡，妙取略地平。", "虹霓就掌握，舒卷隨人輕。", "三州陷犬戎，但見西嶺青。", "公來練猛士，欲奪天邊城。", "此堂不易升，庸蜀日已寧。", "吾徒且加餐，休適蠻與荆。"]'),
('3e025699-a493-49b3-8b9d-be47fd65a2ae','太子張舍人遺織成褥段','杜甫','唐','唐诗','tang','','[]','客從西北來，遺我翠織成。',216,'全唐诗/poet.tang.10000.json','["客從西北來，遺我翠織成。", "開緘風濤湧，中有掉尾鯨。", "逶迤羅水族，瑣細不足名。", "客云充君褥，承君終宴榮。", "空堂魑魅走，高枕形神清。", "領客珍重意，顧我非公卿。", "留之懼不祥，施之混柴荆。", "服飾定尊卑，大哉萬古程。", "今我一賤老，裋褐更無營。", "煌煌珠宮物，寢處禍所嬰。", "歎息當路子，干戈尚縱橫。", "掌握有權柄，衣馬自肥輕。", "李鼎死岐陽，實以驕貴盈。", "來瑱賜自盡，氣豪直阻兵。", "皆聞黃金多，坐見悔吝生。", "奈何田舍翁，受此厚貺情。", "錦鯨卷還客，始覺心和平。", "振我麤席塵，媿客茹藜羹。"]'),
('840f36d1-df6e-4cfe-87ac-692fc102ff44','莫相疑行','杜甫','唐','唐诗','tang','','["\u538c\u5026", "\u6292\u60c5", "\u6124\u61d1"]','男兒生無所成頭皓白，牙齒欲落真可惜。',98,'全唐诗/poet.tang.10000.json','["男兒生無所成頭皓白，牙齒欲落真可惜。", "憶獻三賦蓬萊宮，自怪一日聲輝赫。", "集賢學士如堵牆，觀我落筆中書堂。", "往時文彩動人主，此日飢寒趨路旁。", "晚將末契託年少，當面輸心背面笑。", "寄謝悠悠世上兒，不爭好惡莫相疑。"]'),
('bb0dd009-15ad-4537-ab58-29593bc44970','別蔡十四著作','杜甫','唐','唐诗','tang','','[]','賈生慟哭後，寥落無其人。',240,'全唐诗/poet.tang.10000.json','["賈生慟哭後，寥落無其人。", "安知蔡夫子，高義邁等倫。", "獻書謁皇帝，志以清風塵。", "流涕灑丹極，萬乘爲酸辛。", "天地則創痍，朝廷當正臣。", "異才復間出，周道日惟新。", "使蜀見知己，別顏始一伸。", "主人薨城府，扶櫬歸咸秦。", "巴道此相逢，會我病江濱。", "憶念鳳翔都，聚散俄十春。", "我衰不足道，但願子意陳。", "稍令社稷安，自契魚水親。", "我雖消渴甚，敢望帝力勤。", "尚思未朽骨，復覩耕桑民。", "積水架三峽，浮龍倚長津。", "揚舲洪濤間，仗子濟物身。", "鞍馬下秦塞，王城通北辰。", "玄甲聚不散，兵久食恐貧。", "窮谷無粟帛，使者來相因。", "若憑南轅吏，書札到天垠。"]'),
('c507b869-c422-46dc-be74-0d9ca10a7217','杜鵑','杜甫','唐','唐诗','tang','','[]','西川有杜鵑，東川無杜鵑。',168,'全唐诗/poet.tang.10000.json','["西川有杜鵑，東川無杜鵑。", "涪萬無杜鵑，雲安有杜鵑。", "我昔遊錦城，結廬錦水邊。", "有竹一頃餘，喬木上參天。", "杜鵑暮春至，哀哀叫其間。", "我見常再拜，重是古帝魂。", "生子百鳥巢，百鳥不敢嗔。", "仍爲餧其子，禮若奉至尊。", "鴻雁及羔羊，有禮太古前。", "行飛與跪乳，識序如知恩。", "聖賢古法則，付與後世傳。", "君看禽鳥情，猶解事杜鵑。", "今忽暮春間，值我病經年。", "身病不能拜，淚下如迸泉。"]'),
('bf0e59c3-a674-4d8b-aaf9-03e64bee7588','客居','杜甫','唐','唐诗','tang','','[]','客居所居堂，前江後山根。',240,'全唐诗/poet.tang.10000.json','["客居所居堂，前江後山根。", "下塹萬尋岸，蒼濤鬱飛飜。", "蔥青衆木梢，邪豎雜石痕。", "子規晝夜啼，壯士斂精魂。", "峽開四千里，水合數百源。", "人虎相半居，相傷終兩存。", "蜀麻久不來，吳鹽擁荆門。", "西南失大將，商旅自星奔。", "今又降元戎，已聞動行軒。", "舟子候利涉，亦憑節制尊。", "我在路中央，生理不得論。", "臥愁病脚廢，徐步視小園。", "短畦帶碧草，悵望思王孫。", "鳳隨其皇去，籬雀暮喧繁。", "覽物想故國，十年別荒邨。", "日暮歸幾翼，北林空自昏。", "安得覆八溟，爲君洗乾坤。", "稷契易爲力，犬戎何足吞。", "儒生老無成，臣子憂四番。", "篋中有舊筆，情至時復援。"]'),
('08a1e3ad-8246-4b60-a17c-fc27951dd35a','客堂','杜甫','唐','唐诗','tang','','[]','憶昨離少城，而今異楚蜀。',252,'全唐诗/poet.tang.10000.json','["憶昨離少城，而今異楚蜀。", "舍舟復深山，窅窕一林麓。", "棲泊雲安縣，消中內相毒。", "舊疾甘載來，衰年得無足。", "死爲殊方鬼，頭白免短促。", "老馬終望雲，南雁意在北。", "別家長兒女，欲起慙筋力。", "客堂序節改，具物對羈束。", "石暄蕨芽紫，渚秀蘆筍綠。", "巴鶯紛未稀，徼麥早向熟。", "悠悠日動江，漠漠春辭木。", "臺郎選才俊，自顧亦已極。", "前輩聲名人，埋沒何所得。", "居然綰章紱，受性本幽獨。", "平生憩息地，必種數竿竹。", "事業只濁醪，營葺但草屋。", "上公有記者，累奏資薄祿。", "主憂豈濟時，身遠彌曠職。", "循文廟算正，獻可天衢直。", "尚想趨朝廷，毫髮裨社稷。", "形骸今若是，進退委行色。"]'),
('1de59ac9-a4b2-4e1a-a4c7-9ae2505b8cf4','石研詩','杜甫','唐','唐诗','tang','','[]','平公今詩伯，秀發吾所羨。',120,'全唐诗/poet.tang.10000.json','["平公今詩伯，秀發吾所羨。", "奉使三峽中，長嘯得石研。", "巨璞禹鑿餘，異壯君獨見。", "其滑乃波濤，其光或雷電。", "聊坳各盡墨，多水遞隱現。", "揮灑容數人，十手可對面。", "比公頭上冠，貞質未爲賤。", "當公賦佳句，況得終清宴。", "公含起草姿，不遠明光殿。", "致於丹青地，知汝隨顧眄。"]'),
('a4c287ae-d6f5-414a-a05b-f69d7baff4a0','水閣朝霽奉簡嚴雲安','杜甫','唐','唐诗','tang','','[]','東城抱春岑，江閣鄰石面。',72,'全唐诗/poet.tang.10000.json','["東城抱春岑，江閣鄰石面。", "崔嵬晨雲白，朝旭射芳甸。", "雨檻臥花叢，風牀展書卷。", "鉤簾宿鷺起，丸藥流鶯囀。", "呼婢取酒壺，績兒誦文選。", "晚交嚴明府，矧此數相見。"]'),
('75727b65-afda-4363-abdf-a7c94fc9e380','贈鄭十八賁','杜甫','唐','唐诗','tang','','[]','溫溫士君子，令我懷抱盡。',168,'全唐诗/poet.tang.10000.json','["溫溫士君子，令我懷抱盡。", "靈芝冠衆芳，安得闕親近。", "遭亂意不歸，竄身跡非隱。", "細人尚姑息，吾子色愈謹。", "高懷見物理，識者安肯哂。", "卑飛欲何待，捷徑應未忍。", "示我百篇文，詩家一標準。", "羇離交屈宋，牢落值顏閔。", "水路迷畏途，藥餌駐修軫。", "古人日以遠，青史字不泯。", "步趾詠唐虞，追隨飯葵堇。", "數杯資好事，異味煩縣尹。", "心雖在朝謁，力與願矛盾。", "抱病排金門，衰容豈爲敏。"]'),
('57744626-3438-4f25-a2e6-3b9978376056','三韻三篇 一','杜甫','唐','唐诗','tang','','[]','高馬勿唾面，長魚無損鱗。',36,'全唐诗/poet.tang.10000.json','["高馬勿唾面，長魚無損鱗。", "辱馬馬毛焦，困魚魚有神。", "君看磊落士，不肯易其身。"]'),
('c2859274-fd6f-4c48-a4a5-53e1754b6aa2','三韻三篇 二','杜甫','唐','唐诗','tang','','[]','蕩蕩萬斛船，影若揚白虹。',36,'全唐诗/poet.tang.10000.json','["蕩蕩萬斛船，影若揚白虹。", "起檣必椎牛，挂席集衆功。", "自非風動天，莫置大水中。"]'),
('73368692-b14f-4e13-a388-ff5acccf9a12','三韻三篇 三','杜甫','唐','唐诗','tang','','[]','烈士惡多門，小人自同調。',36,'全唐诗/poet.tang.10000.json','["烈士惡多門，小人自同調。", "名利苟可取，殺身傍權要。", "何當官曹清，爾輩堪一笑。"]'),
('c9f15368-7b2d-445a-95c8-835ddcbd03bf','青絲','杜甫','唐','唐诗','tang','','[]','青絲白馬誰家子，麤豪且逐風塵起。',64,'全唐诗/poet.tang.10000.json','["青絲白馬誰家子，麤豪且逐風塵起。", "不聞漢主放妃嬪，近靜潼關埽蠭蟻。", "殿前兵馬破汝時，十月即爲齏粉期。", "未如面縛歸金闕，萬一皇恩下玉墀。"]'),
('d9e237c6-27c4-46c7-a998-d5c3bd12426b','近聞','杜甫','唐','唐诗','tang','','[]','近聞犬戎遠遁逃，牧馬不敢侵臨洮。',64,'全唐诗/poet.tang.10000.json','["近聞犬戎遠遁逃，牧馬不敢侵臨洮。", "渭水逶迤白日淨，隴山蕭瑟秋雲高。", "崆峒五原亦無事，北庭數有關中使。", "似聞贊普更求親，舅甥和好應難棄。"]'),
('5a655242-25cf-4681-9d4d-9fb7e217b214','蠶穀行','杜甫','唐','唐诗','tang','','["\u6218\u4e89", "\u7406\u60f3", "\u613f\u671b"]','天下郡國向萬城，無有一城無甲兵。',56,'全唐诗/poet.tang.10000.json','["天下郡國向萬城，無有一城無甲兵。", "焉得鑄甲作農器，一寸荒田牛得耕。", "牛盡耕，蠶亦成。", "不勞烈士淚滂沱，男穀女絲行復歌。"]'),
('479f5094-eb0e-4254-a729-84bef1043f97','折檻行','杜甫','唐','唐诗','tang','','[]','嗚呼房魏不復見，秦王學士時難羨。',64,'全唐诗/poet.tang.10000.json','["嗚呼房魏不復見，秦王學士時難羨。", "青衿胄子困泥塗，白馬將軍若雷電。", "千載少似朱雲人，至今折檻空嶙峋。", "婁公不語宋公語，尚憶先皇容直臣。"]'),
('8c527981-a52c-4127-b686-3f4596e38818','引水','杜甫','唐','唐诗','tang','','[]','月峽瞿塘雲作頂，亂石崢嶸俗無井。',64,'全唐诗/poet.tang.10000.json','["月峽瞿塘雲作頂，亂石崢嶸俗無井。", "雲安酤水奴僕悲，魚復移居心力省。", "白帝城西萬竹蟠，接筒引水喉不乾。", "人生留滯生理難，斗水何直百憂寬。"]'),
('383d41a8-5155-4fff-b91f-87d5585ff03e','古柏行','杜甫','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u7269", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u53e4\u8bd7", "\u548f\u7269\u8bd7", "\u6000\u624d\u4e0d\u9047"]','孔明廟前有老柏，柯如青銅根如石。',192,'全唐诗/poet.tang.10000.json','["孔明廟前有老柏，柯如青銅根如石。", "霜皮溜雨四十圍，黛色參天二千尺。", "君臣已與時際會，樹木猶爲人愛惜。", "雲來氣接巫峽長，月出寒通雪山白。", "憶昨路繞錦亭東，先主武侯同閟宮。", "崔嵬枝幹郊原古，窈窕丹青戶牖空。", "落落盤踞雖得地，冥冥孤高多烈風。", "扶持自是神明力，正直原因造化功。", "大廈如傾要梁棟，萬牛回首丘山重。", "不露文章世已驚，未辭剪伐誰能送。", "苦心豈免容螻蟻，香葉終經宿鸞鳳。", "志士幽人莫怨嗟，古來材大難爲用。"]'),
('b94d5bf5-9fcd-4ab4-984d-0c537f9e37d6','縛雞行','杜甫','唐','唐诗','tang','','[]','小奴縛雞向市賣，雞被縛急相喧爭。',64,'全唐诗/poet.tang.10000.json','["小奴縛雞向市賣，雞被縛急相喧爭。", "家中厭雞食蟲蟻，不知雞賣還遭烹。", "蟲雞與人何厚薄，吾叱奴人解其縛。", "雞蟲得失無了時，注目寒江倚山閣。"]'),
('7f4b9cac-65c4-42e8-949c-4dabc621de01','負薪行','杜甫','唐','唐诗','tang','','[]','夔州處女髮半華，四十五十無夫家。',128,'全唐诗/poet.tang.10000.json','["夔州處女髮半華，四十五十無夫家。", "更遭喪亂嫁不售，一生抱恨堪咨嗟。", "土風坐男使女立，應當門戶女出入。", "十猶八九負薪歸，賣薪得錢應供給。", "至老雙鬟只垂頸，野花山葉銀釵竝。", "筋力登危集市門，死生射利兼鹽井。", "面妝首飾雜啼痕，地褊衣寒困石根。", "若道巫山女麤醜，何得此有昭君邨。"]'),
('bbbbba72-14ae-42d1-9f5a-09a077f2d0c6','最能行','杜甫','唐','唐诗','tang','','[]','峽中丈夫絕輕死，少在公門多在水。',128,'全唐诗/poet.tang.10000.json','["峽中丈夫絕輕死，少在公門多在水。", "富豪有錢駕大舸，貧窮取給行艓子。", "小兒學問止論語，大兒結束隨商旅。", "攲帆側柁入波濤，撇漩捎濆無險阻。", "朝發白帝暮江陵，頃來目擊幸有徵。", "瞿堂漫天虎鬚怒，歸州長年行最能。", "此鄉之人氣量窄，誤競南風疎北客。", "若道土無英俊才，何得山有屈原宅。"]'),
('e675d0f2-e768-41b3-8c9e-da83383287bd','寄裴施州','杜甫','唐','唐诗','tang','','[]','廊廟之具裴施州，宿昔一逢無此流。',128,'全唐诗/poet.tang.10000.json','["廊廟之具裴施州，宿昔一逢無此流。", "金鐘大鏞在東序，冰壺玉衡懸清秋。", "自從相遇感多病，三歲爲客寬邊愁。", "堯有四岳明至理，漢二千石真分憂。", "幾度寄書白鹽北，苦寒贈我青羔裘。", "霜雪回光避錦袖，龍蛇動篋蟠銀鉤。", "紫衣使者辭復命，再拜故人謝佳政。", "將老已失子孫憂，後來況接才華盛。"]'),
('5c676620-1448-4ee7-815d-35512077d8ad','鄭典設自施州歸','杜甫','唐','唐诗','tang','','[]','吾憐滎陽秀，冒暑初有適。',288,'全唐诗/poet.tang.10000.json','["吾憐滎陽秀，冒暑初有適。", "名賢慎所出，不肯妄行役。", "旅茲殊俗遠，竟以屢空迫。", "南謁裴施州，氣合無險僻。", "攀援懸根木，登頓入天石。", "青山自一川，城郭洗憂慼。", "聽子話此邦，令我心悅懌。", "其俗則純樸，不知有主客。", "溫溫諸侯門，禮亦如古昔。", "敕廚倍常羞，杯盤頗狼藉。", "時雖屬喪亂，事貴賞匹敵。", "中宵愜良會，裴鄭非遠戚。", "羣書一萬卷，博涉供務隙。", "他日辱銀鉤，森疎見矛戟。", "倒屣喜旋歸，畫地求所歷。", "乃聞風土質，又重田疇闢。", "刺史似寇恂，列郡宜競惜。", "北風吹瘴癘，羸老思散策。", "渚拂蒹葭塞，嶠穿蘿蔦冪。", "此身仗兒僕，高興潛有激。", "孟冬方首路，強飯取崖壁。", "歎爾疲駑駘，汗溝血不赤。", "終然備外飾，駕馭何所益。", "我有平肩輿，前途猶準的。"]'),
('ae472a2c-7977-4ed6-a893-7ef7c3136666','柴門','杜甫','唐','唐诗','tang','','[]','孤舟登瀼西，回首望兩崖。',252,'全唐诗/poet.tang.10000.json','["孤舟登瀼西，回首望兩崖。", "東城乾旱天，其氣如焚柴。", "長影沒窈窕，餘光散唅呀。", "大江蟠嵌根，歸海成一家。", "下衝割坤軸，竦壁攢鏌铘。", "蕭颯灑秋色，氛昏霾日車。", "峽門自此始，最窄容浮查。", "禹功翊造化，疎鑿就攲斜。", "巨渠決太古，衆水爲長蛇。", "風煙渺吳蜀，舟楫通鹽麻。", "我今遠遊子，飄轉混泥沙。", "萬物附本性，約身不願奢。", "茅棟蓋一牀，清池有餘花。", "濁醪與脫粟，在眼無咨嗟。", "山荒人民少，地僻日夕佳。", "貧病固其常，富貴任生涯。", "老於干戈際，宅幸蓬蓽遮。", "石亂上雲氣，杉清延月華。", "賞妍又分外，理愜夫何誇。", "足了垂白年，敢居高士差。", "書此豁平昔，回首猶暮霞。"]'),
('70cfbaa0-6ea5-4a6a-a6ac-0e8bbfd8413c','貽華陽柳少府','杜甫','唐','唐诗','tang','','[]','繫馬喬木間，問人野寺門。',240,'全唐诗/poet.tang.10000.json','["繫馬喬木間，問人野寺門。", "柳侯披衣笑，見我顏色溫。", "竝坐石下堂，俛視大江奔。", "火雲洗月露，絕壁上朝暾。", "自非曉相訪，觸熱生病根。", "南方六七月，出入異中原。", "老少多暍死，汗踰水漿飜。", "俊才得之子，筋力不辭煩。", "指揮當世事，語及戎馬存。", "涕淚濺我裳，悲氣排帝閽。", "鬱陶抱長策，義仗知者論。", "吾衰臥江漢，但媿識璵璠。", "文章一小技，於道未爲尊。", "起予幸斑白，因是託子孫。", "俱客古信州，結廬依毀垣。", "相去四五里，徑微山葉繁。", "時危挹佳士，況免軍旅喧。", "醉從趙女舞，歌鼓秦人盆。", "子壯顧我傷，我驩兼淚痕。", "餘生如過鳥，故里今空邨。"]'),
('5177af03-db57-45b9-836b-9f888b793d8b','雷','杜甫','唐','唐诗','tang','','[]','大旱山岳燋，密雲復無雨。',192,'全唐诗/poet.tang.10000.json','["大旱山岳燋，密雲復無雨。", "南方瘴癘地，罹此農事苦。", "封內必舞雩，峽中喧擊鼓。", "真龍竟寂莫，土梗空俯僂。", "吁嗟公私病，稅斂缺不補。", "故老仰面啼，瘡痍向誰數。", "暴尫或前聞，鞭巫非稽古。", "請先偃甲兵，處分聽人主。", "萬邦但各業，一物休盡取。", "水旱其數然，堯湯免親覩。", "上天鑠金石，羣盜亂豺虎。", "二者存一端，愆陽不猶愈。", "昨宵殷其雷，風過齊萬弩。", "復吹霾翳散，虛覺神靈聚。", "氣暍腸胃融，汗滋衣裳污。", "吾衰尤拙計，失望築場圃。"]'),
('ac0f88ac-e2a2-4251-b333-08f5d799cfeb','火','杜甫','唐','唐诗','tang','','[]','楚山經月火，大旱則斯舉。',168,'全唐诗/poet.tang.10000.json','["楚山經月火，大旱則斯舉。", "舊俗燒蛟龍，驚惶致雷雨。", "爆嵌魑魅泣，崩凍嵐陰昈。", "羅落沸百泓，根源皆萬古。", "青林一灰燼，雲氣無處所。", "入夜殊赫然，新秋照牛女。", "風吹巨燄作，河櫂騰煙柱。", "勢欲焚崑崙，光彌焮洲渚。", "腥至焦長蛇，聲吼纏猛虎。", "神物已高飛，不見石與土。", "爾寧要謗讟，憑此近熒侮。", "薄關長吏憂，甚昧至精主。", "遠遷誰撲滅，將恐及環堵。", "流汗臥江亭，更深氣如縷。"]'),
('f2413b7a-cfda-4d88-8c24-6684aa4bcf8a','七月三日亭午已後較熱退晚加小涼穩睡有詩因論壯年樂事戲呈元二十一曹長','杜甫','唐','唐诗','tang','','[]','今茲商用事，餘熱亦已末。',264,'全唐诗/poet.tang.10000.json','["今茲商用事，餘熱亦已末。", "衰年旅炎方，生意從此活。", "亭午減汗流，北鄰耐人聒。", "晚風爽烏匼，筋力蘇摧折。", "閉目踰十旬，大江不止渴。", "退藏恨雨師，健步聞旱魃。", "園蔬抱金玉，無以供采掇。", "密雲雖聚散，徂暑終衰歇。", "前聖眘焚巫，武王親救暍。", "陰陽相主客，時序遞回斡。", "灑落唯清秋，昏霾一空闊。", "蕭蕭紫塞雁，南向欲行列。", "歘思紅顏日，霜露凍階闥。", "胡馬挾雕弓，鳴弦不虛發。", "長鈚逐狡兔，突羽當滿月。", "惆悵白頭吟，蕭條游俠窟。", "臨軒望山閣，縹緲安可越。", "高人鍊丹砂，未念將朽骨。", "少壯跡頗疎，歡樂曾倏忽。", "杖藜風塵際，老醜難翦拂。", "吾子得神仙，本是池中物。", "賤夫美一睡，煩促嬰詞筆。"]'),
('449c81fd-d52a-40f2-ae8c-9d3fc5ddd290','牽牛織女','杜甫','唐','唐诗','tang','','[]','牽牛出河西，織女處其東。',216,'全唐诗/poet.tang.10000.json','["牽牛出河西，織女處其東。", "萬古永相望，七夕誰見同。", "神光意難候，此事終蒙朧。", "颯然精靈合，何必秋遂通。", "亭亭新妝立，龍駕具曾空。", "世人亦爲爾，祈請走兒童。", "稱家隨豐儉，白屋達公宮。", "膳夫翊堂殿，鳴玉淒房櫳。", "曝衣徧天下，曳月揚微風。", "蛛絲小人態，曲綴瓜果中。", "初筵裛重露，日出甘所終。", "嗟汝未嫁女，秉心鬱忡忡。", "防身動如律，竭力機杼中。", "雖無姑舅事，敢昧織作功。", "明明君臣契，咫尺或未容。", "義無棄禮法，恩始夫婦恭。", "小大有佳期，戒之在至公。", "方圓苟齟齬，丈夫多英雄。"]'),
('4229906f-4467-4500-9cf5-149be471eb11','毒熱寄簡崔評事十六弟','杜甫','唐','唐诗','tang','','[]','大暑運金氣，荆揚不知秋。',168,'全唐诗/poet.tang.10000.json','["大暑運金氣，荆揚不知秋。", "林下有塌翼，水中無行舟。", "千室但埽地，閉關人事休。", "老夫轉不樂，旅次兼百憂。", "蝮蛇暮偃蹇，空牀難暗投。", "炎宵惡明燭，況乃懷舊丘。", "開襟仰內弟，執熱露白頭。", "束帶負芒刺，接居成阻修。", "何當清霜飛，會子臨江樓。", "載聞大易義，諷興詩家流。", "蘊藉異時輩，檢身非苟求。", "皇皇使臣體，信是德業優。", "楚材擇杞梓，漢苑歸驊騮。", "短章達我心，理爲識者籌。"]'),
('be5dacfb-7444-484e-96d8-66ff88e6f10a','殿中楊監見示張旭草書圖','杜甫','唐','唐诗','tang','','[]','斯人已云亡，草聖祕難得。',132,'全唐诗/poet.tang.10000.json','["斯人已云亡，草聖祕難得。", "及茲煩見示，滿目一淒惻。", "悲風生微綃，萬里起古色。", "鏘鏘鳴玉動，落落羣松直。", "連山蟠其間，溟漲與筆力。", "有練實先書，臨池真盡墨。", "俊拔爲之主，暮年思轉極。", "未知張王後，誰竝百代則。", "嗚呼東吳精，逸氣感清識。", "楊公拂篋笥，舒卷忘寢食。", "念昔揮毫端，不獨觀酒德。"]'),
('5a3a92a7-6f2f-4e3f-9790-313e9daf1e9d','楊監又出畫鷹十二扇','杜甫','唐','唐诗','tang','','[]','近時馮紹正，能畫鷙鳥樣。',120,'全唐诗/poet.tang.10000.json','["近時馮紹正，能畫鷙鳥樣。", "明公出此圖，無乃傳其狀。", "殊姿各獨立，清絕心有向。", "疾禁千里馬，氣敵萬人將。", "憶昔驪山宮，冬移含元仗。", "天寒大羽獵，此物神俱王。", "當時無凡材，百中皆用壯。", "粉墨形似間，識者一惆悵。", "干戈少暇日，真骨老崖嶂。", "爲君除狡兔，會是飜韝上。"]'),
('9bf99b21-ab26-43d3-aabb-9a06cf6d8953','送殿中楊監赴蜀見相公','杜甫','唐','唐诗','tang','','[]','去水絕還波，洩雲無定姿。',144,'全唐诗/poet.tang.10000.json','["去水絕還波，洩雲無定姿。", "人生在世間，聚散亦暫時。", "離別重相逢，偶然豈定期。", "送子清秋暮，風物長年悲。", "豪俊貴勳業，邦家頻出師。", "相公鎮梁益，軍事無孑遺。", "解榻再見今，用才復擇誰。", "況子已高位，爲郡得固辭。", "難拒供給費，慎哀漁奪私。", "干戈未甚息，紀綱正所持。", "泛舟巨石橫，登陸草露滋。", "山門日易久，當念居者思。"]'),
('0ebfe689-4572-4375-82b0-820b7f14d4fb','贈李十五丈別','杜甫','唐','唐诗','tang','','[]','峽人鳥獸居，其室附層顛。',252,'全唐诗/poet.tang.10000.json','["峽人鳥獸居，其室附層顛。", "下臨不測江，中有萬里船。", "多病紛倚薄，少留改歲年。", "絕域誰慰懷，開顏喜名賢。", "孤陋忝末親，等級敢比肩。", "人生意頗合，相與襟袂連。", "一日兩遣僕，三日一共筵。", "揚論展寸心，壯筆過飛泉。", "玄成美價存，子山舊業傳。", "不聞八尺軀，常受衆目憐。", "且爲辛苦行，蓋被生事牽。", "北回白帝櫂，南入黔陽天。", "汧公制方隅，迥出諸侯先。", "封內如太古，時危獨蕭然。", "清高金莖露，正直朱絲弦。", "昔在堯四岳，今之黃潁川。", "于邁恨不同，所思無由宣。", "山深水增波，解榻秋露懸。", "客遊雖云久，主要月再圓。", "晨集風渚亭，醉操雲嶠篇。", "丈夫貴知己，歡罷念歸旋。"]'),
('57990c9f-c5a0-479a-81bc-284da6828046','西閣曝日','杜甫','唐','唐诗','tang','','[]','凜冽倦玄冬，負暄嗜飛閣。',120,'全唐诗/poet.tang.10000.json','["凜冽倦玄冬，負暄嗜飛閣。", "羲和流德澤，顓頊媿倚薄。", "毛髮具自和，肌膚潛沃若。", "太陽信深仁，衰氣歘有託。", "攲傾煩注眼，容易收病脚。", "流離木杪猨，翩躚山顛鶴。", "用知苦聚散，哀樂日已作。", "即事會賦詩，人生忽如昨。", "古來遭喪亂，賢聖盡蕭索。", "胡爲將暮年，憂世心力弱。"]'),
('3a334a5a-5aad-4261-b2e3-54524c4ad9f2','課伐木','杜甫','唐','唐诗','tang','','[]','長夏無所爲，客居課奴僕。',216,'全唐诗/poet.tang.10000.json','["長夏無所爲，客居課奴僕。", "清晨飯其腹，持斧入白谷。", "青冥曾巔後，十里斬陰木。", "人肩四根已，亭午下山麓。", "尚聞丁丁聲，功課日各足。", "蒼皮成委積，素節相照燭。", "藉汝跨小籬，當仗苦虛竹。", "空荒咆熊羆，乳獸待人肉。", "不示知禁情，豈惟干戈哭。", "城中賢府主，處貴如白屋。", "蕭蕭理體淨，蠭蠆不敢毒。", "虎穴連里閭，隄防舊風俗。", "泊舟滄江岸，久客慎所觸。", "舍西崖嶠壯，雷雨蔚含蓄。", "牆宇資屢修，衰年怯幽獨。", "爾曹輕執熱，爲我忍煩促。", "秋光近青岑，季月當泛菊。", "報之以微寒，共給酒一斛。"]'),
('15c01eb1-1eb8-4d68-b25e-ae244c049afc','園人送瓜','杜甫','唐','唐诗','tang','','[]','江間雖炎瘴，瓜熟亦不早。',120,'全唐诗/poet.tang.10000.json','["江間雖炎瘴，瓜熟亦不早。", "柏公鎮夔國，滯務茲一埽。", "食新先戰士，共少及溪老。", "傾筐蒲鴿青，滿眼顏色好。", "竹竿接嵌竇，引注來鳥道。", "沈浮亂水玉，愛惜如芝草。", "落刃嚼冰霜，開懷慰枯槁。", "許以秋蔕除，仍看小童抱。", "東陵跡蕪絕，楚漢休征討。", "園人非故侯，種此何草草。"]'),
('3eef1d5f-2011-4417-be2c-57667aa3bea6','信行遠修水筒','杜甫','唐','唐诗','tang','','[]','汝性不茹葷，清靜僕夫內。',120,'全唐诗/poet.tang.10000.json','["汝性不茹葷，清靜僕夫內。", "秉心識本源，於事少滯礙。", "雲端水筒坼，林表山石碎。", "觸熱藉子修，通流與廚會。", "往來四十里，荒險崖谷大。", "日熏驚未餐，貌赤媿相對。", "浮瓜供老病，裂餅嘗所愛。", "於斯荅恭謹，足以殊殿最。", "詎要方士符，何假將軍蓋。", "行諸直如筆，用意崎嶇外。"]'),
('ca42b16b-5f16-40f4-8291-34970d922fac','槐葉冷淘','杜甫','唐','唐诗','tang','','[]','青青高槐葉，采掇付中廚。',120,'全唐诗/poet.tang.10000.json','["青青高槐葉，采掇付中廚。", "新麪來近市，汁滓宛相俱。", "入鼎資過熟，加餐愁欲無。", "碧鮮俱照箸，香飯兼苞蘆。", "經齒冷於雪，勸人投此珠。", "願隨金騕褭，走置錦屠蘇。", "路遠思恐泥，興深終不渝。", "獻芹則小小，薦藻明區區。", "萬里露寒殿，開冰清玉壺。", "君王納涼晚，此味亦時須。"]'),
('ed927451-c3fd-4566-97a2-c86f8c2fa756','行官張望補稻畦水歸','杜甫','唐','唐诗','tang','','[]','東屯大江北，百頃平若案。',144,'全唐诗/poet.tang.10000.json','["東屯大江北，百頃平若案。", "六月青稻多，千畦碧泉亂。", "插秧適云已，引溜加溉灌。", "更僕往方塘，決渠當斷岸。", "公私各地著，浸潤無天旱。", "主守問家臣，分明見溪伴。", "芊芊炯翠羽，剡剡生銀漢。", "歐鳥鏡裏來，關山雲邊看。", "秋菰成黑米，精鑿傳白粲。", "玉粒足晨炊，紅鮮任霞散。", "終然添旅食，作苦期壯觀。", "遺穗及衆多，我倉戒滋蔓。"]'),
('a8eb9d52-faa2-42b8-9ed3-3bec5f1413d6','催宗文樹雞柵','杜甫','唐','唐诗','tang','','[]','吾衰怯行邁，旅次展崩迫。',216,'全唐诗/poet.tang.10000.json','["吾衰怯行邁，旅次展崩迫。", "愈風傳烏雞，秋卵方漫喫。", "自春生成者，隨母向百翮。", "驅趁制不禁，喧呼山腰宅。", "課奴殺青竹，終日憎赤幘。", "蹋藉盤案飜，塞蹊使之隔。", "牆東有隙地，可以樹高柵。", "避熱時來歸，問兒所爲跡。", "織籠曹其內，令入不得擲。", "稀間可突過，觜爪還污席。", "我寬螻蟻遭，彼免狐貉厄。", "應宜各長幼，自此均勍敵。", "籠柵念有修，近身見損益。", "明明領處分，一一當剖析。", "不昧風雨晨，亂離減憂慽。", "其流則凡鳥，其氣心匪石。", "倚賴窮歲晏，撥煩去冰釋。", "未似尸鄉翁，拘留蓋阡陌。"]'),
('246ff90e-bd5c-4e81-8637-f1605fa647d9','園官送茶','杜甫','唐','唐诗','tang','','[]','清晨蒙菜把，常荷地主恩。',156,'全唐诗/poet.tang.10000.json','["清晨蒙菜把，常荷地主恩。", "守者愆實數，略有其名存。", "苦苣刺如針，馬齒葉亦繁。", "青青嘉蔬色，埋沒在中園。", "園吏未足怪，世事固堪論。", "嗚呼戰伐久，荆棘暗長原。", "乃知苦苣輩，傾奪蕙草根。", "小人塞道路，爲態何喧喧。", "又如馬齒盛，氣擁葵荏昏。", "點染不易虞，絲麻雜羅紈。", "一經器物內，永挂麤刺痕。", "志士采紫芝，放歌避戎軒。", "畦丁負籠至，感動百慮端。"]'),
('26580e07-44fb-4e5c-b6a2-9da99a0ef0a1','上後園山脚','杜甫','唐','唐诗','tang','','[]','朱夏熱所嬰，清旭步北林。',144,'全唐诗/poet.tang.10000.json','["朱夏熱所嬰，清旭步北林。", "小園背高岡，挽葛上崎崟。", "曠望延駐目，飄颻散疎襟。", "潛鱗恨水壯，去翼依雲深。", "勿謂地無疆，劣於山有陰。", "石榞徧天下，水陸兼浮沈。", "自我登隴首，十年經碧岑。", "劒門來巫峽，薄倚浩至今。", "故園暗戎馬，骨肉失追尋。", "時危無消息，老去多歸心。", "志士惜白日，久客藉黃金。", "敢爲蘇門嘯，庶作梁父吟。"]'),
('15ebb60f-02a0-4915-900a-eade0191f674','驅豎子摘蒼耳','杜甫','唐','唐诗','tang','','[]','江上秋已分，林中瘴猶劇。',144,'全唐诗/poet.tang.10000.json','["江上秋已分，林中瘴猶劇。", "畦丁告勞苦，無以供日夕。", "蓬莠獨不焦，野蔬暗泉石。", "卷耳況療風，童兒且時摘。", "侵星驅之去，爛熳任遠適。", "放筐亭午際，洗剝相蒙冪。", "登牀半生熟，下箸還小益。", "加點瓜薤間，依稀橘奴跡。", "亂世誅求急，黎民糠籺窄。", "飽食復何心，荒哉膏粱客。", "富家廚肉臭，戰地骸骨白。", "寄語惡少年，黃金且休擲。"]'),
('e3bf5676-319c-460e-b5b2-e53daad7f6d0','秋行官張請督促東渚耗稻向畢清晨遣女奴阿稽豎子阿段往問','杜甫','唐','唐诗','tang','','[]','東渚雨今足，佇聞稉稻香。',204,'全唐诗/poet.tang.10000.json','["東渚雨今足，佇聞稉稻香。", "上天無偏頗，蒲稗各自長。", "人情見非類，田家戒其荒。", "功夫競搰搰，除草置岸旁。", "穀者命之本，客居安可忘。", "青春具所務，勤墾免亂常。", "吳牛力容易，竝驅動莫當。", "豐苗亦已穊，雲水照方塘。", "有生固蔓延，靜一資隄防。", "督領不無人，提攜頗在綱。", "荆揚風土暖，肅肅候微霜。", "尚恐主守疎，用心未甚臧。", "清朝遣婢僕，寄語踰崇岡。", "西成聚必散，不獨陵我倉。", "豈要仁里譽，感此亂世忙。", "北風吹蒹葭，蟋蟀近中堂。", "荏苒百工休，鬱紆遲暮傷。"]'),
('50b39f91-4d82-4166-b291-d73be5d35733','阻雨不得歸瀼西甘林','杜甫','唐','唐诗','tang','','[]','三伏適已過，驕陽化爲霖。',192,'全唐诗/poet.tang.10000.json','["三伏適已過，驕陽化爲霖。", "欲歸瀼西宅，阻此江浦深。", "壞舟百版坼，峻岸復萬尋。", "篙工初一棄，恐泥勞寸心。", "佇立東城隅，悵望高飛禽。", "草堂亂懸圃，不隔崑崙岑。", "昏渾衣裳外，曠絕同層陰。", "園甘長成時，三寸如黃金。", "諸侯舊上計，厥貢傾千林。", "邦人不足重，所迫豪吏侵。", "客居暫封殖，日夜偶瑤琴。", "虛徐五株態，側塞煩胸襟。", "焉得輟兩足，杖藜出嶇嶔。", "條流數翠實，偃息歸碧潯。", "拂拭烏皮几，喜聞樵牧音。", "令兒快搔背，脫我頭上簪。"]'),
('d1c092e6-cdc6-43e3-a7cd-54397c4f31dd','雨','杜甫','唐','唐诗','tang','','[]','峽雲行清曉，煙霧相裴回。',96,'全唐诗/poet.tang.10000.json','["峽雲行清曉，煙霧相裴回。", "風吹蒼江樹，雨灑石壁來。", "淒淒生餘寒，殷殷兼出雷。", "白谷變氣候，朱炎安在哉？", "高鳥濕不下，居人門未開。", "楚宮久已滅，幽佩爲誰哀。", "侍臣書王夢，賦有冠古才。", "冥冥翠龍駕，多自巫山臺。"]'),
('17c35064-6bb1-4b91-a555-c2ae3768ec7c','雨二首 一','杜甫','唐','唐诗','tang','','[]','青山澹無姿，白露誰能數。',72,'全唐诗/poet.tang.10000.json','["青山澹無姿，白露誰能數。", "片片水上雲，蕭蕭沙中雨。", "殊俗狀巢居，曾臺俯風渚。", "佳客適萬里，沈思情延佇。", "挂帆遠色外，驚浪滿吳楚。", "久陰蛟螭出，寇盜復幾許。"]'),
('da0befbd-3655-4d16-8413-0d699c88e75c','雨二首 二','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','空山中宵陰，微冷先枕席。',120,'全唐诗/poet.tang.10000.json','["空山中宵陰，微冷先枕席。", "迴風起清曙，萬象萋已碧。", "落落出岫雲，渾渾倚天石。", "日假何道行，雨含長江白。", "連檣荆州船，有士荷矛戟。", "南防草鎮慘，霑濕赴遠役。", "羣盜下辟山，總戎備強敵。", "水深雲光廓，鳴櫓各有適。", "漁艇息悠悠，夷歌負樵客。", "留滯一老翁，書時記朝夕。"]'),
('6b5a9040-28e2-4179-8a83-b211cd4b0341','晚登瀼上堂','杜甫','唐','唐诗','tang','','[]','故躋瀼岸高，頗免崖石擁。',144,'全唐诗/poet.tang.10000.json','["故躋瀼岸高，頗免崖石擁。", "開襟野堂豁，繫馬林花動。", "雉堞粉如雲，山田麥無壠。", "春氣晚更生，江流靜猶湧。", "四序嬰我懷，羣盜久相踵。", "黎民困逆節，天子渴垂拱。", "所思注東北，深峽轉修聳。", "衰老自成病，郎官未爲冗。", "淒其望呂葛，不復夢周孔。", "濟世數嚮時，斯人各枯冢。", "楚星南天黑，蜀月西霧重。", "安得隨鳥翎，迫此懼將恐。"]'),
('ba6dd0da-55f1-411a-bfd7-a85c4693c996','又上後園山脚','杜甫','唐','唐诗','tang','','["\u6cf0\u5c71"]','昔我遊山東，憶戲東嶽陽。',216,'全唐诗/poet.tang.10000.json','["昔我遊山東，憶戲東嶽陽。", "窮秋立日觀，矯首望八荒。", "朱崖著毫髮，碧海吹衣裳。", "蓐收困用事，玄冥蔚強梁。", "逝水自朝宗，鎮名各其方。", "平原獨顦顇，農力廢耕桑。", "非關風露凋，曾是戍役傷。", "於時國用富，足以守邊疆。", "朝廷任猛將，遠奪戎虜場。", "到今事反覆，故老淚萬行。", "龜蒙不復見，況乃懷舊鄉。", "肺萎屬久戰，骨出熱中腸。", "憂來杖匣劒，更上林北岡。", "瘴毒猨鳥落，峽乾南日黃。", "秋風亦已起，江漢始如湯。", "登高欲有往，蕩析川無梁。", "哀彼遠征人，去家死路旁。", "不及祖父塋，纍纍冢相當。"]'),
('cc5abbb6-01a9-4346-8ba9-29770f446154','雨','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','山雨不作埿，江雲薄爲霧。',192,'全唐诗/poet.tang.10000.json','["山雨不作埿，江雲薄爲霧。", "晴飛半嶺鶴，風亂平沙樹。", "明滅洲景微，隱見巖姿露。", "拘悶出門遊，曠絕經目趣。", "消中日伏枕，臥久塵及屨。", "豈無平肩輿，莫辨望鄉路。", "兵戈浩未息，蛇虺反相顧。", "悠悠邊月破，鬱鬱流年度。", "針灸阻朋曹，糠籺對童孺。", "一命須屈色，新知漸成故。", "窮荒益自卑，飄泊欲誰訴。", "虺羸愁應接，俄頃恐違迕。", "浮俗何萬端，幽人有獨步。", "龐公竟獨往，尚子終罕遇。", "宿留洞庭秋，天寒瀟湘素。", "杖策可入舟，送此齒髮暮。"]'),
('6a3c8790-6ad2-47ce-8295-ee5512ba2d28','甘林','杜甫','唐','唐诗','tang','','[]','舍舟越西岡，入林解我衣。',192,'全唐诗/poet.tang.10000.json','["舍舟越西岡，入林解我衣。", "青芻適馬性，好鳥知人歸。", "晨光映遠岫，夕露見日晞。", "遲暮少寢食，清曠喜荆扉。", "經過倦俗態，在野無所違。", "試問甘藜藿，未肯羨輕肥。", "喧靜不同科，出處各天機。", "勿矜朱門是，陋此白屋非。", "明朝步鄰里，長老可以依。", "時危賦斂數，脫粟爲爾揮。", "相攜行荳田，秋花靄菲菲。", "子實不得喫，貨市送王畿。", "盡添軍旅用，迫此公家威。", "主人長跪問，戎馬何時稀。", "我衰易悲傷，屈指數賊圍。", "勸其死王命，慎莫遠奮飛。"]'),
('24f9e8b4-e32d-49e7-af89-50e05880b662','雨','杜甫','唐','唐诗','tang','','[]','行雲遞崇高，飛雨靄而至。',120,'全唐诗/poet.tang.10000.json','["行雲遞崇高，飛雨靄而至。", "潺潺石間溜，汩汩松上駛。", "亢陽乘秋熱，百穀皆已棄。", "皇天德澤降，焦卷有生意。", "前雨傷卒暴，今雨喜容易。", "不可無雷霆，間作鼓增氣。", "佳聲達中宵，所望時一致。", "清霜九月天，髣髴見滯穗。", "郊扉及我私，我圃日蒼翠。", "恨無抱甕力，庶減臨江費。"]'),
('a44b9d2a-65fb-40d6-ba19-6cea71b89b53','種萵苣','杜甫','唐','唐诗','tang','','[]','陰陽一錯亂，驕蹇不復理。',252,'全唐诗/poet.tang.10000.json','["陰陽一錯亂，驕蹇不復理。", "枯旱於其中，炎方慘如燬。", "植物半蹉跎，嘉生將已矣。", "雲雷歘奔命，師伯集所使。", "指麾赤白日，澒洞青光起。", "雨聲先已風，散足盡西靡。", "山泉落滄江，霹靂猶在耳。", "終朝紆颯沓，信宿罷瀟灑。", "堂下可以畦，呼童對經始。", "苣兮蔬之常，隨事蓺其子。", "破塊數席間，荷鋤功易止。", "兩旬不甲坼，空惜埋泥滓。", "野莧迷汝來，宗生實於此。", "此輩豈無秋，亦蒙寒露委。", "飜然出地速，滋蔓戶庭毀。", "因知邪干正，掩抑至沒齒。", "賢良雖得祿，守道不封己。", "擁寒敗芝蘭，衆多盛荆杞。", "中園陷蕭艾，老圃永爲恥。", "登於白玉盤，藉以如霞綺。", "莧也無所施，胡顏入筐篚。"]'),
('bc01d10d-a14f-40e0-9e3e-74a2a3c01115','暇日小園散病將種秋菜督勒耕牛兼書觸目','杜甫','唐','唐诗','tang','','[]','不愛入州府，畏人嫌我真。',180,'全唐诗/poet.tang.10000.json','["不愛入州府，畏人嫌我真。", "及乎歸茅宇，旁舍未曾嗔。", "老病忌拘束，應接喪精神。", "江邨意自放，林木心所欣。", "秋耕屬地濕，山雨近甚勻。", "冬菁飯之半，牛力晚來新。", "深耕種數畝，未甚後四鄰。", "嘉蔬既不一，名數頗具陳。", "荆巫非苦寒，采擷接青春。", "飛來兩白鶴，暮啄泥中芹。", "雄者左翮垂，損傷已露筋。", "一步再流血，尚經矰繳勤。", "三步六號叫，志屈悲哀頻。", "鸞皇不相待，側頸訴高旻。", "杖藜俯沙渚，爲汝鼻酸辛。"]'),
('40c8fa66-2802-43df-ada6-1bd286cb49db','八哀詩 贈司空王公思禮','杜甫','唐','唐诗','tang','','[]','司空出東夷，童稚刷勁翮。',298,'全唐诗/poet.tang.10000.json','["司空出東夷，童稚刷勁翮。", "追隨燕薊兒，穎銳物不隔。", "服事哥舒翰，意無流沙磧。", "未甚拔行間，犬戎大充斥。", "短小精悍姿，屹然強寇敵。", "貫穿百萬衆，出入由咫尺。", "馬鞍懸將首，甲外控鳴鏑。", "洗劒青海水，刻銘天山石。", "九曲非外蕃，其王轉深壁。", "飛兔不近駕，鷙鳥資遠擊。", "曉達兵家流，飽聞春秋癖。", "胷襟日沈靜，肅肅自有適。", "潼關初潰散，萬乘猶辟易。", "偏裨無所施，元帥見手格。", "太子入朔方，至尊狩梁益。", "胡馬纏伊洛，中原氣甚逆。", "肅宗登寶位，塞望勢敦迫。", "公時徒步至，請罪將厚責。", "際會清河公，間道傳玉冊天王拜跪畢，讜議果冰釋。", "翠華卷飛雪，熊虎亙阡陌。", "屯兵鳳皇山，帳殿涇渭闢。", "金成賊咽喉詔鎮雄所搤。", "禁暴清無雙，爽氣春淅瀝。", "巷有從公歌，野多青青麥。"]'),
('ee523bdd-916e-4c51-b261-5bbc2d6f5bfd','八哀詩 故司徒李公光弼','杜甫','唐','唐诗','tang','','["\u6cf0\u5c71"]','司徒天寶末，北收晉陽甲。',243,'全唐诗/poet.tang.10000.json','["司徒天寶末，北收晉陽甲。", "胡騎攻吾城，愁寂意不愜。", "人安若泰山，薊北斷右脅。", "朔方氣乃蘇，黎首見帝業。", "二宮泣西郊，九廟起頹壓。", "未散河陽卒，思明僞臣妾。", "復自碣石來，火焚乾坤獵。", "高視笑祿山，公又大獻捷。", "異王冊崇勳，小敵信所怯。", "擁兵鎮河汴，千里初妥帖。", "青蠅紛營營，風雨秋一葉。", "內省未入朝死淚終映睫。", "大屋去高棟，長城埽遺堞。", "平生白羽扇，零落蛟龍匣。", "雅望與英姿，惻愴槐里接。", "三軍晦光彩，烈士痛稠疊。", "直筆在史臣，將來洗箱篋。", "吾思哭孤冢，南紀阻歸楫。", "扶顛永蕭條，未濟失利涉。", "疲{艹/尔}竟何人，灑涕巴東峽。"]'),
('57fcfc8f-4993-43a2-a154-615b75a5105f','八哀詩 贈左僕射鄭國公嚴公武','杜甫','唐','唐诗','tang','','[]','鄭公瑚璉器，華岳金天晶。',288,'全唐诗/poet.tang.10000.json','["鄭公瑚璉器，華岳金天晶。", "昔在童子日，已聞老成名。", "嶷然大賢後，復見秀骨清。", "開口取將相，小心事友生。", "閱書百紙盡，落筆四座驚。", "歷識匪父任，嫉邪常力爭。", "漢議尚整肅，胡騎忽縱橫。", "飛傳自河隴，逢人問公卿。", "不知萬乘出，雪涕風悲鳴。", "受詞劒閣道，謁帝蕭關城。", "寂寞雲臺仗，飄颻沙塞旌。", "江山少使者，笳鼓凝皇情。", "壯士血相視，忠臣氣不平。", "密論貞觀體，揮發岐陽征。", "感激動四極，聯翩收二京。", "西郊牛酒再，原廟丹青明。", "匡汲俄寵辱，衛霍竟哀榮。", "四登會府地，三掌華陽兵。", "京兆空柳色，尚書無履聲。", "羣烏自朝夕，白馬休橫行。", "諸葛蜀人愛，文翁儒化成。", "公來雪山重，公去雪山輕。", "記室得何遜，韜鈐延子荆。", "四郊失壁壘，虛館開逢迎。"]'),
('45110b81-0f02-4c85-b72a-f2210d10c12f','八哀詩 贈太子師汝陽郡王璡','杜甫','唐','唐诗','tang','','[]','汝陽讓帝子，眉宇真天人。',288,'全唐诗/poet.tang.10000.json','["汝陽讓帝子，眉宇真天人。", "虯鬚似太宗，色映塞外春。", "往者開元中，主恩視遇頻。", "出入獨非時，禮異見羣臣。", "愛其謹潔極，倍此骨肉親。", "從容聽朝後，或在風雪晨。", "忽思格猛獸，苑囿騰清塵。", "羽旗動若一，萬馬肅駪駪。", "詔王來射雁，拜命已挺身。", "箭出飛鞚內，上又回翠麟。", "飜然紫塞翮，下拂明月輪。", "胡人雖獲多，天笑不爲新。", "王每中一物，手自與金銀。", "袖中諫獵書，扣馬久上陳。", "竟無銜橛虞，聖聰矧多仁。", "官免供給費，水有在藻鱗。", "匪唯帝老大，皆是王忠勤。", "晚年務置醴，門引申白賓。", "道大容無能，永懷侍芳茵。", "好學尚貞烈，義形必霑巾。", "揮翰綺繡揚，篇什若有神。", "川廣不可泝，墓久狐兔鄰。", "宛彼漢中郡，文雅見天倫。", "何以開我悲，泛舟俱遠津。"]'),
('03733be3-cf7c-442c-b6ce-9918b9aa57ac','八哀詩 贈祕書監江夏李公邕','杜甫','唐','唐诗','tang','','[]','長嘯宇宙間，高才日陵替。',288,'全唐诗/poet.tang.10000.json','["長嘯宇宙間，高才日陵替。", "古人不可見，前輩復誰繼。", "憶昔李公存，詞林有根柢。", "聲華當健筆，灑落富清製。", "風流散金石，追琢山岳銳。", "情窮造化理，學貫天人際。", "干謁走其門，碑版照四裔。", "各滿深望還，森然起凡例。", "蕭蕭白楊路，洞徹寶珠惠。", "龍宮墖廟湧，浩劫浮雲衛。", "宗儒俎豆事，故吏去思計。", "眄睞已皆虛，跋涉曾不泥。", "向來映當時，豈獨勸後世。", "豐屋珊瑚鉤，騏驎織成罽。", "紫騮隨劒几，義取無虛歲。", "分宅脫驂間，感激懷未濟。", "衆歸賙給美，擺落多藏穢。", "獨步四十年，風聽九臯唳。", "嗚呼江夏姿，竟掩宣尼袂。", "往者武后朝，引用多寵嬖。", "否臧太常議，面折二張勢。", "衰俗凜生風，排蕩秋旻霽。", "忠貞負冤恨，宮闕深旒綴。", "放逐早聯翩，低垂困炎厲。"]'),
('0d07875d-bf3e-4a2e-9139-ba767079c8ad','八哀詩 故祕書少監武功蘇公源明','杜甫','唐','唐诗','tang','','[]','武功少也孤，徒步客徐衮。',288,'全唐诗/poet.tang.10000.json','["武功少也孤，徒步客徐衮。", "讀書東岳中，十載考墳典。", "時下萊蕪郭，忍飢浮雲巘。", "負米晚爲身，每食臉必泫。", "夜字照爇薪，垢衣生碧蘚。", "庶以勤苦志，報茲劬勞顯。", "學蔚醇儒姿，文包舊史善。", "灑落辭幽人，歸來潛京輦。", "射君東堂策，宗匠集精選。", "制可題未乾，乙科已大闡。", "文章日自負，吏祿亦累踐。", "晨趨閶闔內，足蹋宿昔趼。", "一麾出守還，黃屋朔風卷。", "不暇陪八駿，虜庭悲所遣。", "平生滿尊酒，斷此朋知展。", "憂憤病二秋，有恨石可轉。", "肅宗復社稷，得無逆順辨。", "范曄顧其兒，李斯憶黃犬。", "祕書茂松意，溟漲本末淺。", "青熒芙蓉劒，犀兕豈獨剸。", "反爲後輩褻，予實苦懷緬。", "煌煌齋房芝，事絕萬手搴。", "垂之俟來者，正始徵勸勉。", "不要懸黃金，胡爲投乳贙。"]'),
('5077e64f-8b7b-489b-a9fc-6c8f11f52315','八哀詩 故著作郎貶台州司戶滎陽鄭公虔','杜甫','唐','唐诗','tang','','[]','鶢鶋至魯門，不識鐘鼓饗。',288,'全唐诗/poet.tang.10000.json','["鶢鶋至魯門，不識鐘鼓饗。", "孔翠望赤霄，愁思雕籠養。", "滎陽冠衆儒，早聞名公賞。", "地崇士大夫，況乃氣精爽。", "天然生知姿，學立游夏上。", "神農極闕漏，黃石媿師長。", "藥纂西極名，兵流指諸掌。", "貫穿無遺恨，薈蕞何技癢。", "圭臬星經奧，蟲篆丹青廣。", "子雲窺未徧，方朔諧太枉。", "神翰顧不一，體變鍾兼兩。", "文傳天下口，大字猶在牓。", "昔獻書畫圖，新詩亦俱往。", "滄洲動玉陛，宣鶴誤一響。", "三絕自御題，四方尤所仰。", "嗜酒益疎放，彈琴視天壤。", "形骸實土木，親近唯几杖。", "未曾寄官曹，突兀倚書幌。", "晚就芸香閣，胡塵昏坱莽。", "反覆歸聖朝，點染無滌盪。", "老蒙台州掾，泛泛淛江槳。", "覆穿四明雪，飢拾楢溪橡。", "空聞紫芝歌，不見杏壇丈。", "天長眺東南，秋色餘魍魎。"]'),
('fd949d64-858c-4734-b54f-fcfd99aff432','八哀詩 故右僕射相國張公九齢','杜甫','唐','唐诗','tang','','[]','相國生南紀，金璞無留礦。',288,'全唐诗/poet.tang.10000.json','["相國生南紀，金璞無留礦。", "仙鶴下人間，獨立霜毛整。", "矯然江海思，復與雲路永。", "寂寞想土階，未遑等箕潁。", "上君白玉堂，倚君金華省。", "碣石歲崢嶸，天地日蛙黽。", "退食吟大庭，何心記榛梗。", "骨驚畏曩哲，鬒變負人境。", "雖蒙換蟬冠，右地恧多幸。", "敢忘二疏歸，痛迫蘇耽井。", "紫綬映暮年，荆州謝所領。", "庾公興不淺，黃霸鎮每靜。", "賓客引調同，諷詠在務屏。", "詩罷地有餘，篇終語清省。", "一陽發陰管，淑氣含公鼎。", "乃知君子心，用才文章境。", "散帙起翠螭，倚薄巫廬竝。", "綺麗玄暉擁，牋誄任昉騁。", "自我一家則，未缺隻字警。", "千秋滄海南，名繫朱鳥影。", "歸老守故林，戀闕悄延頸。", "波濤良史筆，蕪絕大庾嶺。", "向時禮數隔，制作難上請。", "再讀徐孺碑，猶思理煙艇。"]'),
('c7f5d5b7-b7ac-4d43-b795-d9e76677e7e2','寫懷二首 一','杜甫','唐','唐诗','tang','','[]','勞生共乾坤，何處異風俗。',144,'全唐诗/poet.tang.10000.json','["勞生共乾坤，何處異風俗。", "冉冉自趨競，行行見羈束。", "無貴賤不悲，無富貧亦足。", "萬古一骸骨，鄰家遞歌哭。", "鄙夫到巫峽，三歲如轉燭。", "全命甘留滯，忘情任榮辱。", "朝班及暮齒，日給還脫粟。", "編蓬石城東，采藥山北谷。", "用心霜雪間，不必條蔓綠。", "非關故安排，曾是順幽獨。", "達士如弦直，小人似鉤曲。", "曲直我不知，負暄候樵牧。"]'),
('2e87b554-124f-4a56-b208-4bdffe0550b9','寫懷二首 二','杜甫','唐','唐诗','tang','','[]','夜深坐南軒，明月照我膝。',144,'全唐诗/poet.tang.10000.json','["夜深坐南軒，明月照我膝。", "驚風飜河漢，梁棟已出日。", "羣生各一宿，飛動自儔匹。", "吾亦驅其兒，營營爲私實。", "天寒行旅稀，歲暮日月疾。", "榮名忽中人，世亂如蟣蝨。", "古者三皇前，滿腹志願畢。", "胡爲有結繩，陷此膠與漆。", "禍首燧人氏，厲階董孤筆。", "君看燈燭張，轉使飛蛾密。", "放神八極外，俯仰俱蕭瑟。", "終契如往還，得匪合仙術。"]'),
('982f789a-c377-4b64-808a-56f36abf9ff0','可歎','杜甫','唐','唐诗','tang','','[]','天上浮雲如白衣，斯須改變如蒼狗。',272,'全唐诗/poet.tang.10000.json','["天上浮雲如白衣，斯須改變如蒼狗。", "古往今來共一時，人生萬事無不有。", "近者抉眼去其夫，河東女兒身姓柳。", "丈夫正色動引經，酆城客子王季友。", "羣書萬卷常暗誦，孝經一通看在手。", "貧窮老瘦家賣屐，好事就之爲攜酒。", "豫章太守高帝孫，引爲賓客敬頗久。", "聞道三年未曾語，小心恐懼閉其口。", "太守得之更不疑，人生反覆看亦醜。", "明月無瑕豈容易，紫氣鬱鬱猶衝斗。", "時危可仗真豪俊，二人得置君側否。", "太守頃者領山南，邦人思之比父母。", "王生早曾拜顏色，高山之外皆培塿。", "用爲羲和天爲成，用平水土地爲厚。", "王也論道阻江湖，李也丞疑曠前後。", "死爲星辰終不滅，致君堯舜焉肯朽。", "吾輩碌碌飽飯行，風后力牧長回首。"]'),
('61304178-6b16-4f98-87b2-4ad6bc98da98','觀公孫大娘弟子舞劒器行','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','昔有佳人公孫氏，一舞劒氣動四方。',208,'全唐诗/poet.tang.10000.json','["昔有佳人公孫氏，一舞劒氣動四方。", "觀者如山色沮喪，天地爲之久低昂。", "㸌如羿射九日落，矯如羣帝驂龍翔。", "來如雷霆收震怒，罷如江海凝清光。", "絳脣珠袖兩寂莫，況有弟子傳芬芳。", "臨潁美人在白帝，妙舞此曲神揚揚。", "與余問答既有以，感時撫事增惋傷。", "先帝侍女八千人，公孫劒器初第一。", "五十年間似反掌，風塵傾動昏王室。", "棃園子弟散如煙，女樂餘姿映寒日。", "金粟堆南木已拱，瞿唐石城草蕭瑟。", "玳筵急管曲復終，樂極哀來月東出。", "老夫不知其所往，足繭荒山轉愁疾。"]'),
('3ec9cb88-517c-4922-a82e-e6cc561ace29','往在','杜甫','唐','唐诗','tang','','[]','往在西京日，胡來滿彤宮。',299,'全唐诗/poet.tang.10000.json','["往在西京日，胡來滿彤宮。", "中宵焚九廟，雲漢爲之紅。", "解瓦飛十里，繐帷紛曾空。", "疚心惜木主，一一灰悲風。", "合昏排鐵騎，清旭散錦𩦺賊臣表逆節，相賀以成功。", "是時妃嬪戮，連爲糞土叢。", "當宁陷玉座，白間剝畫蟲。", "不知二聖處，私泣百歲翁。", "車駕既云還，楹桷歘穹崇。", "故老復涕泗，祠官樹椅桐。", "宏壯不如初，已見帝力雄。", "前春禮郊廟，祀事親聖躬。", "微軀忝近臣，景從陪羣公。", "登階捧玉冊，峨冕耿金鍾。", "侍祠恧先露，掖垣邇濯龍。", "天子惟孝孫，五雲起九重。", "鏡匳換粉黛，翠羽猶蔥朧。", "前者厭羯胡，後來遭犬戎。", "俎豆腐膻肉，罘罳行角弓。", "安得自西極，申命空山東。", "盡軀詣闕下，士庶塞關中。", "主將曉逆順，元元歸始終。", "一朝自罪己，萬里車書通。", "鋒鏑供鋤犂，征戍聽所從。"]'),
('eb527751-8039-4031-bded-476c82a0ebe1','昔遊','杜甫','唐','唐诗','tang','','[]','昔者與高李，晚登單父臺。',216,'全唐诗/poet.tang.10000.json','["昔者與高李，晚登單父臺。", "寒蕪際碣石，萬里風雲來。", "桑柘葉如雨，飛藿去裴回。", "清霜大澤凍，禽獸有餘哀。", "是時倉廩實，洞達寰區開。", "猛士思滅胡，將帥望三台。", "君王無所惜，駕馭英雄材。", "幽燕盛用武，供給亦勞哉。", "吳門轉粟帛，泛海陵蓬萊。", "肉食三十萬，獵射起黃埃。", "隔河憶長眺，青歲已摧頹。", "不及少年日，無復故人杯。", "賦詩獨流涕，亂世想賢才。", "有能市駿骨，莫恨少龍媒。", "商山議得失，蜀主脫嫌猜。", "呂尚封國邑，傅說已鹽梅。", "景晏楚山深，水鶴去低回。", "龐公任本性，攜子臥蒼苔。"]'),
('46013ebf-55a5-421e-a8fb-c1d55a3c67b3','壯遊','杜甫','唐','唐诗','tang','','[]','往昔十四五，出遊翰墨場。',288,'全唐诗/poet.tang.10000.json','["往昔十四五，出遊翰墨場。", "斯文崔魏徒，以我似班揚。", "七齡思即壯，開口詠鳳皇。", "九齡書大字，有作成一囊。", "性豪業嗜酒，嫉惡懷剛腸。", "脫略小時輩，結交皆老蒼。", "飲酣視八極，俗物都茫茫。", "東下姑蘇臺，已具浮海航。", "到今有遺恨，不得窮扶桑。", "王謝風流遠，闔廬丘墓荒。", "劒池石壁仄，長洲荷芰香。", "嵯峨閶門北，清廟映回塘。", "每趨吳太伯，撫事淚浪浪。", "枕戈憶句踐，渡浙想秦皇。", "蒸魚聞匕首，除道哂要章。", "越女天下白，鑑湖五月涼。", "剡溪蘊秀異，欲罷不能忘。", "歸帆拂天姥，中歲貢舊鄉。", "氣劘屈賈壘，目短曹劉牆。", "忤下考功第，獨辭京尹堂。", "放蕩齊趙間，裘馬頗清狂。", "春歌叢臺上，冬獵青丘旁。", "呼鷹皁櫪林，逐獸雲雪岡。", "射飛曾縱鞚，引臂落鶖鶬。"]'),
('f5003828-ec14-49f6-a2b4-9eb6ce67a9d8','遣懷','杜甫','唐','唐诗','tang','','[]','昔我遊宋中，惟梁孝王都。',252,'全唐诗/poet.tang.10000.json','["昔我遊宋中，惟梁孝王都。", "名今陳留亞，劇則貝魏俱。", "邑中九萬家，高棟照通衢。", "舟車半天下，主客多歡娛。", "白刃讐不義，黃金傾有無。", "殺人紅塵裏，報答在斯須。", "憶與高李輩，論交入酒壚。", "兩公壯藻思，得我色敷腴。", "氣酣登吹臺，懷古視平蕪。", "芒碭雲一去，雁鶩空相呼。", "先帝正好武，寰海未凋枯。", "猛將收西域，長戟破林胡。", "百萬攻一城，獻捷不云輸。", "組練棄如泥，尺土負百夫。", "拓境功未已，元和辭大爐。", "亂離朋友盡，合沓歲月徂。", "吾衰將焉託，存歿再嗚呼。", "蕭條益堪媿，獨在天一隅。", "乘黃已去矣，凡馬徒區區。", "不復見顏鮑，繫舟臥荆巫。", "臨餐吐更食，常恐違撫孤。"]'),
('817f76ca-8ee1-4eb7-b20a-0d44cef2c24b','同元使君舂陵行','杜甫','唐','唐诗','tang','','[]','遭亂髮盡白，轉衰病相嬰。',264,'全唐诗/poet.tang.10000.json','["遭亂髮盡白，轉衰病相嬰。", "沈緜盜賊際，狼狽江漢行。", "歎時藥力薄，爲客羸瘵成。", "吾人詩家秀，博采世上名。", "粲粲元道州，前聖畏後生。", "觀呼舂陵作，歘見俊哲情。", "復覽賊退篇，結也實國楨。", "賈誼昔流慟，匡衡常引經。", "道州憂黎庶，詞氣浩縱橫。", "兩章對秋月，一字偕華星。", "至君唐虞際，純樸憶大庭。", "何時降璽書，用爾爲丹青。", "獄訟永衰息，豈唯偃甲兵。", "悽惻念誅求，薄斂近休明。", "乃知正人意，不苟飛長纓。", "涼飆振南岳，之子寵若驚。", "色阻金印大，興含滄浪清。", "我多長卿病，日夕思朝廷。", "肺枯渴太甚，漂泊公孫城。", "呼兒具紙筆，隱几臨軒楹。", "作詩呻吟內，黑澹字攲傾。", "感彼危苦詞，庶幾知者聽。"]'),
('0a14f11c-1fa5-4d47-abf7-7fd511b82373','李潮八分小篆歌','杜甫','唐','唐诗','tang','','[]','蒼頡鳥跡既茫昧，字體變化如浮雲。',218,'全唐诗/poet.tang.10000.json','["蒼頡鳥跡既茫昧，字體變化如浮雲。", "陳倉石鼓又已訛，大小二篆生八分。", "秦有李斯漢蔡邕，中間作者寂不聞。", "嶧山之碑野火焚，棗木傳客肥失真。", "苦縣光和尚骨立，書貴瘦硬方通神。", "惜哉李蔡不復得，吾甥李潮下筆親。", "尚書韓擇木，騎曹蔡有鄰。", "開元已來數八分，潮也奄有二子成三人。", "況潮小篆逼秦相，快劒長戟森相向。", "八分一字直百金，蛟龍盤拏肉屈強。", "吳郡張顛誇草書，草書非古空雄壯。", "豈如吾甥不流宕，丞相中郎丈人行。", "巴東逢李潮，逾月求我歌。", "我今衰老才力薄，潮乎潮乎奈汝何。"]'),
('4a61c679-137e-47fb-a94c-dc41ff685ab9','覽柏中允兼子姪數人除官制詞因述父子兄弟四美載歌絲綸','杜甫','唐','唐诗','tang','','[]','紛然喪亂際，見此忠孝門。',180,'全唐诗/poet.tang.10000.json','["紛然喪亂際，見此忠孝門。", "蜀中寇亦甚，柏氏功彌存。", "深誠補王室，戮力自元昆。", "三止錦江沸，獨清玉壘昏。", "高名入竹帛，新渥照乾坤。", "子弟先卒伍，芝蘭疊璵璠。", "同心注師律，灑血在戎軒。", "絲綸實具載，紱冕已殊恩。", "奉公舉骨肉，誅叛經寒溫。", "金甲雪猶凍，朱旗塵不飜。", "每聞戰場說，歘激懦氣奔。", "聖主國多盜，賢臣官則尊。", "方當節鉞用，必絕祲沴根。", "吾病日回首，雲臺誰再論。", "作歌挹盛事，推轂期孤騫。"]'),
('7bbfc188-31b0-4e94-99b9-7622a821b815','聽楊氏歌','杜甫','唐','唐诗','tang','','[]','佳人絕代歌，獨立發皓齒。',96,'全唐诗/poet.tang.10000.json','["佳人絕代歌，獨立發皓齒。", "滿堂慘不樂，響下清虛裏。", "江城帶素月，況乃清夜起。", "老夫悲暮年，壯士淚如水。", "玉杯久寂寞，金管迷宮徵。", "勿云聽者疲，愚智心盡死。", "古來傑出士，豈待一知己。", "吾聞昔秦青，傾側天下耳。"]'),
('0cc77a07-c1db-4875-9e12-9574e51aab15','荆南兵馬使太常卿趙公大食刀歌','杜甫','唐','唐诗','tang','','[]','太常樓船聲嗷嘈，問兵刮寇趨下牢。',256,'全唐诗/poet.tang.10000.json','["太常樓船聲嗷嘈，問兵刮寇趨下牢。", "牧出令奔飛百艘，猛蛟突獸紛騰逃。", "白帝寒城駐錦袍，玄冬示我胡國刀。", "壯士短衣頭虎毛，憑軒拔鞘天爲高。", "翻風轉日木怒號，冰翼雪澹傷哀猱。", "鐫錯碧甖鸊鵜膏，鋩鍔已瑩虛秋濤。", "鬼物撇捩辭坑壕，蒼水使者捫赤條。", "龍伯國人罷釣鼇，芮公回首顏色勞。", "分閫救世用賢豪，趙公玉立高歌起。", "攬環結佩相終始，萬歲持之護天子。", "得君亂絲與君理，蜀江如線如鍼水。", "荆岑彈丸心未已，賊臣惡子休干紀。", "魑魅魍魎徒爲耳，妖腰亂領敢欣喜。", "用之不高亦不庳，不似長劒須天倚。", "吁嗟光祿英雄弭，大食寶刀聊可比。", "丹青宛轉麒麟裏，光芒六合無泥滓。"]'),
('3383ff3c-b6bf-44b6-900a-766acc558644','王兵馬使二角鷹','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','悲臺蕭颯石巃嵸，哀壑杈枒浩呼洶。',168,'全唐诗/poet.tang.10000.json','["悲臺蕭颯石巃嵸，哀壑杈枒浩呼洶。", "中有萬里之長江，迴風滔日孤光動。", "角鷹飜倒壯士臂，將軍玉帳軒翠氣。", "二鷹猛腦徐侯穟，目如愁胡視天地。", "杉雞竹兔不自惜，溪虎野羊俱辟易。", "韝上鋒稜十二翮，將軍勇銳與之敵。", "將軍樹勳起安西，崑崙虞泉入馬蹄。", "白羽曾肉三狻猊，敢決豈不與之齊。", "荆南芮公得將軍，亦如角鷹下翔雲。", "惡鳥飛飛啄金屋，安得爾輩開其羣，驅出六合梟鸞分。"]'),
('397cb7f5-51a4-4897-8fe0-7dd40d1ab332','狄明府','杜甫','唐','唐诗','tang','','[]','梁公曾孫我姨弟，不見十年官濟濟。',252,'全唐诗/poet.tang.10000.json','["梁公曾孫我姨弟，不見十年官濟濟。", "大賢之後竟陵遲，浩蕩古今同一體。", "比看叔伯四十人，有才無命百寮底。", "今者兄弟一百人，幾人卓絕秉周禮。", "在汝更用文章爲，長兄白眉復天啓。", "汝門請從曾翁說，太后當朝多巧詆。", "狄公執政在末年，濁河終不污清濟。", "國嗣初將付諸武，公獨廷諍守丹陛。", "禁中決冊請房陵，前朝長老皆流涕。", "太宗社稷一朝正，漢宮威儀重昭洗。", "時危始識不世才，誰謂荼苦甘如薺。", "汝曹又宜列土食，身使門戶多旌棨。", "胡爲漂泊岷漢間，干謁王侯頗歷抵。", "況乃山高水有波，秋風蕭蕭露泥泥。", "虎之飢，下巉嵒。", "蛟之橫，出清泚。", "早歸來，黃土泥衣眼易眯。"]'),
('02304a34-5fd7-44fc-a781-9a1ed35a8a03','秋風二首 一','杜甫','唐','唐诗','tang','','[]','秋風淅淅吹巫山，上牢下牢修水關。',64,'全唐诗/poet.tang.10000.json','["秋風淅淅吹巫山，上牢下牢修水關。", "吳檣楚柁牽百丈，暖向神都寒未還。", "要路何日罷長戟，戰自青羌連百蠻。", "中巴不曾消息好，暝傳戍鼓長雲間。"]'),
('f1177b2a-c00f-4d1a-a8f8-95e33bd6c4f5','秋風二首 二','杜甫','唐','唐诗','tang','','[]','秋風淅淅吹我衣，東流之外西日微。',64,'全唐诗/poet.tang.10000.json','["秋風淅淅吹我衣，東流之外西日微。", "天清小城搗練急，石古細路行人稀。", "不知明月爲誰好，早晚孤帆他夜歸。", "會將白髮倚庭樹，故園池臺今是非。"]'),
('70ea423c-d3c0-4870-885f-4ebadc8b8fcf','久雨期王將軍不至','杜甫','唐','唐诗','tang','','[]','天雨蕭蕭滯茅屋，空山無以慰幽獨。',192,'全唐诗/poet.tang.10000.json','["天雨蕭蕭滯茅屋，空山無以慰幽獨。", "銳頭將軍來何遲，令我心中苦不足。", "數看黃霧亂玄雲，時聽嚴風折喬木。", "泉源泠泠雜猿狖，泥濘漠漠飢鴻鵠。", "歲暮窮陰耿未已，人生會面難再得。", "憶爾腰下鐵絲箭，射殺林中雪色鹿。", "前者坐皮因問毛，知子歷險人馬勞。", "異獸如飛星宿落，應弦不礙蒼山高。", "安得突騎只五千，崒然眉骨皆爾曹。", "走平亂世相催促，一豁明主正鬱陶。", "憶昔范增碎玉斗，未使吳兵著白袍。", "昏昏閶闔閉氛祲，十月荆南雷怒號。"]'),
('7a27b2b0-bc65-4741-9b66-e9cf0051358a','別李祕書始興寺所居','杜甫','唐','唐诗','tang','','[]','不見祕書心若失，及見祕書失心疾。',64,'全唐诗/poet.tang.10000.json','["不見祕書心若失，及見祕書失心疾。", "安爲動主理信然，我獨覺子神充實。", "重聞西方止觀經，老身古寺風泠泠。", "妻兒待我且歸去，他日杖藜來細聽。"]'),
('92593a2f-df35-424b-a4e3-51521a80c50e','虎牙行','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','秋風歘吸吹南國，天地慘慘無顏色。',136,'全唐诗/poet.tang.10000.json','["秋風歘吸吹南國，天地慘慘無顏色。", "洞庭揚波江漢迴，虎牙銅柱皆傾側。", "巫峽陰岑朔漠氣，峰巒窈窕谿谷黑。", "杜鵑不來猿狖寒，山鬼幽憂雪霜逼。", "楚老長嗟憶炎瘴，三尺角弓兩斛力。", "壁立石城橫塞起，金錯旌竿滿雲直。", "漁陽突騎獵青丘，犬戎鎖甲聞丹極。", "八荒十年防盜賊，征戍誅求寡妻哭，遠客中宵淚霑臆。"]'),
('b04b21d5-0f49-468d-963b-cfc58ae76654','錦樹行','杜甫','唐','唐诗','tang','','[]','今日苦短昨日休，歲云暮矣增離憂。',160,'全唐诗/poet.tang.10000.json','["今日苦短昨日休，歲云暮矣增離憂。", "霜凋碧樹待錦樹，萬壑東逝無停留。", "荒戍之城石色古，東郭老人住青丘。", "飛書白帝營斗粟，琴瑟几杖柴門幽。", "青草萋萋盡枯死，天馬跂足隨氂牛。", "自古聖賢多薄命，姦雄惡少皆封侯。", "故國三年一消息，終南渭水寒悠悠。", "五陵豪貴反顛倒，鄉里小兒狐白裘。", "生男墮地要膂力，一生富貴傾邦國。", "莫愁父母少黃金，天下風塵兒亦得。"]'),
('3c55ddde-5ba6-4c4a-868d-a1741df7c270','赤霄行','杜甫','唐','唐诗','tang','','[]','孔雀未知牛有角，渴飲寒泉逢觝觸。',96,'全唐诗/poet.tang.10000.json','["孔雀未知牛有角，渴飲寒泉逢觝觸。", "赤霄懸圃須往來，翠尾金花不辭辱。", "江中淘河嚇飛燕，銜泥却落羞華屋。", "皇孫猶曾蓮勺困，衛莊見貶傷其足。", "老翁慎莫怪少年，葛亮貴和書有篇。", "丈夫垂名動萬年，記憶細故非高賢。"]'),
('c2013b6f-2707-4f63-8fc4-af831d86bc9f','前苦寒行二首 一','杜甫','唐','唐诗','tang','','[]','漢時長安雪一丈，牛馬毛寒縮如蝟。',64,'全唐诗/poet.tang.10000.json','["漢時長安雪一丈，牛馬毛寒縮如蝟。", "楚江巫峽冰入懷，虎豹哀號又堪記。", "秦城老翁荆揚客，慣習炎蒸歲絺綌。", "玄冥祝融氣或交，手持白羽未敢釋。"]'),
('9b91c872-6629-4b66-83a1-402a9e26238f','前苦寒行二首 二','杜甫','唐','唐诗','tang','','[]','去年白帝雪在山，今年白帝雪在地。',64,'全唐诗/poet.tang.10000.json','["去年白帝雪在山，今年白帝雪在地。", "凍埋蛟龍南浦縮，寒刮肌膚北風利。", "楚人四時皆麻衣，楚天萬里無晶輝。", "三足之烏足恐斷，羲和送將何所歸。"]'),
('edfab8d8-0b21-4198-b103-275f0433a339','後苦寒行二首 一','杜甫','唐','唐诗','tang','','[]','南紀巫廬瘴不絕，太古以來無尺雪。',32,'全唐诗/poet.tang.10000.json','["南紀巫廬瘴不絕，太古以來無尺雪。", "蠻夷長老怨苦寒，崑崙天關凍應折。"]'),
('ad408522-3d66-49f7-be14-8ca7a8d29301','後苦寒行二首 二','杜甫','唐','唐诗','tang','','[]','晚來江門失大木，猛風中夜吹白屋。',56,'全唐诗/poet.tang.10000.json','["晚來江門失大木，猛風中夜吹白屋。", "天兵斬斷青海戎，殺氣南行動地軸，不爾苦寒何太酷。", "巴東之峽生凌澌，彼蒼回軒人得知。"]'),
('5534cce2-5493-48fb-908d-7e13a5487c33','晚晴','杜甫','唐','唐诗','tang','','[]','高唐暮冬雪壯哉，舊瘴無復似塵埃。',104,'全唐诗/poet.tang.10000.json','["高唐暮冬雪壯哉，舊瘴無復似塵埃。", "崖沈谷沒白皚皚，江石缺裂青楓摧。", "南天三旬苦霧開，赤日照耀從西來。", "六龍寒急光裴回，照我衰顏忽落地，口雖吟詠心中哀。", "未怪及時少年子，揚眉結義黃金臺。", "洎乎吾生何飄零，支離委絕同死灰。"]'),
('59ddc03d-8cc2-48c7-9fe2-6f7dc4931a73','復陰','杜甫','唐','唐诗','tang','','[]','方冬合沓玄陰塞，昨日晚晴今日黑。',67,'全唐诗/poet.tang.10000.json','["方冬合沓玄陰塞，昨日晚晴今日黑。", "萬里飛蓬映天過，孤城樹羽揚風直。", "江濤簸岸黃沙走，雲雪埋山蒼兕吼。", "君不見夔子之國杜陵翁，牙齒半落左耳聾。"]'),
('84d91507-c2a6-4260-8145-2ed3cab95504','夜歸','杜甫','唐','唐诗','tang','','[]','夜來歸來衝虎過，山黑家中已眠臥。',64,'全唐诗/poet.tang.10000.json','["夜來歸來衝虎過，山黑家中已眠臥。", "傍見北斗向江低，仰看明星當空大。", "庭前把燭嗔兩炬，峽口驚猿聞一箇。", "白頭老罷舞復歌，杖藜不睡誰能那。"]'),
('797a6309-5f6b-47f3-80e7-d83142478dd6','寄柏學士林居','杜甫','唐','唐诗','tang','','[]','自胡之反持干戈，天下學士亦奔波。',128,'全唐诗/poet.tang.10000.json','["自胡之反持干戈，天下學士亦奔波。", "歎彼幽棲載典籍，蕭然暴露依山阿。", "青山萬里靜散地，白雨一洗空垂蘿。", "亂代飄零余到此，古人成敗子如何。", "荆揚春冬異風土，巫峽日夜多雲雨。", "赤葉楓林百舌鳴，黃泥野岸天雞舞。", "盜賊縱橫甚密邇，形神寂莫甘辛苦。", "幾時高議排金門，各使蒼生有環堵。"]'),
('82840988-dfdf-4348-84e7-1d0f873bb988','寄從孫崇簡','杜甫','唐','唐诗','tang','','[]','嵯峨白帝城東西，南有龍湫北虎溪。',80,'全唐诗/poet.tang.10000.json','["嵯峨白帝城東西，南有龍湫北虎溪。", "吾孫騎曹不騎馬，業學尸鄉多養雞。", "龐公隱時盡室去，武陵春樹他人迷。", "與汝林居未相失，近身藥裹酒長攜。", "牧豎樵童亦無賴，莫令斬斷青雲梯。"]'),
('93c2af72-5550-4403-8c15-53be3d38913e','奉酬薛十二丈判官見贈','杜甫','唐','唐诗','tang','','[]','忽忽峽中睡，悲風方一醒。',288,'全唐诗/poet.tang.10000.json','["忽忽峽中睡，悲風方一醒。", "西來有好鳥，爲我下青冥。", "羽毛淨白雪，慘澹飛雲汀。", "既蒙主人顧，舉翮唳孤亭。", "持以比佳士，及此慰揚舲。", "清文動哀玉，見道發新硎。", "欲學鴟夷子，待勒燕山銘。", "誰重斷蛇劒，致君君未聽。", "志在麒麟閣，無心雲母屏。", "卓氏近新寡，豪家朱門扃。", "相如才調逸，銀漢會雙星。", "客來洗粉黛，日暮拾流螢。", "不是無膏火，勸郎勤六經。", "老夫自汲澗，野水日泠泠。", "我歎黑頭白，君看銀印青。", "臥病識山鬼，爲農知地形。", "誰矜坐錦帳，苦厭食魚腥。", "東西兩岸坼，橫水注滄溟。", "碧色忽惆悵，風雷搜百靈。", "空中右白虎，赤節引娉婷。", "自云帝里女，噀雨鳳凰翎。", "襄王薄行跡，莫學冷如丁。", "千秋一拭淚，夢覺有微馨。", "人生相感動，金石兩青熒。"]'),
('de948fac-a55e-462b-98f8-aa3b9214fc54','醉爲馬墜諸公攜酒相看','杜甫','唐','唐诗','tang','','[]','甫也諸侯老賓客，罷酒酣歌拓金戟。',227,'全唐诗/poet.tang.10000.json','["甫也諸侯老賓客，罷酒酣歌拓金戟。", "騎馬忽憶少年時，散蹄迸落瞿塘石。", "白帝城門水雲外，低身直下八千尺。", "粉堞電轉紫遊韁，東得平岡出天壁。", "江村野堂爭入眼，垂鞭嚲鞚凌紫陌。", "向來皓首驚萬人，自倚紅顏能騎射。", "安知決臆追風足，朱汗驂驔猶噴玉。", "不虞一蹶終損傷，人生快意多所辱。", "職當憂戚伏衾枕，況乃遲暮加煩促。", "明知來問腆我顏，杖藜強起依僮僕。", "語盡還成開口笑，提攜別埽清谿曲。", "酒肉如山又一時，初筵哀絲動豪竹。", "共指西日不相貸，喧呼且覆杯中淥。", "何必走馬來爲問，君不見嵇康養生遭殺戮。"]'),
('fc722fa9-6e62-4d59-9bcd-b8d0ef06daa6','別李義','杜甫','唐','唐诗','tang','','[]','神堯十八子，十七王其門。',278,'全唐诗/poet.tang.10000.json','["神堯十八子，十七王其門。", "道國洎舒國，督唯親弟昆。", "中外貴賤殊，余亦忝諸孫。", "丈人嗣三葉，之子白玉溫。", "道國繼德業，請從丈人論。", "丈人領宗卿，肅穆古制敦。", "先朝納諫諍，直氣橫乾坤。", "子建文筆壯，河間經術存。", "爾克富詩禮，骨清慮不喧。", "洗然遇知几，談論淮湖奔。", "憶昔初見時，小襦繡芳蓀。", "長成忽會面，慰我久疾魂。", "三峽春冬交，江山雲霧昏。", "正宜且聚集，恨此當離尊。", "莫怪執杯遲，我衰涕唾煩。", "重問子何之，西上岷江源。", "願子少干謁，蜀都足戎軒。", "誤失將帥意，不如親故恩。", "少年早歸來，梅花已飛飜。", "努力慎風水，豈惟數盤[飧]。", "猛虎臥在岸，蛟螭出無痕。", "王子自愛惜，老夫困石根。", "生別古所嗟，發聲爲爾吞。"]'),
('26587ca4-6af1-4180-a430-b29652a14f1d','送高司直尋封閬州','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','丹雀銜書來，暮棲何鄉樹。',240,'全唐诗/poet.tang.10000.json','["丹雀銜書來，暮棲何鄉樹。", "驊騮事天子，辛苦在道路。", "司直非冗官，荒山甚無趣。", "借問泛舟人，胡爲入雲霧。", "與子姻婭間，即親亦有故。", "萬里長江邊，邂逅一相遇。", "長卿消渴再，公幹沈緜屢。", "清談慰老夫，開卷得佳句。", "時見文章士，欣然澹情素。", "伏枕聞別離，疇能忍漂寓。", "良會苦短促，溪行水奔注。", "熊羆咆空林，游子慎馳騖。", "西謁巴中侯，艱險如跬步。", "主人不世才，先帝常特顧。", "拔爲天軍佐，崇大王法度。", "淮海生清風，南翁尚思慕。", "公宮造廣廈，木石乃無數。", "初聞伐松柏，猶臥天一柱。", "我瘦書不成，成字讀亦誤。", "爲我問故人，勞心練征戍。"]'),
('4cfeb483-2cfb-4f3e-8ed1-059eaccdd260','君不見簡蘇徯','杜甫','唐','唐诗','tang','','[]','君不見道邊廢棄池，君不見前者摧折桐。',74,'全唐诗/poet.tang.10000.json','["君不見道邊廢棄池，君不見前者摧折桐。", "百年死樹中琴瑟，一斛舊水藏蛟龍。", "丈夫蓋棺事始定，君今幸未成老翁。", "何恨顦顇在山中，深山窮谷不可處，霹靂魍魎兼狂風。"]'),
('1974de1f-6f04-486a-a348-c8f8ee0fc9c6','贈蘇四徯','杜甫','唐','唐诗','tang','','[]','異縣昔同遊，各云厭轉蓬。',180,'全唐诗/poet.tang.10000.json','["異縣昔同遊，各云厭轉蓬。", "別離已五年，尚在行李中。", "戎馬日衰息，乘輿安九重。", "有才何棲棲，將老委所窮。", "爲郎未爲賤，其奈疾病攻。", "子何面黧黑，不得豁心胷。", "巴蜀倦剽掠，下愚成土風。", "幽薊已削平，荒徼尚彎弓。", "斯人脫身來，豈非吾道東。", "乾坤雖寬大，所適裝囊空。", "肉食哂菜色，少壯欺老翁。", "況乃主客間，古來偪側同。", "君今下荆揚，獨帆如飛鴻。", "二州豪俠場，人馬皆自雄。", "一請甘飢寒，再請甘養蒙。"]'),
('250f7cf0-6e19-4bfc-bcc3-96c0c2c67622','寄薛三郎中','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','人生無賢愚，飄颻若埃塵。',288,'全唐诗/poet.tang.10000.json','["人生無賢愚，飄颻若埃塵。", "自非得神仙，誰免危其身。", "與子俱白頭，役役常苦辛。", "雖爲尚書郎，不及村野人。", "憶昔村野人，其樂難具陳。", "藹藹桑麻交，公侯爲等倫。", "天未厭戎馬，我輩本常貧。", "子尚客荆州，我亦滯江濱。", "峽中一臥病，瘧癘終冬春。", "春復加肺氣，此病蓋有因。", "早歲與蘇鄭，痛飲情相親。", "二公化爲土，嗜酒不失真。", "余今委修短，豈得恨命屯。", "聞子心甚壯，所遇信席珍。", "上馬不用扶，每扶必怒嗔。", "賦詩賓客間，揮灑動八垠。", "乃知蓋代手，才力老益神。", "青草洞庭湖，東浮滄海漘。", "君山可避暑，況足采白蘋。", "子豈無扁舟，往復江漢津。", "我未下瞿塘，空念禹功勤。", "聽說松門峽，吐藥攬衣巾。", "高秋却束帶，鼓枻視青旻。", "鳳池日澄碧，濟濟多士新。"]'),
('d549304d-762c-49d7-a661-d008586a3ec1','大覺高僧蘭若','杜甫','唐','唐诗','tang','','["\u5e90\u5c71"]','巫山不見廬山遠，松林蘭若秋風晚。',64,'全唐诗/poet.tang.10000.json','["巫山不見廬山遠，松林蘭若秋風晚。", "一老猶鳴日暮鐘，諸僧尚乞齋時飯。", "香爐峰色隱晴湖，種杏仙家近白榆。", "飛錫去年啼邑子，獻花何日許門徒。"]'),
('71817edb-5481-405b-90ae-0d67ed39c59c','宿青溪驛奉懷張員外十五兄之緒','杜甫','唐','唐诗','tang','','[]','漾舟千山內，日入泊枉渚。',72,'全唐诗/poet.tang.10000.json','["漾舟千山內，日入泊枉渚。", "我生本飄飄，今復在何許。", "石根青楓林，猿鳥聚儔侶。", "月明游子靜，畏虎不得語。", "中夜懷友朋，乾坤此深阻。", "浩蕩前後間，佳期付荆楚。"]'),
('47efe0be-f2da-4171-9d3b-abd166ae86f9','敬寄族弟唐十八使君','杜甫','唐','唐诗','tang','','[]','與君陶唐後，盛族多其人。',192,'全唐诗/poet.tang.10000.json','["與君陶唐後，盛族多其人。", "聖賢冠史籍，枝派羅源津。", "在今氣磊落，巧僞莫敢親。", "介立實吾弟，濟時肯殺身。", "物白諱受玷，行高無污真。", "得罪永泰末，放之五溪濱。", "鸞鳳有鎩翮，先儒曾抱麟。", "雷霆霹長松，骨大却生筋。", "一失不足傷，念子孰自珍。", "泊舟楚宮岸，戀闕浩酸辛。", "除名配清江，厥土巫峽鄰。", "登陸將首途，筆札枉所申。", "歸朝跼病肺，敘舊思重陳。", "春風洪濤壯，谷轉頗彌旬。", "我能泛中流，搪突鼉獺瞋。", "長年已省柁，慰此貞良臣。"]'),
('8e416ce8-2636-46ef-b193-83fe64d189e9','憶昔行','杜甫','唐','唐诗','tang','','[]','憶昔北尋小有洞，洪河怒濤過輕舸。',191,'全唐诗/poet.tang.10000.json','["憶昔北尋小有洞，洪河怒濤過輕舸。", "辛勤不見華蓋君，艮岑青輝慘么麼。", "千崖無人萬壑靜，三步回頭五步坐。", "秋山眼冷魂未歸，仙賞心違淚交墮。", "弟子誰依白茅室，盧老獨啓青銅鎖。", "巾拂香餘搗藥塵，階除灰死燒丹火。", "懸圃滄洲莽空闊，金節羽衣飄婀娜。", "落日初霞閃餘映，倏忽東西無不可。", "松風澗水聲合時，青兕黃熊啼向我。", "徒然咨嗟撫遺迹，至今夢想猶佐。", "祕訣隱文須內教，晚歲何功使願果。", "更討衡陽董鍊師，南浮早鼓瀟湘柁。"]'),
('67761270-0287-499c-b702-123d49c2786d','魏將軍歌','杜甫','唐','唐诗','tang','','[]','將軍昔著從事衫，鐵馬馳突重兩銜。',144,'全唐诗/poet.tang.10000.json','["將軍昔著從事衫，鐵馬馳突重兩銜。", "披堅執銳略西極，崑崙月窟東嶄巖。", "君門羽林萬猛士，惡若哮虎子所監。", "五年起家列霜戟，一日過海收風帆。", "平生流輩徒蠢蠢，長安少年氣欲盡。", "魏侯骨聳精爽緊，華岳峰尖見秋隼。", "星躔寶校金盤陀，夜騎天駟超天河。", "欃槍熒惑不敢動，翠蕤雲旓相蕩摩。", "吾爲子起歌都護，酒闌插劒肝膽露。"]'),
('5afe3c27-812c-4eed-bb30-74e657009e41','北風','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','北風破南極，朱鳳日威垂。',48,'全唐诗/poet.tang.10000.json','["北風破南極，朱鳳日威垂。", "洞庭秋欲雪，鴻雁將安歸。", "十年殺氣盛，六合人煙稀。", "吾慕漢初老，時清猶茹芝。"]'),
('89afce4e-3ab0-4e02-9a9d-a91a555a88b2','客從','杜甫','唐','唐诗','tang','','[]','客從南溟來，遺我泉客珠。',48,'全唐诗/poet.tang.10000.json','["客從南溟來，遺我泉客珠。", "珠中有隱字，欲辨不成書。", "緘之篋笥久，以俟公家須。", "開視化爲血，哀今徵斂無。"]'),
('be76202d-c128-4278-b070-dcb351ae96ae','白馬','杜甫','唐','唐诗','tang','','[]','白馬東北來，空鞍貫雙箭。',48,'全唐诗/poet.tang.10000.json','["白馬東北來，空鞍貫雙箭。", "可憐馬上郎，意氣今誰見。", "近時主將戳，中夜商於戰。", "喪亂死多門，嗚呼淚如霰。"]'),
('f7c9ee6f-c868-4850-9b8e-30ab5c1891e9','白鳧行','杜甫','唐','唐诗','tang','','[]','君不見黃鵠高於五尺童，化爲白鳧似老翁。',67,'全唐诗/poet.tang.10000.json','["君不見黃鵠高於五尺童，化爲白鳧似老翁。", "故畦遺穗已蕩盡，天寒歲暮波濤中。", "鱗介腥羶素不食，終日忍飢西復東。", "魯門鶢鶋亦蹭蹬，聞道如今猶避風。"]'),
('90b89639-fa5f-4458-9c0a-c4dc25fd5b97','朱鳳行','杜甫','唐','唐诗','tang','','["\u8861\u5c71"]','君不見瀟湘之山衡山高，山巔朱鳳聲嗷嗷。',67,'全唐诗/poet.tang.10000.json','["君不見瀟湘之山衡山高，山巔朱鳳聲嗷嗷。", "側身長顧求其羣，翅垂口噤心甚勞。", "下愍百鳥在羅網，黃雀最小猶難逃。", "願分竹實及螻蟻，盡使鴟梟相怒號。"]'),
('7e6e299e-64bd-43d0-a15b-7512bead4c84','惜別行送向卿進奉端午御衣之上都','杜甫','唐','唐诗','tang','','[]','肅宗昔在靈武城，指揮猛將收咸京。',128,'全唐诗/poet.tang.10000.json','["肅宗昔在靈武城，指揮猛將收咸京。", "向公泣血灑行殿，佐佑卿相乾坤平。", "逆胡冥寞隨煙燼，卿家兄弟功名震。", "麒麟圖畫鴻雁行，紫極出入黃金印。", "尚書勳業超千古，雄鎮荆州繼吾祖。", "裁縫雲霧成御衣，拜跪題封向端午。", "向卿將命寸心赤，青山落日江潮白。", "卿到朝廷說老翁，漂零已是滄浪客。"]'),
('dff1b780-5ef1-4c4f-abff-ef38d41e3c32','醉歌行贈公安顏少府請顧八題壁','杜甫','唐','唐诗','tang','','[]','神仙中人不易得，顏氏之子才孤標。',106,'全唐诗/poet.tang.10000.json','["神仙中人不易得，顏氏之子才孤標。", "天馬長鳴待駕馭，秋鷹整翮當雲霄。", "君不見東吳顧文學，君不見西漢杜陵老。", "詩家筆勢君不嫌，詞翰升堂爲君埽。", "是日霜風凍七澤，烏蠻落照銜赤壁。", "酒酣耳熱忘頭白，感君意氣無所惜，一爲歌行歌主客。"]'),
('b6985205-7423-47bf-ad4d-19e2ee4eaed0','夜聞觱篥','杜甫','唐','唐诗','tang','','[]','夜聞觱篥滄江上，衰年側耳情所嚮。',64,'全唐诗/poet.tang.10000.json','["夜聞觱篥滄江上，衰年側耳情所嚮。", "鄰舟一聽多感傷，塞曲三更歘悲壯。", "積雪飛霜此夜寒，孤燈急管復風湍。", "君知天地干戈滿，不見江湖行路難。"]'),
('83fab156-6339-4b67-aca1-5ee2b16f2680','發劉郎浦','杜甫','唐','唐诗','tang','','[]','挂帆早發劉郎浦，疾風颯颯昏亭午。',64,'全唐诗/poet.tang.10000.json','["挂帆早發劉郎浦，疾風颯颯昏亭午。", "舟中無日不沙塵，岸上空村盡豺虎。", "十日北風風未回，客行歲晚晚相催。", "白頭厭伴漁人宿，黃帽青鞋歸去來。"]'),
('60c5878d-7369-4694-bf73-7d9835693502','別董頲','杜甫','唐','唐诗','tang','','[]','窮冬急風水，逆浪開帆難。',120,'全唐诗/poet.tang.10000.json','["窮冬急風水，逆浪開帆難。", "士子甘旨闕，不知道里寒。", "有求彼樂土，南適小長安。", "到我舟檝去，覺君衣裳單。", "素聞趙公節，兼盡賓主歡。", "已結門廬望，無令霜雪殘。", "老夫纜亦解，脫粟朝未餐。", "飄蕩兵甲際，幾時懷抱寬。", "漢陽頗寧靜，峴首試考槃。", "當念著白帽，采薇青雲端。"]'),
('d375e62b-149d-4aae-ac75-eb0457e9b7e0','送重表姪王砅評事使南海','杜甫','唐','唐诗','tang','','[]','我之曾祖姑，爾之高祖母。',299,'全唐诗/poet.tang.10000.json','["我之曾祖姑，爾之高祖母。", "爾祖未顯時，歸爲尚書婦。", "隋朝大業末，房杜俱交友長者來在門，荒年自餬口。", "家貧無供給，客位但箕帚。", "俄頃羞頗珍，寂寥人散後。", "入怪鬢髮空，吁嗟爲之久。", "自陳剪髻鬟，鬻市充杯酒。", "上云天下亂，宜與英俊厚。", "向竊窺數公，經綸亦俱有。", "次問最少年，虯髯十八九。", "子等成大名，皆因此人手。", "下云風雲合，龍虎一吟吼。", "願展丈夫雄，得辭兒女醜。", "秦王時在坐，真氣驚戶牖。", "及乎貞觀初，尚書踐台斗。", "夫人常肩輿，上殿稱萬壽。", "六宮師柔順，法則化妃后。", "至尊均嫂叔，盛事垂不朽。", "鳳雛無凡毛，五色非爾曹。", "往者胡作逆，乾坤沸嗷嗷。", "吾客左馮翊，爾家同遁逃。", "爭奪至徒步，塊獨委蓬蒿。", "逗留熱爾腸，十里却呼號。", "自下所騎馬，右持腰間刀。"]'),
('4216bc54-ef1a-4edf-bdcd-059248446dd2','詠懷二首 一','杜甫','唐','唐诗','tang','','[]','人生貴是男，丈夫重天機。',195,'全唐诗/poet.tang.10000.json','["人生貴是男，丈夫重天機。", "未達善一身，得志行所爲。", "嗟余竟轗軻，將老逢艱危。", "胡雛逼神器，逆節同所歸。", "河雒化爲血，公侯草間啼。", "西京復陷沒，翠蓋蒙塵飛。", "萬姓悲赤子，兩宮棄紫微。", "倏忽向二紀，奸雄多是非。", "本朝再樹立，未及貞觀時。", "日給在軍儲，上官督有司。", "高賢迫形勢，豈暇相扶持。", "疲{艹尔}苟懷策，棲屑無所施。", "先王實罪己，愁痛正爲茲。", "歲月不我與，蹉跎病於斯。", "夜看豐城氣，回首蛟龍池。", "齒髮已自料，意深陳苦詞。"]'),
('2066e225-eae6-4861-abd4-f326a958ff93','詠懷二首 二','杜甫','唐','唐诗','tang','','[]','邦危壞法則，聖遠益愁慕。',240,'全唐诗/poet.tang.10000.json','["邦危壞法則，聖遠益愁慕。", "飄颻桂水遊，悵望蒼梧暮。", "潛魚不銜鉤，走鹿無反顧。", "皦皦幽曠心，拳拳異平素。", "衣食相拘閡，朋知限流寓。", "風濤上春沙，千里侵江樹。", "逆行少吉日，時節空復度。", "井竈任塵埃，舟航煩數具。", "牽纏加老病，瑣細隘俗務。", "萬古一死生，胡爲足名數。", "多憂污桃源，拙計泥銅柱。", "未辭炎瘴毒，擺落跋涉懼。", "虎狼窺中原，焉得所歷住。", "葛洪及許靖，避世常此路。", "賢愚誠等差，自愛各馳騖。", "羸瘠且如何，魄奪鍼灸屢。", "擁滯僮僕慵，稽留篙師怒。", "終當挂帆席，天意難告訴。", "南爲祝融客，勉強親杖屨。", "結託老人星，羅浮展衰步。"]'),
('d2cb0132-c27d-4037-abb6-c76f576b866b','送顧八分文學適洪吉州','杜甫','唐','唐诗','tang','','[]','中郎石經後，八分蓋顦顇。',288,'全唐诗/poet.tang.10000.json','["中郎石經後，八分蓋顦顇。", "願侯運鑪錘，筆力破餘地。", "昔在開元中，韓蔡同贔屭。", "玄宗妙其書，是以數子至。", "御札早流傳，揄揚非造次。", "三人竝入直，恩澤各不二。", "願於韓蔡內，辨眼工小字。", "分日示諸王，鉤深法更祕。", "文學與我遊，蕭疎外聲利。", "追隨二十載，浩蕩長安醉。", "高歌卿相宅，文翰飛省寺。", "視我揚馬間，白首不相棄。", "驊騮入窮巷，必脫黃金轡。", "一論朋友難，遲暮敢失墜。", "古來事反覆，相見橫涕泗。", "嚮者玉珂人，誰是青雲器。", "才盡傷形體，病渴污官位。", "故舊獨依然，時危話顛躓。", "我甘多病老，子負憂世志。", "胡爲困衣食，顏色少稱遂。", "遠作辛苦行，順從衆多意。", "舟檝無根蔕，蛟鼉好爲祟。", "況兼水賊繁，特戒風飆駛。", "崩騰戎馬際，往往殺長吏。"]'),
('5ea2d30d-eb58-425b-8b47-97368777a411','上水遣懷','杜甫','唐','唐诗','tang','','[]','我衰太平時，身病戎馬後。',264,'全唐诗/poet.tang.10000.json','["我衰太平時，身病戎馬後。", "蹭蹬多拙爲，安得不皓首。", "驅馳四海內，童稚日餬口。", "但遇新少年，少逢舊親友。", "低顏下色地，故人知善誘。", "後生血氣豪，舉動見老醜。", "窮迫挫曩懷，常如中風走。", "一紀出西蜀，於今向南斗。", "孤舟亂春華，暮齒依蒲柳。", "冥冥九疑葬，聖者骨亦朽。", "蹉跎陶唐人，鞭撻日月久。", "中間屈賈輩，讒毀竟自取。", "鬱沒二悲魂，蕭條猶在否。", "崷崒清湘石，逆行雜林藪。", "篙工密逞巧，氣若酣杯酒。", "歌謳互激遠，回斡明受授。", "善知應觸類，各藉穎脫手。", "古來經濟才，何事獨罕有。", "蒼蒼衆色晚，熊挂玄蛇吼。", "黃羆在樹顛，正爲羣虎守。", "羸骸將何適，履險顏益厚。", "庶與達者論，吞聲混瑕垢。"]'),
('2e957686-af9b-4a48-ac04-e6a7fa807617','遣遇','杜甫','唐','唐诗','tang','','[]','磬折辭主人，開帆駕洪濤。',132,'全唐诗/poet.tang.10000.json','["磬折辭主人，開帆駕洪濤。", "春水滿南國，朱崖雲日高。", "舟子廢寢食，飄風爭所操。", "我行匪利涉，謝爾從者勞。", "石間采蕨女，鬻菜輸官曹。", "丈夫死百役，暮返空邨號。", "聞見事略同，刻剥及錐刀。", "貴人豈不仁，視汝如莠蒿。", "索錢多門戶，喪亂紛嗷嗷。", "奈何黠吏徒，漁奪成逋逃。", "自喜遂生理，花時甘緼袍。"]'),
('d9835b47-0c0b-4f62-be13-c063e47939b6','解憂','杜甫','唐','唐诗','tang','','[]','減米散同舟，路難恩共濟。',72,'全唐诗/poet.tang.10000.json','["減米散同舟，路難恩共濟。", "向來雲濤盤，衆力亦不細。", "呀坑瞥眼過，飛櫓本無蔕。", "得失瞬息間，致遠宜恐泥。", "百慮視安危，分明曩賢計。", "茲理庶可廣，拳拳期勿替。"]'),
('cdd25eec-c677-4c60-a12c-784ae0fa932f','宿鑒石浦','杜甫','唐','唐诗','tang','','[]','早宿賓從勞，仲春江山麗。',84,'全唐诗/poet.tang.10000.json','["早宿賓從勞，仲春江山麗。", "飄風過無時，舟檝敢不繫。", "回塘澹暮色，日沒衆星嘒。", "缺月殘未生，青燈死分翳。", "窮途多俊異，亂世少恩惠。", "鄙夫亦放蕩，草草頻卒歲。", "斯文憂患餘，聖哲垂彖繫。"]'),
('2fae28d1-c350-40ce-8d22-eb8e3011b580','早行','杜甫','唐','唐诗','tang','','[]','歌哭俱在曉，行邁有期程。',72,'全唐诗/poet.tang.10000.json','["歌哭俱在曉，行邁有期程。", "孤舟似昨日，聞見同一聲。", "飛鳥數求食，潛魚亦獨驚。", "前王作網罟，設法害生成。", "碧藻非不茂，高帆終日征。", "干戈未揖讓，崩迫開其情。"]'),
('c64edbb6-04bf-4e6d-bc04-8cd4f0e0df72','過津口','杜甫','唐','唐诗','tang','','[]','南岳自茲近，湘流東逝深。',84,'全唐诗/poet.tang.10000.json','["南岳自茲近，湘流東逝深。", "和風引桂楫，春日漲雲岑。", "回首過津口，而多楓樹林。", "白魚困密網，黃鳥喧嘉音。", "物微限通塞，惻隱仁者心。", "甕餘不盡酒，膝有無聲琴。", "聖賢兩寂寞，眇眇獨開襟。"]'),
('19d92ae8-fd5a-407d-b235-7cdca38e1ca5','次空靈岸','杜甫','唐','唐诗','tang','','[]','沄沄逆素浪，落落展清眺。',96,'全唐诗/poet.tang.10000.json','["沄沄逆素浪，落落展清眺。", "幸有舟檝遲，得盡所歷妙。", "空靈霞石峻，楓栝隱奔峭。", "青春猶無私，白日亦偏照。", "可使營吾居，終焉託長嘯。", "毒瘴未足憂，兵戈滿邊徼。", "嚮者留遺恨，恥爲達人誚。", "迴帆凱賞延，佳處領其要。"]'),
('b7973452-0af7-431c-9b72-bd4b5e391ab0','宿花石戍','杜甫','唐','唐诗','tang','','[]','午辭空靈岑，夕得花石戍。',120,'全唐诗/poet.tang.10000.json','["午辭空靈岑，夕得花石戍。", "岸疏開闢水，木雜今古樹。", "地蒸南風盛，春熱西日暮。", "四序本平分，氣候何迴互。", "茫茫天造間，理亂豈恒數。", "繫舟盤藤輪，策杖古樵路。", "罷人不在村，野圃泉自注。", "柴扉雖蕪沒，農器尚牢固。", "山東殘逆氣，吳楚守王度。", "誰能扣君門，下令減征賦。"]'),
('1100cc25-0c98-41cd-ba29-9d042906fbc7','早發','杜甫','唐','唐诗','tang','','[]','有求常百慮，斯文亦吾病。',144,'全唐诗/poet.tang.10000.json','["有求常百慮，斯文亦吾病。", "以茲朋故多，窮老驅馳幷。", "早行篙師怠，席挂風不正。", "昔人戒垂堂，今則奚奔命。", "濤飜黑蛟躍，日山黃霧映。", "煩促瘴豈侵，頹倚睡未醒。", "僕夫問盥櫛，暮顏靦青鏡。", "隨意簪葛巾，仰慙林花盛。", "側聞夜來寇，幸喜囊中淨。", "艱危作遠客，干請傷直性。", "薇蕨餓首陽，粟馬資歷聘。", "賤子欲適從，疑誤此二柄。"]'),
('bf50e425-add3-4619-9a08-19e391591cf7','次晚洲','杜甫','唐','唐诗','tang','','[]','參錯雲石稠，坡陀風濤壯。',72,'全唐诗/poet.tang.10000.json','["參錯雲石稠，坡陀風濤壯。", "晚洲適知名，秀色固異狀。", "櫂經垂猨把，身在度鳥上。", "擺浪散帙妨，危沙折花當。", "羈離暫愉悅，羸老反惆悵。", "中原未解兵，吾得終疎放。"]'),
('56e89b4c-2998-4cb7-8b96-1e2b7687007f','望嶽','杜甫','唐','唐诗','tang','','["\u8861\u5c71", "\u5199\u5c71", "\u63cf\u5199\u5c71"]','南嶽配朱鳥，秩禮自百王。',168,'全唐诗/poet.tang.10000.json','["南嶽配朱鳥，秩禮自百王。", "歘吸領地靈，鴻洞半炎方。", "邦家用祀典，在德非馨香。", "巡守何寂寥，有虞今則亡。", "洎吾隘世網，行邁越瀟湘。", "渴日絕壁出，漾舟清光旁。", "祝融五峰尊，峰峰次低昴。", "紫蓋獨不朝，爭長嶫相望。", "恭聞魏夫人，羣仙夾翱翔。", "有時五峰氣，散風如飛霜。", "牽迫限修途，未暇杖崇岡。", "歸來覬命駕，沐浴休玉堂。", "三歎問府主，曷以贊我皇。", "牲璧忍衰俗，神其思降祥。"]'),
('d01967b0-571b-4800-90fb-b25872b5651d','湘江宴餞裴二端公赴道州','杜甫','唐','唐诗','tang','','[]','白日照舟師，朱旗散廣川。',180,'全唐诗/poet.tang.10000.json','["白日照舟師，朱旗散廣川。", "羣公餞南伯，肅肅秩初筵。", "鄙人奉末眷，佩服自早年。", "義均骨肉地，懷抱罄所宣。", "盛名富事業，無取媿高賢。", "不以喪亂嬰，保愛金石堅。", "計拙百僚下，氣蘇君子前。", "會合苦不久，哀樂本相纏。", "交遊颯向盡，宿昔浩茫然。", "促觴激百慮，掩抑淚潺湲。", "熱雲集曛黑，缺月未生天。", "白團爲我破，華燭蟠長煙。", "鴰鶡催明星，解袂從此旋。", "上請減兵甲，下請安井田。", "永念病渴老，附書遠山巔。"]'),
('de7404b1-b2f2-4924-b187-b47aa50039d7','清明','杜甫','唐','唐诗','tang','','[]','著處繁花務是日，長沙千人萬人出。',128,'全唐诗/poet.tang.10000.json','["著處繁花務是日，長沙千人萬人出。", "渡頭翠柳豔明眉，爭道朱蹄驕齧膝。", "此都好遊湘西寺，諸將亦自軍中至。", "馬援征行在眼前，葛強親近同心事。", "金鐙下山紅粉晚，牙檣捩柁青樓遠。", "古時喪亂皆可知，人世悲歡暫相遣。", "弟姪雖存不得書，干戈未息苦離居。", "逢迎少壯非吾道，況乃今朝更祓除。"]'),
('32c6a206-1a90-452e-a032-19a7665bceba','風雨看舟前落花戲爲新句','杜甫','唐','唐诗','tang','','[]','江上人家桃樹枝，春寒細雨出疎籬。',96,'全唐诗/poet.tang.10000.json','["江上人家桃樹枝，春寒細雨出疎籬。", "影遭碧水潛勾引，風妒紅花却倒吹。", "吹花困癲傍舟檝，水光風力俱相怯。", "赤憎輕薄遮入懷，珍重分明不來接。", "濕久飛遲半日高，縈沙惹草細於毛。", "蜜蜂蝴蝶生情性，偷眼蜻蜓避百勞。"]'),
('d893768c-c581-4169-8d36-636e552ec09e','岳麓山道林二寺行','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','玉泉之南麓山殊，道林林壑爭盤紆。',256,'全唐诗/poet.tang.10000.json','["玉泉之南麓山殊，道林林壑爭盤紆。", "寺門高開洞庭野，殿脚插入赤沙湖。", "五月寒風冷佛骨，六時天樂朝香爐。", "地靈步步雪山草，僧寶人人滄海珠。", "墖劫宮牆壯麗敵，香廚松道清涼俱。", "連花交響共命鳥，金牓雙迴三足烏。", "方丈涉海費時節，懸圃尋河知有無。", "暮年且喜經行近，春日兼蒙暄暖扶。", "飄然斑白身奚適，傍此煙霞茅可誅。", "桃源人家易制度，橘洲田土仍膏腴。", "潭府邑中甚淳古，太守庭內不喧呼。", "昔遭衰世皆晦迹，今幸樂國養微軀。", "依止老宿亦未晚，富貴功名焉足圖。", "久爲野客尋幽慣，細學何顒免興孤。", "一重一掩吾肺腑，山鳥山花吾友于。", "宋公放逐曾題壁，物色分留與老夫。"]'),
('6b6a1b8f-22a0-4450-81d3-6baf77533e5d','奉送魏六丈佑少府之交廣','杜甫','唐','唐诗','tang','','[]','賢豪贊經綸，功成空名垂。',288,'全唐诗/poet.tang.10000.json','["賢豪贊經綸，功成空名垂。", "子孫不振耀，歷代皆有之。", "鄭公四葉孫，長大常苦飢。", "衆中見毛骨，猶是麒麟兒。", "磊落貞觀事，致君樸直詞。", "家聲蓋六合，行色何其微。", "遇我蒼吾陰，忽驚會面稀。", "議論有餘地，公侯來未遲。", "虛思黃金貴，自笑青雲期。", "長卿久病渴，武帝元同時。", "季子黑貂敝，得無妻嫂欺。", "尚爲諸侯客，獨屈州縣卑。", "南游炎海甸，浩蕩從此辭。", "窮途仗神道，世亂輕土宜。", "解帆歲云暮，可與春風歸。", "出入朱門家，華屋刻蛟螭。", "玉食亞王者，樂張游子悲。", "侍婢豔傾城，綃綺輕霧霏。", "掌中琥珀鍾，行酒雙逶迤。", "新歡繼明燭，梁棟星辰飛。", "兩情顧盼合，珠碧贈于斯。", "上貴見肝膽，下貴不相疑。", "心事披寫間，氣酣達所爲。", "錯揮鐵如意，莫避珊瑚枝。"]'),
('b4af6fc2-0752-4841-88c1-30a208a020a1','別張十三建封','杜甫','唐','唐诗','tang','','[]','嘗讀唐實錄，國家草昧初。',252,'全唐诗/poet.tang.10000.json','["嘗讀唐實錄，國家草昧初。", "劉裴建首義，龍見尚躊躇。", "秦王撥亂姿，一劒總兵符。", "汾晉爲豐沛，暴隋竟滌除。", "宗臣則廟食，後祀何疎蕪。", "彭城英雄種，宜膺將相圖。", "爾惟外曾孫，倜儻汗血駒。", "眼中萬少年，用意盡崎嶇。", "相逢長沙亭，乍問緒業餘。", "乃吾故人子，童丱聊居諸。", "揮手灑衰淚，仰看八尺軀。", "內外名家流，風神蕩江湖。", "范雲堪晚友，嵇紹自不孤。", "擇材征南幕，湖落回鯨魚。", "載感賈生慟，復聞樂毅書。", "主憂急盜賊，師老荒京都。", "舊丘豈稅駕，大廈傾宜扶。", "君臣各有分，管葛本時須。", "雖當霰雪嚴，未覺栝柏枯。", "高義在雲臺，嘶鳴望天衢。", "羽人埽碧海，功業竟何如。"]'),
('1b942cdf-a8ec-4bf9-8c1e-bba47e0c4726','暮秋枉裴道州手札率爾遣興寄近呈蘇渙侍御','杜甫','唐','唐诗','tang','','[]','久客多枉友朋書，素書一月凡一束。',368,'全唐诗/poet.tang.10000.json','["久客多枉友朋書，素書一月凡一束。", "虛名但蒙寒溫問，泛愛不救溝壑辱。", "齒落未是無心人，舌存恥作窮途哭。", "道州手札適復至，紙長要自三過讀。", "盈把那須滄海珠，入懷本倚崑山玉。", "撥棄潭州百斛酒，蕪沒瀟岸千株菊。", "使我晝立煩兒孫，令我夜坐費燈燭。", "憶子初尉永嘉去，紅顏白面花映肉。", "軍符侯印取豈遲，紫燕騄耳行甚速。", "聖朝尚飛戰鬬塵，濟世宜引英俊人。", "黎元愁痛會蘇息，夷狄跋扈徒逡巡。", "授鉞築壇聞意旨，頹綱漏網期彌綸。", "郭欽上書見大計，劉毅答詔驚羣臣。", "他日更僕語不淺，明公論兵氣益振。", "傾壺簫管黑白髮，儛劒霜雪吹青春。", "宴筵曾語蘇季子，後來傑出雲孫比。", "茅齋定王城郭門，藥物楚老漁商市。", "市北肩輿每聯袂，郭南抱甕亦隱几。", "無數將軍西第成，早作丞相東山起。", "鳥雀苦肥秋粟菽，蛟龍欲蟄寒沙水。", "天下鼓角何時休，陣前部曲終日死。", "附書與裴因示蘇，此生已媿須人扶。", "致君堯舜付公等，早據要路思捐軀。"]'),
('6176b224-9362-4973-a649-2f3de578e3ff','奉贈李八丈判官','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','我丈時英特，宗枝神堯後。',180,'全唐诗/poet.tang.10000.json','["我丈時英特，宗枝神堯後。", "珊瑚市則無，騄驥人得有。", "早年見標格，秀氣衝星斗。", "事業富清機，官曹正獨守。", "頃來樹嘉政，皆已傳衆口。", "艱難體貴安，冗長吾敢取。", "區區猶歷試，炯炯更持久。", "討論實解頤，操割紛應手。", "篋書積諷諫，宮闕限奔走。", "入幕未展材，秉鈞孰爲偶。", "所親問淹泊，泛愛惜衰朽。", "垂白亂南翁，委身希北叟。", "真成窮轍鮒，或似喪家狗。", "秋枯洞庭石，風颯長沙柳。", "高興激荆衡，知音爲回首。"]'),
('1a285196-1fe5-4d28-9ba1-dd75e9ce0af2','歲晏行','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5fe7\u56fd\u5fe7\u6c11", "\u51ac\u5929"]','歲云暮矣多北風，瀟湘洞庭白雪中。',144,'全唐诗/poet.tang.10000.json','["歲云暮矣多北風，瀟湘洞庭白雪中。", "漁父天寒網罟凍，莫徭射雁鳴桑弓。", "去年米貴闕軍食，今年米賤大傷農。", "高馬達官厭酒肉，此輩杼軸茅茨空。", "楚人重魚不重鳥，汝休枉殺南飛鴻。", "況聞處處鬻男女，割慈忍愛還租庸。", "往日用錢捉私鑄，今許鉛錫和青銅。", "刻泥爲之最易得，好惡不合長相蒙。", "萬國城頭吹畫角，此曲哀怨何時終。"]'),
('3057f1b2-f2c5-482d-a9c8-b4d1a02125e9','追酬故高蜀州人日見寄','杜甫','唐','唐诗','tang','','[]','自蒙蜀州人日作，不意清詩久零落。',192,'全唐诗/poet.tang.10000.json','["自蒙蜀州人日作，不意清詩久零落。", "今晨散帙眼忽開，迸淚幽吟事如昨。", "嗚呼壯士多慷慨，合沓高名動寥廊。", "歎我悽悽求友篇，感時鬱鬱匡君略。", "錦里春光空爛熳，瑤墀侍臣已冥莫。", "瀟湘水國傍黿鼉，鄠杜秋天失鵰鶚。", "東西南北更誰論，白首扁舟病獨存。", "遙拱北辰纏寇盜，欲傾東海洗乾坤。", "邊塞西蕃最充斥，衣冠南渡多崩奔。", "鼓瑟至今悲帝子，曳裾何處覓王門。", "文章曹植波瀾闊，服食劉安德業尊。", "長笛誰能亂愁思，昭州詞翰與招魂。"]'),
('e263d29c-c7b0-4cd9-a1ef-d7426a8846c8','蘇大侍御訪江浦賦八韻記異','杜甫','唐','唐诗','tang','','[]','龐公不浪出，蘇氏今有之。',84,'全唐诗/poet.tang.10000.json','["龐公不浪出，蘇氏今有之。", "再聞誦新作，突過黃初詩。", "乾坤幾反覆，揚馬宣同時。", "今晨清鏡中，勝食齋房芝。", "余髮喜却變，白間生黑絲。", "昨夜舟火滅，湘娥簾外悲。", "百靈未敢散，風破寒江遲。"]'),
('704cf3c8-46c0-4e9f-b015-7e386bd0eff2','題衡山縣文宣王廟新學堂呈陸宰','杜甫','唐','唐诗','tang','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','旄頭彗紫微，無復俎豆事。',240,'全唐诗/poet.tang.10000.json','["旄頭彗紫微，無復俎豆事。", "金甲相排蕩，青衿一顦顇。", "嗚呼已十年，儒服弊於地。", "征夫不遑息，學者淪素志。", "我行洞庭野，歘得文翁肆。", "侁侁胄子行，若舞風雩至。", "周室宜中興，孔門未應棄。", "是以資雅才，渙然立新意。", "衡山雖小邑，首唱恢大義。", "因見縣尹心，根源舊宮閟。", "講堂非曩搆，大屋加塗墍。", "下可容百人，牆隅亦深邃。", "何必三千徒，始壓戎馬氣。", "林木在庭戶，密幹疊蒼翠。", "有井朱夏時，轆轤凍階戺。", "耳聞讀書聲，殺伐災髣髴。", "故國延歸望，衰顏減愁思。", "南紀改波瀾，西河共風味。", "采詩倦跋涉，載筆尚可記。", "高歌激宇宙，凡百慎失墜。"]'),
('2e0f6fa4-0e8b-449e-bb5d-0ab704403d37','入衡州','杜甫','唐','唐诗','tang','','[]','兵革自久遠，興衰看帝王。',288,'全唐诗/poet.tang.10000.json','["兵革自久遠，興衰看帝王。", "漢儀甚照耀，胡馬何猖狂。", "老將一失律，清邊生戰場。", "君臣忍瑕垢，河岳空金湯。", "重鎮如割據，輕權絕紀綱。", "軍州體不一，寬猛性所將。", "嗟彼苦節士，素于圓鑿方。", "寡妻從爲郡，兀者安堵牆。", "凋弊惜邦本，哀矜存事常。", "旌麾非其任，府庫實過防。", "恕己獨在此，多憂增內傷。", "偏裨限酒肉，卒伍單衣裳。", "元惡迷是似，聚謀洩康莊。", "竟流帳下血，大降湖南殃。", "烈火發中夜，高煙焦上蒼。", "至今分粟帛，殺氣吹沅湘。", "福善理顛倒，明徵天莽茫。", "銷魂避飛鏑，累足穿豺狼。", "隱忍枳棘刺，遷延胝趼瘡。", "遠歸兒侍側，猶乳女在旁。", "久客幸脫免，暮年慙激昴。", "蕭條向水陸，汩沒隨魚商。", "報主身已老，入朝病見妨。", "悠悠委薄俗，鬱鬱回剛腸。"]'),
('d95fc5a3-4109-4871-8615-5d71f248eace','舟中苦熱遣懷奉呈[陽]中丞通簡臺省諸公','杜甫','唐','唐诗','tang','','[]','媿爲湖外客，看此戎馬亂。',288,'全唐诗/poet.tang.10000.json','["媿爲湖外客，看此戎馬亂。", "中夜混黎甿，脫身亦奔竄。", "平生方寸心，反掌帳下難。", "嗚呼殺賢良，不叱白刃散。", "吾非丈夫特，沒齒埋冰炭。", "恥以風病辭，胡然泊湘岸。", "入舟雖苦熱，垢膩可溉灌。", "痛彼道邊人，形骸改昏旦。", "中丞連帥職，封內權得按。", "身當問罪先，縣實諸侯半。", "士卒既輯睦，啓行促精悍。", "似聞上游兵，稍逼長沙館。", "鄰好彼克修，天機自明斷。", "南圖卷雲水，北拱戴霄漢。", "美名光史臣，長策何壯觀。", "驅馳數公子，咸願同伐叛。", "聲節衰有餘，夫何激衰懦。", "偏裨表三上，鹵莽同一貫。", "始謀誰其間，回首增憤惋。", "宗英李端公，守職甚昭煥。", "變通迫脅地，謀畫焉得算。", "王室不肯微，凶徒略無憚。", "此流須卒斬，神器資強幹。", "扣寂豁煩襟，皇天照嗟歎。"]'),
('d64eae7b-aed2-4cad-b8dc-26f8f7dca88d','聶耒陽以僕阻水書致酒肉療飢荒江詩得代懷興盡本韻至縣呈聶令陸路去方田驛四十里舟行一日時屬江漲泊於方田','杜甫','唐','唐诗','tang','','[]','耒陽馳尺素，見訪荒江眇。',156,'全唐诗/poet.tang.10000.json','["耒陽馳尺素，見訪荒江眇。", "義士烈女家，風流吾賢紹。", "昨見狄相孫，許公人倫表。", "前期翰林後，屈跡縣邑小。", "知我礙湍濤，半旬獲浩溔。", "麾下殺元戎，湖邊有飛旐。", "孤舟增鬱鬱，僻路殊悄悄。", "側驚猿猱捷，仰羨鸛鶴矯。", "禮過宰肥羊，愁當置清醥。", "人非西喻蜀，興在北坑趙。", "方行郴岸靜，未話長沙擾。", "崔師乞已至，澧卒用矜少。", "問罪消息真，開顏憩亭沼。"]'),
('883fcd05-a7b4-40f8-8cbe-5d93d4fad76c','冬日洛城北謁玄元皇帝廟','杜甫','唐','唐诗','tang','','[]','配極玄都閟，憑虛禁禦長。',168,'全唐诗/poet.tang.10000.json','["配極玄都閟，憑虛禁禦長。", "守祧嚴具禮，掌節鎮非常。", "碧瓦初寒外，金莖一氣旁。", "山河扶繡戶，日月近雕梁。", "仙李盤根大，猗蘭奕葉光。", "世家遺舊史，道德付今王。", "畫手看前輩，吳生遠擅場。", "森羅移地軸，妙絕動宮牆。", "五聖聯龍衮，千官列雁行。", "冕旒俱秀發，旌斾盡飛揚。", "翠柏深留景，紅棃迥得霜。", "風箏吹玉柱，露井凍銀牀。", "身退卑周室，經傳拱漢皇。", "谷神如不死，養拙更何鄉。"]'),
('d3698389-b134-4532-a9d1-f260824ab33a','贈韋左丞丈','杜甫','唐','唐诗','tang','','[]','左轄頻虛位，今年得舊儒。',120,'全唐诗/poet.tang.10000.json','["左轄頻虛位，今年得舊儒。", "相門韋氏在，經術漢臣須。", "時議歸前烈，天倫恨莫俱。", "鴒原荒宿草，鳳沼接亨衢。", "有客雖安命，衰容豈壯夫。", "家人憂几杖，甲子混泥途。", "不謂矜餘力，還來謁大巫。", "歲寒仍顧遇，日暮且踟躕。", "老驥思千里，飢鷹待一呼。", "君能微感激，亦足慰榛蕪。"]'),
('7bc75da9-c2b9-44c9-afd3-03d6d36f8166','投贈哥舒開府二十韻','杜甫','唐','唐诗','tang','','[]','今代麒麟閣，何人第一功。',240,'全唐诗/poet.tang.10000.json','["今代麒麟閣，何人第一功。", "君王自神武，駕馭必英雄。", "開府當朝傑，論兵邁古風。", "先鋒百勝在，略地兩隅空。", "青海無傳箭，天山早挂弓。", "廉頗仍走敵，魏絳已和戎。", "每惜河湟棄，新兼節制通。", "智謀垂睿想，出入冠諸公。", "日月低秦樹，乾坤繞漢宮。", "胡人愁逐北，宛馬又從東。", "受命邊沙遠，歸來御席同。", "軒墀曾寵鶴，畋獵舊非熊。", "茅土加名數，山河誓始終。", "策行遺戰伐，契合動昭融。", "勳業青冥上，交親氣概中。", "未爲珠履客，已見白頭翁。", "壯節初題柱，生涯獨轉蓬。", "幾年春草歇，今日暮途窮。", "軍事留孫楚，行間識呂蒙。", "防身一長劒，將欲倚崆峒。"]'),
('41815024-acd3-414d-9520-a00f0ceb3edd','上韋左相二十韻','杜甫','唐','唐诗','tang','','[]','鳳曆軒轅紀，龍飛四十春。',240,'全唐诗/poet.tang.10000.json','["鳳曆軒轅紀，龍飛四十春。", "八荒開壽域，一氣轉洪鈞。", "霖雨思賢佐，丹青憶老臣。", "應圖求駿馬，驚代得麒麟。", "沙汰江河濁，調和鼎鼐新。", "韋賢初相漢，范叔已歸秦。", "盛業今如此，傳經固絕倫。", "豫樟深出地，滄海闊無津。", "北斗司喉舌，東方領搢紳。", "持衡留藻鑑，聽履上星辰。", "獨步才超古，餘波德照鄰。", "聰明過管輅，尺牘倒陳遵。", "豈是池中物，由來席上珍。", "廟堂知至理，風俗盡還淳。", "才傑俱登用，愚蒙但隱淪。", "長卿多病久，子夏索居頻。", "回首驅流俗，生涯似衆人。", "巫咸不可問，鄒魯莫容身。", "感激時將晚，蒼茫興有神。", "爲公歌此曲，涕淚在衣巾。"]'),
('bc6d843e-5cf3-4ecb-ab77-d69c7f653445','奉贈太常張卿二十韻','杜甫','唐','唐诗','tang','','[]','方丈三韓外，崑崙萬國西。',240,'全唐诗/poet.tang.10000.json','["方丈三韓外，崑崙萬國西。", "建標天地闊，詣絕古今迷。", "氣得神仙迥，恩承雨露低。", "相門清議衆，儒術大名齊。", "軒冕羅天闕，琳琅識介珪。", "伶官詩必誦，夔樂典猶稽。", "健筆凌鸚鵡，銛鋒瑩鸊鵜。", "友于皆挺拔，公望各端倪。", "通籍踰青瑣，亨衢照紫泥。", "靈虯傳夕箭，歸馬散霜蹄。", "能事聞重譯，嘉謨及遠黎。", "弼諧方一展，班序更何躋。", "適越空顛躓，遊梁竟慘悽。", "謬知終畫虎，微分是醯雞。", "萍泛無休日，桃陰想舊蹊。", "吹噓人所羨，騰躍事仍暌。", "碧海真難涉，青雲不可梯。", "顧深慙鍛煉，才小辱提攜。", "檻束哀猨叫，枝驚夜鵲棲。", "幾時陪羽獵，應指釣璜溪。"]'),
('d4349582-0e9c-466c-8a27-da4663f34029','敬贈鄭諫議十韻','杜甫','唐','唐诗','tang','','[]','諫官非不達，詩義早知名。',120,'全唐诗/poet.tang.10000.json','["諫官非不達，詩義早知名。", "破的由來事，先鋒孰敢爭。", "思飄雲物外，律中鬼神驚。", "毫髮無遺恨，波瀾獨老成。", "野人寧得所，天意薄浮生。", "多病休儒服，冥搜信客旌。", "築居仙縹緲，旅食歲崢嶸。", "使者求顏闔，諸公厭禰衡。", "將期一諾重，歘使寸心傾。", "君見途窮哭，宜憂阮步兵。"]'),
('c9b2022c-a970-4fab-ab56-3b7b55e78096','奉贈鮮于京兆二十韻','杜甫','唐','唐诗','tang','','[]','王國稱多土，賢良復幾人。',240,'全唐诗/poet.tang.10000.json','["王國稱多土，賢良復幾人。", "異才應間出，爽氣必殊倫。", "始見張京兆，宜居漢近臣。", "驊騮開道路，鵰鶚離風塵。", "侯伯知何等，文章實致身。", "奮飛超等級，容易失沈淪。", "脫略磻谿釣，操持郢匠斤。", "雲霄今已逼，台衮更誰親。", "鳳穴雛皆好，龍門客又新。", "義聲紛感激，敗績自逡巡。", "途遠欲何向，天高難重陳。", "學詩猶孺子，鄉賦念嘉賓。", "不得同鼌錯，吁嗟後郄詵。", "計疎疑翰墨，時過憶松筠。", "獻納紆皇眷，中間謁紫宸。", "且隨諸彥集，方凱薄才伸。", "破膽遭前政，陰謀獨秉鈞。", "微生霑忌刻，萬事益酸辛。", "交合丹青地，恩傾雨露辰。", "有儒愁餓死，早晚報平津。"]'),
('32e164a6-e25b-497c-993b-6a2f63e25daa','贈特進汝陽王二十韻','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u611f\u6fc0"]','特進羣公表，天人夙德升。',264,'全唐诗/poet.tang.10000.json','["特進羣公表，天人夙德升。", "霜蹄千里駿，風翮九霄鵬。", "服禮求毫髮，惟忠忘寢興。", "聖情常有眷，朝退若無憑。", "仙醴來浮蟻，奇毛或賜鷹。", "清關塵不雜，中使日相乘。", "晚節嬉遊簡，平居孝義稱。", "自多親棣萼，誰敢問山陵。", "學業醇儒富，辭華哲匠能。", "筆飛鸞聳立，章罷鳳騫騰。", "精理通談笑，忘形向友朋。", "寸長堪繾綣，一諾豈驕矜。", "已忝歸曹植，何知對李膺。", "招要恩屢至，崇重力難勝。", "披霧初歡夕，高秋爽氣澄。", "尊罍臨極浦，鳧雁宿張燈。", "花月窮游宴，炎天避鬱蒸。", "研寒金井水，檐動玉壺冰。", "瓢飲唯三徑，巖棲在百層。", "且持蠡測海，況挹酒如澠。", "鴻寶寧全祕，丹梯庶可凌。", "淮王門有客，終不媿孫登。"]'),
('6a35a5c8-851b-4f2d-aa73-a0fd3b2fd2b6','鄭駙馬宅宴洞中','杜甫','唐','唐诗','tang','','[]','主家陰洞細煙霧，留客夏簟清琅玕。',64,'全唐诗/poet.tang.10000.json','["主家陰洞細煙霧，留客夏簟清琅玕。", "春酒杯濃琥珀薄，冰漿椀碧瑪瑙寒。", "誤疑茅堂過江麓，已入風磴霾雲端。", "自是秦樓壓鄭谷，時聞雜佩聲珊珊。"]'),
('9ac8ab3a-5948-40f6-a552-ac94361bfe7e','李監宅','杜甫','唐','唐诗','tang','','[]','尚覺王孫貴，豪家意頗濃。',48,'全唐诗/poet.tang.10000.json','["尚覺王孫貴，豪家意頗濃。", "屏開金孔雀，褥隱繡芙蓉。", "且食雙魚美，誰看異味重。", "門闌多喜色，女壻近乘龍。"]'),
('10022fe3-6956-474b-b41e-531c8ef9fc16','重題鄭氏東亭','杜甫','唐','唐诗','tang','','[]','華亭入翠微，秋日亂清暉。',48,'全唐诗/poet.tang.10000.json','["華亭入翠微，秋日亂清暉。", "崩石欹山樹，清漣曳水衣。", "紫鱗衝岸躍，蒼隼護巢歸。", "向晚尋征路，殘雲傍馬飛。"]'),
('cf913d33-9ec7-4d06-a644-07dc1adafde1','題張氏隱居二首 一','杜甫','唐','唐诗','tang','','[]','春山無伴獨相求，伐木丁丁山更幽。',64,'全唐诗/poet.tang.10000.json','["春山無伴獨相求，伐木丁丁山更幽。", "澗道餘寒歷冰雪，石門斜日到林丘。", "不貪夜識金銀氣，遠害朝看糜鹿遊。", "乘興杳然迷出處，對君疑是泛虛舟。"]'),
('b8e70521-2e35-4f23-bde4-64b7cc9a0400','題張氏隱居二首 二','杜甫','唐','唐诗','tang','','[]','之子時相見，邀人晚興留。',48,'全唐诗/poet.tang.10000.json','["之子時相見，邀人晚興留。", "霽潭鱣發發，春草鹿呦呦。", "杜酒偏勞勸，張棃不外求。", "前村山路險，歸醉每無愁。"]'),
('2c4755aa-a07d-4e0a-97b6-afdf906a3f00','天寶初南曹小司寇舅於我太夫人堂下累土爲山一匱盈尺以代彼朽木承諸焚香瓷甌甌甚安矣旁植慈竹蓋茲數峰嶔岑嬋娟宛有塵外數致乃不知興之所至而作是詩','杜甫','唐','唐诗','tang','','[]','一匱功盈尺，三峰意出羣。',48,'全唐诗/poet.tang.10000.json','["一匱功盈尺，三峰意出羣。", "望中疑在野，幽處欲生雲。", "慈竹春陰覆，香爐曉勢分。", "惟南將獻壽，佳氣日氛氳。"]'),
('aa5d85b7-f78f-4be4-9419-8453c46dd842','龍門','杜甫','唐','唐诗','tang','','[]','龍門橫野斷，驛樹出城來。',48,'全唐诗/poet.tang.10000.json','["龍門橫野斷，驛樹出城來。", "氣色皇居近，金銀佛寺開。", "往還時屢改，川水日悠哉。", "相閱征途上，生涯盡幾迴。"]'),
('2c762309-e91e-4231-bf09-ab28d7802bd4','奉寄河南韋尹丈人','杜甫','唐','唐诗','tang','','[]','有客傳河尹，逢人問孔融。',120,'全唐诗/poet.tang.10000.json','["有客傳河尹，逢人問孔融。", "青囊仍隱逸，章甫尚西東。", "鼎石分門戶，詞場繼國風。", "尊榮瞻地絕，疎放憶途窮。", "濁酒尋陶令，丹砂訪葛洪。", "江湖漂短褐，霜雪滿飛蓬。", "牢落乾坤大，周流道術空。", "謬慙知薊子，真怯笑揚雄。", "盤錯神明懼，謳歌德義豐。", "尸鄉餘土室，難說祝雞翁。"]'),
('2fb56d01-0200-4756-88c3-e8708cc5ca44','赠李白','杜甫','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba", "\u751f\u6d3b"]','秋來相顧尚飄蓬，未就丹砂媿葛洪。',32,'全唐诗/poet.tang.10000.json','["秋來相顧尚飄蓬，未就丹砂媿葛洪。", "痛飲狂歌空度日，飛揚跋扈爲誰雄。"]'),
('c1499110-9316-46f9-bc91-4a57ec461761','與任城許主簿遊南池','杜甫','唐','唐诗','tang','','[]','秋水通溝洫，城隅進小船。',48,'全唐诗/poet.tang.10000.json','["秋水通溝洫，城隅進小船。", "晚涼看洗馬，森木亂鳴蟬。", "菱熟經時雨，蒲荒八月天。", "晨朝降白露，遙憶舊青氊。"]'),
('eabe74ad-1a13-481d-92e4-9207a59396c5','登兖州城樓','杜甫','唐','唐诗','tang','','[]','東郡趨庭日，南樓縱目初。',48,'全唐诗/poet.tang.10000.json','["東郡趨庭日，南樓縱目初。", "浮雲連海嶽，平野入青徐。", "孤嶂秦碑在，荒城魯殿餘。", "從來多古意，臨眺獨躊躇。"]'),
('6a04ad47-c0ea-461f-aa52-f89454a1b4eb','劉九法曹鄭瑕丘石門宴集','杜甫','唐','唐诗','tang','','[]','秋水清無底，蕭然靜客心。',48,'全唐诗/poet.tang.10000.json','["秋水清無底，蕭然靜客心。", "掾曹乘逸興，鞍馬去相尋。", "能吏逢聊璧，華筵直一金。", "晚來橫吹好，泓下亦龍吟。"]'),
('4a2d7277-b99e-4dec-88ae-2ccd1fe594c9','暫如臨邑至㟙山湖亭奉懷李員外率爾成興','杜甫','唐','唐诗','tang','','[]','野亭逼湖水，歇馬高林間。',48,'全唐诗/poet.tang.10000.json','["野亭逼湖水，歇馬高林間。", "鼉吼風奔浪，魚跳日映山。", "暫遊阻詞伯，却望懷青關。", "靄靄生雲霧，唯應促駕還。"]'),
('fea6e004-d905-4fa0-9f6c-c813af7862e6','對雨書懷走邀許十一簿公','杜甫','唐','唐诗','tang','','[]','東岳雲峰起，溶溶滿太虛。',48,'全唐诗/poet.tang.10000.json','["東岳雲峰起，溶溶滿太虛。", "震雷飜幕燕，驟雨落河魚。", "座對賢人酒，門聽長者車。", "相邀媿泥濘，騎馬到階除。"]'),
('502e6a94-3ae9-4b92-920c-4ab6db1213da','巳上人茅齋','杜甫','唐','唐诗','tang','','[]','巳公茅屋下，可以賦新詩。',47,'全唐诗/poet.tang.10000.json','["巳公茅屋下，可以賦新詩。", "枕簟入林僻，茶瓜留客遲。", "江蓮搖白羽，天棘夢青絲空忝許詢輩，難酬支遁詞。"]'),
('47cb698a-c951-49a4-b17c-032bc033ac87','房兵曹胡馬詩','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u8a00\u5fd7", "\u548f\u7269"]','胡馬大宛名，鋒棱瘦骨成。',48,'全唐诗/poet.tang.10000.json','["胡馬大宛名，鋒棱瘦骨成。", "竹批雙耳峻，風入四蹄輕。", "所向無空闊，真堪託死生。", "驍騰有如此，萬里可橫行。"]'),
('9f190888-4df3-4c51-81d4-42237f9f60fc','畫鷹','杜甫','唐','唐诗','tang','','["\u9898\u753b", "\u5199\u9e1f", "\u52b1\u5fd7", "\u9e1f"]','素練風霜起，蒼鷹畫作殊。',48,'全唐诗/poet.tang.10000.json','["素練風霜起，蒼鷹畫作殊。", "身思狡兔，俱目似愁胡。", "絛旋光堪擿，軒楹勢可呼。", "何當擊凡鳥，毛血灑平蕪。"]'),
('64b7dbe3-a2e2-47a2-9ca0-32413250c0c4','與李十二白同尋范十隱居','杜甫','唐','唐诗','tang','','["\u9690\u9038", "\u53cb\u60c5"]','李侯有佳句，往往似陰鏗。',96,'全唐诗/poet.tang.10000.json','["李侯有佳句，往往似陰鏗。", "余亦東蒙客，憐君如弟兄。", "醉眠秋共被，攜手日同行。", "更想幽期處，還尋北郭生。", "入門高興發，侍立小童清。", "落景聞寒杵，屯雲對古城。", "向來吟橘頌，誰欲討蓴羹。", "不願論簪笏，悠悠滄海情。"]'),
('df4bd05c-a0a4-4c19-8e8d-ada2db3ccbf2','臨邑舍弟書至苦雨黃河泛溢隄防之患簿領所憂因寄此詩用寬其意','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','二儀積風雨，百谷漏波濤。',144,'全唐诗/poet.tang.10000.json','["二儀積風雨，百谷漏波濤。", "聞道洪何坼，遙連滄海高。", "職思憂悄悄，郡國訴嗷嗷。", "舍弟卑棲邑，防川領簿曹。", "尺書前日至，版築不時操。", "難假黿鼉力，空瞻烏鵲毛。", "燕南吹畎畝，濟上沒蓬蒿。", "螺蚌滿近郭，蛟螭乘九臯。", "徐關深水府，碣石小秋毫。", "白屋留孤樹，清天矢萬艘。", "吾衰同泛梗，利涉想蟠桃。", "倚賴天涯釣，猶能掣巨鼇。"]'),
('752f84a6-887d-46e2-b8cf-b18645289e89','過宋員外之問舊莊','杜甫','唐','唐诗','tang','','[]','宋公舊池館，零落守陽阿。',48,'全唐诗/poet.tang.11000.json','["宋公舊池館，零落守陽阿。", "枉道祗從入，吟詩許更過。", "淹留問耆老，寂莫向山河。", "更識將軍樹，悲風日暮多。"]'),
('43ca0051-95f4-4bbb-8171-09b420f4b3e3','夜宴左氏莊','杜甫','唐','唐诗','tang','','[]','風林纖月落，衣露淨琴張。',48,'全唐诗/poet.tang.11000.json','["風林纖月落，衣露淨琴張。", "暗水流花徑，春星帶草堂。", "檢書燒燭短，看劒引杯長。", "詩罷聞吳詠，扁舟意不忘。"]'),
('7d89d155-45a6-432d-a873-d00d2917c366','送蔡希曾都尉還隴右因寄高三十五書記','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','蔡子勇成癖，彎弓西射胡。',120,'全唐诗/poet.tang.11000.json','["蔡子勇成癖，彎弓西射胡。", "健兒寧鬬死，壯士恥爲儒。", "官是先鋒得，材緣挑戰須。", "身輕一鳥過，槍急萬人呼。", "雲幕隨開府，春城赴上都。", "馬頭金狎帢，駝背錦糢糊。", "咫尺雲山路，歸飛青海隅。", "上公猶寵錫，突將且前驅。", "漢使黃河遠，涼州白麥枯。", "因君問消息，好在阮元瑜。"]'),
('571a9d34-1572-42f4-bb50-96c4d88974b4','春日憶李白','杜甫','唐','唐诗','tang','','["\u6000\u5ff5", "\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','白也詩無敵，飄然思不羣。',48,'全唐诗/poet.tang.11000.json','["白也詩無敵，飄然思不羣。", "清新庾開府，俊逸鮑參軍。", "渭北春天樹，江東日暮雲。", "何時一尊酒，重與細論文。"]'),
('e07d2690-df2b-40db-a730-409d0ccf2263','贈陳二補闕','杜甫','唐','唐诗','tang','','[]','世儒多汩沒，夫子獨聲名。',48,'全唐诗/poet.tang.11000.json','["世儒多汩沒，夫子獨聲名。", "獻納開東觀，君王問長卿。", "皁雕寒始急，天馬老能行。", "自到青冥裏，休看白髮生。"]'),
('4a04ffb1-5b06-412e-8cbb-d021aaff929c','寄高三十五書記','杜甫','唐','唐诗','tang','','[]','歎惜高生老，新詩日又多。',48,'全唐诗/poet.tang.11000.json','["歎惜高生老，新詩日又多。", "美名人不及，佳句法如何。", "主將收才子，崆峒足凱歌。", "聞君已朱紱，且得慰蹉跎。"]'),
('707956ea-1893-4d4b-81f0-2d0786647e46','送裴二虯作尉永嘉','杜甫','唐','唐诗','tang','','["\u9001\u522b"]','孤嶼亭何處，天涯水氣中。',48,'全唐诗/poet.tang.11000.json','["孤嶼亭何處，天涯水氣中。", "故人官就此，絕境興誰同。", "隱吏逢梅福，遊山憶謝公。", "扁舟吾已就，把釣待秋風。"]'),
('2646aa96-72fd-42bf-9671-83924dbb4236','城西陂泛舟','杜甫','唐','唐诗','tang','','[]','青蛾皓齒在樓船，橫笛短簫悲遠天。',64,'全唐诗/poet.tang.11000.json','["青蛾皓齒在樓船，橫笛短簫悲遠天。", "春風自信牙檣動，遲日徐看錦纜牽。", "魚吹細浪搖歌扇，燕蹴飛花落舞筵。", "不有小舟能蘯槳，百壺那送酒如泉。"]'),
('3e8e3a49-7135-4e53-94a1-524f3801d40e','贈田九判官','杜甫','唐','唐诗','tang','','[]','崆峒使節上青霄，河隴降王款聖朝。',64,'全唐诗/poet.tang.11000.json','["崆峒使節上青霄，河隴降王款聖朝。", "宛馬總肥春苜蓿，將軍只數漢嫖姚。", "陳留阮瑀誰爭長，京兆田郎早見招。", "麾下賴君才竝入，獨能無意向漁樵。"]'),
('03b5716c-b741-411d-a388-b2f3fab090e1','贈獻納使起居田舍人','杜甫','唐','唐诗','tang','','[]','獻納司存雨露邊，地分清切任才賢。',64,'全唐诗/poet.tang.11000.json','["獻納司存雨露邊，地分清切任才賢。", "舍人退食收封事，宮女開函近御筵。", "曉漏追飛青瑣闥，晴窗點檢白雲篇。", "揚雄更有河東賦，唯待吹噓送上天。"]'),
('e3a5cf75-a207-4e84-8579-c48c16317966','送韋書記赴安西','杜甫','唐','唐诗','tang','','[]','夫子歘通貴，雲泥相望懸。',48,'全唐诗/poet.tang.11000.json','["夫子歘通貴，雲泥相望懸。", "白頭無藉在，朱紱有哀憐。", "書記赴三捷，公車留二年。", "欲浮江海去，此別意蒼然。"]'),
('1e325ad6-d00a-4ed2-8d87-849bb63a2efa','陪鄭廣文遊何將軍山林十首 一','杜甫','唐','唐诗','tang','','[]','不識南塘路，今知第五橋。',48,'全唐诗/poet.tang.11000.json','["不識南塘路，今知第五橋。", "名園依綠水，野竹上青霄。", "谷口舊相得，濠梁同見招。", "平生爲幽興，未惜馬蹄遙。"]'),
('7881ef4b-b7ae-4a62-9681-2ff7050dfb20','陪鄭廣文遊何將軍山林十首 二','杜甫','唐','唐诗','tang','','[]','百頃風潭上，千重夏木清。',48,'全唐诗/poet.tang.11000.json','["百頃風潭上，千重夏木清。", "卑枝低結子，接葉暗巢鶯。", "鮮鯽銀絲膾，香芹碧澗羹。", "飜疑柁樓底，晚飯越中行。"]'),
('51ac3a6e-d8ae-4286-b3f0-9b6448e1b138','陪鄭廣文遊何將軍山林十首 三','杜甫','唐','唐诗','tang','','[]','萬里戎王子，何年別月支。',48,'全唐诗/poet.tang.11000.json','["萬里戎王子，何年別月支。", "異花開絕域，滋蔓匝清池。", "漢使徒空到，神農竟不知。", "露飜兼雨打，開坼日離披。"]'),
('d34ad9f8-018c-4f05-b19a-8fd388b39165','陪鄭廣文遊何將軍山林十首 四','杜甫','唐','唐诗','tang','','[]','旁舍連高竹，疎籬帶晚花。',48,'全唐诗/poet.tang.11000.json','["旁舍連高竹，疎籬帶晚花。", "碾渦深沒馬，藤蔓曲藏蛇。", "詞賦工無益，山林跡未賒。", "盡捻書籍賣，來問爾東家。"]'),
('acddc789-88a1-42a4-a12a-f5a6830c7432','陪鄭廣文遊何將軍山林十首 五','杜甫','唐','唐诗','tang','','[]','賸水滄江破，殘山碣石開。',48,'全唐诗/poet.tang.11000.json','["賸水滄江破，殘山碣石開。", "綠垂風折筍，紅綻雨肥梅。", "銀甲彈箏用，金魚換酒來。", "興移無灑埽，隨意坐莓苔。"]'),
('2f6db6d9-e276-4da3-9e9e-06d1d3f75bd2','陪鄭廣文遊何將軍山林十首 六','杜甫','唐','唐诗','tang','','[]','風磴吹陰雪，雲門吼瀑泉。',48,'全唐诗/poet.tang.11000.json','["風磴吹陰雪，雲門吼瀑泉。", "酒醒思臥簟，衣冷欲裝綿。", "野老來看客，河魚不取錢。", "只疑淳樸處，自有一山川。"]'),
('5226fbe5-7035-4c09-9baa-ce4fc9009bfa','陪鄭廣文遊何將軍山林十首 七','杜甫','唐','唐诗','tang','','[]','棘樹寒雲色，茵蔯春藕香。',48,'全唐诗/poet.tang.11000.json','["棘樹寒雲色，茵蔯春藕香。", "脆添生菜美，陰益食單涼。", "野鶴清晨出，山精白日藏。", "石林蟠水府，百里獨蒼蒼。"]'),
('29be806c-b27a-4050-a2a6-8c69a1eebf5f','陪鄭廣文遊何將軍山林十首 八','杜甫','唐','唐诗','tang','','[]','憶過楊柳渚，走馬定昆池。',48,'全唐诗/poet.tang.11000.json','["憶過楊柳渚，走馬定昆池。", "醉把青荷葉，狂遺白接䍦。", "刺船思郢客，解水乞吳兒。", "坐對秦山晚，江湖興頗隨。"]'),
('14b59e7e-8085-40bd-89eb-9c83003ce625','陪鄭廣文遊何將軍山林十首 九','杜甫','唐','唐诗','tang','','[]','牀上書連屋，階前樹拂雲。',48,'全唐诗/poet.tang.11000.json','["牀上書連屋，階前樹拂雲。", "將軍不好武，稚子總能文。", "醒酒微風入，聽詩靜夜分。", "絺衣挂蘿薜，涼月白紛紛。"]'),
('6ef037cc-4fa7-4feb-955a-a454ca3713a2','陪鄭廣文遊何將軍山林十首 十','杜甫','唐','唐诗','tang','','[]','幽意忽不愜，歸期無奈何。',48,'全唐诗/poet.tang.11000.json','["幽意忽不愜，歸期無奈何。", "出門流水注，回首白雲多。", "自笑燈前舞，誰憐醉後歌。", "祗應與朋好，風雨亦來過。"]'),
('46381f44-e44c-44e1-8d3d-fa0313757063','重過何氏五首 一','杜甫','唐','唐诗','tang','','[]','問訊東橋竹，將軍有報書。',48,'全唐诗/poet.tang.11000.json','["問訊東橋竹，將軍有報書。", "倒衣還命駕，高枕乃吾廬。", "花妥鶯捎蝶，溪喧獺趁魚。", "重來休沐地，真作野人居。"]'),
('dcac42cf-0623-45f1-98d7-9f710dec8863','重過何氏五首 二','杜甫','唐','唐诗','tang','','[]','山雨尊仍在，沙沈榻未移。',48,'全唐诗/poet.tang.11000.json','["山雨尊仍在，沙沈榻未移。", "犬迎曾宿客，鴉護落巢兒。", "雲薄翠微寺，天清黃子陂。", "向來幽興極，步屣過東籬。"]'),
('66369c6e-ff5b-49e3-b2c9-4ec90030ee6f','重過何氏五首 三','杜甫','唐','唐诗','tang','','[]','落日平臺上，春風啜茗時。',48,'全唐诗/poet.tang.11000.json','["落日平臺上，春風啜茗時。", "石闌斜點筆，桐葉坐題詩。", "翡翠鳴衣桁，蜻蜓立釣絲。", "自今幽興熟，來往亦無期。"]'),
('5730ab68-4012-414b-916a-748fc81583e3','重過何氏五首 四','杜甫','唐','唐诗','tang','','[]','頗怪朝參嬾，應耽野趣長。',48,'全唐诗/poet.tang.11000.json','["頗怪朝參嬾，應耽野趣長。", "雨拋金鎖甲，苔臥綠沈槍。", "手自移蒲柳，家纔足稻粱。", "看君用幽意，白日到羲皇。"]'),
('2b147516-e870-4934-96da-02ee91b0046b','重過何氏五首 五','杜甫','唐','唐诗','tang','','[]','到此應常宿，相留可判年。',48,'全唐诗/poet.tang.11000.json','["到此應常宿，相留可判年。", "蹉跎暮容色，悵望好林泉。", "何路霑微祿，歸山買薄田。", "斯遊恐不遂，把酒意茫然。"]'),
('c2e105eb-bf47-46ea-b2d3-fc6e0613e869','冬日有懷李白','杜甫','唐','唐诗','tang','','[]','寂寞書齋裏，終朝獨爾思。',48,'全唐诗/poet.tang.11000.json','["寂寞書齋裏，終朝獨爾思。", "更尋嘉樹傳，不忘角弓詩。", "短褐風霜入，還丹日月遲。", "未因乘興去，空有鹿門期。"]'),
('75f08978-8abb-4b09-82b7-30f90ce56d68','杜位宅守歲','杜甫','唐','唐诗','tang','','[]','守歲阿戎家，椒盤已頌花。',48,'全唐诗/poet.tang.11000.json','["守歲阿戎家，椒盤已頌花。", "盍簪喧櫪馬，列炬散林鴉。", "四十明朝過，飛騰暮景斜。", "誰能更拘束，爛醉是生涯。"]'),
('a2e67053-fb77-4b11-8dde-9c726aaa7ec0','與鄠縣源大少府宴渼陂','杜甫','唐','唐诗','tang','','[]','應爲四陂好，金錢罄一餐。',48,'全唐诗/poet.tang.11000.json','["應爲四陂好，金錢罄一餐。", "飯抄雲子白，瓜嚼水精寒。", "無計迴船下，空愁避酒難。", "主人情爛熳，持荅翠琅玕。"]'),
('8c811630-909b-4aa3-ac92-db90021e132d','崔駙馬山亭宴集','杜甫','唐','唐诗','tang','','[]','蕭史幽棲地，林間蹋鳳毛。',48,'全唐诗/poet.tang.11000.json','["蕭史幽棲地，林間蹋鳳毛。", "洑流何處入，亂石閉門高。", "客醉揮金椀，詩成得繡袍。", "清秋多宴會，終日困香醪。"]'),
('81c3df1e-6db1-43ab-8b2e-1fa9490f6531','九日楊奉化會白水崔明府','杜甫','唐','唐诗','tang','','["\u91cd\u9633\u8282"]','今日潘懷縣，同時陸浚儀。',48,'全唐诗/poet.tang.11000.json','["今日潘懷縣，同時陸浚儀。", "坐開桑落酒，來把菊花枝。", "天宇清霜淨，公堂宿霧披。", "晚酣留客舞，鳧舄共差池。"]'),
('e49af687-a500-425c-a9cb-0e7816bbb04e','贈翰林張四學士','杜甫','唐','唐诗','tang','','[]','翰林逼華蓋，鯨力破滄溟。',95,'全唐诗/poet.tang.11000.json','["翰林逼華蓋，鯨力破滄溟。", "天上張公子，宮中漢客星賦詩拾翠殿，佐酒望雲亭。", "紫誥仍兼綰，黃麻似六經。", "內分金帶赤，恩與荔枝青。", "無復隨高鳳，空餘泣聚螢。", "此生任春草，垂老獨漂萍。", "儻憶山陽會，悲歌在一聽。"]'),
('3f847798-230a-4e1b-946f-5ae62cfad00b','送張二十參軍赴蜀州因呈楊五侍御','杜甫','唐','唐诗','tang','','[]','好去張公子，通家別恨添。',48,'全唐诗/poet.tang.11000.json','["好去張公子，通家別恨添。", "兩行秦樹直，萬點蜀山尖。", "御史新驄馬，參軍舊紫髯。", "皇華吾善處，於汝定無嫌。"]'),
('86d084a1-6ccd-49a1-8757-cebc29ef13e8','陪諸貴公子丈八溝攜妓納涼晚際遇雨二首 一','杜甫','唐','唐诗','tang','','[]','落日放船好，輕風生浪遲。',48,'全唐诗/poet.tang.11000.json','["落日放船好，輕風生浪遲。", "竹深留客處，荷淨納涼時。", "公子調冰水，佳人雪藕絲。", "片雲頭上黑，應是雨催詩。"]'),
('faada38b-ba84-4066-b426-10159e66011b','陪諸貴公子丈八溝攜妓納涼晚際遇雨二首 二','杜甫','唐','唐诗','tang','','[]','雨來霑席上，風急打船頭。',48,'全唐诗/poet.tang.11000.json','["雨來霑席上，風急打船頭。", "越女紅帬濕，燕姬翠黛愁。", "纜侵隄柳繫，幔宛浪花浮。", "歸路飜蕭颯，陂塘五月秋。"]'),
('b188d669-90b1-4227-8fed-d725bde3105d','白水明府舅宅喜雨','杜甫','唐','唐诗','tang','','[]','吾舅政如此，古人誰復過。',48,'全唐诗/poet.tang.11000.json','["吾舅政如此，古人誰復過。", "碧山晴又濕，白水雨偏多。", "精禱既不昧，歡娛將謂何。", "湯年旱頗甚，今日醉弦歌。"]'),
('ab5ba449-0413-41db-ae33-c2354bc02526','陪李金吾花下飲','杜甫','唐','唐诗','tang','','[]','勝地初相引，余行得自娛。',48,'全唐诗/poet.tang.11000.json','["勝地初相引，余行得自娛。", "見輕吹鳥毳，隨意數花鬚。", "細草稱偏坐，香醪嬾再酤。", "醉歸應犯夜，可怕李金吾。"]'),
('2ff8d911-4b5b-4128-b35d-7714115f6db0','贈高式顏','杜甫','唐','唐诗','tang','','[]','昔別是何處，相逢皆老夫。',48,'全唐诗/poet.tang.11000.json','["昔別是何處，相逢皆老夫。", "故人還寂寞，削跡共艱虞。", "自失論文友，空知賣酒壚。", "平生飛動意，見爾不能無。"]'),
('d40a3095-f2e8-4ee3-9f18-b8dba56e4131','贈比部蕭郎中十兄','杜甫','唐','唐诗','tang','','[]','有美生人傑，由來積德門。',120,'全唐诗/poet.tang.11000.json','["有美生人傑，由來積德門。", "漢朝丞相系，梁日帝王孫。", "蘊藉爲郎久，魁梧秉哲尊。", "詞華傾後輩，風雅藹孤騫。", "宅相榮姻戚，兒童惠討論。", "見知真自幼，謀拙醜諸昆。", "漂蕩雲天闊，沈埋日月奔。", "致君時已晚，懷古意空存。", "中散山陽鍛，愚公野谷村。", "寧紆長者轍，歸老任乾坤。"]'),
('b5afe65e-41f6-4c7a-8bc7-ff3f024937cb','九日曲江','杜甫','唐','唐诗','tang','','[]','綴席茱萸好，浮舟菡萏衰。',48,'全唐诗/poet.tang.11000.json','["綴席茱萸好，浮舟菡萏衰。", "季秋時欲半，九日意兼悲。", "江水清源曲，荆門此路疑。", "晚來高興盡，搖蕩菊花期。"]'),
('aac265f0-080e-4861-8308-80d102a6c63d','承沈八丈東美除膳部員外阻雨未遂馳賀奉寄此詩','杜甫','唐','唐诗','tang','','[]','今日西京掾，多除內省郎。',120,'全唐诗/poet.tang.11000.json','["今日西京掾，多除內省郎。", "通家惟沈氏，謁帝似馮唐。", "詩律羣公問，儒門舊史長。", "清秋便寓直，列宿頓輝光。", "未暇申宴慰，含情空激揚。", "司存何所比，膳部默悽傷。", "貧賤人事略，經過霖潦妨。", "禮同諸父長，恩豈布衣忘。", "天路牽騏驥，雲臺引棟梁。", "徒懷貢公喜，颯颯鬢毛蒼。"]'),
('8bbcdf98-b24e-4e1f-8b61-54fe765ce200','奉留贈集賢院崔于二學士','杜甫','唐','唐诗','tang','','[]','昭代將垂白，途窮乃叫閽。',120,'全唐诗/poet.tang.11000.json','["昭代將垂白，途窮乃叫閽。", "氣衝星象表，詞感帝王尊。", "天老書題目，春宮驗討論。", "倚風遺鶂路，隨水到龍門。", "竟與蛟螭雜，空聞燕雀喧。", "青冥猶契闊，陵厲不飛飜。", "儒術誠難起，家聲庶已存。", "故山多藥物，勝概憶桃源。", "欲整還鄉斾，長懷禁掖垣。", "謬稱三賦在，難述二公恩。"]'),
('501c3090-1ab5-4532-bbe4-533572f8ed66','故武衛將軍輓歌三首 一','杜甫','唐','唐诗','tang','','[]','嚴警當寒夜，前軍落大星。',48,'全唐诗/poet.tang.11000.json','["嚴警當寒夜，前軍落大星。", "壯夫思感決，哀詔惜精靈。", "王者今無戰，書生已勒銘。", "封侯意疎闊，編簡爲誰青。"]'),
('cf8aa5b6-2baa-45ef-af3c-7a1f04138f8a','故武衛將軍輓歌三首 二','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','舞劒過人絕，鳴弓射獸能。',48,'全唐诗/poet.tang.11000.json','["舞劒過人絕，鳴弓射獸能。", "銛鋒行愜順，猛噬失蹻騰。", "赤羽千夫膳，黃河十月冰。", "橫行沙漠外，神速至今稱。"]'),
('e7d5c37f-03d1-4795-a503-3461c7c43c7b','故武衛將軍輓歌三首 三','杜甫','唐','唐诗','tang','','[]','哀輓青門去，新阡絳水遙。',48,'全唐诗/poet.tang.11000.json','["哀輓青門去，新阡絳水遙。", "路人紛雨泣，天意颯風飄。", "部曲精仍銳，匈奴氣不驕。", "無由覩雄略，大樹日蕭蕭。"]'),
('93422ee0-895d-4778-a7f1-269cedb9bb6b','官定後戲贈','杜甫','唐','唐诗','tang','','[]','不作河西尉，淒涼爲折腰。',48,'全唐诗/poet.tang.11000.json','["不作河西尉，淒涼爲折腰。", "老夫怕趨走，率府且逍遙。", "耽酒須微祿，狂歌託聖朝。", "故山歸興盡，回首向風飆。"]'),
('3a06af16-eafc-421a-b261-97245ef0dbf5','九日藍田崔氏莊','杜甫','唐','唐诗','tang','','["\u91cd\u9633\u8282", "\u60b2\u79cb"]','老去悲秋強自寬，興來今日盡君歡。',64,'全唐诗/poet.tang.11000.json','["老去悲秋強自寬，興來今日盡君歡。", "羞將短髮還吹帽，笑倩旁人爲正冠。", "藍水遠從千澗落，玉山高並兩峰寒。", "明年此會知誰健，醉把茱萸子細看。"]'),
('0c4c451c-c3be-4ded-8d6d-83ae2210a157','崔氏東山草堂','杜甫','唐','唐诗','tang','','[]','愛汝玉山草堂靜，高秋爽氣相鮮新。',64,'全唐诗/poet.tang.11000.json','["愛汝玉山草堂靜，高秋爽氣相鮮新。", "有時自發鐘磬響，落日更見漁樵人。", "盤剝白鴉谷口栗，飯煮青泥坊底芹。", "何爲西莊王給事，柴門空閉鏁松筠。"]'),
('b5246cf9-130a-4cd8-afc5-ca0f33a16b32','對雪','杜甫','唐','唐诗','tang','','["\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','戰哭多新鬼，愁吟獨老翁。',48,'全唐诗/poet.tang.11000.json','["戰哭多新鬼，愁吟獨老翁。", "亂雲低薄暮，急雪舞迴風。", "瓢棄尊無綠，爐存火似紅。", "數州消息斷，愁坐正書空。"]'),
('59c7eaa9-3c05-4857-8cff-10376706ccb9','月夜','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u5973\u5b50", "\u4e94\u8a00\u5f8b\u8bd7", "\u9ad8\u4e2d\u53e4\u8bd7", "\u6708\u4eae"]','今夜鄜州月，閨中只獨看。',48,'全唐诗/poet.tang.11000.json','["今夜鄜州月，閨中只獨看。", "遙憐小兒女，未解憶長安。", "香霧雲鬟濕，清輝玉臂寒。", "何時倚虛幌，雙照淚痕乾。"]'),
('f265b866-4ac3-4deb-aea5-c07157043755','遣興','杜甫','唐','唐诗','tang','','[]','驥子好男兒，前年學語時。',72,'全唐诗/poet.tang.11000.json','["驥子好男兒，前年學語時。", "問知人客姓，誦得老夫詩。", "世亂憐渠小，家貧仰母慈。", "鹿門攜不遂，雁足繫難期。", "天地軍麾滿，山河戰角悲。", "儻歸免相失，見日敢辭遲。"]'),
('5846db55-7817-45af-bdf7-f4bd4eea5386','元日寄韋氏妹','杜甫','唐','唐诗','tang','','[]','近聞韋氏妹，迎在漢鍾離。',48,'全唐诗/poet.tang.11000.json','["近聞韋氏妹，迎在漢鍾離。", "郎伯殊方鎮，京華舊國移。", "春城回北斗，郢樹發南枝。", "不見朝正使，啼痕滿面垂。"]'),
('e9e6425c-6c14-4f69-8694-87a8b96a43de','春望','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u5fe7\u56fd\u5fe7\u6c11", "\u7231\u56fd", "\u4e94\u8a00\u5f8b\u8bd7", "\u521d\u4e2d\u53e4\u8bd7"]','國破山河在，城春草木深。',48,'全唐诗/poet.tang.11000.json','["國破山河在，城春草木深。", "感時花濺淚，恨別鳥驚心。", "烽火連三月，家書抵萬金。", "白頭搔更短，渾欲不勝簪。"]'),
('08dc6c3a-07bc-479a-9bbe-4225ff0352e6','憶幼子','杜甫','唐','唐诗','tang','','[]','驥子春猶隔，鶯歌暖正繁。',48,'全唐诗/poet.tang.11000.json','["驥子春猶隔，鶯歌暖正繁。", "別離驚節換，聰慧與誰論。", "澗水空山道，柴門老樹村。", "憶渠愁只睡，炙背俯晴軒。"]'),
('9482c243-95f3-4929-a211-9081efcc386d','一百五日夜對月','杜甫','唐','唐诗','tang','','["\u601d\u5ff5", "\u79bb\u6101"]','無家對寒食，有淚如金波。',48,'全唐诗/poet.tang.11000.json','["無家對寒食，有淚如金波。", "斫却月中桂，清光應更多。", "仳離放紅蘂，想像嚬青蛾。", "牛女漫愁思，秋期猶渡河。"]'),
('bcb3ac74-1891-4dc4-b4cf-902bfb557786','喜達行在所三首 一','杜甫','唐','唐诗','tang','','[]','西憶岐陽信，無人遂却回。',48,'全唐诗/poet.tang.11000.json','["西憶岐陽信，無人遂却回。", "眼穿當落日，心死著寒灰。", "霧樹行相引，蓮峰望忽開。", "所親驚老瘦，辛苦賊中來。"]'),
('42a236eb-db9d-42f2-a3ae-e415a4e48ebe','喜達行在所三首 二','杜甫','唐','唐诗','tang','','[]','愁思胡笳夕，淒涼漢苑春。',48,'全唐诗/poet.tang.11000.json','["愁思胡笳夕，淒涼漢苑春。", "生還今日事，間道暫時人。", "司隸章初覩，南陽氣已新。", "喜心飜倒極，嗚咽淚霑巾。"]'),
('8aa47a3d-a824-4c5d-866d-337bbf9d386b','喜達行在所三首 三','杜甫','唐','唐诗','tang','','[]','死去憑誰報，歸來始自憐。',48,'全唐诗/poet.tang.11000.json','["死去憑誰報，歸來始自憐。", "猶瞻太白雪，喜遇武功天。", "影靜千官裏，心蘇七校前。", "今朝漢社稷，新數中興年。"]'),
('6f23b1cc-5071-4fb2-95c2-a2e94c7016e9','得家書','杜甫','唐','唐诗','tang','','[]','去憑遊客寄，來爲附家書。',96,'全唐诗/poet.tang.11000.json','["去憑遊客寄，來爲附家書。", "今日知消息，他鄉且舊居。", "熊兒幸無恙，驥子最憐渠。", "臨老羈孤極，傷時會合疎。", "二毛趨帳殿，一命侍鸞輿。", "北闕妖氛滿，西郊白露初。", "涼風新過雁，秋雨欲生魚。", "農事空山裏，眷言終荷鋤。"]'),
('f4836a0b-ba8d-4561-adfe-a7b862c42f5f','奉贈嚴八閣老','杜甫','唐','唐诗','tang','','[]','扈聖登黃閣，明公獨妙年。',48,'全唐诗/poet.tang.11000.json','["扈聖登黃閣，明公獨妙年。", "蛟龍得雲雨，鵰鶚在秋天。", "客禮容疎放，官曹可接聯。", "新詩句句好，應任老夫傳。"]'),
('e3c12144-2047-423c-82ab-59ac817de071','奉送郭中丞兼太僕卿充隴右節度使三十韻','杜甫','唐','唐诗','tang','','[]','詔發西山將，秋屯隴右兵。',288,'全唐诗/poet.tang.11000.json','["詔發西山將，秋屯隴右兵。", "淒涼餘部曲，燀赫舊家聲。", "鵰鶚乘時去，驊騮顧主鳴。", "艱難須上策，容易即前程。", "斜日當軒蓋，高風卷斾旌。", "松悲天水冷，沙亂雪山清。", "和虜猶懷惠，防邊不敢驚。", "古來於異域，鎮靜示專征。", "燕薊奔封豕，周秦觸駭鯨。", "中原何慘黷，餘孽尚縱橫。", "箭入昭陽殿，笳吟細柳營。", "內人紅袖泣，王子白衣行。", "宸極祅星動，園陵殺氣平。", "空餘金椀出，無復繐帷輕。", "毀廟天飛雨，焚宮火徹明。", "罘罳朝共落，棆桷夜同傾。", "三月師逾整，羣胡勢就烹。", "瘡痍親接戰，勇決冠垂成。", "妙譽期元宰，殊恩且列卿。", "幾時迴節鉞，戮力埽欃槍。", "圭竇三千士，雲梯七十城。", "恥非齊說客，祗似魯諸生。", "通籍微班忝，周行獨坐榮。", "隨肩趨漏刻，短髮寄簪纓。"]'),
('79409b2e-e571-44e6-a49d-46f40cbbbc2f','送楊六判官使西蕃','杜甫','唐','唐诗','tang','','[]','送遠秋風落，西征海氣寒。',144,'全唐诗/poet.tang.11000.json','["送遠秋風落，西征海氣寒。", "帝京氛祲滿，人世別離難。", "絕域遙懷怒，和親願結歡。", "敕書憐贊普，兵甲望長安。", "宣命前程急，惟良待士寬。", "子雲清自守，今日起爲官。", "垂淚方投筆，傷時即據鞍。", "儒衣山鳥怪，漢節野童看。", "邊酒排金醆，夷歌捧玉盤。", "草輕蕃馬健，雪重拂廬乾。", "慎爾參籌畫，從茲正羽翰。", "歸來權可取，九萬一朝摶。"]'),
('a35f4223-3156-4912-a5f5-037679ced8a3','月','杜甫','唐','唐诗','tang','','[]','天上秋期近，人間月影清。',48,'全唐诗/poet.tang.11000.json','["天上秋期近，人間月影清。", "入河蟾不沒，擣藥兔長生。", "只益丹心苦，能添白髮明。", "干戈知滿地，休照國西營。"]'),
('f35c4d3c-1141-4821-9c39-99a480960d98','留別賈嚴二閣老兩院補闕','杜甫','唐','唐诗','tang','','[]','田園須蹔往，戎馬惜離羣。',48,'全唐诗/poet.tang.11000.json','["田園須蹔往，戎馬惜離羣。", "去遠留詩別，愁多任酒醺。", "一秋常苦雨，今日始無雲。", "山路時吹角，那堪處處聞。"]'),
('2fc53dc2-02b8-4730-9591-f38761ec08c4','晚行口號','杜甫','唐','唐诗','tang','','[]','三川不可到，歸路晚山稠。',48,'全唐诗/poet.tang.11000.json','["三川不可到，歸路晚山稠。", "落雁浮寒水，飢烏集戍樓。", "市朝今日異，喪亂幾時休。", "遠媿梁江總，還家尚黑頭。"]'),
('bae42ddc-7641-43fc-8edc-882c1f6f53d0','獨酌成詩','杜甫','唐','唐诗','tang','','[]','燈花何太喜，酒綠正相親。',48,'全唐诗/poet.tang.11000.json','["燈花何太喜，酒綠正相親。", "醉裏從爲客，詩成覺有神。", "兵戈猶在眼，儒術豈謀身。", "共被微官縛，低頭媿野人。"]'),
('e11ed7c1-450d-4504-8a6b-a040475e92d9','行次昭陵','杜甫','唐','唐诗','tang','','[]','舊俗疲庸主，羣雄問獨夫。',144,'全唐诗/poet.tang.11000.json','["舊俗疲庸主，羣雄問獨夫。", "讖歸龍鳳質，威定虎狼都。", "天屬尊堯典，神功協禹謨。", "風雲隨絕足，日月繼高衢。", "文物多師古，朝廷半老儒。", "直詞寧戮辱，賢路不崎嶇。", "往者災猶降，蒼生喘未蘇。", "指麾安率土，盪滌撫洪爐。", "壯士悲陵邑，幽人拜鼎湖。", "玉衣晨自舉，鐵馬汗常趨。", "松柏瞻虛殿，塵沙立暝途。", "寂寥開國日，流恨滿山隅。"]'),
('a68b8610-8269-46fa-b015-d367d71e04eb','重經昭陵','杜甫','唐','唐诗','tang','','[]','草昧英雄起，謳歌曆數歸。',72,'全唐诗/poet.tang.11000.json','["草昧英雄起，謳歌曆數歸。", "風塵三尺劒，社稷一戎衣。", "翼亮貞文德，丕承戢武威。", "聖圖天廣大，宗祀日光輝。", "陵寢盤空曲，熊羆守翠微。", "再窺松柏路，還見五雲飛。"]'),
('fbb109b7-3b66-4f82-a111-97892b26fa7a','喜聞官軍已臨賊境二十韻','杜甫','唐','唐诗','tang','','[]','胡虜潛京縣，官軍擁賊壕。',240,'全唐诗/poet.tang.11000.json','["胡虜潛京縣，官軍擁賊壕。", "鼎魚猶假息，穴蟻欲何逃。", "帳殿羅玄冕，轅門照白袍。", "秦山當警蹕，漢苑入旌旄。", "路失羊腸險，雲橫雉尾高。", "五原空壁壘，八水散風濤。", "今日看天意，遊魂貸爾曹。", "乞降那更得，尚詐莫徒勞。", "元帥歸龍種，司空握豹韜。", "前軍蘇武節，左將呂虔刀。", "兵氣回飛鳥，威聲沒巨鼇。", "戈鋋開雪色，弓矢尚秋毫。", "天步艱方盡，時和運更遭。", "誰云遺毒螫，已是沃腥臊。", "睿想丹墀近，神行羽衛牢。", "花門騰絕漠，拓羯渡臨洮。", "此輩感恩至，羸俘何足操。", "鋒先衣染血，騎突劒吹毛。", "喜覺都城動，悲憐子女號。", "家家賣釵釧，只待獻春醪。"]'),
('b755f069-b0a4-48e4-9a32-ccd5760c8145','收京三首 一','杜甫','唐','唐诗','tang','','[]','仙仗離丹極，妖星照玉除。',48,'全唐诗/poet.tang.11000.json','["仙仗離丹極，妖星照玉除。", "須爲下殿走，不可好樓居。", "暫屈汾陽駕，聊飛燕將書。", "依然七廟略，更與萬方初。"]'),
('ba89d909-9652-4b7d-92d0-322cf35d5884','收京三首 二','杜甫','唐','唐诗','tang','','[]','生意甘衰白，天涯正寂寥。',48,'全唐诗/poet.tang.11000.json','["生意甘衰白，天涯正寂寥。", "忽聞哀痛詔，又下聖明朝。", "羽翼懷商老，文思憶帝堯。", "叨逢罪己日，霑灑望青霄。"]'),
('330d805a-4167-40f4-9541-bfedc51bf4ae','收京三首 三','杜甫','唐','唐诗','tang','','[]','汗馬收宮闕，春城剷賊壕。',48,'全唐诗/poet.tang.11000.json','["汗馬收宮闕，春城剷賊壕。", "賞應歌杕杜，歸及薦櫻桃。", "雜虜橫戈數，功臣甲第高。", "萬方頻送喜，無乃聖躬勞。"]'),
('93c07519-1b9a-4ec0-b8e8-841cd597e49c','臘日','杜甫','唐','唐诗','tang','','["\u51ac\u5929", "\u77db\u76fe", "\u5f52\u4e61"]','臘日常年暖尚遙，今年臘日凍全消。',64,'全唐诗/poet.tang.11000.json','["臘日常年暖尚遙，今年臘日凍全消。", "侵陵雪色還萱草，漏洩春光有柳條。", "縱酒欲謀良夜醉，還家初散紫宸朝。", "口脂面藥隨恩澤，翠管銀罌下九霄。"]'),
('1452d4a0-8b49-4c25-918f-9fb14f35a2bc','紫宸殿退朝口號','杜甫','唐','唐诗','tang','','[]','戶外昭容紫袖垂，雙瞻御座引朝儀。',64,'全唐诗/poet.tang.11000.json','["戶外昭容紫袖垂，雙瞻御座引朝儀。", "香飄合殿春風轉，花覆千官淑景移。", "晝漏希聞高閣報，天顏有喜近臣知。", "宮中每出歸東省，會送夔龍集鳳池。"]'),
('d954e300-4edc-4819-8b39-8da5d11b7592','曲江二首 一','杜甫','唐','唐诗','tang','','[]','一片花飛減却春，風飄萬點正愁人。',64,'全唐诗/poet.tang.11000.json','["一片花飛減却春，風飄萬點正愁人。", "且看欲盡花經眼，莫厭傷多酒入脣。", "江上小堂巢翡翠，花邊高冢臥麒麟。", "細推物理須行樂，何用浮名絆此身。"]'),
('23834447-1596-4ba9-ab2b-3db0d39108bb','曲江二首 二','杜甫','唐','唐诗','tang','','[]','朝回日日典春衣，每日江頭盡醉歸。',64,'全唐诗/poet.tang.11000.json','["朝回日日典春衣，每日江頭盡醉歸。", "酒債尋常行處有，人生七十古來稀。", "穿花蛺蝶深深見，點水蜻蜓款款飛。", "傳語風光共流轉，暫時相賞莫相違。"]'),
('acc3a0aa-9e2e-4d09-a9e7-afc040bcdd31','曲江對酒','杜甫','唐','唐诗','tang','','["\u7231\u56fd"]','苑外江頭坐不歸，水精春殿轉霏微。',64,'全唐诗/poet.tang.11000.json','["苑外江頭坐不歸，水精春殿轉霏微。", "桃花細逐楊花落，黃鳥時兼白鳥飛。", "縱飲久判人共棄，嬾朝真與世相違。", "吏情更覺滄洲遠，老大悲傷未拂衣。"]'),
('eb4e050e-22ed-4f7e-8b41-078534a7e01b','曲江對雨','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5"]','城上春雲覆苑牆，江亭晚色靜年芳。',64,'全唐诗/poet.tang.11000.json','["城上春雲覆苑牆，江亭晚色靜年芳。", "林花著雨燕脂落，水荇牽風翠帶長。", "龍武新軍深駐輦，芙蓉別殿謾焚香。", "何時詔此金錢會，暫醉佳人錦瑟旁。"]'),
('56df51aa-0b14-4261-aaca-6866007287b1','奉和賈至舍人早朝大明宮','杜甫','唐','唐诗','tang','','[]','五夜漏聲催曉箭，九重春色醉仙桃。',64,'全唐诗/poet.tang.11000.json','["五夜漏聲催曉箭，九重春色醉仙桃。", "旌旗日暖龍蛇動，宮殿風微燕雀高。", "朝罷香煙攜滿袖，詩成珠玉在揮毫。", "欲知世掌絲綸美，池上於今有鳳毛。"]'),
('7e6abc60-ab63-4865-a822-638f63805fe1','宣政殿退朝晚出左掖','杜甫','唐','唐诗','tang','','[]','天門日射黃金牓，春殿晴曛赤羽旗。',64,'全唐诗/poet.tang.11000.json','["天門日射黃金牓，春殿晴曛赤羽旗。", "宮草微微承委佩，鑪煙細細駐遊絲。", "雲近蓬萊常好色，雪殘鳷鵲亦多時。", "侍臣緩步歸青瑣，退食從容出每遲。"]'),
('fe54c75c-9e9a-4c5c-91df-47c14716818e','題省中院壁','杜甫','唐','唐诗','tang','','[]','掖垣竹埤梧十尋，洞門對霤常陰陰。',64,'全唐诗/poet.tang.11000.json','["掖垣竹埤梧十尋，洞門對霤常陰陰。", "落花遊絲白日靜，鳴鳩乳燕青春深。", "腐儒衰晚謬通籍，退食遲迴違寸心。", "衮職曾無一字補，許身媿比雙南金。"]'),
('2769113d-0cac-4e67-83cb-0c10685f8381','春宿左省','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7231\u56fd", "\u5199\u666f", "\u4e94\u8a00\u5f8b\u8bd7"]','花隱掖垣暮，啾啾棲鳥過。',48,'全唐诗/poet.tang.11000.json','["花隱掖垣暮，啾啾棲鳥過。", "星臨萬戶動，月傍九霄多。", "不寢聽金鑰，因風想玉珂。", "明朝有封事，數問夜如何。"]'),
('f5c7c474-4fff-4fec-9f4a-d8e2d1447a77','送翰林張司馬南海勒碑','杜甫','唐','唐诗','tang','','[]','冠冕通南極，文章落上台。',48,'全唐诗/poet.tang.11000.json','["冠冕通南極，文章落上台。", "詔從三殿去，碑到百蠻開。", "野館濃花發，春帆細雨來。", "不知滄海上，天遣幾時回。"]'),
('f3d9772e-9eec-4dd0-9ac1-fe1f94646c61','晚出左掖','杜甫','唐','唐诗','tang','','[]','晝刻傳呼淺，春旗簇仗齊。',48,'全唐诗/poet.tang.11000.json','["晝刻傳呼淺，春旗簇仗齊。", "退朝花底散，歸院柳邊迷。", "樓雪融城濕，宮雲去殿低。", "避人焚諫草，騎馬欲雞棲。"]'),
('d5f78fdb-2066-4ff7-8b29-8a1ce54c0c28','曲江陪鄭八丈南史飲','杜甫','唐','唐诗','tang','','[]','雀啄江頭黃柳花，鵁鶄鸂鶒滿晴沙。',64,'全唐诗/poet.tang.11000.json','["雀啄江頭黃柳花，鵁鶄鸂鶒滿晴沙。", "自知白髮非春事，且盡芳尊戀物華。", "近侍即今難浪迹，此身那得更無家。", "丈人文力猶強健，豈傍青門學種瓜。"]'),
('88a4cb52-fee3-461b-b681-32275a0edd24','送賈閣老出汝州','杜甫','唐','唐诗','tang','','[]','西掖梧桐樹，空留一院陰。',48,'全唐诗/poet.tang.11000.json','["西掖梧桐樹，空留一院陰。", "艱難歸故里，去住損春心。", "宮殿青門隔，雲山紫邏深。", "人生五馬貴，莫受二毛侵。"]'),
('19b577a6-dca0-4c95-9365-7e4a8356e71d','鄭駙馬池臺喜遇鄭廣文同飲','杜甫','唐','唐诗','tang','','[]','不謂生戎馬，何知共酒杯。',72,'全唐诗/poet.tang.11000.json','["不謂生戎馬，何知共酒杯。", "然臍郿塢敗，握節漢臣回。", "白髮千莖雪，丹心一寸灰。", "別離經死地，披寫忽登臺。", "重對秦簫發，俱過阮宅來。", "留連春夜舞，淚落強裴回。"]'),
('9bfc8f27-b527-4cce-9c7b-000d7285c0ea','送鄭十八虔貶台州司戶傷其臨老陷賊之故闕爲面別情見於詩','杜甫','唐','唐诗','tang','','["\u9001\u522b", "\u540c\u60c5"]','鄭公樗散鬢成絲，酒後常稱老畫師。',64,'全唐诗/poet.tang.11000.json','["鄭公樗散鬢成絲，酒後常稱老畫師。", "萬里傷心嚴譴日，百年垂死中興時。", "蒼惶已就長途往，邂逅無端出餞遲。", "便與先生應永訣，九重泉路盡交期。"]'),
('cf854c36-62d7-4c54-ad3f-258cfedbb14a','題鄭十八著作虔','杜甫','唐','唐诗','tang','','[]','台州地闊海冥冥，雲水長和島嶼青。',128,'全唐诗/poet.tang.11000.json','["台州地闊海冥冥，雲水長和島嶼青。", "亂後故人雙別淚，春深逐客一浮萍。", "酒酣嬾舞誰相拽，詩罷能吟不復聽。", "第五橋東流恨水，皇陂岸北結愁亭。", "賈生對鵩傷王傅，蘇武看羊陷賊庭。", "可念此翁懷直道，也霑新國用輕刑。", "禰衡實恐遭江夏，方朔虛傳是歲星。", "窮巷悄然車馬絕，案頭乾死讀書螢。"]'),
('54954a45-c90c-4fa5-858e-90a189f637b4','端午日賜衣','杜甫','唐','唐诗','tang','','["\u7aef\u5348\u8282", "\u611f\u6069"]','宮衣亦有名，端午被恩榮。',48,'全唐诗/poet.tang.11000.json','["宮衣亦有名，端午被恩榮。", "細葛含風輭，香羅疊雪輕。", "自天題處濕，當暑著來清。", "意內稱長短，終身荷聖情。"]'),
('c79ae130-83bb-423d-b3d3-0ce169c5af49','贈畢四','杜甫','唐','唐诗','tang','','[]','才大今詩伯，家貧苦宦卑。',48,'全唐诗/poet.tang.11000.json','["才大今詩伯，家貧苦宦卑。", "飢寒奴僕賤，顏狀老翁爲。", "同調嗟誰惜，論文笑自知。", "流傳江鮑體，相顧免無兒。"]'),
('ab870495-7671-41b5-922d-c9c5e7bb3726','酬孟雲卿','杜甫','唐','唐诗','tang','','[]','樂極傷頭白，更長愛燭紅。',48,'全唐诗/poet.tang.11000.json','["樂極傷頭白，更長愛燭紅。", "相逢難衮衮，告別莫怱怱。", "但恐天河落，寧辭酒醆空。", "明朝牽世務，揮淚各西東。"]'),
('63aa0a1e-4b50-42f0-adbf-15fea1394963','奉贈王中允','杜甫','唐','唐诗','tang','','[]','中允聲名久，如今契闊深。',47,'全唐诗/poet.tang.11000.json','["中允聲名久，如今契闊深。", "共傳收庾信，不比得陳琳一病緣明主，三年獨此心。", "窮愁應有作，試誦白頭吟。"]'),
('ea9ee6ef-9a41-42c5-8676-e47b412f0db9','奉陪鄭駙馬韋曲二首 一','杜甫','唐','唐诗','tang','','[]','韋曲花無賴，家家惱殺人。',48,'全唐诗/poet.tang.11000.json','["韋曲花無賴，家家惱殺人。", "綠尊雖盡日，白髮好禁春。", "石角鉤衣破，藤枝刺眼新。", "何時占業竹，頭戴小烏巾。"]'),
('c50ef689-8ad8-43b3-8504-54a2a5a54171','奉陪鄭駙馬韋曲二首 二','杜甫','唐','唐诗','tang','','[]','野寺垂楊裏，春畦亂水間。',48,'全唐诗/poet.tang.11000.json','["野寺垂楊裏，春畦亂水間。", "美花多映竹，好鳥不歸山。", "城郭終何事，風塵豈駐顏。", "誰能共公子，薄暮欲俱還。"]'),
('2503d099-6e39-4c1e-bf86-cd84c0e61d85','奉荅岑參補闕見贈','杜甫','唐','唐诗','tang','','[]','窈窕清禁闥，罷朝歸不同。',48,'全唐诗/poet.tang.11000.json','["窈窕清禁闥，罷朝歸不同。", "君隨丞相後，我往日華東。", "冉冉柳枝碧，娟娟花蘂紅。", "故人得佳句，獨贈白頭翁。"]'),
('b14af996-a066-4cff-8903-35e2d658155a','送許八拾遺歸江寧覲省甫昔時嘗客遊此縣於許生處乞瓦棺寺維摩圖樣志諸篇末','杜甫','唐','唐诗','tang','','[]','詔許辭中禁，慈顏赴北堂。',96,'全唐诗/poet.tang.11000.json','["詔許辭中禁，慈顏赴北堂。", "聖朝新孝理，祖席倍輝光。", "內帛擎偏重，宮衣著更香。", "淮陰清夜驛，京口渡江航。", "春隔雞人晝，秋期燕子涼。", "賜書誇父老，壽酒樂城隍。", "看畫曾飢渴，追蹤恨淼茫。", "虎頭金粟影，神妙獨難忘。"]'),
('8330e313-8085-4cb6-aff2-ae060be0427f','因許八奉寄江寧旻上人','杜甫','唐','唐诗','tang','','[]','不見旻公三十年，對書寄與淚潺湲。',64,'全唐诗/poet.tang.11000.json','["不見旻公三十年，對書寄與淚潺湲。", "舊來好事今能否，老去新詩誰與傳。", "棊局動隨尋澗竹，袈裟憶上泛湖船。", "聞君話我爲官在，頭白昏昏只醉眠。"]'),
('f88a6dbd-bf83-458c-b5e2-85fdd1ed98b2','至德二載甫自京金光門出問道歸鳳翔乾元初從左拾遺移華州掾與親故別因出此門有悲往事','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c81\u6708", "\u4e94\u8a00\u5f8b\u8bd7", "\u6000\u5ff5"]','此道昔歸順，西郊胡正繁。',48,'全唐诗/poet.tang.11000.json','["此道昔歸順，西郊胡正繁。", "至今殘破膽，應有未招魂。", "近得歸京邑，移官豈至尊。", "無才日衰老，駐馬望千門。"]'),
('450412bc-cbe8-4ed5-9f44-80257de60195','寄高三十五詹事','杜甫','唐','唐诗','tang','','[]','安穩高詹事，兵戈久索居。',48,'全唐诗/poet.tang.11000.json','["安穩高詹事，兵戈久索居。", "時來如宦達，歲晚莫情疎。", "天上多鴻雁，池中足鯉魚。", "相看過半百，不寄一行書。"]'),
('3de2b064-649b-4161-8ca5-6eef38ed7a13','路逢襄陽楊少府入城戲呈楊員外綰','杜甫','唐','唐诗','tang','','[]','寄語楊員外，山寒少茯苓。',48,'全唐诗/poet.tang.11000.json','["寄語楊員外，山寒少茯苓。", "歸來稍喧暖，當爲斸青冥。", "飜動神仙窟，封題鳥獸形。", "兼將老藤杖，扶汝醉初醒。"]'),
('2d1d49b5-035f-4a94-a44f-62a626cfef42','題鄭縣亭子','杜甫','唐','唐诗','tang','','[]','鄭縣亭子澗之濱，戶牖憑高發興新。',64,'全唐诗/poet.tang.11000.json','["鄭縣亭子澗之濱，戶牖憑高發興新。", "雲斷岳蓮臨大路，天晴宮柳暗長春。", "巢邊野雀羣欺燕，花底山蜂遠趁人。", "更欲題詩滿青竹，晚來幽獨恐傷神。"]'),
('708eb748-5e4c-45b8-9d44-221f9099b801','早秋苦熱堆案相仍','杜甫','唐','唐诗','tang','','[]','七月六日苦炎熱，對食暫餐還不能。',64,'全唐诗/poet.tang.11000.json','["七月六日苦炎熱，對食暫餐還不能。", "每愁夜中自足蝎，況乃秋後轉多蠅。", "束帶發狂欲大叫，簿書何急來相仍。", "南望青松架短壑，安得赤脚蹋層冰。"]'),
('08952280-f6c8-4e0d-a585-363c240a5e16','望岳','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u63cf\u5199\u5c71", "\u548f\u7269", "\u5199\u5c71"]','西岳崚嶒竦處尊，諸峰羅立如兒孫。',64,'全唐诗/poet.tang.11000.json','["西岳崚嶒竦處尊，諸峰羅立如兒孫。", "安得仙人九節杖，拄到玉女洗頭盆。", "車箱入谷無歸路，箭栝通天有一門。", "稍待西風涼冷後，高尋白帝問真源。"]'),
('6cf4f8dd-9d3b-4ba0-84e6-109d36a9863e','至日遣興奉寄北省舊閣老兩院故人二首 一','杜甫','唐','唐诗','tang','','[]','去歲茲辰捧御牀，五更三點入鵷行。',64,'全唐诗/poet.tang.11000.json','["去歲茲辰捧御牀，五更三點入鵷行。", "欲知趨走傷心地，正想氛氳滿眼香。", "無路從容陪語笑，有時顛倒著衣裳。", "何人錯憶窮愁日，愁日愁隨一線長。"]'),
('80b59d90-c62e-4269-8883-3b625cd91ba7','至日遣興奉寄北省舊閣老兩院故人二首 二','杜甫','唐','唐诗','tang','','[]','憶昨逍遙供奉班，去年今日侍龍顏。',64,'全唐诗/poet.tang.11000.json','["憶昨逍遙供奉班，去年今日侍龍顏。", "麒麟不動爐煙上，孔雀徐開扇影還。", "玉几由來天北極，朱衣只在殿中間。", "孤城此日堪腸斷，愁對寒雲雪滿山。"]'),
('194fa0f1-ddae-472b-9605-5cd82616abb3','得弟消息二首 一','杜甫','唐','唐诗','tang','','[]','近有平陰信，遙憐舍弟存。',48,'全唐诗/poet.tang.11000.json','["近有平陰信，遙憐舍弟存。", "側身千里道，寄食一家村。", "烽舉新酣戰，啼垂舊血痕。", "不知臨老日，招得幾人魂。"]'),
('102793c0-2d3d-458f-a7e6-dfc302477324','得弟消息二首 二','杜甫','唐','唐诗','tang','','[]','汝懦歸無計，吾衰往未期。',48,'全唐诗/poet.tang.11000.json','["汝懦歸無計，吾衰往未期。", "浪傳烏鵲喜，深負鶺鴿詩。", "生理何顏面，憂端且歲時。", "兩京三十口，雖在命如絲。"]'),
('fb0d6385-8dff-4da5-b2c2-6e1a9b5cf48d','憶弟二首 一','杜甫','唐','唐诗','tang','','[]','喪亂聞吾弟，飢寒傍濟州。',48,'全唐诗/poet.tang.11000.json','["喪亂聞吾弟，飢寒傍濟州。", "人稀吾不到，兵在見何由。", "憶昨狂催走，無時病去憂。", "即今千種恨，惟共水東流。"]'),
('964923ad-cd19-4377-9743-2b29b7b6e644','憶弟二首 二','杜甫','唐','唐诗','tang','','[]','且喜河南定，不問鄴城圍。',48,'全唐诗/poet.tang.11000.json','["且喜河南定，不問鄴城圍。", "百戰今誰在，三年望汝歸。", "故園花自發，春日鳥還飛。", "斷絕人煙久，東西消息稀。"]'),
('d2cf3e2d-249b-41bc-ba86-cd4f899dc840','得舍弟消息','杜甫','唐','唐诗','tang','','[]','亂後誰歸得，他鄉勝故鄉。',48,'全唐诗/poet.tang.11000.json','["亂後誰歸得，他鄉勝故鄉。", "直爲心厄苦，久念與存亡。", "汝書猶在壁，汝妾已辭房。", "舊犬知愁恨，垂頭傍我牀。"]'),
('a9a5c088-8d7d-44cf-9554-4b1bd43e9d6b','秦州雜詩二十首 一','杜甫','唐','唐诗','tang','','[]','滿目悲生事，因人作遠遊。',48,'全唐诗/poet.tang.11000.json','["滿目悲生事，因人作遠遊。", "遲迴度隴怯，浩蕩及關愁。", "水落魚龍夜，山空鳥鼠秋。", "西征問烽火，心折此淹留。"]'),
('9a725c40-d060-4cfb-a800-df3c309f66aa','秦州雜詩二十首 二','杜甫','唐','唐诗','tang','','[]','秦州山北寺，勝跡隗囂宮。',48,'全唐诗/poet.tang.11000.json','["秦州山北寺，勝跡隗囂宮。", "苔蘚山門古，丹青野殿空。", "月明垂葉露，雲逐渡溪風。", "清渭無情極，愁時獨向東。"]'),
('5845a436-04f1-4954-a6e7-3ea1c4ac752a','秦州雜詩二十首 三','杜甫','唐','唐诗','tang','','[]','州圖領同谷，驛道出流沙。',48,'全唐诗/poet.tang.11000.json','["州圖領同谷，驛道出流沙。", "降虜兼千帳，居人有萬家。", "馬驕珠汗落，胡舞白蹄斜。", "年少臨洮子，西來亦自誇。"]'),
('cac3df5d-c0a0-4208-8fd5-794975b165b0','秦州雜詩二十首 四','杜甫','唐','唐诗','tang','','[]','鼓角緣邊郡，川原欲夜時。',48,'全唐诗/poet.tang.11000.json','["鼓角緣邊郡，川原欲夜時。", "秋聽殷地發，風散入雲悲。", "抱葉寒蟬靜，歸來獨鳥遲。", "萬方聲一概，吾道竟何之。"]'),
('90667fd7-b11e-44db-9dec-68cdba9e2fc5','秦州雜詩二十首 五','杜甫','唐','唐诗','tang','','[]','南使宜天馬，由來萬匹強。',48,'全唐诗/poet.tang.11000.json','["南使宜天馬，由來萬匹強。", "浮雲連陣沒，秋草徧山長。", "聞說真龍種，仍殘老驌驦。", "哀鳴思戰鬬，逈立向蒼蒼。"]'),
('6a5b7e29-19a8-4ca5-9911-b1e4803f5cd9','秦州雜詩二十首 六','杜甫','唐','唐诗','tang','','[]','城上胡笳奏，山邊漢節歸。',48,'全唐诗/poet.tang.11000.json','["城上胡笳奏，山邊漢節歸。", "防河赴滄海，奉詔發金微。", "士苦形骸黑，旌疎鳥獸稀。", "那聞往來戍，恨解鄴城圍。"]'),
('ee3631a2-3091-4beb-8356-a16d004ca08f','秦州雜詩二十首 七','杜甫','唐','唐诗','tang','','[]','莽莽萬重山，孤城山谷間。',48,'全唐诗/poet.tang.11000.json','["莽莽萬重山，孤城山谷間。", "無風雲出塞，不夜月臨關。", "屬國歸何晚，樓蘭斬未還。", "煙塵獨長望，衰颯正摧顏。"]'),
('c716f7b3-931d-4deb-97dc-0e83232e0372','秦州雜詩二十首 八','杜甫','唐','唐诗','tang','','[]','聞道尋源使，從天此路迴。',48,'全唐诗/poet.tang.11000.json','["聞道尋源使，從天此路迴。", "牽牛去幾許，宛馬至今來。", "一望幽燕隔，何時郡國開。", "東征健兒盡，羌笛暮吹哀。"]'),
('1c716801-1e00-42bc-8f99-473b707c6e3f','秦州雜詩二十首 九','杜甫','唐','唐诗','tang','','[]','今日明人眼，臨池好驛亭。',48,'全唐诗/poet.tang.11000.json','["今日明人眼，臨池好驛亭。", "叢篁低地碧，高柳半天青。", "稠疊多幽事，喧呼閱使星。", "老夫如有此，不異在郊坰。"]'),
('da88e355-99df-4d78-9680-2f61b0bf8336','秦州雜詩二十首 十','杜甫','唐','唐诗','tang','','[]','雲氣接崑崙，涔涔塞雨繁。',48,'全唐诗/poet.tang.11000.json','["雲氣接崑崙，涔涔塞雨繁。", "羌童看渭水，使客向河源。", "煙火軍中幕，牛羊嶺上村。", "所居秋草淨，正閉小蓬門。"]'),
('fd56f333-f562-4b79-a24f-dda16cbf66d4','秦州雜詩二十首 十一','杜甫','唐','唐诗','tang','','[]','蕭蕭古塞冷，漠漠秋雲低。',48,'全唐诗/poet.tang.11000.json','["蕭蕭古塞冷，漠漠秋雲低。", "黃鵠翅垂雨，蒼鷹飢啄泥。", "薊門誰自北，漢將獨征西。", "不意書生耳，臨衰厭鼓鞞。"]'),
('c0956099-4071-47fe-af2d-5c5826a58d19','秦州雜詩二十首 十二','杜甫','唐','唐诗','tang','','[]','山頭南郭寺，水號北流泉。',48,'全唐诗/poet.tang.11000.json','["山頭南郭寺，水號北流泉。", "老樹空庭得，清渠一邑傳。", "秋花危石底，晚景臥鐘邊。", "俯仰悲身世，溪風爲颯然。"]'),
('2c03d6d7-bcd3-42d0-9f9e-2b6ff6ec58ce','秦州雜詩二十首 十三','杜甫','唐','唐诗','tang','','[]','傳道東柯谷，深藏數十家。',48,'全唐诗/poet.tang.11000.json','["傳道東柯谷，深藏數十家。", "對門藤蓋瓦，映竹水穿沙。", "瘦地飜宜粟，陽坡可種瓜。", "船人近相報，但恐失桃花。"]'),
('c4617163-8647-4cc2-bdcf-a3d6aeb2ee74','秦州雜詩二十首 十四','杜甫','唐','唐诗','tang','','[]','萬古仇池穴，潛通小有天。',48,'全唐诗/poet.tang.11000.json','["萬古仇池穴，潛通小有天。", "神魚人不見，福地語真傳。", "近接西南境，長懷十九泉。", "何時一茅屋，送老白雲邊。"]'),
('ccea1bac-1e88-45d6-859a-91e8cf29e811','秦州雜詩二十首 十五','杜甫','唐','唐诗','tang','','[]','未暇泛蒼海，悠悠兵馬間。',48,'全唐诗/poet.tang.11000.json','["未暇泛蒼海，悠悠兵馬間。", "塞門風落木，客舍雨連山。", "阮籍行多興，龐公隱不還。", "東柯遂疎嬾，休鑷鬢毛斑。"]'),
('da625d4b-a775-4c5e-9860-4bfe89e481ce','秦州雜詩二十首 十六','杜甫','唐','唐诗','tang','','[]','東柯好崖谷，不與衆峰羣。',48,'全唐诗/poet.tang.11000.json','["東柯好崖谷，不與衆峰羣。", "落日邀雙鳥，晴天養片雲。", "野人矜險絕，水竹會平分。", "采藥吾將老，兒童未遣聞。"]'),
('f5d1ccf8-66f3-4c96-aa51-a935cd0b71d4','秦州雜詩二十首 十七','杜甫','唐','唐诗','tang','','[]','邊秋陰易久，不復辨晨光。',48,'全唐诗/poet.tang.11000.json','["邊秋陰易久，不復辨晨光。", "檐雨亂淋幔，山雲低度牆。", "鸕鶿窺淺井，蚯蚓上深堂。", "車馬何蕭索，門前百草長。"]'),
('060f8950-7f13-4184-8a7d-d5eb30c3bf01','秦州雜詩二十首 十八','杜甫','唐','唐诗','tang','','[]','地僻秋將盡，山高客未歸。',48,'全唐诗/poet.tang.11000.json','["地僻秋將盡，山高客未歸。", "塞雲多斷績，邊日少光輝。", "警急烽常報，傳聞檄屢飛。", "西戎外甥國，何得迕天威。"]'),
('ca525a27-f594-438d-99ba-e7de2ec3ac0a','秦州雜詩二十首 十九','杜甫','唐','唐诗','tang','','[]','鳳林戈未息，魚海路常難。',48,'全唐诗/poet.tang.11000.json','["鳳林戈未息，魚海路常難。", "候火雲烽峻，懸軍幕井乾。", "風連西極動，月過北庭寒。", "故老思飛將，何時議築壇。"]'),
('98910f3c-cec8-4530-9c3a-c0e34c39b3b6','秦州雜詩二十首 二十','杜甫','唐','唐诗','tang','','[]','唐堯真自聖，野老復何知。',48,'全唐诗/poet.tang.11000.json','["唐堯真自聖，野老復何知。", "曬藥能無婦，應門幸有兒。", "藏書聞禹穴，讀記憶仇池。", "爲報鴛行舊，鷦鷯在一枝。"]'),
('c1280e87-ac81-4f9b-9de5-377d6af38ae8','月夜憶舍弟','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6708\u591c", "\u79cb\u5929", "\u8fb9\u585e", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','戍鼓斷人行，秋邊一雁聲。',48,'全唐诗/poet.tang.11000.json','["戍鼓斷人行，秋邊一雁聲。", "露從今夜白，月是故鄉明。", "有弟皆分散，無家問死生。", "寄書長不避，況乃未休兵。"]'),
('6c492d0a-ef0a-4938-8c65-fa50a5de7d5e','宿贊公房','杜甫','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u4eba", "\u5199\u666f"]','杖錫何來此，秋風已颯然。',48,'全唐诗/poet.tang.11000.json','["杖錫何來此，秋風已颯然。", "雨荒深院菊，霜倒半池蓮。", "放逐寧違性，虛空不離禪。", "相逢成夜宿，隴月向人圓。"]'),
('3d449437-09a5-462b-86e5-e1ff2fdfc832','東樓','杜甫','唐','唐诗','tang','','[]','萬里流沙道，西征過北門。',48,'全唐诗/poet.tang.11000.json','["萬里流沙道，西征過北門。", "但添新戰骨，不返舊征魂。", "樓角臨風迥，城陰帶水昏。", "傳聲看驛使，送節向河源。"]'),
('be9d4d46-2848-4724-aae8-dab695b16714','雨晴','杜甫','唐','唐诗','tang','','[]','天水秋雲薄，從西萬里風。',48,'全唐诗/poet.tang.11000.json','["天水秋雲薄，從西萬里風。", "今朝好晴景，久雨不妨農。", "塞柳行疎翠，山棃結小紅。", "胡笳樓上發，一雁入高空。"]'),
('87fc6086-4359-4046-bde9-4d724d1f2d6d','寓目','杜甫','唐','唐诗','tang','','[]','一縣蒲萄熟，秋山苜蓿多。',48,'全唐诗/poet.tang.11000.json','["一縣蒲萄熟，秋山苜蓿多。", "關雲常帶雨，塞水不成河。", "羌女輕烽燧，胡兒制駱駝。", "自傷遲暮眼，喪亂飽經過。"]'),
('8b73a514-a34d-4229-8583-cdbd778403d4','山寺','杜甫','唐','唐诗','tang','','[]','野寺殘僧少，山園細路高。',48,'全唐诗/poet.tang.11000.json','["野寺殘僧少，山園細路高。", "麝香眠石竹，鸚鵡啄金桃。", "亂石通人過，懸崖置屋牢。", "上方重閣晚，百里見秋毫。"]'),
('e5018a28-92f8-458f-92e2-cc62ce096164','即事','杜甫','唐','唐诗','tang','','[]','聞道花門破，和親事却非。',48,'全唐诗/poet.tang.11000.json','["聞道花門破，和親事却非。", "人憐漢公主，生得渡河歸。", "秋思拋雲髻，腰支勝寶衣。", "羣兇猶索戰，回首意多違。"]'),
('b1b76a70-be94-4373-b9d6-e52dc893e6b2','遣懷','杜甫','唐','唐诗','tang','','[]','愁眼看霜露，寒城菊自花。',48,'全唐诗/poet.tang.11000.json','["愁眼看霜露，寒城菊自花。", "天風隨斷柳，客淚墮清笳。", "水淨樓陰直，山昏塞日斜。", "夜來歸鳥盡，啼殺後棲鴉。"]'),
('54313608-eb28-4f12-9583-7a821d285ec4','天河','杜甫','唐','唐诗','tang','','[]','常時任顯晦，秋至輒分明。',48,'全唐诗/poet.tang.11000.json','["常時任顯晦，秋至輒分明。", "縱被微雲掩，終能永夜清。", "含星動雙闕，伴月照邊城。", "牛女年年渡，何曾風浪生。"]'),
('4176367c-f23b-4d58-a008-22c48b9e5979','初月','杜甫','唐','唐诗','tang','','[]','光細弦豈上，影斜輪未安。',48,'全唐诗/poet.tang.11000.json','["光細弦豈上，影斜輪未安。", "微升古塞外，已隱暮雲端。", "河漢不改色，關山空自寒。", "庭前有白露，暗滿菊花團。"]'),
('f8e07cab-06f6-4ea0-a6b6-815bd8c22506','歸燕','杜甫','唐','唐诗','tang','','[]','不獨避霜雪，其如儔侶稀。',48,'全唐诗/poet.tang.11000.json','["不獨避霜雪，其如儔侶稀。", "四時無失序，八月自知歸。", "春色豈相訪，衆雛還識機。", "故巢儻未毀，會傍主人飛。"]'),
('1d4a0228-d51b-462c-ae8b-4a811e5509a1','擣衣','杜甫','唐','唐诗','tang','','[]','亦知戍不返，秋至拭清砧。',48,'全唐诗/poet.tang.11000.json','["亦知戍不返，秋至拭清砧。", "已近苦寒月，況經長別心。", "寧辭擣熨倦，一寄塞垣深。", "用盡閨中力，君聽空外音。"]'),
('ef44ed15-6181-4597-93e9-94431ee9df4b','促織','杜甫','唐','唐诗','tang','','["\u7f81\u65c5", "\u6292\u60c5", "\u79cb\u5929", "\u6101\u7eea"]','促織甚微細，哀音何動人。',48,'全唐诗/poet.tang.11000.json','["促織甚微細，哀音何動人。", "草根吟不穩，牀下夜相親。", "久客得無淚，放妻難及晨。", "悲絲與急管，感激異天真。"]'),
('337b1cbf-675e-490f-a23d-48bee622b21f','螢火','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u8bbd\u523a"]','幸因腐草出，敢近太陽飛。',48,'全唐诗/poet.tang.11000.json','["幸因腐草出，敢近太陽飛。", "未足臨書卷，時能點客衣。", "隨風隔幔小，帶雨傍林微。", "十月清霜重，飄零何處歸。"]'),
('f5584095-bed0-43b3-a45b-a437877d266c','蒹葭','杜甫','唐','唐诗','tang','','[]','摧折不自守，秋風吹若何。',48,'全唐诗/poet.tang.11000.json','["摧折不自守，秋風吹若何。", "暫時花戴雪，幾處葉沈波。", "體弱春風早，叢長夜露多。", "江湖後搖落，亦恐歲蹉跎。"]'),
('2ecf783d-8e3f-4d06-8560-11ba520f5e37','苦竹','杜甫','唐','唐诗','tang','','[]','青冥亦自守，輭弱強扶持。',48,'全唐诗/poet.tang.11000.json','["青冥亦自守，輭弱強扶持。", "味苦夏蟲避，叢卑春鳥疑。", "軒墀曾不重，剪伐欲無辭。", "幸近幽人屋，霜根結在茲。"]'),
('eacfad64-4b0a-461d-9f76-5ae2a1558ab7','除架','杜甫','唐','唐诗','tang','','[]','束薪已零落，瓠葉轉蕭疎。',48,'全唐诗/poet.tang.11000.json','["束薪已零落，瓠葉轉蕭疎。", "幸結白花了，寧辭青蔓除。", "秋蟲聲不去，暮雀意何如。", "寒事今牢落，人生亦有初。"]'),
('0c72700e-23a9-4717-b52c-843621c092f1','廢畦','杜甫','唐','唐诗','tang','','[]','秋蔬擁霜露，豈敢惜凋殘。',48,'全唐诗/poet.tang.11000.json','["秋蔬擁霜露，豈敢惜凋殘。", "暮景數枝葉，天風吹汝寒。", "綠霑泥滓盡，香與歲時闌。", "生意春如昨，悲君白玉盤。"]'),
('71db67d2-6d13-444d-9ef4-0f7e1ef35d97','夕烽','杜甫','唐','唐诗','tang','','[]','夕峰來不近，每日報平安。',48,'全唐诗/poet.tang.11000.json','["夕峰來不近，每日報平安。", "塞上傳光小，雲邊落點殘。", "照秦通警急，過隴自艱難。", "聞道蓬萊殿，千門立馬看。"]'),
('964cf095-7893-4844-941b-9549a49cd3b1','秋笛','杜甫','唐','唐诗','tang','','[]','清商欲盡奏，奏苦血霑衣。',48,'全唐诗/poet.tang.11000.json','["清商欲盡奏，奏苦血霑衣。", "他日傷心極，征人白骨歸。", "相逢恐恨過，故作發聲微。", "不見秋雲動，悲風稍稍飛。"]'),
('65526803-d701-435f-8d19-9fd9c960080c','送遠','杜甫','唐','唐诗','tang','','["\u79bb\u522b", "\u5b64\u72ec"]','帶甲滿天地，胡爲君遠行。',48,'全唐诗/poet.tang.11000.json','["帶甲滿天地，胡爲君遠行。", "親朋盡一哭，鞍馬去孤城。", "草木歲月晚，關河霜雪清。", "別離已昨日，因見古人情。"]'),
('7540b747-b085-435f-b814-8218b9a6313b','觀兵','杜甫','唐','唐诗','tang','','[]','北庭送壯士，貔虎數尤多。',48,'全唐诗/poet.tang.11000.json','["北庭送壯士，貔虎數尤多。", "精銳舊無敵，邊隅今若何。", "妖氛擁白馬，元帥待彫戈。", "莫守鄴城下，斬鯨遼海波。"]'),
('916d6382-2751-4d92-8faf-9799436f778f','不歸','杜甫','唐','唐诗','tang','','[]','河間尚征伐，汝骨在空城。',48,'全唐诗/poet.tang.11000.json','["河間尚征伐，汝骨在空城。", "從弟人皆有，終身恨不平。", "數金憐俊邁，總角愛聰明。", "而上三年土，春風草又生。"]'),
('2c036362-9f1d-434c-854f-b97a2a4bb19b','天末憶李白','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u98ce", "\u4e94\u8a00\u5f8b\u8bd7", "\u98ce", "\u6000\u4eba"]','涼風起天末，君子意如何。',48,'全唐诗/poet.tang.11000.json','["涼風起天末，君子意如何。", "鴻雁幾時到，江湖秋水多。", "文章憎命達，魑魅喜人過。", "應共冤魂語，投詩贈汩羅。"]'),
('77190d46-4155-4a30-99e3-0534b8e9481b','獨立','杜甫','唐','唐诗','tang','','[]','空外一鷙鳥，河間雙白鷗。',48,'全唐诗/poet.tang.11000.json','["空外一鷙鳥，河間雙白鷗。", "飄颻搏擊便，容易往來遊。", "草露亦多濕，蛛絲仍未收。", "天機近人事，獨立萬端憂。"]'),
('2e2f3d54-351b-455a-8dbb-c4aada51996b','日暮','杜甫','唐','唐诗','tang','','[]','日落風亦起，城頭鳥尾訛。',48,'全唐诗/poet.tang.11000.json','["日落風亦起，城頭鳥尾訛。", "黃雲高未動，白水已揚波。", "羌婦語還哭，胡兒行且歌。", "將軍別換馬，夜出擁彫戈。"]'),
('4b34b8fd-9e51-4e5a-96fe-a168a11fe696','空囊','杜甫','唐','唐诗','tang','','[]','翠柏苦猶食，晨霞高可餐。',48,'全唐诗/poet.tang.11000.json','["翠柏苦猶食，晨霞高可餐。", "世人共鹵莽，吾道屬艱難。", "不爨井晨凍，無衣牀夜寒。", "囊空恐羞澀，留得一錢看。"]'),
('057c887c-9525-4a2e-b553-23d5afab9275','病馬','杜甫','唐','唐诗','tang','','["\u5199\u9a6c", "\u548f\u7269", "\u843d\u9b44", "\u6292\u6000", "\u548f\u7269\u8bd7", "\u9a6c"]','乘爾亦已久，天寒關塞深。',48,'全唐诗/poet.tang.11000.json','["乘爾亦已久，天寒關塞深。", "塵中老盡力，歲晚病傷心。", "毛骨豈殊衆，馴良猶至今。", "物微意不淺，感動一沈吟。"]'),
('6e4f767b-c903-4dcc-8e08-33ef70e81445','蕃劒','杜甫','唐','唐诗','tang','','[]','致此自僻遠，又非珠玉裝。',48,'全唐诗/poet.tang.11000.json','["致此自僻遠，又非珠玉裝。", "如何有奇怪，每夜吐光芒。", "虎氣必騰趠，龍身寧久藏。", "風塵苦未息，持汝奉明王。"]'),
('ea9aa292-1c78-4494-b621-c8edd9329b96','銅缾','杜甫','唐','唐诗','tang','','[]','Ｂ亂後碧井廢，時清瑤殿深。',49,'全唐诗/poet.tang.11000.json','["Ｂ亂後碧井廢，時清瑤殿深。", "銅缾未失水，百丈有哀音。", "側想美人意，應非寒甃沈。", "蛟龍半缺落，猶得折黃金。"]'),
('57d11f12-bb85-47ff-9b97-0676acc9d4bc','觀安西兵過赴關中待命二首 一','杜甫','唐','唐诗','tang','','[]','四鎮富精銳，摧鋒皆絕倫。',48,'全唐诗/poet.tang.11000.json','["四鎮富精銳，摧鋒皆絕倫。", "還聞獻士卒，足以靜風塵。", "老馬夜知道，蒼鷹飢著人。", "臨危經久戰，用急始如神。"]'),
('111f8ccd-6456-408c-86d6-0bbdbdf1a41e','觀安西兵過赴關中待命二首 二','杜甫','唐','唐诗','tang','','[]','奇兵不在衆，萬馬救中原。',48,'全唐诗/poet.tang.11000.json','["奇兵不在衆，萬馬救中原。", "談笑無河北，心肝奉至尊。", "孤雲隨殺氣，飛鳥避轅門。", "竟日留歡樂，城池未覺喧。"]'),
('530eb94b-97b1-4630-8005-556cfd4a53d3','送人從軍','杜甫','唐','唐诗','tang','','[]','弱水應無地，陽關已近天。',48,'全唐诗/poet.tang.11000.json','["弱水應無地，陽關已近天。", "今君渡沙磧，累月斷人煙。", "好武寧論命，封侯不計年。", "馬寒防失道，雪沒錦鞍韉。"]'),
('342116e5-c4b1-48a4-968c-68e9e7a4057d','野望','杜甫','唐','唐诗','tang','','[]','清秋望不極，迢遰起曾陰。',48,'全唐诗/poet.tang.11000.json','["清秋望不極，迢遰起曾陰。", "遠水兼天淨，孤城隱霧深。", "葉稀風更落，山迥日初沈。", "獨鶴歸何晚，昏鴉已滿林。"]'),
('d305b310-788d-4242-a9df-be50bdb884a0','示姪佐','杜甫','唐','唐诗','tang','','[]','多病秋風落，君來慰眼前。',48,'全唐诗/poet.tang.11000.json','["多病秋風落，君來慰眼前。", "自聞茅屋趣，只想竹林眠。", "滿谷山雲起，侵籬澗水懸。", "嗣宗諸子姪，早覺仲容賢。"]'),
('f4ebe616-20f4-4b12-964a-8b1f41f7dbab','佐還山後寄三首 一','杜甫','唐','唐诗','tang','','[]','山晚浮雲合，歸時恐路迷。',48,'全唐诗/poet.tang.11000.json','["山晚浮雲合，歸時恐路迷。", "澗寒人欲到，村黑鳥應棲。", "野客茅茨小，田家樹木低。", "舊諳疎嬾叔，須汝故相攜。"]'),
('24ca9d45-cb54-4cfe-bd3c-00c7ff303385','佐還山後寄三首 二','杜甫','唐','唐诗','tang','','[]','白露黃粱熟，分張素有期。',48,'全唐诗/poet.tang.11000.json','["白露黃粱熟，分張素有期。", "已應舂得細，頗覺寄來遲。", "味豈同金菊，香宜配綠葵。", "老人佗日愛，正想滑流匙。"]'),
('ba4d7faa-1894-49de-9902-b426b4bc250b','佐還山後寄三首 三','杜甫','唐','唐诗','tang','','[]','幾道泉澆圃，交橫落慢坡。',48,'全唐诗/poet.tang.11000.json','["幾道泉澆圃，交橫落慢坡。", "葳蕤秋葉少，隱映野雲多。", "隔沼連香芰，通林帶女蘿。", "甚聞霜薤白，重惠意如何。"]'),
('257315b5-3e86-4d9e-96ea-0855de476059','從人覓小胡孫許寄','杜甫','唐','唐诗','tang','','[]','人說南州路，山猨樹樹懸。',48,'全唐诗/poet.tang.11000.json','["人說南州路，山猨樹樹懸。", "舉家聞若駭，爲寄小如拳。", "預哂愁胡面，初調見馬鞭。", "許求聰慧者，童稚捧應癲。"]'),
('7499d3c4-f9ec-44f6-ab1f-ac3c83471ee8','秋日阮隱居致薤三十束','杜甫','唐','唐诗','tang','','[]','隱者柴門內，畦蔬繞舍秋。',48,'全唐诗/poet.tang.11000.json','["隱者柴門內，畦蔬繞舍秋。", "盈筐承露薤，不待致書求。", "束比青芻色，圓齊玉箸頭。", "衰年關鬲冷，味煖幷無憂。"]'),
('cf724cea-153c-470e-ae32-aba401213d55','秦州見敕目薛三璩授司議郎畢四曜除監察與二子有故遠喜遷官兼述索居凡三十韻','杜甫','唐','唐诗','tang','','[]','大雅何寥闊，斯人尚典刑。',288,'全唐诗/poet.tang.11000.json','["大雅何寥闊，斯人尚典刑。", "交期余潦倒，材力爾精靈。", "二子聲同日，諸生困一經。", "文章開穾奧，遷擢潤朝廷。", "舊好何由展，新詩更憶聽。", "別來頭幷白，相見眼終青。", "伊昔貧皆甚，同憂心不寧。", "栖遑分半菽，浩蕩逐流萍。", "俗態猶猜忌，妖氛忽杳冥。", "獨慙投漢閣，俱議哭秦庭。", "遠蜀祗無補，囚梁亦固扃。", "華夷相混合，宇宙一羶腥。", "帝力收三統，天威總四溟。", "舊都俄望幸，清廟肅惟馨。", "雜種雖高壘，長驅甚建瓴。", "焚香淑景殿，漲水望雲亭。", "法駕初還日，羣公若會星。", "宮臣仍點染，柱史正零丁。", "官忝趨棲鳳，朝回歎聚螢。", "喚人看腰褭，不嫁惜娉婷。", "掘劒知埋獄，提刀見發硎。", "侏儒應共飽，漁父忌偏醒。", "旅泊窮清渭，長吟望濁涇。", "羽書還似急，烽火未全停。"]'),
('ad25550b-b0b6-49cd-981a-88d90471b624','寄彭州高三十五使君適虢州岑二十七長史參三十韻','杜甫','唐','唐诗','tang','','[]','故人何寂寞，今我獨淒涼。',288,'全唐诗/poet.tang.11000.json','["故人何寂寞，今我獨淒涼。", "老去才難盡，秋來興甚長。", "物情尤可見，辭客未能忘。", "海內知名士，雲端各異方。", "高岑殊緩步，沈鮑得同行。", "意愜關飛動，篇終接混茫。", "舉天悲富駱，近代惜盧王。", "似爾官仍貴，前賢命可傷。", "諸侯非棄擲，半刺已翱翔。", "詩好幾時見，書成無信將。", "男兒行處是，客子鬬身強。", "羈旅推賢聖，沈綿抵咎殃。", "三年猶瘧疾，一鬼不銷亡。", "隔日搜脂髓，增寒抱雪霜。", "徒然潛隙地，有靦屢鮮妝。", "何太龍鍾極，於今出處妨。", "無錢居帝里，盡室在邊疆。", "劉表雖遺恨，龐公至死藏。", "心微傍魚鳥，肉瘦怯豺狼。", "隴草蕭蕭白，洮雲片片黃。", "彭門劒閣外，虢略鼎湖旁。", "荆玉簪頭冷，巴箋染翰光。", "烏麻蒸續曬，丹橘露應嘗。", "豈異神仙宅，俱兼山水鄉。"]'),
('33123302-8a66-424b-afcd-44ef1d671410','寄岳州賈司馬六丈巴州嚴八使君兩閣老五十韻','杜甫','唐','唐诗','tang','','[]','衡岳啼猨裏，巴州鳥道邊。',288,'全唐诗/poet.tang.11000.json','["衡岳啼猨裏，巴州鳥道邊。", "故人俱不利，謫宦兩悠然。", "開闢乾坤正，榮枯雨露偏。", "長沙才子遠，釣瀨客星懸。", "憶昨趨行殿，殷憂捧御筵。", "討胡愁李廣，奉使待張騫。", "無復雲臺仗，虛修水戰船。", "蒼茫城七十，流落劒三千。", "畫角吹秦晉，旄頭俯澗瀍。", "小儒輕董卓，有識笑苻堅。", "浪作禽填海，那將血射天。", "萬方思助順，一鼓氣無前。", "陰散陳倉北，晴熏太白巔。", "亂麻屍積衛，破竹勢臨燕。", "法駕還雙闕，王師下八川。", "此時霑奉引，佳氣拂周旋。", "貔虎開金甲，麒麟受玉鞭。", "侍臣諳入仗，廄馬解登仙。", "花動朱樓雪，城凝碧樹煙。", "衣冠心慘愴，故老淚潺湲。", "哭廟悲風急，朝正霽景鮮。", "月分梁漢米，春得水衡錢。", "內蘂繁於纈，宮莎輭勝緜。", "恩榮同拜手，出入最隨肩。"]'),
('186aab50-4ead-4c61-9764-1867aec86f52','寄張十二山人彪三十韻','杜甫','唐','唐诗','tang','','[]','獨臥蒿陽客，三違潁水春。',288,'全唐诗/poet.tang.11000.json','["獨臥蒿陽客，三違潁水春。", "艱難隨老母，慘澹向時人。", "謝氏尋山屐，陶公漉酒巾。", "羣兇彌宇宙，此物在風塵。", "歷下辭姜被，關西得孟鄰。", "早通交契密，晚接道流新。", "靜者心多妙，先生藝絕倫。", "草書何太苦，詩興不無神。", "曹植休前輩，張芝更後身。", "數篇吟可老，一字買堪貧。", "將恐曾防寇，深潛託所親。", "寧聞倚門夕，盡力潔飧晨。", "疎嬾爲名誤，驅馳喪我真。", "索居猶寂寞，相遇益悲辛。", "流轉依邊徼，逢迎念席珍。", "時來故舊少，亂後別離頻。", "世祖修高廟，文公賞從臣。", "商山猶入楚，源水不離秦。", "存想青龍祕，騎行白鹿馴。", "耕巖非谷口，結草即河濱。", "肘後符應驗，囊中藥未陳。", "旅懷殊不愜，良覿渺無因。", "自古皆悲恨，浮生有屈伸。", "此邦今尚武，何處且依仁。"]'),
('e80bca1f-12ef-4187-b623-b614aa6bee78','寄李十二白二十韻','杜甫','唐','唐诗','tang','','["\u8d5e\u9882", "\u5199\u4eba", "\u53cb\u60c5", "\u5199\u4eba\u8bd7"]','昔年有狂客，號爾謫仙人。',240,'全唐诗/poet.tang.11000.json','["昔年有狂客，號爾謫仙人。", "筆落驚風雨，詩成泣鬼神。", "聲名從此大，汩沒一朝伸。", "文彩承殊渥，流傳必絕倫。", "龍舟移櫂晚，獸錦奪袍新。", "白日來深殿，青雲滿後塵。", "乞歸優詔許，遇我宿心親。", "未負幽棲志，兼全寵辱身。", "劇談憐野逸，嗜酒見天真。", "醉舞梁園夜，行歌泗水春。", "才高心不展，道屈善無鄰。", "處士禰衡俊，諸生原憲貧。", "稻粱求未足，薏苡謗何頻。", "五嶺炎蒸地，三危放逐臣。", "幾年遭鵩鳥，獨泣向麒麟。", "蘇武先還漢，黃公豈事秦。", "楚筵辭醴日，梁獄上書辰。", "已用當時法，誰將此義陳。", "老吟秋月下，病起暮江濱。", "莫怪恩波隔，乘槎與問津。"]'),
('a353dcb1-12cc-4ca8-af1e-55d1d62445f8','蜀相','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u5fe7\u56fd\u5fe7\u6c11", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4"]','丞相祠堂何處尋，錦官城外柏森森。',64,'全唐诗/poet.tang.11000.json','["丞相祠堂何處尋，錦官城外柏森森。", "映堦碧草自春色，隔葉黃鸝空好音。", "三顧頻煩天下計，兩朝開濟老臣心。", "出師未捷身先死，長使英雄淚滿襟。"]'),
('ffa6c105-9135-4b40-91e9-760296dc673b','卜居','杜甫','唐','唐诗','tang','','[]','浣花流水水西頭，主人爲卜林塘幽。',64,'全唐诗/poet.tang.11000.json','["浣花流水水西頭，主人爲卜林塘幽。", "已知出郭少塵事，更有澄江銷客愁。", "無數蜻蜓齊上下，一雙鸂鶒對沈浮。", "東行萬里堪乘興，須向山陰上小舟。"]'),
('653beb5d-33b0-40bf-8877-3fe058dd473c','一室','杜甫','唐','唐诗','tang','','[]','一室他鄉遠，空林暮景懸。',48,'全唐诗/poet.tang.11000.json','["一室他鄉遠，空林暮景懸。", "正愁聞塞笛，獨立見江船。", "巴蜀來多病，荆蠻去幾年。", "應同王粲宅，留井峴山前。"]'),
('d30b4748-72eb-4f1d-b8de-99126216c38c','梅雨','杜甫','唐','唐诗','tang','','["\u957f\u6c5f", "\u5199\u96e8", "\u5199\u666f", "\u96e8"]','南京西浦道，四月熟黃梅。',48,'全唐诗/poet.tang.11000.json','["南京西浦道，四月熟黃梅。", "湛湛長江去，冥冥細雨來。", "茅茨疎易濕，雲霧密難開。", "竟日蛟龍喜，盤渦與岸迴。"]'),
('70d380f8-bc23-408b-8b97-d17b81beb068','爲農','杜甫','唐','唐诗','tang','','[]','錦里煙塵外，江村八九家。',48,'全唐诗/poet.tang.11000.json','["錦里煙塵外，江村八九家。", "圓荷浮小葉，細麥落輕花。", "卜宅從茲老，爲農去國賒。", "遠慚句漏令，不得問丹砂。"]'),
('b9eb7ec2-9795-4b96-bf52-2b23cf2ca4f1','有客','杜甫','唐','唐诗','tang','','[]','幽棲地僻經過少，老病人扶再拜難。',64,'全唐诗/poet.tang.11000.json','["幽棲地僻經過少，老病人扶再拜難。", "豈有文章驚海內，漫勞車馬駐江干。", "竟日淹留佳客坐，百年麤糲腐儒餐。", "不嫌野外無供給，乘興還來看藥欄。"]'),
('81c77b01-47cd-4aba-a980-5bc74b5b9711','狂夫','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u4eba", "\u5199\u666f"]','萬里橋西一，草堂，百花潭水即滄浪。',65,'全唐诗/poet.tang.11000.json','["萬里橋西一，草堂，百花潭水即滄浪。", "風含翠篠娟娟靜，雨裛紅蕖冉冉香。", "厚祿故人書斷絕，恒飢稚子色淒涼。", "欲填溝壑唯疎放，自笑狂夫老更狂。"]'),
('16efc3a7-3ee7-473f-96ec-e25516cfe2cb','賓至','杜甫','唐','唐诗','tang','','[]','患氣經時久，臨江卜宅新。',48,'全唐诗/poet.tang.11000.json','["患氣經時久，臨江卜宅新。", "喧卑方避俗，疎快頗宜人。", "有客過茅宇，呼兒正葛巾。", "自鋤稀菜甲，小摘爲情親。"]'),
('7666f1f3-5124-440d-af0b-735914481fc1','王十五司馬弟出郭相訪兼遺營茅屋貲','杜甫','唐','唐诗','tang','','[]','客裏何遷次，江邊正寂寥。',48,'全唐诗/poet.tang.11000.json','["客裏何遷次，江邊正寂寥。", "肯來尋一老，愁破是今朝。", "憂我營茅棟，攜錢過野橋。", "他鄉唯表弟，還往莫辭遙。"]'),
('f9775db8-a4b0-4a95-a6e5-3424d5159c97','堂成','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','背郭堂成蔭白茅，緣江路熟俯青郊。',64,'全唐诗/poet.tang.11000.json','["背郭堂成蔭白茅，緣江路熟俯青郊。", "榿林礙日吟風葉，籠竹和煙滴露梢。", "暫止飛烏將數子，頻來語燕定新巢。", "旁人錯比揚雄宅，嬾惰無心作解嘲。"]'),
('f54c52d8-8544-482e-9b63-34f6f3b1bdd6','田舍','杜甫','唐','唐诗','tang','','["\u5199\u666f", "\u7530\u56ed"]','田舍清江曲，柴門古道旁。',48,'全唐诗/poet.tang.11000.json','["田舍清江曲，柴門古道旁。", "草深迷市井，地僻嬾衣裳。", "櫸柳枝枝弱，枇杷樹樹香。", "鸕鶿西日照，曬翅滿魚梁。"]'),
('d453f469-2a2c-48a1-8581-0193560729f3','進艇','杜甫','唐','唐诗','tang','','[]','南京久客耕南畝，北望傷神坐北窗。',64,'全唐诗/poet.tang.11000.json','["南京久客耕南畝，北望傷神坐北窗。", "晝引老妻乘小艇，晴看稚子浴清江。", "俱飛蛺蝶元相逐，并蔕芙蓉本自雙。", "茗飲蔗漿攜所有，瓷甖無謝玉爲缸。"]'),
('7147a2b9-5940-46c4-b48b-9316c8112ba1','西郊','杜甫','唐','唐诗','tang','','[]','時出碧雞坊，西郊向草堂。',48,'全唐诗/poet.tang.11000.json','["時出碧雞坊，西郊向草堂。", "市橋官柳細，江路野梅香。", "傍架齊書帙，看題減藥囊。", "無人覺來往，疎嬾意何長。"]'),
('bad1eb23-f31e-4099-bc52-9a9c7e10bb06','所思','杜甫','唐','唐诗','tang','','[]','苦憶荆州醉司馬，謫官樽俎定常開。',64,'全唐诗/poet.tang.11000.json','["苦憶荆州醉司馬，謫官樽俎定常開。", "九江日落醒何處，一柱觀頭眠幾回。", "可憐懷抱向人盡，欲問平安無使來。", "故憑錦水將雙淚，好過瞿塘灧澦堆。"]'),
('a5546090-d778-47ce-abde-d3184e225f64','江村','杜甫','唐','唐诗','tang','','["\u590f\u5929", "\u7530\u56ed", "\u6109\u60a6"]','清江一曲抱村流，長夏江村事事幽。',64,'全唐诗/poet.tang.11000.json','["清江一曲抱村流，長夏江村事事幽。", "自去自來堂上燕，相親相近水中鷗。", "老妻畫紙爲碁局，稚子敲鍼作釣鉤。", "多病所須唯藥物，微軀此外更何求。"]'),
('7a6e1b7d-494b-4ffe-94ac-2b69f9784f35','江漲','杜甫','唐','唐诗','tang','','[]','江漲柴門外，兒童報急流。',48,'全唐诗/poet.tang.11000.json','["江漲柴門外，兒童報急流。", "下牀高數尺，倚杖沒中洲。", "細動迎風燕，輕搖逐浪鷗。", "漁人縈小楫，容易拔船頭。"]'),
('6d3b137e-8d62-4d8d-be0f-88c9589f8ae6','野老','杜甫','唐','唐诗','tang','','["\u7231\u56fd", "\u6292\u6000"]','野老籬前江岸迴，柴門不正逐江開。',64,'全唐诗/poet.tang.11000.json','["野老籬前江岸迴，柴門不正逐江開。", "漁人網集澄潭下，賈客船隨返照來。", "長路關心悲劒閣，片雲何意傍琴臺。", "王師未報收東郡，城闕秋生畫角哀。"]'),
('39f705dc-3756-4ec4-bbc3-ea2e48e3e010','雲山','杜甫','唐','唐诗','tang','','[]','京洛雲山外，音書靜不來。',48,'全唐诗/poet.tang.11000.json','["京洛雲山外，音書靜不來。", "神交作賦客，力盡望鄉臺。", "衰疾江邊臥，親朋日暮迴。", "白鷗元水宿，何事有餘哀。"]'),
('0a9e1040-2e92-4788-ab85-789b57551c08','遣興','杜甫','唐','唐诗','tang','','[]','干戈猶未定，弟妹各何之。',48,'全唐诗/poet.tang.11000.json','["干戈猶未定，弟妹各何之。", "拭淚霑襟血，梳頭滿面絲。", "地卑荒野大，天遠暮江遲。", "衰疾那能久，應無見汝時。"]'),
('a8822810-0ad6-4eb1-8351-688d5cf81991','北鄰','杜甫','唐','唐诗','tang','','[]','明府豈辭滿，藏身方告勞。',48,'全唐诗/poet.tang.11000.json','["明府豈辭滿，藏身方告勞。", "青錢買野竹，白幘岸江臯。", "愛酒晉山簡，能詩何水曹。", "時來訪老疾，步屧到蓬蒿。"]'),
('c8bae0f0-12c6-4d6c-a35d-7077217cfdea','南鄰','杜甫','唐','唐诗','tang','','["\u9001\u522b", "\u751f\u6d3b", "\u6708\u591c"]','錦里先生烏角巾，園收芋粟不全貧。',64,'全唐诗/poet.tang.11000.json','["錦里先生烏角巾，園收芋粟不全貧。", "慣看賓客兒童喜，得食階除鳥雀馴。", "秋水纔深四五尺，野航恰受兩三人。", "白沙翠竹江村暮，相對柴門月色新。"]'),
('d0084305-f95a-4366-b276-ee70d0feb826','出郭','杜甫','唐','唐诗','tang','','[]','霜露晚淒淒，高天逐望低。',48,'全唐诗/poet.tang.11000.json','["霜露晚淒淒，高天逐望低。", "遠煙鹽井上，斜景雪峰西。", "故國猶兵馬，他鄉亦鼓鼙。", "江城今夜客，還與舊烏啼。"]'),
('6299dbfa-43e4-4d45-bb02-83f765e3ea33','過南鄰朱山人水亭','杜甫','唐','唐诗','tang','','[]','相近竹參差，相過人不知。',48,'全唐诗/poet.tang.11000.json','["相近竹參差，相過人不知。", "幽花欹滿樹，小水細通池。", "歸客村非遠，殘樽席更移。", "看君多道氣，從此數追隨。"]'),
('3c24608f-08a4-440f-8401-1c253732f4fc','恨別','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u601d\u4e61", "\u65e0\u5948"]','洛城一別四千里，胡騎長驅五六年。',64,'全唐诗/poet.tang.11000.json','["洛城一別四千里，胡騎長驅五六年。", "草木變衰行劒外，兵戈阻絕老江邊。", "思家步月清宵立，憶弟看雲白日眠。", "聞道河陽近乘勝，司徒急爲破幽燕。"]');
